window.HADITH_CACHE["abu-dawud_1"] = {"501":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا زَيْدٌ يَعْنِي ابْنَ الْحُبَابِ عَنْ مُحَمَّدِ بْنِ صَالِحٍ حَدَّثَنِي حُصَيْنٌ مِنْ وَلَدِ سَعْدِ بْنِ مُعَاذٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍأَنَّهُ كَانَ يَؤُمُّهُمْ قَالَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ إِمَامَنَا مَرِيضٌ فَقَالَ إِذَا صَلَّى قَاعِدًا فَصَلُّوا قُعُودًاقَالَ أَبُو دَاوُد وَهَذَا الْحَدِيثُ لَيْسَ بِمُتَّصِلٍ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah] telah mengabarkan kepada kami [Zaid, yakni Ibnu Al-Hubab] dari [Muhammad bin Shalih] telah menceritakan kepada saya [Hushain] dari anaknya Sa'ad bin Mu'adz dari [Usaid bin Hudhair] bahwa dia mengimami mereka (kaumnya), lalu Rasulullah shallallahu 'alaihi wasallam datang untuk menjenguknya, mereka (kaumnya) berkata; Ya Rasulallah, sesungguhnya imam kami (Usaid bin Hudhair) sedang sakit! Maka beliau bersabda: \"Apabila imam kalian shalat dengan duduk maka shalatlah kalian dengan duduk.\" Abu Dawud berkata; Hadits ini tidak muttashil (bersambung sanadnya). "},"502":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى أُمِّ حَرَامٍ فَأَتَوْهُ بِسَمْنٍ وَتَمْرٍ فَقَالَ رُدُّوا هَذَا فِي وِعَائِهِ وَهَذَا فِي سِقَائِهِ فَإِنِّي صَائِمٌ ثُمَّ قَامَ فَصَلَّى بِنَا رَكْعَتَيْنِ تَطَوُّعًا فَقَامَتْ أُمُّ سُلَيْمٍ وَأُمُّ حَرَامٍ خَلْفَنَا قَالَ ثَابِتٌ وَلَا أَعْلَمُهُ إِلَّا قَالَ ��َقَامَنِي عَنْ يَمِينِهِ عَلَى بِسَاطٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi Ummu Haram, kemudian mereka memberikan beliau samin dan kurma, maka beliau bersabda: \"Kembalikan ini ke tempatnya dan ini ke tempatnya, sesungguhnya aku sedang berpuasa.\" Kemudian beliau shalat sunnah dua rakaat bersama kami. Ummu Sulaim dan Ummu Haram berdiri di belakang kami. Tsabit berkata; Saya tidak mengetahuinya kecuali mengatakan; Beliau memberdirikanku di sebelah kanannya di atas permadani. "},"503":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ الْمُخْتَارِ عَنْ مُوسَى بْنِ أَنَسٍ يُحَدِّثُ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّهُ وَامْرَأَةً مِنْهُمْ فَجَعَلَهُ عَنْ يَمِينِهِ وَالْمَرْأَةَ خَلْفَ ذَلِكَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Al-Mukhtar] dari [Musa bin Anas] dia menceritakan dari [Anas] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah mengimaminya dan seorang wanita dari mereka, maka beliau menjadikan Anas di sebelah kanannya dan wanita tersebut di belakang mereka. "},"504":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ خَالَتِي مَيْمُونَةَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ فَأَطْلَقَ الْقِرْبَةَ فَتَوَضَّأَ ثُمَّ أَوْكَأَ الْقِرْبَةَ ثُمَّ قَامَ إِلَى الصَّلَاةِ فَقُمْتُ فَتَوَضَّأْتُ كَمَا تَوَضَّأَ ثُمَّ جِئْتُ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَنِي بِيَمِينِهِ فَأَدَارَنِي مِنْ وَرَائِهِ فَأَقَامَنِي عَنْ يَمِينِهِ فَصَلَّيْتُ مَعَهُحَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ قَالَ فَأَخَذَ بِرَأْسِي أَوْ بِذُؤَابَتِي فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha`] dari [Ibnu Abbas] dia berkata; Saya pernah bermalam di rumah bibi, Maimunah, kemudian Rasulullah shallallahu 'alaihi wasallam bangun di malam hari, beliau membuka geriba (kantong air dari kulit) dan berwudhu, kemudian menutup kembali geriba tersebut dan berdiri untuk shalat. Lalu saya bangun dan berwudhu sebagaimana beliau berwudhu, kemudian saya menghampiri beliau dan berdiri sisi kiri beliau, namun kemudian beliau memegang tanganku dan memindahkanku lewat belakang beliau hingga aku ditempatkan di sisi kanan beliau, lalu aku pun shalat dengan beliau. Telah menceritakan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dalam kisah ini dia berkata; Beliau shallallahu 'alaihi wasallam memegang kepalaku atau rambut kepalaku kemudian menempatkanku di sebelah kanan beliau. "},"505":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ فَأَكَلَ مِنْهُ ثُمَّ قَالَ قُومُوا فَلَأُصَلِّيَ لَكُمْ قَالَ أَنَسٌ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ أَنَا وَالْيَتِيمُ وَرَاءَهُ وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى لَنَا رَكْعَتَيْنِ ثُمَّ انْصَرَفَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al-Qa'nabi] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa Neneknya, Mulaikah pernah mengundang Rasulullah shallallahu 'alaihi wasallam untuk suatu jamuan makan yang telah dibuatnya. Beliau makan darinya kemudian bersabda: \"Bangkitlah, saya akan mengerjakan shalat untuk kalian.\" Kata Anas; Saya bangkit untuk mengambil tikar kami yang telah menghitam karena lamanya dipakai, lalu saya memercikinya dengan air, kemudian Rasulullah shallallahu 'alaihi wasallam berdiri di atasnya. Saya dan seorang yatim berbaris membuat shaf di belakang beliau, sedangkan nenekku berdiri di belakang kami. Beliau mengerjakan shalat dua rakaat untuk kami, kemudian beliau shallallahu 'alaihi wasallam pergi."},"506":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ هَارُونَ بْنِ عَنْتَرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ قَالَاسْتَأْذَنَ عَلْقَمَةُ وَالْأَسْوَدُ عَلَى عَبْدِ اللَّهِ وَقَدْ كُنَّا أَطَلْنَا الْقُعُودَ عَلَى بَابِهِ فَخَرَجَتْ الْجَارِيَةُ فَاسْتَأْذَنَتْ لَهُمَا فَأَذِنَ لَهُمَا ثُمَّ قَامَ فَصَلَّى بَيْنِي وَبَيْنَهُ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Harun bin 'Antarah] dari [Abdurrahman bin Al-Aswad] dari [Ayahnya] dia berkata; Alqamah dan Al-Aswad pernah meminta izin untuk berkunjung ke rumah [Abdullah bin Mas'ud], kami telah lama duduk menunggu di depan pintunya. Tidak lama kemudian keluar seorang gadis, lalu memohonkan izin untuk kedua orang ini, maka beliau (Abdullah) mengizinkan keduanya. Kemudian Abdullah berdiri mengerjakan shalat antara saya dan Alqamah, setelah itu dia berkata; Demikianlah saya melihat Rasulullah shallallahu 'alaihi wasallam mengerjakannya. "},"507":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي يَعْلَى بْنُ عَطَاءٍ عَنْ جَابِرِ بْنِ يَزِيدَ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا انْصَرَفَ انْحَرَفَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Ya'la bin 'Atha`] dari [Jabir bin Yazid Al-Aswad] dari [Ayahnya] dia berkata; Saya pernah shalat di belakang Rasulullah Shallallahu alaihi wasallam, beliau apabila selesai melaksanakan shalat, beliau merubah posisi duduk. "},"508":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا مِسْعَرٌ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ عُبَيْدِ بْنِ الْبَرَاءِ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْبَبْنَا أَنْ نَكُونَ عَنْ يَمِينِهِ فَيُقْبِلُ عَلَيْنَا بِوَجْهِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Ahmad Az-Zubairi] telah menceritakan kepada kami [Mis'ar] dari [Tsabit bin Ubaid] dari [Ubaid bin Al Barra'] dari [Al-Bara` bin 'Azib] dia berkata; Kami apabila mengerjakan shalat di belakang Rasulullah shallallahu 'alaihi wasallam, kami suka berada di sebelah kanan beliau, karena beliau menghadap kepada kami dengan wajahnya shallallahu 'alaihi wasallam (setelah salam). "},"509":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الْمَلِكِ الْقُرَشِيُّ حَدَّثَنَا عَطَاءٌ الْخُرَاسَانِيُّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّ الْإِمَامُ فِي الْمَوْضِعِ الَّذِي صَلَّى فِيهِ حَتَّى يَتَحَوَّلَقَالَ أَبُو دَاوُد عَطَاءٌ الْخُرَاسَانِيُّ لَمْ يُدْرِكْ الْمُغِيرَةَ بْنَ شُعْبَةَ","id":"Telah menceritakan kepada kami [Abu Taubah, Ar-Rabi' bin Nafi'] telah menceritakan kepada kami [Abdul Aziz bin Abdul Malik Al-Qurasyi] telah menceritakan kepada kami ['Atha` Al-Khurasani] dari [Mughirah bin Syu'bah] dia berkata; Rasulullah Shallallahu alaihi wasallam bersabda: \"Jangan seorang imam shalat di tempat yang semula dipergunakannya untuk shalat wajib, hingga dia bergeser.\" Abu Dawud berkata; 'Atha` Al-Khurasani tidak bertemu dengan Al Mughirah bin Syu'bah. "},"510":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ وَبَكْرِ بْنِ سَوَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى الْإِمَامُ الصَّلَاةَ وَقَعَدَ فَأَحْدَثَ قَبْلَ أَنْ يَتَكَلَّمَ فَقَدْ تَمَّتْ صَلَاتُهُ وَمَنْ كَانَ خَلْفَهُ مِمَّنْ أَتَمَّ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdurrahman bin Ziyad bin An'um] dari [Abdurrahman bin Rafi'] dan [Bakr bin Sawadah] dari [Abdurrahman bin Amru] bahwasanya Rasulullah Shallallahu alaihi wasallam bersabda: \"Apabila seorang imam telah selesai melaksanakan shalat, lalu duduk sejenak lalu batal wudhunya sebelum dia berbicara, maka shalatnya sudah sempurna walaupun di belakangnya masih ada orang yang belum selesai melaksanakanya.\""},"511":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ ابْنِ عَقِيلٍ عَنْ مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu 'Aqil] dari [Muhammad bin Al-Hanafiyyah] dari [Ali radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kunci shalat adalah bersuci, sedangkan yang mengharamkan (segala aktivitas di luar shalat) adalah takbir, dan yang menghalalkannya kembali adalah salam.\""},"512":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَادِرُونِي بِرُكُوعٍ وَلَا بِسُجُودٍ فَإِنَّهُ مَهْمَا أَسْبِقْكُمْ بِهِ إِذَا رَكَعْتُ تُدْرِكُونِي بِهِ إِذَا رَفَعْتُ إِنِّي قَدْ بَدَّنْتُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] telah menceritakan kepadaku [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Mu'awiyah bin Abi Sufyan] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendahuluiku dengan ruku' dan sujud, karena meskipun saya mendahului kalian tatkala ruku', niscaya kalian akan mendapatkanku tatkala saya mengangkat kepalaku (i'tidal), karena saya telah berumur dan badanku berat.\""},"513":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْخَطْمِيَّ يَخْطُبُ النَّاسَ قَالَ حَدَّثَنَا الْبَرَاءُ وَهُوَ غَيْرُ كَذُوبٍأَنَّهُمْ كَانُوا إِذَا رَفَعُوا رُءُوسَهُمْ مِنْ الرُّكُوعِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامُوا قِيَامًا فَإِذَا رَأَوْهُ قَدْ سَجَدَ سَجَدُوا","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] mengatakan, aku mendengar ['Abdullah bin Yazid Alkhatmi] berpidato didepan orang-orang dengan mengatakan, Telah menceritakan kepada kami [Al Barra'] yang dia bukan pendusta,: \"Jika para sahabat mengangkat kepala mereka dari ruku' bersama Rasulullah Shallallahu'alaihiwasallam, mereka berdiri hingga betul-betul telah berdiri, dan jika telah mereka lihat beliau sujud, mereka bersujud.\""},"514":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ مَعْرُوفٍ الْمَعْنَى قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبَانَ بْنِ تَغْلِبَ قَالَ زُهَيْرٌ حَدَّثَنَا الْكُوفِيُّونَ أَبَانُ وَغَيْرُهُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا يَحْنُو أَحَدٌ مِنَّا ظَهْرَهُ حَتَّى يَرَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin Ma'ruf] secara makna, mereka berdua berkata; Telah menceritakan kepada kami [Sufyan] dari [Aban bin Taghlab], berkata [Zuhair]; Telah menceritakan kepada kami Al-Kufiyyun [Aban dan selainnya], dari [Al-Hakam] dari [Abdurrahman bin Abi Laila] dari [Al-Bara`] dia berkata; Kami shalat bersama Nabi shallallahu 'alaihi wasallam, maka tidak ada seorang pun dari kami yang ruku' sampai melihat Nabi shallallahu 'alaihi wasallam ruku'."},"515":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ أَبِي إِسْحَقَ عَنْ مُحَارِبِ بْنِ دِثَارٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يَقُولُ عَلَى الْمِنْبَرِ حَدَّثَنِي الْبَرَاءُأَنَّهُمْ كَانُوا يُصَلُّونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَكَعَ رَكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ لَمْ نَزَلْ قِيَامًا حَتَّى يَرَوْهُ قَدْ وَضَعَ جَبْهَتَهُ بِالْأَرْضِ ثُمَّ يَتَّبِعُونَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ar-Rabi' bin Nafi'] telah menceritakan kepada kami [Abu Ishaq Al-Fazari] dari [Abu Ishaq] dari [Muharib bin Ditsar] dia berkata; Saya pernah mendengar [Abdullah bin Yazid] berkhubtah di atas mimbar, dia berkata; Telah menceritakan kepadaku [Al-Bara`]; bahwasanya mereka (para sahabat) shalat bersama Rasulullah shallallahu 'alaihi wasallam, apabila beliau ruku', mereka pun ruku', dan apabila beliau mengucapkan: Sami'allau liman hamidah (tatkala I'tidal), mereka pun berdiri dan tetap demikian hingga mereka melihat beliau meletakkan keningnya di tanah (sujud) kemudian mereka pun mengikuti beliau shallallahu 'alaihi wasallam. "},"516":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا يَخْشَى أَوْ أَلَا يَخْشَى أَحَدُكُمْ إِذَا رَفَعَ رَأْسَهُ وَالْإِمَامُ سَاجِدٌ أَنْ يُحَوِّلَ اللَّهُ رَأْسَهُ رَأْسَ حِمَارٍ أَوْ صُورَتَهُ صُورَةَ حِمَارٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah takut seseorang di antara kalian apabila mengangkat kepalanya, sementara imamnya masih sersujud, Allah akan merubah kepalanya menjadi kepala keledai atau rupanya menjadi rupa keledai?\""},"517":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَفْصُ بْنُ بُغَيْلٍ الْمُرْهِبِيُّ حَدَّثَنَا زَائِدَةُ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَضَّهُمْ عَلَى الصَّلَاةِ وَنَهَاهُمْ أَنْ يَنْصَرِفُوا قَبْلَ انْصِرَافِهِ مِنْ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al-'Ala`] telah menceritakan kepada kami [Hafsh bin Bughail Al-Murhibi] telah menceritakan kepada kami [Za`idah] dari [Al-Mukhtar bin Fulful] dari [Anas] bahwasanya Nabi shallallahu 'alaihi wasallam memotivasi mereka untuk mengerjakan shalat (berjamaah) dan melarang mereka pergi (meninggalkan tempat) sebelum imam pergi. "},"518":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الصَّلَاةِ فِي ثَوْبٍ وَاحِدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَلِكُلِّكُمْ ثَوْبَانِ","id":"Telah menceritakan kepada kami [Al-Qa'nabi'] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al-Musayyib] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang shalat dengan memakai sehelai kain, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah setiap kalian memiliki dua kain (pakain luar dan pakaian dalam)?\""},"519":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّ أَحَدُكُمْ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى مَنْكِبَيْهِ مِنْهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Abu Az-Zinad] dari [Al-A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang di antara kalian mengerjakan shalat dengan hanya memakai sehelai kain, sedang tidak ada sesuatu yang menutupi bagian atas kedua pundaknya.\""},"520":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ الْمَعْنَى عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فِي ثَوْبٍ فَلْيُخَالِفْ بِطَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] -dari jalur lain- Dan telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] secara makna, dari [Hisyam bin Abi Abdullah] dari [Yahya bin Abi Katsir] dari [Ikrimah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengerjakan shalat dengan memakai sehelai kain, maka silangkanlah kedua ujungnya pada kedua pundaknya.\""},"521":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُلْتَحِفًا مُخَالِفًا بَيْنَ طَرَفَيْهِ عَلَى مَنْكِبَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al-Laits] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahl] dari [Umar bin Abu Salamah] dia berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat memakai sehelai kain dengan cara berselimut. Beliau silangkan kedua ujungnya di atas kedua pundak beliau.\""},"522":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو الْحَنَفِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَقَدِمْنَا عَلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ فَقَالَ يَا نَبِيَّ اللَّهِ مَا تَرَى فِي الصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ قَالَ فَأَطْلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِزَارَهُ طَارَقَ بِهِ رِدَاءَهُ فَاشْتَمَلَ بِهِمَا ثُمَّ قَامَ فَصَلَّى بِنَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَنْ قَضَى الصَّلَاةَ قَالَ أَوَكُلُّكُمْ يَجِدُ ثَوْبَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mulazim bin Amru Al-Hanafi] telah menceritakan kepada kami [Abdullah bin Badr] dari [Qais bin Thalq] dari [Ayahnya] dia berkata; Kami pernah datang kepada Nabi shallallahu 'alaihi wasallam, lalu datang seorang laki laki seraya berkata; Wahai Nabi Allah, bagaimana pendapat Anda tentang shalat dengan memakai sehelai kain? Katanya; Rasulullah shallallahu 'alaihi wasallam lalu melepaskan kain selimut beliau kemudian dipergunakannya untuk berselimut, lalu Nabi shallallahu 'alaihi wasallam berdiri mengerjakan shalat bersama kami, setelah mengerjakan shalat, beliau bersabda: \"Apakah setiap kalian mempunyai dua pakaian?\""},"523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَلَقَدْ رَأَيْتُ الرِّجَالَ عَاقِدِي أُزُرِهِمْ فِي أَعْنَاقِهِمْ مِنْ ضِيقِ الْأُزُرِ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ كَأَمْثَالِ الصِّبْيَانِ فَقَالَ قَائِلٌ يَا مَعْشَرَ النِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَرْفَعَ الرِّجَالُ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al-Anbari] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; Sungguh saya melihat kaum lelaki yang mengikat kain selimutnya di leher mereka karena sempit sedang mengerjakan shalat di belakang Rasulullah shallallahu 'alaihi wasallam seperti anak kecil. Lalu ada seseorang berkata; Wahai kaum wanita, janganlah kalian mengangkat kepala sehingga kaum pria (terlebih dahulu) mengangkat kepala.. "},"524":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زَائِدَةُ عَنْ أَبِي حُصَيْنٍ عَنْ أَبِي صَالِحٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي ثَوْبٍ وَاحِدٍ بَعْضُهُ عَلَيَّ","id":"Telah menceritakan kepada kami [Abul Walid Ath-Thayalisi] telah menceritakan kepada kami [Za`idah] dari [Abu Hushain] dari [Abu Shalih] dari [Aisyah radliallahu 'anha] bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat dengan memakai sehelai kain, sementara sebagiannya mengenaiku. "},"525":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ مُوسَى بْنِ إِبْرَاهِيمَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ أَصِيدُ أَفَأُصَلِّي فِي الْقَمِيصِ الْوَاحِدِ قَالَ نَعَمْ وَازْرُرْهُ وَلَوْ بِشَوْكَةٍ","id":"Telah menceritakan kepada kami [Al-Qa'nabi'] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Musa bin Ibrahim] dari [Salamah bin Al-Akwa'] dia berkata; Saya pernah bertanya; Ya Rasulullah, saya sedang berburu, apakah saya boleh shalat dengan menggunakan sehelai baju? Beliau menjawab: \"Ya, dan ikatlah dia walau hanya dengan duri.\""},"526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي حَوْمَلٍ الْعَامِرِيِّ قَالَ أَبُو دَاوُد كَذَا قَالَ وَالصَّوَابُ أَبُو حَرْمَلٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ قَالَأَمَّنَا جَابِرُ بْنُ عَبْدِ اللَّهِ فِي قَمِيصٍ لَيْسَ عَلَيْهِ رِدَاءٌ فَلَمَّا انْصَرَفَ قَالَ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي قَمِيصٍ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'] telah menceritakan kepada kami [Yahya bin Abi Bukair] dari [Isra`il] dari [Abu Haumal Al-'Amiri], Abu Dawud berkata; demikian dia mengatakan, sedangkan yang benar adalah Abu Harmal dari [Muhammad bin Abdurrahman bin Abu Bakar] dari [Ayahnya] dia berkata; [Jabir bin Abdullah] pernah mengimami kami dengan mengenakan baju yang tidak berselendang. Tatkala selesai, dia berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan baju. "},"527":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ وَيَحْيَى بْنُ الْفَضْلِ السِّجِسْتَانِيُّ قَالُوا حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ حَدَّثَنَا يَعْقُوبُ بْنُ مُجَاهِدٍ أَبُو حَزْرَةَ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ قَالَأَتَيْنَا جَابِرًا يَعْنِي ابْنَ عَبْدِ اللَّهِ قَالَ سِرْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَقَامَ يُصَلِّي وَكَانَتْ عَلَيَّ بُرْدَةٌ ذَهَبْتُ أُخَالِفُ بَيْنَ طَرَفَيْهَا فَلَمْ تَبْلُغْ لِي وَكَانَتْ لَهَا ذَبَاذِبُ فَنَكَّسْتُهَا ثُمَّ خَالَفْتُ بَيْنَ طَرَفَيْهَا ثُمَّ تَوَاقَصْتُ عَلَيْهَا لَا تَسْقُطُ ثُمَّ جِئْتُ حَتَّى قُمْتُ عَنْ يَسَارِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِيَدِي فَأَدَارَنِي حَتَّى أَقَامَنِي عَنْ يَمِينِهِ فَجَاءَ ابْنُ صَخْرٍ حَتَّى قَامَ عَنْ يَسَارِهِ فَأَخَذَنَا بِيَدَيْهِ جَمِيعًا حَتَّى أَقَامَنَا خَلْفَهُ قَالَ وَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُنِي وَأَنَا لَا أَشْعُرُ ثُمَّ فَطِنْتُ بِهِ فَأَشَارَ إِلَيَّ أَنْ أَتَّزِرَ بِهَا فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا جَابِرُ قَالَ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ إِذَا كَانَ وَاسِعًا فَخَالِفْ بَيْنَ طَرَفَيْهِ وَإِذَا كَانَ ضَيِّقًا فَاشْدُدْهُ عَلَى حِقْوِكَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sulaiman bin Abdurrahman Ad-Dimasyqi] dan [Yahya bin Al-Fadll As-Sijistani] mereka berkata; Telah menceritakan kepada kami [Hatim bin Isma'il] telah menceritakan kepada kami [Ya`qub bin Mujahid, Abu Hazrah] dari [Ubadah bin Al-Walid bin Ubadah bin Ash-Shamit] dia berkata; Kami pernah mengunjungi [Jabir bin Abdullah], dia berkata; Saya pernah pergi bersama Nabi shallallahu 'alaihi wasallam dalam suatu peperangan. Lalu beliau berdiri mengerjakan shalat, sementara saya memakai kain selimut yang saya silangkan kedua ujungnya, namun tidak memadai untukku. Kain itu berumbai bagian bawahnya, maka saya membaliknya, lalu saya silangkan kedua ujungnya, kemudian saya apit (dengan leher) supaya tidak jatuh. Lalu saya datang sehingga saya berdiri di sebelah kiri Rasulullah shallallahu 'alaihi wasallam, maka beliau memegang tanganku, dan memindahkanku sehingga saya ditempatkan di sebelah kanan beliau, tiba tiba datang Ibnu Sakhr langsung berdiri di sebelah kiri beliau, maka beliau memegang kami berdua dengan kedua tangannya, sampai beliau menempatkan kami di belakang. Kata Jabir; Rasulullah menatapku, sedangkan saya tidak merasa, akhirnya saya juga dapat memahaminya. Beliau kemudian memberi isyarat kepadaku supaya saya memakai kain tersebut sebagai sarung. Setelah Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Wahai Jabir.\" Kata Jabir; Aku jawab, ya Rasulullah. Beliau bersabda: \"Apabila kain itu longgar, maka silangkanlah kedua ujungnya, dan apabila sempit, ikatlah pada pinggangmu.\""},"528":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِذَا كَانَ لِأَحَدِكُمْ ثَوْبَانِ فَلْيُصَلِّ فِيهِمَا فَإِنْ لَمْ يَكُنْ إِلَّا ثَوْبٌ وَاحِدٌ فَلْيَتَّزِرْ بِهِ وَلَا يَشْتَمِلْ اشْتِمَالَ الْيَهُودِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda, atau Ibnu Umar berkata; Umar radliallahu 'anhu berkata; \"Apabila salah seorang di antara kalian mempunyai dua kain pakaian, maka shalatlah dengan keduanya. Apabila dia mempunyai sehelai kain pakaian saja, hendaklah dia mengenakannya seperti kain sarung dan janganlah dia berselubung seperti orang-orang yahudi.\""},"529":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ الذُّهْلِيُّ حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو تُمَيْلَةَ يَحْيَى بْنُ وَاضِحٍ حَدَّثَنَا أَبُو الْمُنِيبِ عُبَيْدُ اللَّهِ الْعَتَكِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ فِي لِحَافٍ لَا يَتَوَشَّحُ بِهِ وَالْآخَرُ أَنْ تُصَلِّيَ فِي سَرَاوِيلَ وَلَيْسَ عَلَيْكَ رِدَاءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris Adz-Dzuhli] telah menceritakan kepada kami [Sa'id bin Muhammad] telah menceritakan kepada kami [Abu Tumailah, Yahya bin Wadlih] telah menceritakan kepada kami [Abu Al-Munib, Ubaidullah Al-'Ataki] dari [Abdullah bin Buraidah] dari [Ayahnya] dia berkata; Rasulullah Shallallahu alaihi wasallam melarang seseorang shalat dengan menggunakan selimut yang tidak ada pengikatnya untuk pundak, dan beliau juga melarang seseorang yang lain yang shalat menggunakan celana tanpa melapisi badannya dengan selendang. "},"530":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ أَبِي عَوَانَةَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَسْبَلَ إِزَارَهُ فِي صَلَاتِهِ خُيَلَاءَ فَلَيْسَ مِنْ اللَّهِ فِي حِلٍّ وَلَا حَرَامٍقَالَ أَبُو دَاوُد رَوَى هَذَا جَمَاعَةٌ عَنْ عَاصِمٍ مَوْقُوفًا عَلَى ابْنِ مَسْعُودٍ مِنْهُمْ حَمَّادُ بْنُ سَلَمَةَ وَحَمَّادُ بْنُ زَيْدٍ وَأَبُو الْأَحْوَصِ وَأَبُو مُعَاوِيَةَ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam] telah menceritakan kepada kami [Abu Dawud] dari [Abu 'Awanah] dari ['Ashim] dari [Abu Utsman] dari [Ibnu Mas'ud] dia berkata; Saya mendengar Rasulullah Shallallahu alaihi wasallam bersabda; \"Barangsiapa yang isbal (memanjangkan) pakaiannya (hingga melewati mata kaki) dalam shalat karena sombong, maka Allah tidak menghalalkan baginya surga dan tidak mengharamkan neraka untuknya.\" Abu Dawud berkata; Hadits ini diriwayatkan oleh Jama'ah dari ['Ashim] mauquf terhadap [Ibnu Mas'ud], di antara mereka adalah [Hammad bin Salamah] dan [Hammad bin Zaid] dan [Abul Ahwash] dan [Abu Mu'awiyah]. "},"531":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ أَبِي جَعْفَرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا رَجُلٌ يُصَلِّي مُسْبِلًا إِزَارَهُ إِذْ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ ثُمَّ قَالَ اذْهَبْ فَتَوَضَّأْ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ مَا لَكَ أَمَرْتَهُ أَنْ يَتَوَضَّأَ ثُمَّ سَكَتَّ عَنْهُ فَقَالَ إِنَّهُ كَانَ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ وَإِنَّ اللَّهَ تَعَالَى لَا يَقْبَلُ صَلَاةَ رَجُلٍ مُسْبِلٍ إِزَارَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya] dari [Abi Ja'far] dari ['Atha` bin Yasar] dari [Abu Hurairah] dia berkata; Ketika ada seseorang melaksanakan shalat dengan memanjangkan pakaiannya (hingga melewati mata kaki), Rasulullah Shallallahu alaihi wasallam bersabda kepadanya: \"Pergilah dan ulangi wudlumu!\" Maka orang tersebut pergi dan berwudlu lagi, kemudian datang lagi, lalu beliau bersabda lagi kepadanya: \"Pergilah dan ulangi wudlumu!\" Maka dia pergi lagi dan mengulangi wudlunya lalu kembali, dan ada seseorang berkata; Ya Rasulullah, kenapa engkau memerintahkannya untuk berwudlu lagi kemudian engkau mendiamkannya? Beliau bersabda; \"Sesungguhnya orang tersebut shalat dengan memanjangkan pakaiannya (melewati mata kaki), dan sesungguhnya Allah Ta'ala tidak menerima shalat seseorang yang memanjangkan pakaiannya (hingga melewati mata kaki).\""},"532":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ قُنْفُذٍ عَنْ أُمِّهِ أَنَّهَا سَأَلَتْ أُمَّ سَلَمَةَمَاذَا تُصَلِّي فِيهِ الْمَرْأَةُ مِنْ الثِّيَابِ فَقَالَتْ تُصَلِّي فِي الْخِمَارِ وَالدِّرْعِ السَّابِغِ الَّذِي يُغَيِّبُ ظُهُورَ قَدَمَيْهَا","id":"Telah menceritakan kepada kami [Al-Qa'nabi'] dari [Malik] dari [Muhammad bin Zaid bin Qunfudz] dari [Ibunya] bahwasanya dia pernah bertanya kepada [Ummu Salamah]; Pakaian apakah yang boleh digunakan wanita untuk shalat? Dia menjawab; Wanita shalat dengan menggunakan jilbab yang panjang dan gamis yang menutupi telapak kakinya. "},"533":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ يَعْنِي ابْنَ دِينَارٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ بِهَذَا الْحَدِيثِ قَالَ عَنْ أُمِّ سَلَمَةَأَنَّهَا سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُصَلِّي الْمَرْأَةُ فِي دِرْعٍ وَخِمَارٍ لَيْسَ عَلَيْهَا إِزَارٌ قَالَ إِذَا كَانَ الدِّرْعُ سَابِغًا يُغَطِّي ظُهُورَ قَدَمَيْهَاقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ مَالِكُ بْنُ أَنَسٍ وَبَكْرُ بْنُ مُضَرَ وَحَفْصُ بْنُ غِيَاثٍ وَإِسْمَعِيلُ بْنُ جَعْفَرٍ وَابْنُ أَبِي ذِئْبٍ وَابْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ لَمْ يَذْكُرْ أَحَدٌ مِنْهُمْ النَّبِيَّ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ قَصَرُوا بِهِ عَلَى أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Abdurrahman bin Abdullah bin Dinar] dari [Muhammad bin Zaid] dengan hadits ini, dia berkata dari [Ummu Salamah] bahwasanya dia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam; Bolehkah wanita shalat memakai gamis dan jilbab tanpa memakai kain sarung? Beliau menjawab: \"Boleh apabila gamisnya itu longgar yang dapat menutupi punggung kakinya. Abu Dawud berkata; Hadits ini telah diriwayatkan oleh [Malik bin Anas] dan [Bakr bin Mudlar] dan [Hafzh bin Ghiyats] dan [Isma'il bin Ja'far] dan [Ibnu Abi Dzi`b] dan [Ibnu Ishaq] dari [Muhammad bin Zaid] dari [Ibunya] dari [Ummu Salamah], salah satu dari mereka tidak menyebutkan Nabi shallallahu 'alaihi wasallam, mereka hanya menyebutkan Ummu Salamah radliallahu 'anha."},"534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ صَفِيَّةَ بِنْتِ الْحَارِثِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَقْبَلُ اللَّهُ صَلَاةَ حَائِضٍ إِلَّا بِخِمَارٍقَالَ أَبُو دَاوُد رَوَاهُ سَعِيدٌ يَعْنِي ابْنَ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al-Mutsanna] telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Muhammad bin Sirin] dari [Shafiyyah binti Al-Harits] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Allah tidak menerima shalat wanita yang sudah haid (baligh), kecuali dengan memakai tutup kepala.\" Abu Dawud berkata; Diriwayatkan oleh [Sa'id bin Abi 'Arubah] dari [Qatadah] dari [Al-Hasan] dari Nabi shallallahu 'alaihi wasallam. "},"535":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ أَنَّ عَائِشَةَنَزَلَتْ عَلَى صَفِيَّةَ أُمِّ طَلْحَةَ الطَّلَحَاتِ فَرَأَتْ بَنَاتٍ لَهَا فَقَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ وَفِي حُجْرَتِي جَارِيَةٌ فَأَلْقَى لِي حَقْوَهُ وَقَالَ لِي شُقِّيهِ بِشُقَّتَيْنِ فَأَعْطِي هَذِهِ نِصْفًا وَالْفَتَاةَ الَّتِي عِنْدَ أُمِّ سَلَمَةَ نِصْفًا فَإِنِّي لَا أَرَاهَا إِلَّا قَدْ حَاضَتْ أَوْ لَا أُرَاهُمَا إِلَّا قَدْ حَاضَتَاقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ هِشَامٌ عَنْ ابْنِ سِيرِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] bahwasanya [Aisyah] singgah di rumah Shafiyyah, Ummu Thalhah Ath-Thalahat lalu dia meliaht putri-putrinya, maka dia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah masuk, sedangkan di kamarku ada seorang gadis kecil. Maka beliau memberikan kain penutup badan kepadaku dan bersabda: \"Robeklah menjadi dua bagian, kemudian berilah setengahnya untuk gadis ini dan setengah lagi untuk gadis yang berada di Ummu Salamah, karena sesungguhnya saya memandangnya telah baligh, atau beliau bersabda: Saya tidak memandang keduanya kecuali telah baligh. Abu Dawud berkata; Dan demikian pula diriwayatkan oleh [Hisyam] dari [Ibnu Sirin]."},"536":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَإِبْرَاهِيمُ بْنُ مُوسَى عَنْ ابْنِ الْمُبَارَكِ عَنْ الْحَسَنِ بْنِ ذَكْوَانَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ عَطَاءٍ قَالَ إِبْرَاهِيمُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ السَّدْلِ فِي الصَّلَاةِ وَأَنْ يُغَطِّيَ الرَّجُلُ فَاهُقَالَ أَبُو دَاوُد رَوَاهُ عِسْلٌ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ السَّدْلِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al-'Ala`] dan [Ibrahim bin Musa] dari [Ibnu Al-Mubarak] dari [Al-Hasan bin Dzakwan] dari [Sulaiman Al-Ahwal] dari ['Atha`] berkata Ibrahim dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam melarang menjulurkan pakaian dalam shalat dan melarang seseorang menutupi mulutnya (dengan kain). Abu Dawud berkata; Diriwayatkan oleh ['isl] dari ['Atha`] dari [Abu Hurairah] bahwasanya Nabi shallallahu 'alaihi wasallam melarang menjulurkan pakaian ketika shalat. "},"537":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى بْنِ الطَّبَّاعِ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَأَكْثَرُ مَا رَأَيْتُ عَطَاءً يُصَلِّي سَادِلًاقَالَ أَبُو دَاوُد وَهَذَا يُضَعِّفُ ذَلِكَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa bin Ath-Thabba'] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; Sering saya melihat ['Atha`] shalat dengan menjulurkan pakaian. Abu Dawud berkata: Hadits ini melemahkan hadits sebelumnya. "},"538":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَشْعَثُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي فِي شُعُرِنَا أَوْ لُحُفِنَا قَالَ عُبَيْدُ اللَّهِ شَكَّ أَبِي","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al-Asy'ats] dari [Muhammad bin Sirin] dari [Abdullah bin Syaqiq] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam tidak biasa mengerjakan shalat dengan memakai pakaian atau selimut kami. Ubaidullah berkata; Ayahku ragu-ragu. "},"539":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي عِمْرَانُ بْنُ مُوسَى عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ يُحَدِّثُ عَنْ أَبِيهِأَنَّهُ رَأَى أَبَا رَافِعٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِحَسَنِ بْنِ عَلِيٍّ عَلَيْهِمَا السَّلَام وَهُوَ يُصَلِّي قَائِمًا وَقَدْ غَرَزَ ضَفْرَهُ فِي قَفَاهُ فَحَلَّهَا أَبُو رَافِعٍ فَالْتَفَتَ حَسَنٌ إِلَيْهِ مُغْضَبًا فَقَالَ أَبُو رَافِعٍ أَقْبِلْ عَلَى صَلَاتِكَ وَلَا تَغْضَبْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَ كِفْلُ الشَّيْطَانِ يَعْنِي مَقْعَدَ الشَّيْطَانِ يَعْنِي مَغْرَزَ ضَفْرِهِ","id":"Telah menceritakan kepada kami [Al-Hasan bin Ali] telah menceritakan kepada kami [Abdur Razzaq] dari [Ibnu Juraij] telah menceritakan kepadaku ['Imran bin Musa] dari [Sa'id bin Abi Sa'id Al-Maqburi] dia menceritakan dari [Ayahnya] bahwasanya dia pernah melihat Abu Rafi', mantan sahaya Nabi shallallahu 'alaihi wasallam bertemu dengan Hasan bin Ali radliallahu 'anhuma yang sedang shalat dalam keadaan berdiri dengan menyanggulkan rambutnya pada tengkuknya. Abu Rafi' melepasnya, sehingga Hasan menoleh kepadanya dengan marah, lalu [Abu Rafi'] berkata; Perhatikan shalatmu dan jangan marah, karena sesungguhnya saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah tempat duduk syetan.\""},"540":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَهُأَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَأَى عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُصَلِّي وَرَأْسُهُ مَعْقُوصٌ مِنْ وَرَائِهِ فَقَامَ وَرَاءَهُ فَجَعَلَ يَحُلُّهُ وَأَقَرَّ لَهُ الْآخَرُ فَلَمَّا انْصَرَفَ أَقْبَلَ إِلَى ابْنِ عَبَّاسٍ فَقَالَ مَا لَكَ وَرَأْسِي قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا مَثَلُ هَذَا مَثَلُ الَّذِي يُصَلِّي وَهُوَ مَكْتُوفٌ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah] telah menceritakan kepada kami [Ibnu Wahb] dari [Amru bin Al-Harits] bahwasanya [Bukair] menceritakan kepadanya bahwa [Kuraib, mantan sahaya Ibnu Abbas] telah menceritakan kepadanya bahwasanya [Abdullah bin Abbas] pernah melihat Abdullah bin Al-Harits sedang mengerjakan shalat, sementara rambutnya disanggul. Maka Abdullah bin Abbas berdiri di belakangnya, lalu melepasnya, namun Abdullah bin Al-Harits diam saja tidak bergerak. Setelah selesai shalat, dia menghampiri Ibnu Abbas dan berkata; Ada apa denganmu dan rambutku? Ibnu Abbas menjawab; Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penampilan seperti ini laksana orang yang mengerjakan shalat, sementara kedua tangannya diikat kebelakang pundaknya.\""},"541":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَبَّادِ بْنِ جَعْفَرٍ عَنْ ابْنِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي يَوْمَ الْفَتْحِ وَوَضَعَ نَعْلَيْهِ عَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah menceritakan kepadaku [Muhammad bin Abbad bin Ja'far] dari [Ibnu Sufyan] dari [Abdullah bin As-Sa`ib] dia berkata; Saya melihat Nabi shallallahu 'alaihi wasallam sedang melaksanakan shalat pada hari Fathu Makkah, sementara kedua sandalnya diletakkan di sisi kirinya. "},"542":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَأَبُو عَاصِمٍ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ يَقُولُ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ سُفْيَانَ وَعَبْدُ اللَّهِ بْنُ الْمُسَيِّبِ الْعَابِدِيُّ وَعَبْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ بِمَكَّةَ فَاسْتَفْتَحَ سُورَةَ الْمُؤْمِنِينَ حَتَّى إِذَا جَاءَ ذِكْرُ مُوسَى وَهَارُونَ أَوْ ذِكْرُ مُوسَى وَعِيسَى ابْنُ عَبَّادٍ يَشُكُّ أَوْ اخْتَلَفُوا أَخَذَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْلَةٌ فَحَذَفَ فَرَكَعَ وَعَبْدُ اللَّهِ بْنُ السَّائِبِ حَاضِرٌ لِذَلِكَ","id":"Telah menceritakan kepada kami [Al-Hasan bin Ali] telah menceritakan kepada kami [Abdur Razzaq] dan [Abu 'Ashim] mereka berdua berkata; Telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; Saya telah mendengar [Muhammad bin 'Abbad bin Ja'far] berkata; Telah mengabarkan kepadaku [Abu Salamah bin Sufyan] dan [Abdullah bin Al-Musayyib Al-'Abidi] dan [Abdullah bin Amru] dari [Abdullah bin As-Sa`ib] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat Shubuh bersama kami di Makkah. Beliau membaca surat Al-Muminuun, ketika beliau sampai pada ayat tentang cerita Musa dan Harun, atau cerita tentang Musa dan Isa, -Ibnu Abbad ragu-ragu atau mereka berselisih pendapat-, Rasulullah shallallahu 'alaihi wasallam mengalami batuk batuk, lalu beliau berhenti membaca, kemudian ruku', dan Abdullah bin As-Sa`ib turut hadir ketika kejadian itu. "},"543":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي نَعَامَةَ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِأَصْحَابِهِ إِذْ خَلَعَ نَعْلَيْهِ فَوَضَعَهُمَا عَنْ يَسَارِهِ فَلَمَّا رَأَى ذَلِكَ الْقَوْمُ أَلْقَوْا نِعَالَهُمْ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ مَا حَمَلَكُمْ عَلَى إِلْقَاءِ نِعَالِكُمْ قَالُوا رَأَيْنَاكَ أَلْقَيْتَ نَعْلَيْكَ فَأَلْقَيْنَا نِعَالَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ جِبْرِيلَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي فَأَخْبَرَنِي أَنَّ فِيهِمَا قَذَرًا أَوْ قَالَ أَذًى وَقَالَ إِذَا جَاءَ أَحَدُكُمْ إِلَى الْمَسْجِدِ فَلْيَنْظُرْ فَإِنْ رَأَى فِي نَعْلَيْهِ قَذَرًا أَوْ أَذًى فَلْيَمْسَحْهُ وَلْيُصَلِّ فِيهِمَاحَدَّثَنَا مُوسَى يَعْنِي ابْنَ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنِي بَكْرُ بْنُ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّ��َ بِهَذَا قَالَ فِيهِمَا خَبَثٌ قَالَ فِي الْمَوْضِعَيْنِ خَبَثٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Na'amah As-Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id Al-Khudri] dia berkata; Tatkala Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat bersama para sahabatnya, tiba tiba beliau melepaskan kedua sandalnya lalu meletakkannya di sebelah kirinya. Sewaktu para sahabat melihat tindakan beliau tersebut, mereka ikut pula melepas sandal mereka. Maka tatkala Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Apa gerangan yang membuat kalian melepas sandal sandal kalian?\" Mereka menjawab; Kami melihat engkau melepas sandal, sehingga kami pun melepaskan sandal sandal kami. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Malaikat Jibril 'Alaihis Salam telah datang kepadaku, lalu memberitahukan kepadaku bahwa di sepasang sandal itu ada najisnya.\" Selanjutnya beliau bersabda: \"Apabila salah seorang di antara kalian datang ke masjid, maka perhatikanlah, jika dia melihat di sepasang sandalnya terdapat najis atau kotoran maka bersihkan, dan shalatlah dengan sepasang sandalnya itu.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepadaku [Bakr bin Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti Hadits ini, beliau bersabda: \"Pada keduanya terdapat kotoran.\""},"544":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ هِلَالِ بْنِ مَيْمُونٍ الرَّمْلِيِّ عَنْ يَعْلَى بْنِ شَدَّادِ بْنِ أَوْسٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِفُوا الْيَهُودَ فَإِنَّهُمْ لَا يُصَلُّونَ فِي نِعَالِهِمْ وَلَا خِفَافِهِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Marwan bin Mu'awiyah Al-Fazari] dari [Hilal bin Maimun Ar-Ramli] dari [Ya'la bin Syaddad bin Aus] dari [Ayahnya] dia berkata; Rasulullah Shallallahu alaihi wasallam bersabda: \"Selisihilah orang-orang yahudi, yang mereka beribadah dengan tidak mengenakan sandal-sandal dan juga khuf (sepatu) mereka.\""},"545":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حَافِيًا وَمُنْتَعِلًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Ali bin Al-Mubarak] dari [Husain Al-Mu'allim] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] dia berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dengan kaki telanjang dan memakai sandal. "},"546":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا صَالِحُ بْنُ رُسْتُمَ أَبُو عَامِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ قَيْسٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلَا يَضَعْ نَعْلَيْهِ عَنْ يَمِينِهِ وَلَا عَنْ يَسَارِهِ فَتَكُونَ عَنْ يَمِينِ غَيْرِهِ إِلَّا أَنْ لَا يَكُونَ عَنْ يَسَارِهِ أَحَدٌ وَلْيَضَعْهُمَا بَيْنَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami [Al-Hasan bin Ali] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Shalih bin Rustum, Ab 'Amir] dari [Abdurrahman bin Qais] dari [Yusuf bin Mahak] dari [Abu Hurairah] bahwasanya Rasulullah Shallallahu alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian melaksanakan shalat, janganlah dia meletakkan sandalnya di sisi kanan atau kirinya sehingga menjadi di sisi kanan orang lain, kecuali di sisi kirinya tidak ada orang lain, dan hendaklah dia meletakkannya di antara kedua kakinya.\""},"547":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بَقِيَّةُ وَشُعَيْبُ بْنُ إِسْحَقَ عَنْ الْأَوْزَاعِيِّ حَدَّثَنِي مُحَمَّدُ بْنُ الْوَلِيدِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَخَلَعَ نَعْلَيْهِ فَلَا يُؤْذِ بِهِمَا أَحَدًا لِيَجْعَلْهُمَا بَيْنَ رِجْلَيْهِ أَوْ لِيُصَلِّ فِيهِمَا","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] telah menceritakan kepada kami [Baqiyyah] dan [Syu'aib bin Ishaq] dari [Al-Auza'i] telah menceritakan kepadaku [Muhammad bin Al-Walid] dari [Sa'id bin Abi Sa'id] dari [Ayahnya] dari [Abu Hurairah] dari Rasulullah Shallallahu alaihi wasallam, beliau bersabda: \"Apabila salah seorang di antara kalian shalat dengan melepaskan kedua sandalnya, janganlah mengganggu orang lain dengannya, hendaklah dia meletakkan kedua sandalnya di antara kedua kakinya atau dia shalat dengan menggunakan keduanya.\""},"548":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ حَدَّثَتْنِي مَيْمُونَةُ بِنْتُ الْحَارِثِ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا حِذَاءَهُ وَأَنَا حَائِضٌ وَرُبَّمَا أَصَابَنِي ثَوْبُهُ إِذَا سَجَدَ وَكَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami [Amru bin Aun] telah menceritakan kepada kami [Khalid] dari [Asy-Syaibani] dari [Abdullah bin Syaddad] telah menceritakan kepadaku [Maimunah binti Al-Harits] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat, sementara saya berada dekat kaki beliau dan saya sedang haidl. Terkadang pakaian beliau mengenaiku ketika beliau sujud, beliau itu mengerjakan shalat di atas tikar kecil. "},"549":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ ضَخْمٌ وَكَانَ ضَخْمًا لَا أَسْتَطِيعُ أَنْ أُصَلِّيَ مَعَكَ وَصَنَعَ لَهُ طَعَامًا وَدَعَاهُ إِلَى بَيْتِهِ فَصَلِّ حَتَّى أَرَاكَ كَيْفَ تُصَلِّي فَأَقْتَدِيَ بِكَ فَنَضَحُوا لَهُ طَرَفَ حَصِيرٍ كَانَ لَهُمْ فَقَامَ فَصَلَّى رَكْعَتَيْنِ قَالَ فُلَانُ بْنُ الْجَارُودِ لِأَنَسِ بْنِ مَالِكٍ أَكَانَ يُصَلِّي الضُّحَى قَالَ لَمْ أَرَهُ صَلَّى إِلَّا يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Syu'bah] dari [Anas bin Sirin] dari [Anas bin Malik] dia berkata; Ada seorang laki laki dari golongan Anshar berkata; Wahai Rasulullah, saya seorang laki laki yang sangat gemuk dia memang sangat gemuk, saya tidak mampu shalat bersamamu. Laki laki itu membuat makanan untuk beliau, lalu mengundang beliau ke rumahnya. Laki-laki itu berkata; Maka Shalatlah, sehingga saya dapat melihat bagaimana cara engkau mengerjakan shalat, dan saya mengikuti gerakanmu. Mereka kemudian memerciki ujung tikar mereka dengan air untuk beliau, lalu beliau berdiri mengerjakan shalat dua rakaat. Berkata Fulan bin Al-Jarud kepada Anas bin Malik; Apakah beliau itu shalat Dhuha? Kata Anas, \"Saya belum pernah melihat beliau shalat kecuali pada hari itu. "},"550":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ الذَّارِعُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَزُورُ أُمَّ سُلَيْمٍ فَتُدْرِكُهُ الصَّلَاةُ أَحْيَانًا فَيُصَلِّي عَلَى بِسَاطٍ لَنَا وَهُوَ حَصِيرٌ نَنْضَحُهُ بِالْمَاءِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Al-Mutsanna bin Sa'id Adz-Dzira'] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengunjungi Ummu Sulaim dan terkadang sampai (waktu) shalat tiba, maka beliau mengerjakan shalat di atas hamparan kami, yaitu tikar yang kami perciki dengan air."},"551":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ بِمَعْنَى الْإِسْنَادِ وَالْحَدِيثِ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ عَنْ يُونُسَ بْنِ الْحَارِثِ عَنْ أَبِي عَوْنٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْحَصِيرِ وَالْفَرْوَةِ الْمَدْبُوغَةِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar bin Maisarah] dan [Utsman bin Abi Syaibah] dengan makna yang sama dalam isnad dan lafazh hadits. Mereka berdua berkata; Telah menceritakan kepada kami [Abu Ahmad Az-Zubairi] dari [Yunus bin Al-Harits] dari [Abu 'Aun] dari [Ayahnya] dari [Al-Mughirah bin Syu'bah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat di atas tikar dan kulit yang telah disamak. "},"552":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ حَدَّثَنَا غَالِبٌ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِدَّةِ الْحَرِّ فَإِذَا لَمْ يَسْتَطِعْ أَحَدُنَا أَنْ يُمَكِّنَ وَجْهَهُ مِنْ الْأَرْضِ بَسَطَ ثَوْبَهُ فَسَجَدَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Bisyr bin Al-Mufadldlal] telah menceritakan kepada kami [Ghalib] dari [Bakr bin Abdullah] dari [Anas bin Malik] dia berkata; Kami pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam di waktu yang sangat panas, apabila salah seorang dari kami tidak sanggup menempelkan dahinya di tanah, dia menghamparkan kainnya lalu bersujud di atasnya. "},"553":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ قَالَ سَأَلْتُ سُلَيْمَانَ الْأَعْمَشَ عَنْ حَدِيثِ جَابِرِ بْنِ سَمُرَةَ فِي الصُّفُوفِ الْمُقَدَّمَةِ فَحَدَّثَنَا عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَصُفُّونَ كَمَا تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهِمْ جَلَّ وَعَزَّ قُلْنَا وَكَيْفَ تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهِمْ قَالَ يُتِمُّونَ الصُّفُوفَ الْمُقَدَّمَةَ وَيَتَرَاصُّونَ فِي الصَّفِّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An-Nufaili] telah menceritakan kepada kami [Zuhair] dia berkata; Saya pernah bertanya kepada [Sulaiman Al-A'masy] tentang hadits Jabir bin Samurah dalam hal shaf terdepan, maka dia menceritakan kepada kami dari [Al-Musayyab bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samurah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kalian ingin berbaris sebagaimana para malaikat berbarls di hadapan Rabb mereka Azza wa Jalla?\" Kami berkata; Bagaimana para malaikat berbaris di hadapan Rabb mereka? Baliau bersabda: \"Mereka menyempurnakan shaf shaf yang terdepan, dan mereka saling merapatkan shaf.\""},"554":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِي الْقَاسِمِ الْجُدَلِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّاسِ بِوَجْهِهِ فَقَالَ أَقِيمُوا صُفُوفَكُمْ ثَلَاثًا وَاللَّهِ لَتُقِيمُنَّ صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ قُلُوبِكُمْ قَالَ فَرَأَيْتُ الرَّجُلَ يَلْزَقُ مَنْكِبَهُ بِمَنْكِبِ صَاحِبِهِ وَرُكْبَتَهُ بِرُكْبَةِ صَاحِبِهِ وَكَعْبَهُ بِكَعْبِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Waki'] dari [Zakariyya bin Abi Za`idah] dari [Abul Qasim Al-Judali] dia berkata; Saya telah mendengar [An-Numan bin Basyir] berkata; Rasulullah shallallahu 'alaihi wasallam biasa menghadap kepada jamaah, lalu bersabda: \"Luruskanlah shaf shaf kalian! -beliau mengucapkannya tiga kali- Demi Allah, hendaklah kalian benar-benar meluruskan shaf shaf kalian, atau Allah benar--benar akan membuat hati kalian saling berselisih.\" Kata Nu'man; Maka saya melihat seseorang melekatkan (merapatkan) pundaknya dengan pundak temannya (orang di sampingnya), demikian pula antara lutut dan mata kakinya dengan lutut dan mata kaki temannya. "},"555":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَ��َّمَ يُسَوِّينَا فِي الصُّفُوفِ كَمَا يُقَوَّمُ الْقِدْحُ حَتَّى إِذَا ظَنَّ أَنْ قَدْ أَخَذْنَا ذَلِكَ عَنْهُ وَفَقِهْنَا أَقْبَلَ ذَاتَ يَوْمٍ بِوَجْهِهِ إِذَا رَجُلٌ مُنْتَبِذٌ بِصَدْرِهِ فَقَالَ لَتُسَوُّنَّ صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ وُجُوهِكُمْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Simak bin Harb] dia berkata; Saya telah mendengar [An-Nu'man bin Basyir] berkata; Nabi shallallahu 'alaihi wasallam biasa meluruskan shaf kami, sebagaimana beliau meluruskan anak panah, sehingga setelah beliau merasa bahwa kami telah memenuhi perintahnya dan memahami benar benar, tiba tiba pada suatu hari beliau menghadapkan wajahnya kepada kami dan melihat masih ada seseorang yang menonjolkan dadanya ke depan, maka beliau bersabda: \"Hendaklah kalian meratakan shaf, atau (kalau tidak), maka Allah akan merubah wajah-wajah kalian.\""},"556":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَأَبُو عَاصِمِ بْنُ جَوَّاسٍ الْحَنَفِيُّ عَنْ أَبِي الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ طَلْحَةَ الْيَامِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْسَجَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُ الصَّفَّ مِنْ نَاحِيَةٍ إِلَى نَاحِيَةٍ يَمْسَحُ صُدُورَنَا وَمَنَاكِبَنَا وَيَقُولُ لَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَكَانَ يَقُولُ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصُّفُوفِ الْأُوَلِ","id":"Telah menceritakan kepada kami [Hannad bin As-Sariy] dan [Abu 'Ashim bin Jawwas Al-Hanafi] dari [Abu Al-Ahwash] dari [Manshur] dari [Thalhah Al-Yamiy] dari [Abdurrahman bin Ausajah] dari [Al-Bara` bin 'Azib] dia berkata; Rasulullah shallallahu 'alaihi wasallam biasa memasuki celah celah shaf, dari ujung ke ujung lainnya seraya mengusap dada dan pundak kami, lalu bersabda: \"Janganlah kalian berselisih, sehingga akan membuat hati kalian berselisih juga.\" Beliau juga bersabda: \"Sesungguhnya Allah dan para malaikatNya bershalawat kepada shaf shaf pertama.\""},"557":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ أَبِي صَغِيرَةَ عَنْ سِمَاكٍ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَوِّي صُفُوفَنَا إِذَا قُمْنَا لِلصَّلَاةِ فَإِذَا اسْتَوَيْنَا كَبَّرَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Khalid bin Al-Harits] telah menceritakan kepada kami [Hatim bin Abi Shaghirah] dari [Simak] dia berkata; Saya telah mendengar [An-Nu'man bin Basyir] berkata; Rasulullah shallallahu 'alaihi wasallam biasa meluruskan shaf shaf kami apabila kami berdiri untuk shalat. Kalau barisan kami telah lurus, maka beliau bertakbir. "},"558":{"ar":"حَدَّثَنَا عِيسَى بْنُ إِبْرَاهِيمَ الْغَافِقِيُّ حَدَّثَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ وَحَدِيثُ ابْنِ وَهْبٍ أَتَمُّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ قُتَيْبَةُ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ أَبِي شَجَرَةَ لَمْ يَذْكُرْ ابْنَ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقِيمُوا الصُّفُوفَ وَحَاذُوا بَيْنَ الْمَنَاكِبِ وَسُدُّوا الْخَلَلَ وَلِينُوا بِأَيْدِي إِخْوَانِكُمْ لَمْ يَقُلْ عِيسَى بِأَيْدِي إِخْوَانِكُمْ وَلَا تَذَرُوا فُرُجَاتٍ لِلشَّيْطَانِ وَمَنْ وَصَلَ صَفًّا وَصَلَهُ اللَّهُ وَمَنْ قَطَعَ صَفًّا قَطَعَهُ اللَّهُقَالَ أَبُو دَاوُد أَبُو شَجَرَةَ كَثِيرُ بْنُ مُرَّةَ قَالَ أَبُو دَاوُد وَمَعْنَى وَلِينُوا بِأَيْدِي إِخْوَانِكُمْ إِذَا جَاءَ رَجُلٌ إِلَى الصَّفِّ فَذَهَبَ يَدْخُلُ فِيهِ فَيَنْبَغِي أَنْ يُلِينَ لَهُ كُلُّ رَجُلٍ مَنْكِبَيْهِ حَتَّى يَدْخُلَ فِي الصَّفِّ","id":"Telah menceritakan kepada kami [Isa bin Ibrahim Al-Ghafiqi] telah menceritakan kepada kami [Ibnu Wahb] -dari jalur lain- Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al-Laits] dan hadits riwayat Ibnu Wahb lebih sempurna, dari [Mu'awiyah bin Shalih] dari [Abu Az-Zahiriyyah] dari [Katsir bin Murrah] dari [Abdullah bin Umar], Qutaibah berkata; dari Az-Zahiriyah dari Abi Syajarah tanpa menyebutkan Ibnu Umar bahwasanya Rasulullah Shallallahu alaihi wasallam bersabda: \"Tegakkanlah shaf-shaf, sejajarkanlah antara pundak-pundak, tutuplah celah-celah dan lemah lembutlah terhadap kedua tangan saudara kalian, -[Isa] tidak menyebutkan; tangan saudara kalian- dan janganlah kalian membiarkan celah-celah itu untuk setan, barangsiapa yang menyambung shaf maka Allah akan menyambungnya dan barang siapa yang memutusnya maka Allah Allah akan memutusnya.\" Abu Dawud berkata; Abu Syajarah adalah Katsir bin Murrah. Abu Dawud berkata; Makna dari kalimat lemah lembutlah kalian terhadap tangan saudara kalian adalah, apabila ada seseorang yang baru datang dan masuk ke dalam shaf, maka yang lain hendaknya melemaskan pundaknya hingga dia dapat masuk ke dalam shaf."},"559":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُصُّوا صُفُوفَكُمْ وَقَارِبُوا بَيْنَهَا وَحَاذُوا بِالْأَعْنَاقِ فَوَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَرَى الشَّيْطَانَ يَدْخُلُ مِنْ خَلَلِ الصَّفِّ كَأَنَّهَا الْحَذَفُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] dari [Qatadah] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Rapatkan shaf shaf kalian, dekatkanlah jarak antara keduanya, dan sejajarkanlah antara leher-leher. Demi Dzat yang jiwaku berada di TanganNya, sesungguhnya saya melihat setan masuk ke dalam celah celah shaf itu, tak ubahnya bagai anak kambing kecil.\""},"560":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَسُلَيْمَانُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوُّوا صُفُوفَكُمْ فَإِنَّ تَسْوِيَةَ الصَّفِّ مِنْ تَمَامِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Al-Walid Ath-Thayalisi] dan [Sulaiman bin Harb] mereka berdua berkata; Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luruskan shaf shaf kalian, karena sesungguhnya meluruskan shaf termasuk kesempurnaan shalat (berjama'ah).\""},"561":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ مُصْعَبِ بْنِ ثَابِتِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ السَّائِبِ صَاحِبِ الْمَقْصُورَةِ قَالَصَلَّيْتُ إِلَى جَنْبِ أَنَسِ بْنِ مَالِكٍ يَوْمًا فَقَالَ هَلْ تَدْرِي لِمَ صُنِعَ هَذَا الْعُودُ فَقُلْتُ لَا وَاللَّهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ يَدَهُ عَلَيْهِ فَيَقُولُ اسْتَوُوا وَعَدِّلُوا صُفُوفَكُمْحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ حَدَّثَنَا مُصْعَبُ بْنُ ثَابِتٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ أَنَسٍ بِهَذَا الْحَدِيثِ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ أَخَذَهُ بِيَمِينِهِ ثُمَّ الْتَفَتَ فَقَالَ اعْتَدِلُوا سَوُّوا صُفُوفَكُمْ ثُمَّ أَخَذَهُ بِيَسَارِهِ فَقَالَ اعْتَدِلُوا سَوُّوا صُفُوفَكُمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Mush'ab bin Tsabit bin Abdullah bin Az-Zubair] dari [Muhammad bin Muslim bin As-Sa`ib] dia berkata; Pada suatu hari saya pernah shalat di samping [Anas bin Malik], lalu dia berkata; Tahukah kamu apa yang dilakukan dengan kayu ini? Saya katakan; Tidak tahu, demi Allah. Dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa memegangnya dan bersabda: \"Luruskan dan tegakkan shaf-shaf kalian.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Humaid bin Al-Aswad] telah menceritakan kepada kami [Mush'ab bin Tsabit] dari [Muhammad bin Muslim] dari [Anas] dengan hadits ini, dia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam apabila bangkit untuk shalat, beliau mengambilnya dengan tangan kanannya, kemudian menoleh dan bersabda: \"Tegaklah, luruskanlah shaf-shaf kalian.\" Lalu beliau mengambilnya dengan tangan kirinya dan bersabda: \"Luruskanlah shaf-shaf kalian.\""},"562":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا جَعْفَرُ بْنُ يَحْيَى بْنِ ثَوْبَانَ قَالَ أَخْبَرَنِي عَمِّي عُمَارَةُ بْنُ ثَوْبَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِيَارُكُمْ أَلْيَنُكُمْ مَنَاكِبَ فِي الصَّلَاةِقَالَ أَبُو دَاوُد جَعْفَرُ بْنُ يَحْيَى مِنْ أَهْلِ مَكَّةَ","id":"Telah menceritakan kepada kami [Ibnu Basysyar] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ja'far bin Yahya bin Tsauban] dia berkata; Telah mengabarkan kepadaku [Umarah bin Tsauban] dari ['Atha`] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik baik kalian adalah orang yang paling berlaku lunak menyentuh bahu bahu temannya (ketika meratakan shaf shalat). Abu Dawud berkata; Ja'far bin Yahya termasuk penduduk Makkah. "},"563":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ هَانِئٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ مَحْمُودٍ قَالَصَلَّيْتُ مَعَ أَنَسِ بْنِ مَالِكٍ يَوْمَ الْجُمُعَةِ فَدُفِعْنَا إِلَى السَّوَارِي فَتَقَدَّمْنَا وَتَأَخَّرْنَا فَقَالَ أَنَسٌ كُنَّا نَتَّقِي هَذَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Hani`] dari [Abdul Hamid bin Mahmud] dia berkata; Saya pernah shalat di belakang Anas bin Malik pada Hari Jum'at, kami didorong untuk tidak shalat di antara kedua tiang hingga ada di antara kami yang maju ke depan dan ada yang mundur ke belakang. Lalu [Anas] berkata; Kami pada zaman Rasulullah Shallallahu alaihi wasallam dahulu menghindari tempat (tiang) tersebut ketika shalat. "},"564":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَلِنِي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَزَادَ وَلَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَإِيَّاكُمْ وَهَيْشَاتِ الْأَسْوَاقِ","id":"Telah menceritakan kepada kami [Ibnu Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al-A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dari [Abu Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah yang menempati shaf di belakangku adalah orang orang dewasa dan cerdik pandai, kemudian orang orang yang (kualitas dan umurnya) setelah mereka, kemudian orang orang yang (kualitas dan umurnya) setelah mereka.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari [Abu Ma'syar] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, semisal dengannya, dan menambahkan lafazh; Dan janganlah kalian berselisih sehingga menyebabkan hati kalian saling berselisih. Dan jauhilah olehmu suara ribut seperti di tengah pasar. "},"565":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى مَيَامِنِ الصُّفُوفِ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari [Usamah bin Zaid] dari [Utsman bin Urwah] dari [Urwah] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah dan para malaikatNya mengucapkan shalawat untuk orang orang yang berada di shaf kanan.\""},"566":{"ar":"حَدَّثَنَا عِيسَى بْنُ شَاذَانَ حَدَّثَنَا عَيَّاشٌ الرَّقَّامُ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا بُدَيْلٌ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ قَالَ قَالَ أَبُو مَالِكٍ الْأَشْعَرِيُّأَلَا أُحَدِّثُكُمْ بِصَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَقَامَ الصَّلَاةَ وَصَفَّ الرِّجَالَ وَصَفَّ خَلْفَهُمْ الْغِلْمَانَ ثُمَّ صَلَّى بِهِمْ فَذَكَرَ صَلَاتَهُ ثُمَّ قَالَ هَكَذَا صَلَاةُ قَالَ عَبْدُ الْأَعْلَى لَا أَحْسَبُهُ إِلَّا قَالَ صَلَاةُ أُمَّتِي","id":"Telah menceritakan kepada kami [Isa bin Syadzan] telah menceritakan kepada kami ['Ayyasy Ar-Raqqam] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Budail] telah menceritakan kepada kami [Syahr bin Hausyab] dari [Abdurrahman bin Ghanm] dia berkata; [Abu Malik Al-Asy'ari] berkata; Maukah aku ceritakan kepada kalian tentang shalat Nabi shallallahu 'alaihi wasallam? Dia melanjutkan; Beliau shallallahu 'alaihi wasallam mendirikan shalat, beliau membariskan shaf laki-laki dewasa dan di belakang mereka anak-anak muda, lalu beliau shalat bersama mereka. Abu Malik kemudian menyebutkan shalat beliau, lalu beliau bersabda: \"Inilah shalat.\" Abdul A'la berkata; Saya tidak menyangka Abu Malik kecuali dia menyebutkan sabda beliau: \"Inilah shalat umatku.\""},"567":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا خَالِدٌ وَإِسْمَعِيلُ بْنُ زَكَرِيَّاءَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ صُفُوفِ الرِّجَالِ أَوَّلُهَا وَشَرُّهَا آخِرُهَا وَخَيْرُ صُفُوفِ النِّسَاءِ آخِرُهَا وَشَرُّهَا أَوَّلُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash-Shabbah Al-Bazzaz] telah menceritakan kepada kami [Khalid] dan [Isma'il bin Zakariyya] dari [Suhail bin Abi Shalih] dari [Ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik baik shaf laki laki adalah shaf yang pertama dan sejelek jeleknya adalah shaf yang terakhir. Sebaik baik shaf wanita adalah yang terakhir dan sejelek jeleknya adalah shaf yang pertama.\""},"568":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ قَوْمٌ يَتَأَخَّرُونَ عَنْ الصَّفِّ الْأَوَّلِ حَتَّى يُؤَخِّرَهُمْ اللَّهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Abdur Razzaq] dari [Ikrimah bin Ammar] dari [Yahya bin Abi Katsir] dari [Abu Salamah] dari [Aisyah] dia berkata; Rasulullah Shallallahu alaihi wasallam bersabda: \"Akan ada suatu kaum yang suka melambat-lambatkan diri dari shaf pertama, hingga Allah melambatkan mereka (keluar dari) neraka.\""},"569":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ قَالَا حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي أَصْحَابِهِ تَأَخُّرًا فَقَالَ لَهُمْ تَقَدَّمُوا فَأْتَمُّوا بِي وَلْيَأْتَمَّ بِكُمْ مَنْ بَعْدَكُمْ وَلَا يَزَالُ قَوْمٌ يَتَأَخَّرُونَ حَتَّى يُؤَخِّرَهُمْ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muhammad bin Abdullah Al-Khuza'i] dia berkata; Telah menceritakan kepada kami [Abu Al-Asyhab] dari [Abu Nadlrah] dari [Abu Sa'id Al-Khudri] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah melihat pada sahabat sahabatnya bersikap lamban (untuk maju ke depan), maka beliau bersabda kepada mereka: \"Majulah dan ikutilah aku, dan hendaklah orang yang di belakang kalian mengikuti kalian. Suatu kaum masih saja bersikap lamban, sehingga Allah Azza wa Jalla juga akan memperlamban mereka (dari RahmatNya).\""},"570":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ يَحْيَى بْنِ بَشِيرِ بْنِ خَلَّادٍ عَنْ أُمِّهِ أَنَّهَا دَخَلَتْ عَلَى مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ فَسَمِعَتْهُ يَقُولُ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسِّطُوا الْإِمَامَ وَسُدُّوا الْخَلَلَ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [Ibnu Abi Fudaik] dari [Yahya bin Basyir bin Khallad] dari [Ibunya] bahwasanya dia pernah menemui [Muhammad bin Ka'b Al-Qurazhi] lalu dia mendengarnya berkata; Telah menceritakan kepadaku [Abu Hurairah] dia berkata; Rasulullah Shallallahu alaihi wasallam bersabda: \"Jadikanlah imam berada di tengah-tengah kalian dan tutuplah celah-celah shaf.\""},"571":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَحَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عَمْرِو بْنِ رَاشِدٍ عَنْ وَابِصَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُصَلِّي خَلْفَ الصَّفِّ وَحْدَهُ فَأَمَرَهُ أَنْ يُعِيدَ قَالَ سُلَيْمَانُ بْنُ حَرْبٍ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Hafsh bin Umar] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Hilal bin Yasaf] dari [Amru bin Rasyid] dari [Wabishah] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang laki laki mengerjakan shalat sendirian di belakang shaf, maka beliau memerintahkannya untuk mengulangi kembali shalatnya. Sulaiman bin Harb menyebutkan; (mengulangi) shalatnya. "},"572":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ أَنَّ يَزِيدَ بْنَ زُرَيْعٍ حَدَّثَهُمْ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ زِيَادٍ الْأَعْلَمِ حَدَّثَنَا الْحَسَنُ أَنَّ أَبَا بَكْرَةَ حَدَّثَأَنَّهُ دَخَلَ الْمَسْجِدَ وَنَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَاكِعٌ قَالَ فَرَكَعْتُ دُونَ الصَّفِّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَكَ اللَّهُ حِرْصًا وَلَا تَعُدْ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] bahwasanya [Yazid bin Zurai'] telah menceritakan kepada mereka, Telah menceritakan kepada kami [Sa'id bin Abi 'Arubah] dari [Ziyad Al-A'lam] telah menceritakan kepada kami [Al-Hasan] bahwasanya [Abu Bakrah] telah menceritakan kepadanya bahwa dia pernah masuk ke dalam masjid, sedangkan Nabiyullah shallallahu 'alaihi wasallam sedang ruku'. Kata Abu Bakrah; Maka saya ruku' di luar shaf, lalu setelah Nabi shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Semoga Allah menambahkan untukmu semangat melakukan kebaikan, dan janganlah kamu mengulanginya lagi.\""},"573":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا زِيَادٌ الْأَعْلَمُ عَنْ الْحَسَنِ أَنَّ أَبَا بَكْرَةَجَاءَ وَرَسُولُ اللَّهِ رَاكِعٌ فَرَكَعَ دُونَ الصَّفِّ ثُمَّ مَشَى إِلَى الصَّفِّ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ أَيُّكُمْ الَّذِي رَكَعَ دُونَ الصَّفِّ ثُمَّ مَشَى إِلَى الصَّفِّ فَقَالَ أَبُو بَكْرَةَ أَنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَكَ اللَّهُ حِرْصًا وَلَا تَعُدْقَالَ أَبُو دَاوُد زِيَادٌ الْأَعْلَمُ زِيَادُ بْنُ فُلَانِ بْنِ قُرَّةَ وَهُوَ ابْنُ خَالَةِ يُونُسَ بْنِ عُبَيْدٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Ziyad Al-A'lam] dari [Al-Hasan] bahwasanya [Abu Bakrah] datang, sedangkan Rasulullah shallallahu 'alaihi wasallam dalam keadaan ruku', lalu dia ruku' di luar shaf, kemudian berjalan menuju shaf. Tatkala Nabi shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Siapakah di antara kalian yang ruku di luar shaf kemudian berjalan masuk ke shaf?\" Abu Bakrah menjawab; Saya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Semoga Allah menambahkan semangat untukmu melakukan kebaikan, dan jangan kamu mengulanginya lagi.\" Abu Dawud berkata; Ziyad Al-A'lam adalah Ziyad bin Fulan bin Qurrah, dan dia adalah anak bibinya Yunus bin Ubaid. "},"574":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْعَبْدِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَعَلْتَ بَيْنَ يَدَيْكَ مِثْلَ مُؤَخِّرَةِ الرَّحْلِ فَلَا يَضُرُّكَ مَنْ مَرَّ بَيْنَ يَدَيْكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir Al-'Abdi] telah menceritakan kepada kami [Isra`il] dari [Simak] dari [Musa bin Thahah] dari [Ayahnya, Thahah bin Ubaidillah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu memasang sutrah (pembatas) di depanmu seperti kayu di belakang binatang kendaraan, maka tidak akan memudharatkanmu orang yang lewat di depanmu\""},"575":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَآخِرَةُ الرَّحْلِ ذِرَاعٌ فَمَا فَوْقَهُ","id":"Telah menceritakan kepada kami [Al-Hasan bin Ali] telah menceritakan kepada kami [Abdur Razzaq] dari [Ibnu Juraij] dari ['Atha`] dia berkata: Tinggi kayu yang di letakkan di belakang hewan kendaraan adalah sehasta lebih. "},"576":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ يَوْمَ الْعِيدِ أَمَرَ بِالْحَرْبَةِ فَتُوضَعُ بَيْنَ يَدَيْهِ فَيُصَلِّي إِلَيْهَا وَالنَّاسُ وَرَاءَهُ وَكَانَ يَفْعَلُ ذَلِكَ فِي السَّفَرِ فَمِنْ ثَمَّ اتَّخَذَهَا الْأُمَرَاءُ","id":"Telah menceritakan kepada kami [Al-Hasan bin Ali] telah menceritakan kepada kami [Ibnu Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwasanya apabila Rasulullah shallallahu 'alaihi wasallam hendak pergi melakukan shalat pada Hari Raya, beliau memerintahkan untuk membawa tombak, lalu ditancapkannya di depan beliau. lalu beliau shalat menghadap kepadanya, sementara orang-orang berdiri di belakang beliau. Hal itu juga dilakukan beliau sewaktu dalam perjalanan, yang kemudian dicontoh oleh para pemimpin. "},"577":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ بِالْبَطْحَاءِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ يَمُرُّ خَلْفَ الْعَنَزَةِ الْمَرْأَةُ وَالْحِمَارُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari ['Aun bin Abi Juhaifah] dari [Ayahnya] bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat bersama mereka di Bathha`, sementara di depan beliau ada tongkat, beliau mengerjakan shalat Zhuhur dua rakaat dan Ashar dua rakaat, dan di belakang tongkat itu lewat seorang wanita dan seekor keledai. "},"578":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا إِسْمَعِيلُ بْنُ أُمَيَّةَ حَدَّثَنِي أَبُو عَمْرِو بْنُ مُحَمَّدِ بْنِ حُرَيْثٍ أَنَّهُ سَمِعَ جَدَّهُ حُرَيْثًا يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلْيَجْعَلْ تِلْقَاءَ وَجْهِهِ شَيْئًا فَإِنْ لَمْ يَجِدْ فَلْيَنْصِبْ عَصًا فَإِنْ لَمْ يَكُنْ مَعَهُ عَصًا فَلْيَخْطُطْ خَطًّا ثُمَّ لَا يَضُرُّهُ مَا مَرَّ أَمَامَهُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ الْمَدِينِيِّ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ أَبِي مُحَمَّدِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ جَدِّهِ حُرَيْثٍ رَجُلٍ مِنْ بَنِي عُذْرَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ حَدِيثَ الْخَطِّ قَالَ سُفْيَانُ لَمْ نَجِدْ شَيْئًا نَشُدُّ بِهِ هَذَا الْحَدِيثَ وَلَمْ يَجِئْ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ قُلْتُ لِسُفْيَانَ إِنَّهُمْ يَخْتَلِفُونَ فِيهِ فَتَفَكَّرَ سَاعَةً ثُمَّ قَالَ مَا أَحْفَظُ إِلَّا أَبَا مُحَمَّدِ بْنَ عَمْرٍو قَالَ سُفْيَانُ قَدِمَ هَاهُنَا رَجُلٌ بَعْدَ مَا مَاتَ إِسْمَعِيلُ بْنُ أُمَيَّةَ فَطَلَبَ هَذَا الشَّيْخُ أَبَا مُحَمَّدٍ حَتَّى وَجَدَهُ فَسَأَلَهُ عَنْهُ فَخَلَطَ عَلَيْهِ قَالَ أَبُو دَاوُد و سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ سُئِلَ عَنْ وَصْفِ الْخَطِّ غَيْرَ مَرَّةٍ فَقَالَ هَكَذَا عَرْضًا مِثْلَ الْهِلَالِ قَالَ أَبُو دَاوُد و سَمِعْت مُسَدَّدًا قَالَ قَالَ ابْنُ دَاوُدَ الْخَطُّ بِالطُّولِ قَالَ أَبُو دَاوُد و سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ وَصَفَ الْخَطَّ غَيْرَ مَرَّةٍ فَقَالَ هَكَذَا يَعْنِي بِالْعَرْضِ حَوْرًا دَوْرًا مِثْلَ الْهِلَالِ يَعْنِي مُنْعَطِفًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al-Mufadldlal] telah menceritakan kepada kami [Isma'il bin Umayyah] telah menceritakan kepadaku [Abu Amru bin Muhammad bin Huraits] bahwasanya dia telah mendengar [Kakeknya, Huraits] menceritakan kepadanya dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengerjakan shalat, maka hendaklah dia meletakkan sesuatu di depannya. Jika dia tidak menemukan, hendaklah dia menancapkan sebuah tongkat. Jika dia tidak membawa tongkat, hendaklah dia membuat garis, kemudian tidak memudharatkannya sekalipun ada yang lewat depannya.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Ali bin Al-Madini] dari [Sufyan] dari [Isma'il bin Umayyah] dari [Abu Muhammad bin Amru bin Huraits] dari [Kakeknya, Huraits] seorang laki-laki dari Bani 'Udzrah, dari [Abu Hurairah] dari Abul Qasim shallallahu 'alaihi wasallam, beliau bersabda: kemudian dia menyebutkan hadits tentang garis untuk sutrah. Sufyan berkata; Kami tidak mendapat satu riwayat pun yang dapat menguatkan hadits ini, dan ia tidak diriwayatkan kecuali dari sanad ini. dia berkata; Saya berkata kepada Sufyan; Sesungguhnya mereka berselisih tentangnya. Maka dia berpikir sesaat, kemudian berkata; Saya tidak hafal kecuali Abu Muhammad bin Amru. Sufyan berkata; Ada seorang laki-laki datang ke sini setelah Isma'il bin Umayyah meninggal dunia. Syaikh ini mencari Abu Muhammad hingga dia menemukannya, maka dia bertanya kepadanya tentang hadits ini, namuan hadits ini rancu atasnya. Abu Dawud berkata; Saya mendengar Ahmad bin Hanbal pernah ditanya tentang garis untuk sutrah shalat tidak hanya sekali, maka dia menjawab; Begini, dengan memanjang seperti bentuk hilal (bulan sabit). Abu Dawud berkata; Dan saya telah mendengar Musaddad berkata; Ibnu Dawud berkata; Garis untuk sutrah shalat itu memanjang. Abu Dawud berkata; Dan saya telah mendengar Ahmad bin Hanbal menyifati garis tersebut lebih dari sekali, dia berkata; Begini, yakni dengan memanjang melengkung seperti hilal. "},"579":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ رَأَيْتُ شَرِيكًاصَلَّى بِنَا فِي جَنَازَةٍ الْعَصْرَ فَوَضَعَ قَلَنْسُوَتَهُ بَيْنَ يَدَيْهِ يَعْنِي فِي فَرِيضَةٍ حَضَرَتْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Az-Zuhri] telah menceritakan kepada kami [Sufyan bin Uyainah] dia berkata; Saya pernah melihat [Syarik] shalat janazah menjadi imam kami pada waktu Ashar, lalu dia meletakkan pecinya di depannya, yakni ketika dia melaksanakan shalat wajib. "},"580":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَوَهْبُ بْنُ بَقِيَّةَ وَابْنُ أَبِي خَلَفٍ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ عُثْمَانُ حَدَّثَنَا أَبُو خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي إِلَى بَعِيرٍ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] dan [Wahb bin Baqiyyah] dan [Ibnu Abi Khalaf] dan [Abdullah bin Sa'id] berkata Utsman; Telah menceritakan kepada kami [Abu Khalid] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwasanya Nabi shallallahu 'alaihi wasallam pernah shalat dengan menghadap onta. "},"581":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو عُبَيْدَةَ الْوَلِيدُ بْنُ كَامِلٍ عَنْ الْمُهَلَّبِ بْنِ حُجْرٍ الْبَهْرَانِيِّ عَنْ ضُبَاعَةَ بِنْتِ الْمِقْدَادِ بْنِ الْأَسْوَدِ عَنْ أَبِيهَا قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى عُودٍ وَلَا عَمُودٍ وَلَا شَجَرَةٍ إِلَّا جَعَلَهُ عَلَى حَاجِبِهِ الْأَيْمَنِ أَوْ الْأَيْسَرِ وَلَا يَصْمُدُ لَهُ صَمْدًا","id":"Telah menceritakan kepada kami [Mahmud bin Khalid Ad-Dimasyqi] telah menceritakan kepada kami [Ali bin 'Ayyasy] telah menceritakan kepada kami [Abu Ubaidah Al-Walid bin Kamil] dari [Al-Muhallab bin Hujr Al-Bahrani] dari [Dluba'ah binti Al-Miqdad bin Al-Aswad] dari [Ayahnya] dia berkata; Saya tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat menghadap kayu, tiang, dan tidak pula pohon, kecuali beliau menjadikannya di depan sebelah kanannya atau kirinya, dan beliau tidak menghadapnya. "},"582":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدِ بْنِ أَيْمَنَ عَنْ عَبْدِ اللَّهِ بْنِ يَعْقُوبَ بْنِ إِسْحَقَ عَمَّنْ حَدَّثَهُ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ قَالَ قُلْتُ لَهُ يَعْنِي لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُصَلُّوا خَلْفَ النَّائِمِ وَلَا الْمُتَحَدِّثِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al-Qa'nabi] telah menceritakan kepada kami [Abdul Malik bin Muhammad bin Aiman] dari [Abdullah bin Ya'qub bin Ishaq] dari [orang yang telah menceritakan kepadanya] dari [Muhammad bin Ka'ab Al-Qurazhi] dia berkata; Saya katakan kepada Umar bin Abdul Aziz bahwa [Abdullah bin Abbas] telah menceritakan kepadaku, bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian shalat di belakang orang yang sedang tidur atau orang yang sedang berhadats.\""},"583":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ أَخْبَرَنَا سُفْيَانُ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَحَامِدُ بْنُ يَحْيَى وَابْنُ السَّرْحِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ إِلَى سُتْرَةٍ فَلْيَدْنُ مِنْهَا لَا يَقْطَعْ الشَّيْطَانُ عَلَيْهِ صَلَاتَهُقَالَ أَبُو دَاوُد رَوَاهُ وَاقِدُ بْنُ مُحَمَّدٍ عَنْ صَفْوَانَ عَنْ مُحَمَّدِ بْنِ سَهْلٍ عَنْ أَبِيهِ أَوْ عَنْ مُحَمَّدِ بْنِ سَهْلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَعْضُهُمْ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ سَهْلِ بْنِ سَعْدٍ وَاخْتُلِفَ فِي إِسْنَادِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash-Shabbah bin Sufyan] telah mengabarkan kepada kami [Sufyan] -dari jalur lain- Dan telah menceritakan kepada kami [Utsman bin Abi Syaibah] dan [Hamid bin Yahya] dan [Ibnu As-Sarj] mereka berkata; Telah menceritakan kepada kami [Sufyan] dari [Shafwan bin Sulaim] dari [Nafi' bin Jubair] dari [Sahl bin Abi Hatsmah] yang menyampaikan haditsnya kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang di antara kalian shalat dengan sutrah, hendaklah dia mendekat darinya hingga setan tidak dapat memutus shalatnya.\" Abu Dawud berkata; Hadits ini diriwayatkan oleh [Waqid bin Muhammad] dari [Shafwan] dari [Muhammad bin Sahl] dari [Ayahnya] atau dari [Muhammad bin Sahl] dari Nabi shallallahu 'alaihi wasallam, sebagian mereka berkata dari [Nafi' bin Jubair] dari [Sahl bin Sa'ad] dan sanadnya diperselisihkan."},"584":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ وَالنُّفَيْلِيُّ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ قَالَ أَخْبَرَنِي أَبِي عَنْ سَهْلٍ قَالَوَكَانَ بَيْنَ مَقَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْقِبْلَةِ مَمَرُّ عَنْزٍقَالَ أَبُو دَاوُد الْخَبَرُ لِلنُّفَيْلِيِّ","id":"Telah menceritakan kepada kami [Al-Qa'nabi] dan [An-Nufaili] mereka berdua berkata; Telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dia berkata; Telah mengabarkan kepadaku [Ayahku] dari [Sahl] dia berkata; Jarak antara tempat berdiri Nabi shallallahu 'alaihi wasallam dan antara kiblat adalah sekitar tempat lewat domba. Abu Dawud berkata; Hadits ini adalah riwayat An-Nufaili. "},"585":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَدَعْ أَحَدًا يَمُرُّ بَيْنَ يَدَيْهِ وَلْيَدْرَأْهُ مَا اسْتَطَاعَ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّمَا هُوَ شَيْطَانٌحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو خَالِدٍ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فَلْيُصَلِّ إِلَى سُتْرَةٍ وَلْيَدْنُ مِنْهَا ثُمَّ سَاقَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Al-Qa'nabi] dari [Malik] dari [Zaid bin Aslam] dari [Abdurrahman bin Abi Sa'id Al-Khudri] dari [Abu Sa'id Al-Khudri] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengerjakan shalat, maka janganlah dia membiarkan orang lewat di depannya, dan hendaklah dia mencegahnya semampunya. Jika dia menolak, maka lawanlah, sesungguhnya dia itu setan.\" Telah menceritakan kepada kami [Muhammad bin Al-'Ala`] telah menceritakan kepada kami [Abu Khalid] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari [Abdurrahman bin Abu Sa'id Al-Khudri] dari [Ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian shalat, maka hendaklah dia menghadap sutrah dan mendekatlah padanya\", kemudian dia melanjutkan hadits itu secara makna. "},"586":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ الرَّازِيُّ أَخْبَرَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ أَخْبَرَنَا مَسَرَّةُ بْنُ مَعْبَدٍ اللَّخْمِيُّ لَقِيتُهُ بِالْكُوفَةِ قَالَ حَدَّثَنِي أَبُو عُبَيْدٍ حَاجِبُ سُلَيْمَانَ قَالَ رَأَيْتُ عَطَاءَ بْنَ زَيْدٍ اللَّيْثِيَّقَائِمًا يُصَلِّي فَذَهَبْتُ أَمُرُّ بَيْنَ يَدَيْهِ فَرَدَّنِي ثُمَّ قَالَ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ لَا يَحُولَ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ أَحَدٌ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Ahmad bin Abi Suraij Ar-Razi] telah mengabarkan kepada kami [Abu Ahmad Az-Zubairi] telah mengabarkan kepada kami [Masarrah bin Ma'bad Al-Lakhmi] Saya bertemu dengannya di Kufah, dia berkata; Telah menceritakan kepadaku [Abu Ubaid, seorang penjaga Sulaiman] dia berkata; Saya pernah melihat ['Atha' bin Zaid Al Laitsi] sedang berdiri shalat. Saya lewat di depannya, lalu beliau mencegahku. Setelah selesai shalat dia berkata; Telah menceritakan kepadaku [Abu Sa'id Al-Khudri] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian yang sanggup supaya seseorang tidak dapat lewat antara dia dengan kiblatnya, maka kerjakanlah.\""},"587":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ حُمَيْدٍ يَعْنِي ابْنَ هِلَالٍ قَالَ قَالَ أَبُو صَالِحٍأُحَدِّثُكَ عَمَّا رَأَيْتُ مِنْ أَبِي سَعِيدٍ وَسَمِعْتُهُ مِنْهُ دَخَلَ أَبُو سَعِيدٍ عَلَى مَرْوَانَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا صَلَّى أَحَدُكُمْ إِلَى شَيْءٍ يَسْتُرُهُ مِنْ النَّاسِ فَأَرَادَ أَحَدٌ أَنْ يَجْتَازَ بَيْنَ يَدَيْهِ فَلْيَدْفَعْ فِي نَحْرِهِ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّمَا هُوَ الشَّيْطَانُقَالَ أَبُو دَاوُد قَالَ سُفْيَانُ الثَّوْرِيُّ يَمُرُّ الرَّجُلُ يَتَبَخْتَرُ بَيْنَ يَدَيَّ وَأَنَا أُصَلِّي فَأَمْنَعُهُ وَيَمُرُّ الضَّعِيفُ فَلَا أَمْنَعُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Sulaiman bin Al-Mughirah] dari [Humaid bin Hilal] dia berkata; [Abu Shalih] berkata; Saya ceritakan kepadamu dari apa yang telah saya lihat dari [Abu Sa'id] dan saya dengar darinya. Abu Sa'id pernah berkuinjung kepada Marwan lalu berkata; Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengerjakan shalat dengan bersutrahkan sesuatu, lalu ada seseorang yang hendak lewat di depannya, maka cegahlah (doronglah) dadanya, apabila dia enggan, maka lawanlah, karena sesungguhnya ia itu setan.\" Abu Dawud berkata; Sufyan Ats-Tsauri berkata; Pernah ada seorang laki-laki lewat di depanku dengan sombong, sementara saya sedang shalat, maka saya mencegahnya. Kemudian ada orang lemah lewat di depanku, maka saya tidak mencegahnya. "},"588":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍأَنَّ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ أَرْسَلَهُ إِلَى أَبِي جُهَيْمٍ يَسْأَلُهُ مَاذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَارِّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ أَبُو جُهَيْمٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ الْمَارُّ بَيْنَ يَدَيْ الْمُصَلِّي مَاذَا عَلَيْهِ لَكَانَ أَنْ يَقِفَ أَرْبَعِينَ خَيْرٌ لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِ قَالَ أَبُو النَّضْرِ لَا أَدْرِي قَالَ أَرْبَعِينَ يَوْمًا أَوْ شَهْرًا أَوْ سَنَةً","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Nadlr bekas budak Umar bin Ubaidillah] dari [Busr bin Sa'id] bahwa Zaid bin Khalid Al Juhani mengirinya menemui Abu Juhaim untuk menanyakan sesuatu yang pernah dia dengar dari Rasulullah shallallahu 'alaihi wasallam mengenai seseorang yang lewat di depan orang yang shalat, maka [Abu Juhaim] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya orang yang lewat di depan orang yang shalat mengetahui (dosa) yang akan di pikulnya, niscaya lebih baik baginya berdiri yang lamanya selama empat puluh, daripada lewat di depan orang yang shalat.\" Abu Nadlr berkata; \"Aku tidak tahu apakah yang di maksud empat puluh hari atau empat puluh bulan atau empat puluh tahun.\""},"589":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ وَابْنُ كَثِيرٍ الْمَعْنَى أَنَّ سُلَيْمَانَ بْنَ الْمُغِيرَةِ أَخْبَرَهُمْ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّقَالَ حَفْصٌ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْطَعُ صَلَاةَ الرَّجُلِ وَقَالَ عَنْ سُلَيْمَانَ قَالَ أَبُو ذَرٍّ يَقْطَعُ صَلَاةَ الرَّجُلِ إِذَا لَمْ يَكُنْ بَيْنَ يَدَيْهِ قَيْدُ آخِرَةِ الرَّحْلِ الْحِمَارُ وَالْكَلْبُ الْأَسْوَدُ وَالْمَرْأَةُ فَقُلْتُ مَا بَالُ الْأَسْوَدِ مِنْ الْأَحْمَرِ مِنْ الْأَصْفَرِ مِنْ الْأَبْيَضِ فَقَالَ يَا ابْنَ أَخِي سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا سَأَلْتَنِي فَقَالَ الْكَلْبُ الْأَسْوَدُ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Abdussaalam bin Mutthahir] dan [Ibnu Katsir] sedangkan maksud haditsnya sama, bahwa [Sulaiman bin Mughirah] telah mengabarkan kepada mereka, dari [Humaid bin Hilal] dari [Abdullah bin bin Ash Shamit] dari [Abu Dzar] dia berkata; Hafsh berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang dapat memutuskan shalat seseorang apabila di hadapannya tidak terdapat tabir sepanjang ujung pelana unta yaitu, keledai, anjing hitam dan wanita.\" Kataku; Apa bedanya warna hitam dengan warna merah, kuning atau putih?\" Abu Dzar menjawab; \"Wahai anak saudaraku, aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam sebagaimana yang kamu tanyakan, beliau bersabda: \"Anjing hitam adalah setan.\""},"590":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ جَابِرَ بْنَ زَيْدٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍرَفَعَهُ شُعْبَةُ قَالَ يَقْطَعُ الصَّلَاةَ الْمَرْأَةُ الْحَائِضُ وَالْكَلْبُقَالَ أَبُو دَاوُد وَقَفَهُ سَعِيدٌ وَهِشَامٌ وَهَمَّامٌ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَلَى ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepada kami [Qatadah] dia berkata; saya mendengar [Jabir bin Zaid] bercerita dari [Ibnu Abbas] yang di rafa'kan (bersambung hingga Nabi) oleh Syu'bah dia berkata; \"Yang dapat memutus (membatalkan) shalat seseorang adalah wanita haidh dan anjing.\" Abu Daud berkata; [Sa'id], [Hisyam] dan [Hammam] memauqufkan (riwayat tersebut) dari [Jabir bin Zaid] atas riwayat [ibnu Abbas].\""},"591":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ مَوْلَى بَنِي هَاشِمٍ الْبَصْرِيُّ حَدَّثَنَا مُعَاذٌ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَحْسَبُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ إِلَى غَيْرِ سُتْرَةٍ فَإِنَّهُ يَقْطَعُ صَلَاتَهُ الْكَلْبُ وَالْحِمَارُ وَالْخِنْزِيرُ وَالْيَهُودِيُّ وَالْمَجُوسِيُّ وَالْمَرْأَةُ وَيُجْزِئُ عَنْهُ إِذَا مَرُّوا بَيْنَ يَدَيْهِ عَلَى قَذْفَةٍ بِحَجَرٍقَالَ أَبُو دَاوُد فِي نَفْسِي مِنْ هَذَا الْحَدِيثِ شَيْءٌ كُنْتُ أُذَاكِرُ بِهِ إِبْرَاهِيمَ وَغَيْرَهُ فَلَمْ أَرَ أَحَدًا جَاءَ بِهِ عَنْ هِشَامٍ وَلَا يَعْرِفُهُ وَلَمْ أَرَ أَحَدًا يُحَدِّثُ بِهِ عَنْ هِشَامٍ وَأَحْسَبُ الْوَهْمَ مِنْ ابْنِ أَبِي سَمِينَةَ يَعْنِي مُحَمَّدَ بْنَ إِسْمَعِيلَ الْبَصْرِيَّ مَوْلَى بَنِي هَاشِمٍ وَالْمُنْكَرُ فِيهِ ذِكْرُ الْمَجُوسِيِّ وَفِيهِ عَلَى قَذْفَةٍ بِحَجَرٍ وَذِكْرُ الْخِنْزِيرِ وَفِيهِ نَكَارَةٌ قَالَ أَبُو دَاوُد وَلَمْ أَسْمَعْ هَذَا الْحَدِيثَ إِلَّا مِنْ مُحَمَّدِ بْنِ إِسْمَعِيلَ بْنِ أَبِي سَمِينَةَ وَأَحْسَبُهُ وَهِمَ لِأَنَّهُ كَانَ يُحَدِّثُنَا مِنْ حِفْظِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] bekas budak Bani Hasyim Al Bashri, telah menceritakan kepada kami [Mu'adz] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata; saya kira (hadits ini) dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang dari kalian shalat tanpa ada sutrah (pembatas), maka anjing, keledai, babi, orang Yahudi dan wanita dapat memutuskan shalatnya (apabila lewat di depannya), dan cukuplah baginya (apabila mereka hendak lewat di hadapannya) untuk melempar dengan batu.\" Abu Daud mengatakan; \"Menurutku hadits ini ada masalah, ketika aku menyebutkan hadits tersebut kepada Ibrahim, maka ia tidak pernah tahu seorang pun yang datang (meriwayatkan) dari Haisyam dan dia juga tidak mengetahuinya, begitu juga aku tidak pernah melihat seorang pun yang pernah meriwayatkan dari Hisyam, saya kira Ibnu Abu Saminah yaitu Muhammad bin Isma'il Al Bashri bekas budak Bani Hasyim, terdapat keraguan (dalam riwayatnya) dan kemungkaran, karena ia menyebutkan; \"Orang Majusi\" dan \"Melemparnya dengan batu\" (dalam riwayatnya pula) dia menyebutkan \"babi\" sehingga (riwayatnya) munkar, Abu Daud berkata; \"Aku tidak pernah mendengar hadits ini kecuali dari Muhammad bin Isma'il bin Abu Saminah, dan saya kira dia banyak keraguan karena dia meriwayatkan kepada kami dari hafalannya sendiri.\""},"592":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ مَوْلَى يَزِيدَ بْنِ نِمْرَانَ عَنْ يَزِيدَ بْنِ نِمْرَانَ قَالَرَأَيْتُ رَجُلًا بِتَبُوكَ مُقْعَدًا فَقَالَ مَرَرْتُ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عَلَى حِمَارٍ وَهُوَ يُصَلِّي فَقَالَ اللَّهُمَّ اقْطَعْ أَثَرَهُ فَمَا مَشَيْتُ عَلَيْهَا بَعْدُحَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ يَعْنِي الْمَذْحِجِيَّ حَدَّثَنَا أَبُو حَيْوَةَ عَنْ سَعِيدٍ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ قَالَ قَطَعَ صَلَاتَنَا قَطَعَ اللَّهُ أَثَرَهُ قَالَ أَبُو دَاوُد وَرَوَاهُ أَبُو مُسْهِرٍ عَنْ سَعِيدٍ قَالَ فِيهِ قَطَعَ صَلَاتَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Waki'] dari [Sa'id bin Abdul Aziz] dari [Bekas budak Yazid bin Nimran] dari [Yazid bin Nimran] dia berkata; Aku bertemu [seorang lumpuh] di Tabuk, lalu dia bercerita: \"Aku pernah lewat di hadapan Rasulullah Shallallahu 'alaihi wa Salam dengan mengendarai keledai ketika beliau sedang shalat, maka beliau bersabda: \"Ya Allah, potonglah jejaknya.\" Setelah itu aku tidak dapat berjalan.\" Telah menceritakan kepada kami [Katsir bin Ubaid yaitu Al Madhiji] telah menceritakan kepada kami [Abu Haiwah] dari [Sa'id] dengan isnad dan maknanya, dia menambahkan; \"Dia telah memotong shalat kami, semoga Allah memotong jejaknya.\" Abu Daud berkata; sedangkan [Abu Mushir] meriwayatkan dari [Sa'id] dia berkata; \"Dia telah memotong shalat kami.\""},"593":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مُعَاوِيَةُ عَنْ سَعِيدِ بْنِ غَزْوَانَ عَنْ أَبِيهِأَنَّهُ نَزَلَ بِتَبُوكَ وَهُوَ حَاجٌّ فَإِذَا هُوَ بِرَجُلٍ مُقْعَدٍ فَسَأَلَهُ عَنْ أَمْرِهِ فَقَالَ لَهُ سَأُحَدِّثُكَ حَدِيثًا فَلَا تُحَدِّثْ بِهِ مَا سَمِعْتَ أَنِّي حَيٌّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ بِتَبُوكَ إِلَى نَخْلَةٍ فَقَالَ هَذِهِ قِبْلَتُنَا ثُمَّ صَلَّى إِلَيْهَا فَأَقْبَلْتُ وَأَنَا غُلَامٌ أَسْعَى حَتَّى مَرَرْتُ بَيْنَهُ وَبَيْنَهَا فَقَالَ قَطَعَ صَلَاتَنَا قَطَعَ اللَّهُ أَثَرَهُ فَمَا قُمْتُ عَلَيْهَا إِلَى يَوْمِي هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Sulaiman bin Daud] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Mu'awiyah] dari [Sa'id bin Ghazwan] dari [ayahnya] bahwa dia singgah di Tabuk ketika berhaji, tiba-tiba dia bertemu [seorang laki-laki yang lumpuh], lantas dia bertanya sebab kelumpuhannya, maka laki-laki itu berkata kepadanya; \"Aku akan ceritakan kepadamu suatu cerita, namun kamu jangan ceritakan kepada siapapun yang kamu dengar selagi aku masih hidup, sesungguhnya Rasulullah Shallallahu'alaihiwasallam pernah singgah di Tabuk yaitu di bawah pohon kurma, maka beliau bersabda: \"Ini adalah kiblat kami.\" Kemudian beliau shalat menghadap pohon kurma, lalu aku berusaha menemui beliau -waktu itu usiaku masih kecil- sehingga aku lewat antara beliau dengan pohon kurma tersebut, maka beliau bersabda: \"Dia telah memotong shalat kami, semoga Allah memotong jejaknya.\" Maka saya tidak dapat berdiri sampai hari ini.\""},"594":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَهَبَطْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَنِيَّةِ أَذَاخِرَ فَحَضَرَتْ الصَّلَاةُ يَعْنِي فَصَلَّى إِلَى جِدَارٍ فَاتَّخَذَهُ قِبْلَةً وَنَحْنُ خَلْفَهُ فَجَاءَتْ بَهْمَةٌ تَمُرُّ بَيْنَ يَدَيْهِ فَمَا زَالَ يُدَارِئُهَا حَتَّى لَصَقَ بَطْنَهُ بِالْجِدَارِ وَمَرَّتْ مِنْ وَرَائِهِ أَوْ كَمَا قَالَ مُسَدَّدٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Hisyam bin Al Ghaz] dari ['amru bin Syu'aib] dari [ayahnya] dari [kakeknya] dia berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam pernah menuruni bukit Adzakhir, kemudian tibalah waktu shalat, lantas beliau mengerjakan shalat dengan menjadikan dinding sebagai arah kiblat, sedangkan kami berada di belakang beliau, tiba-tiba ada seekor anak kambing yang lewat di depan beliau di hadapan beliau, namun beliau selalu mencegahnya, sehingga perut beliau hampir menempel di dinding, akhirnya anak kambing tersebut lewat di belakang dinding.\" Atau sebagaimana kata Musaddad.\""},"595":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَحَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي فَذَهَبَ جَدْيٌ يَمُرُّ بَيْنَ يَدَيْهِ فَجَعَلَ يَتَّقِيهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Hafsh bin Umar] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Yahya bin Al Jazzar] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bahwa beliau pernah shalat, lalu seekor anak kambing hendak lewat di depan beliau, maka beliau berusaha menahannya.\""},"596":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْقِبْلَةِ قَالَ شُعْبَةُ أَحْسَبُهَا قَالَتْ وَأَنَا حَائِضٌقَالَ أَبُو دَاوُد رَوَاهُ الزُّهْرِيُّ وَعَطَاءٌ وَأَبُو بَكْرِ بْنُ حَفْصٍ وَهِشَامُ بْنُ عُرْوَةَ وَعِرَاكُ بْنُ مَالِكٍ وَأَبُو الْأَسْوَدِ وَتَمِيمُ بْنُ سَلَمَةَ كُلُّهُمْ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَإِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ وَأَبُو الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ وَالْقَاسِمُ بْنُ مُحَمَّدٍ وَأَبُو سَلَمَةَ عَنْ عَائِشَةَ لَمْ يَذْكُرُوا وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari ['Urwah] dari [Aisyah] dia berkata; \"Aku pernah berada di antara Nabi dan Kiblat.\" Syu'bah berkata; \"Aku mengira Aisyah mengatakan; \"Padahal aku sedang haidh.\" Abu Daud berkata; 'Hadits ini di riwayatkan pula oleh [Az Zuhri], ['Atha`], [Abu Bakar bin Hafsh], [Hisyam bin 'Urwah], ['Irak bin Malik], [Abu Al Aswad] dan [Tamim bin Salamah], mereka semuanya dari ['Urwah] dari [Aisyah]. Sedangkan [Ibrahim] dari [Al Aswad] dari [Aisyah], dan [Abu Dluha] dari [Masruq] dari [Aisyah], sedangkan [Al Qasim bin Muhammad] dan [Abu Salamah] dari [Aisyah], namun mereka tidak menyebutkan; \"Padahal aku sedang haidh.\""},"597":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي صَلَاتَهُ مِنْ اللَّيْلِ وَهِيَ مُعْتَرِضَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ رَاقِدَةٌ عَلَى الْفِرَاشِ الَّذِي يَرْقُدُ عَلَيْهِ حَتَّى إِذَا أَرَادَ أَنْ يُوتِرَ أَيْقَظَهَا فَأَوْتَرَتْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam shalat malam, sedangkan Aisyah melintang antara beliau dengan Kiblat, berbaring di atas tempat tidur yang biasa di tempati oleh beliau, hingga apabila beliau hendak mengerjakan shalat witir, beliau membangunkan Aisyah, untuk shalat witir.\""},"598":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ الْقَاسِمَ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْبِئْسَمَا عَدَلْتُمُونَا بِالْحِمَارِ وَالْكَلْبِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ يُصَلِّي وَأَنَا مُعْتَرِضَةٌ بَيْنَ يَدَيْهِ فَإِذَا أَرَادَ أَنْ يَسْجُدَ غَمَزَ رِجْلِي فَضَمَمْتُهَا إِلَيَّ ثُمَّ يَسْجُدُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dia berkata; saya mendengar [Al Qasim] bercerita dari [Aisyah] dia berkata; alangkah jeleknya kalian yang menyetarakan kami dengan keledai dan anjing, sungguh aku telah melihat Rasulullah mengerjakan shalat sedangkan saya melintang antara diri beliau dengan kiblat, apabila beliau hendak sujud, beliau meraba kakiku, sebab itu aku menarik kakiku lalu beliau sujud.\""},"599":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ النَّضْرِ حَدَّثَنَا الْمُعْتَمِرُ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكُنْتُ أَكُونُ نَائِمَةً وَرِجْلَايَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي مِنْ اللَّيْلِ فَإِذَا أَرَادَ أَنْ يَسْجُدَ ضَرَبَ رِجْلَيَّ فَقَبَضْتُهُمَا فَسَجَدَ","id":"Telah menceritakan kepada kami ['Ashim bin An Nadlr] telah menceritakan kepada kami [Al Mu'tamir] telah menceritakan kepada kami ['Ubaidullah] dari [Abu An Nadlr] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] bahwa dia berkata; \"Aku pernah tidur dan kedua kakiku berada di hadapan Rasulullah shallallahu 'alaihi wasallam padahal beliau sedang mengerjakan shalat malam, apabila beliau hendak sujud, beliau menepuk kakiku, sebab itu aku menarik kedua kakiku, kemudian beliau sujud.\""},"600":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ ح قَالَ أَبُو دَاوُد و حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ وَهَذَا لَفْظُهُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكُنْتُ أَنَامُ وَأَنَا مُعْتَرِضَةٌ فِي قِبْلَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُصَلِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَمَامَهُ إِذَا أَرَادَ أَنْ يُوتِرَ زَادَ عُثْمَانُ غَمَزَنِي ثُمَّ اتَّفَقَا فَقَالَ تَنَحَّيْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisysr] dan telah di riwayatkan dari jalur lain, Abu Daud mengatakan; dan telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Abdul Aziz] yaitu Ibnu Muhammad, dan ini adalah lafadznya dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Aisyah] bahwa dia berkata; \"Aku tidur melintang di antara kiblat Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sementara aku berada di hadapan beliau, apabila beliau hendak mengerjakan witir -Utsman menambahkan; \"beliau meraba (kakiku) \" -lalu riwayatnya Utsman dengan Al Qa'nabi menyatu lagi- Lalu beliau bersabda: \"Pindahlah! (wahai Aisyah).\""},"601":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ جِئْتُ عَلَى حِمَارٍ ح و حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَقْبَلْتُ رَاكِبًا عَلَى أَتَانٍ وَأَنَا يَوْمَئِذٍ قَدْ نَاهَزْتُ الِاحْتِلَامَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ بِمِنًى فَمَرَرْتُ بَيْنَ يَدَيْ بَعْضِ الصَّفِّ فَنَزَلْتُ فَأَرْسَلْتُ الْأَتَانَ تَرْتَعُ وَدَخَلْتُ فِي الصَّفِّ فَلَمْ يُنْكِرْ ذَلِكَ أَحَدٌقَالَ أَبُو دَاوُد وَهَذَا لَفْظُ الْقَعْنَبِيِّ وَهُوَ أَتَمُّ قَالَ مَالِكٌ وَأَنَا أَرَى ذَلِكَ وَاسِعًا إِذَا قَامَتْ الصَّلَاةُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata; \"Aku datang dengan mengendarai seekor keledai…\" dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dia berkata; \"Aku datang sambil menaiki seekor keledai, pada saat itu aku sudah hampir usia baligh, dan Rasulullah shallallahu 'alaihi wasallam sedang melaksanakan shalat bersama orang-orang di Mina, lalu aku lewat di depan sebagian shaf, lalu aku turun. Setelah itu aku melepas keledaiku untuk merumput, lalu aku masuk kedalam shaf, tapi tidak ada satupun orang yang menegur perbuatanku.\" Abu Daud berkata; \"Ini redaksi dari Al Qa'nabi dan lebih lengkap, Malik mengatakan; \"Dan aku melihat hal itu merupakan kemudahan apabila shalat telah di tegakkan.\""},"602":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ أَبِي الصَّهْبَاءِ قَالَتَذَاكَرْنَا مَا يَقْطَعُ الصَّلَاةَ عِنْدَ ابْنِ عَبَّاسٍ فَقَالَ جِئْتُ أَنَا وَغُلَامٌ مِنْ بَنِي عَبْدِ الْمُطَّلِبِ عَلَى حِمَارٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَنَزَلَ وَنَزَلْتُ وَتَرَكْنَا الْحِمَارَ أَمَامَ الصَّفِّ فَمَا بَالَاهُ وَجَاءَتْ جَارِيَتَانِ مِنْ بَنِي عَبْدِ الْمُطَّلِبِ فَدَخَلَتَا بَيْنَ الصَّفِّ فَمَا بَالَى ذَلِكَحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَدَاوُدُ بْنُ مِخْرَاقٍ الْفِرْيَابِيُّ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ قَالَ فَجَاءَتْ جَارِيَتَانِ مِنْ بَنِي عَبْدِ الْمُطَّلِبِ اقْتَتَلَتَا فَأَخَذَهُمَا قَالَ عُثْمَانُ فَفَرَّعَ بَيْنَهُمَا وَقَالَ دَاوُدُ فَنَزَعَ إِحْدَاهُمَا عَنْ الْأُخْرَى فَمَا بَالَى ذَلِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Al Hakam] dari [Yahya bin Al Jazzar] dari [Abu As Shahba`] dia berkata; \"Kami membiacarakan mengenai sesuatu yang dapat memutuskan shalat di samping Ibnu Abbas, maka [Ibnu Abbas] berkata; \"Aku pernah datang bersama seorang budak dari Bani Abdul Mutthalib dengan mengendarai seekor keledai, dan Rasulullah shallallahu 'alaihi wasallam sedang melaksanakan shalat, maka budak itu turun, aku pun ikut turun lalu aku biarkan keledai tersebut di depan shaf, namun beliau tidak menghiraukannya. Setelah itu datang pula dua orang budak wanita dari Bani Abdul Mutthalib, lalu keduanya masuk ke dalam shaf, namun beliau tetap tidak menghiraukannya.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Daud bin Mihraq Al Firyabi] keduanya berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dengan hadits ini dengan isnadnya dia mengatakan; \"Kemudian datang pula dua budak wanita dari Bani Abdul Mutthalib yang sedang bertikai, maka beliau memegang keduanya.\" Utsman mengatakan; \"Kemudian beliau melerai keduanya.\" Sedangkan Daud mengatakan; \"Lalu beliau melerai salah satu dari keduanya, dan beliau tidak memperdulikan hal itu.\""},"603":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ عُمَرَ بْنِ عَلِيٍّ عَنْ عَبَّاسِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي بَادِيَةٍ لَنَا وَمَعَهُ عَبَّاسٌ فَصَلَّى فِي صَحْرَاءَ لَيْسَ بَيْنَ يَدَيْهِ سُتْرَةٌ وَحِمَارَةٌ لَنَا وَكَلْبَةٌ تَعْبَثَانِ بَيْنَ يَدَيْهِ فَمَا بَالَى ذَلِكَ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] dia berkata; telah menceritakan kepadaku [ayahku] dari [kakekku] dari [Yahya bin Ayyub] dari [Muhammad bin Umar bin Ali] dari ['Abbas bin 'Ubaidullah bin 'Abbas] dari [Al Fadl bin 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam mendatangi kami ketika kami berada di kampung, beliau bersama Abbas, lalu beliau shalat di tanah lapang tanpa ada sutrah (pembatas jarak dalam shalat) sementara keledai kami dan seekor anjing berada di sekitar beliau sedang bermain, namun beliau tidak menghiraukannya.\""},"604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْطَعُ الصَّلَاةَ شَيْءٌ وَادْرَءُوا مَا اسْتَطَعْتُمْ فَإِنَّمَا هُوَ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Mujalid] dari [Abu Al Waddak] dari [Abu Sa'id] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan sampai ada sesuatu yang dapat memutuskan shalat kalian, dan cegahlah semampu kalian, karena ia adalah syetan.\""},"605":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مُجَالِدٌ حَدَّثَنَا أَبُو الْوَدَّاكِ قَالَمَرَّ شَابٌّ مِنْ قُرَيْشٍ بَيْنَ يَدَيْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَهُوَ يُصَلِّي فَدَفَعَهُ ثُمَّ عَادَ فَدَفَعَهُ ثَلَاثَ مَرَّاتٍ فَلَمَّا انْصَرَفَ قَالَ إِنَّ الصَّلَاةَ لَا يَقْطَعُهَا شَيْءٌ وَلَكِنْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْرَءُوا مَا اسْتَطَعْتُمْ فَإِنَّهُ شَيْطَانٌقَالَ أَبُو دَاوُد إِذَا تَنَازَعَ الْخَبَرَانِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُظِرَ إِلَى مَا عَمِلَ بِهِ أَصْحَابُهُ مِنْ بَعْدِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Mujalid] telah menceritakan kepada kami [Abu Al Waddak] dia berkata; \"Seorang pemuda Quraisy lewat di hadapan Abu Sa'id Al Khudri yang sedang melaksanakan shalat, kemudian Abu Sa'id mencegahnya (supaya tidak lewat di hadapannya), namun pemuda tersebut mengulanginya lagi, Abu Sa'id tetap mencegahnya dan peristiwa itu berulang-ulang hingga tiga kali, ketika [Abu Sa'id] telah selesai dia berkata; \"Sesungguhnya tidak ada sesuatu yang dapat memutuskan shalat, akan tetapi Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cegahlah semampu kalian, karena ia adalah syetan.\" Abu Daud mengatakan; \"Apabila ada dua hadits dari Rasulullah shallallahu 'alaihi wasallam yang bertentangan, maka di lihat hadits yang di amalkan oleh sahabat setelahnya.\""},"606":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَفْتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ مَنْكِبَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَبَعْدَمَا يَرْفَعُ رَأْسَهُ مِنْ الرُّكُوعِ وَقَالَ سُفْيَانُ مَرَّةً وَإِذَا رَفَعَ رَأْسَهُ وَأَكْثَرُ مَا كَانَ يَقُولُ وَبَعْدَ مَا يَرْفَعُ رَأْسَهُ مِنْ الرُّكُوعِ وَلَا يَرْفَعُ بَيْنَ السَّجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] dia berkata; \"Saya pernah melihat apabila Rasulullah shallallahu 'alaihi wasallam memulai shalat, beliau mengangkat kedua tangannya hingga setara dengan kedua bahunya, demikian juga apabila hendak ruku' yaitu setelah mengangkat kepalanya dari ruku'.\" Di kali yang lain, Sufyan mengatakan; \"Apabila beliau mengangkat kepalanya.\" Dan lafadz yang sering dia pergunakan adalah; \"Yaitu setelah beliau mengangkat kepalanya dari ruku' dan tidak mengangkat kedua tangannya antara dua sujud.\""},"607":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ رَفَعَ يَدَيْهِ حَتَّى تَكُونَ حَذْوَ مَنْكِبَيْهِ ثُمَّ كَبَّرَ وَهُمَا كَذَلِكَ فَيَرْكَعُ ثُمَّ إِذَا أَرَادَ أَنْ يَرْفَعَ صُلْبَهُ رَفَعَهُمَا حَتَّى تَكُونَ حَذْوَ مَنْكِبَيْهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَلَا يَرْفَعُ يَدَيْهِ فِي السُّجُودِ وَيَرْفَعُهُمَا فِي كُلِّ تَكْبِيرَةٍ يُكَبِّرُهَا قَبْلَ الرُّكُوعِ حَتَّى تَنْقَضِيَ صَلَاتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah menceritakan kepada kami [Baqiyah] telah menceritakan kepada kami [Az Zubaidi] dari [Az Zuhri] dari [Salim] dari [Abdullah bin Umar] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak melaksanakan shalat, maka beliau mengangkat kedua tangannya hingga sejajar dengan kedua bahunya, kemudian beliau bertakbir, dan kedua tangannya juga masih seperti itu, lalu beliau ruku'. Dan apabila beliau hendak mengangkat tulang sulbinya (punggung), beliau mengangkat kedua tangannya hingga sejajar dengan kedua bahunya sambil mengucapkan: \"Sami'allahu liman hamidah (Allah Maha mendengar terhadap siapa saja yang memuji-Nya).\" Beliau tidak mengangkat kedua tangannya ketika hendak sujud, namun beliau selalu mengangkat kedua tangannya di setiap takbir yang beliau ucapkan sebelum ruku' sampai selesai shalat.\""},"608":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ الْجُشَمِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ حَدَّثَنِي عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ قَالَكُنْتُ غُلَامًا لَا أَعْقِلُ صَلَاةَ أَبِي قَالَ فَحَدَّثَنِي وَائِلُ بْنُ عَلْقَمَةَ عَنْ أَبِي وَائِلِ بْنِ حُجْرٍ قَالَ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا كَبَّرَ رَفَعَ يَدَيْهِ قَالَ ثُمَّ الْتَحَفَ ثُمَّ أَخَذَ شِمَالَهُ بِيَمِينِهِ وَأَدْخَلَ يَدَيْهِ فِي ثَوْبِهِ قَالَ فَإِذَا أَرَادَ أَنْ يَرْكَعَ أَخْرَجَ يَدَيْهِ ثُمَّ رَفَعَهُمَا وَإِذَا أَرَادَ أَنْ يَرْفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَ يَدَيْهِ ثُمَّ سَجَدَ وَوَضَعَ وَجْهَهُ بَيْنَ كَفَّيْهِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ أَيْضًا رَفَعَ يَدَيْهِ حَتَّى فَرَغَ مِنْ صَلَاتِهِقَالَ مُحَمَّدٌ فَذَكَرْتُ ذَلِكَ لِلْحَسَنِ بْنِ أَبِي الْحَسَنِ فَقَالَ هِيَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَهُ مَنْ فَعَلَهُ وَتَرَكَهُ مَنْ تَرَكَهُ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ هَمَّامٌ عَنْ ابْنِ جُحَادَةَ لَمْ يَذْكُرْ الرَّفْعَ مَعَ الرَّفْعِ مِنْ السُّجُودِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah Al Jusyami] telah menceritakan kepada kami [Abdul Warits bin Sa'id] dia berkata; telah menceritakan kepada kami [Muhammad bin Juhadah] telah menceritakan kepadaku [Abdul Jabbar bin Wa`il bin Hujr] dia berkata; \"Aku adalah seorang anak yang belum mengerti shalat yang di kerjakan ayahku, katanya; maka [\"Wa'il bin 'Alqamah] telah menceritakan kepadaku, dari ayahku [Wa'il bin Hujr] dia berkata; \"Aku shalat bersama Rasulullah shallallahu 'alaihi wasallam, apabila beliau hendak bertakbir, maka beliau mengangkat kedua tangannya.\" Katanya; \"Kemudian beliau melipatkan pakaiannya, lalu tangan kanannya memegang tangan kirinya dan memasukkan kedua tangannya ke dalam pakaian beliau.\" dia melanjutkan; \"Apabila beliau hendak ruku', beliau mengeluarkan kedua tangannya dan mengangkatnya, dan apabila beliau hendak mengangkat kepalanya dari ruku' (i'tidal), beliau mengangkat kedua tangannya, barulah beliau sujud dengan meletakkan wajahnya sejajar dengan kedua telapak tangannya, apabila beliau hendak mengangkat kepalanya dari sujud, maka beliau juga mengangkat kedua tangannya lagi sampai selesai shalat.\" Muhammad mengatakan; \"Lalu aku menyebutkan hal itu kepada Al Hasan bin Abu Al Hasan, maka dia berkata; \"Itu adalah shalat Rasulullah shallallahu 'alaihi wasallam yang di kerjakan oleh orang yang suka mengerjakan dan di tinggalkan oleh orang yang suka meninggalkannya.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan juga oleh [Hammam] dari [Ibnu Juhadah], namun dia tidak menyebutkan 'juga mengangkat tangan ketika bangkit dari sujud'. "},"609":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ النَّخَعِيِّ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِأَنَّهُ أَبْصَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَامَ إِلَى الصَّلَاةِ رَفَعَ يَدَيْهِ حَتَّى كَانَتَا بِحِيَالِ مَنْكِبَيْهِ وَحَاذَى بِإِبْهَامَيْهِ أُذُنَيْهِ ثُمَّ كَبَّرَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Al Hasan bin 'Ubaidulah An Nakha'i] dari [Abdul Jabbar bin Wa`il] dari [ayahnya] bahwa dia memperhatikan Nabi shallallahu 'alaihi wasallam ketika beliau mengerjakan shalat, beliau mengangkat kedua tangannya di atas kedua bahunya dan kedua jempol jarinya hampir menempel di kedua telinganya, kemudian beliau bertakbir.\""},"610":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا الْمَسْعُودِيُّ حَدَّثَنِي عَبْدُ الْجَبَّارِ بْنُ وَائِلٍ حَدَّثَنِي أَهْلُ بَيْتِي عَنْ أَبِي أَنَّهُ حَدَّثَهُمْأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ مَعَ التَّكْبِيرَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'] telah menceritakan kepada kami [Al Mas'udi] telah menceritakan kepadaku [Abdul Jabbar bin Wa'il] telah menceritakan kepadaku [keluargaku] dari [ayahku] bahwa dia menceritakan kepada mereka (ahli baitku) bahwa dia (ayahku) pernah melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya sambil bertakbir.\""},"611":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَقُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَقْبَلَ الْقِبْلَةَ فَكَبَّرَ فَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا أُذُنَيْهِ ثُمَّ أَخَذَ شِمَالَهُ بِيَمِينِهِ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَهُمَا مِثْلَ ذَلِكَ ثُمَّ وَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا مِثْلَ ذَلِكَ فَلَمَّا سَجَدَ وَضَعَ رَأْسَهُ بِذَلِكَ الْمَنْزِلِ مِنْ بَيْنِ يَدَيْهِ ثُمَّ جَلَسَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَحَدَّ مِرْفَقَهُ الْأَيْمَنَ عَلَى فَخِذِهِ الْيُمْنَى وَقَبَضَ ثِنْتَيْنِ وَحَلَّقَ حَلْقَةً وَرَأَيْتُهُ يَقُولُ هَكَذَا وَحَلَّقَ بِشْرٌ الْإِبْهَامَ وَالْوُسْطَى وَأَشَارَ بِالسَّبَّابَةِحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فِيهِ ثُمَّ وَضَعَ يَدَهُ الْيُمْنَى عَلَى ظَهْرِ كَفِّهِ الْيُسْرَى وَالرُّسْغِ وَالسَّاعِدِ وَقَالَ فِيهِ ثُمَّ جِئْتُ بَعْدَ ذَلِكَ فِي زَمَانٍ فِيهِ بَرْدٌ شَدِيدٌ فَرَأَيْتُ النَّاسَ عَلَيْهِمْ جُلُّ الثِّيَابِ تَحَرَّكُ أَيْدِيهِمْ تَحْتَ الثِّيَابِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] dari ['Ashim bin Kulaib] dari [ayahnya] dari [wa'il bin Hujr] dia berkata; kataku; \"Sungguh aku benar-benar akan melihat shalat Rasulullah shallallahu 'alaihi wasallam, dan melihat bagaimana beliau tata cara beliau shalat.\" Wa'il berkata; asulullah shallallahu 'alaihi wasallam berdiri menghadap kiblat, kemudian beliau bertakbir sambil mengangkat kedua tangannya hingga sejajar dengan kedua telinganya, kemudian tangan kanannya memegang tangan kirinya, ketika beliau hendak ruku', beliau mengangkat kedua tangannya seperti tadi, kemudian beliau meletakkan kedua tangannya di atas kedua lututnya, ketika beliau hendak mengangkat kepalanya dari ruku' (i'tidal) beliau mengangkat kedua tangannya lagi seperti tadi, dan ketika sujud, beliau meletakkan kepalanya di tempat tersebut yaitu di antara kedua tangannya kemudian beliau duduk dengan bertumpu di atas kaki yang kiri dan meletakkan tangan kiri di atas paha kiri dan merenggangkan siku yang kanan pada paha yang kanan, menggenggam kedua jarinya dengan membentuk seperti lingkaran, aku melihat beliau memberi tanda demikian -Bisyr memperragakan dengan membentuk seperti lingkaran dengan ibu jari dan jari tengah- telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Za`idah] dari ['Ashim bin Kulaib] dengan isnad dan maknanya, (dalam haditsnya) dia mengatakan; \"Kemudian beliau meletakkan tangan kanannya di atas punggung telapak tangan kirinya dan pergelangan tangan kirinya.\" Dia juga mengatakan; \"Setelah itu aku datang ketika musim dingin tiba, maka aku melihat orang-orang berselimutkan pakaian dan tangan-tangan mereka bergerak di bawah pakaian tersebut.\""},"612":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَن�� أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حِيَالَ أُذُنَيْهِ قَالَ ثُمَّ أَتَيْتُهُمْ فَرَأَيْتُهُمْ يَرْفَعُونَ أَيْدِيَهُمْ إِلَى صُدُورِهِمْ فِي افْتِتَاحِ الصَّلَاةِ وَعَلَيْهِمْ بَرَانِسُ وَأَكْسِيَةٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Wa`il bin Hujr] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam ketika memulai shalat, beliau mengangkat kedua tangannya sejajar dengan kedua telinganya, katanya; kemudian aku datang kepada mereka (para sahabat), maka aku melihat mereka mengangkat kedua tangan sampai ke dada mereka ketika memulai shalat, sementara mereka ada yang mengenakan mantel yang menutupi kepala dan ada juga yang mengenakan pakaian.\""},"613":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الشِّتَاءِ فَرَأَيْتُ أَصْحَابَهُ يَرْفَعُونَ أَيْدِيَهُمْ فِي ثِيَابِهِمْ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Waki'] dari [Syarik] dari ['Ashim bin Kulaib] dari ['Alqamah bin Wa'il] dari [Wa'il bin Hujr] dia berkata; \"Aku datang kepada Nabi shallallahu 'alaihi wasallam di musim dingin, maka aku melihat para sahabat beliau mengangkat tangan di dalam pakaian mereka ketika sedang shalat.\""},"614":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى وَهَذَا حَدِيثُ أَحْمَدَ قَالَ أَخْبَرَنَا عَبْدُ الْحَمِيدِ يَعْنِي ابْنَ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدُ بْنُ عُمَرَ بْنِ عَطَاءٍ قَالَسَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ فِي عَشْرَةٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو قَتَادَةَ قَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا فَلِمَ فَوَاللَّهِ مَا كُنْتَ بِأَكْثَرِنَا لَهُ تَبَعًا وَلَا أَقْدَمِنَا لَهُ صُحْبَةً قَالَ بَلَى قَالُوا فَاعْرِضْ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ يَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ يُكَبِّرُ حَتَّى يَقِرَّ كُلُّ عَظْمٍ فِي مَوْضِعِهِ مُعْتَدِلًا ثُمَّ يَقْرَأُ ثُمَّ يُكَبِّرُ فَيَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ يَرْكَعُ وَيَضَعُ رَاحَتَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ يَعْتَدِلُ فَلَا يَصُبُّ رَأْسَهُ وَلَا يُقْنِعُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ يَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ مُعْتَدِلًا ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ يَهْوِي إِلَى الْأَرْضِ فَيُجَافِي يَدَيْهِ عَنْ جَنْبَيْهِ ثُمَّ يَرْفَعُ رَأْسَهُ وَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا وَيَفْتَحُ أَصَابِعَ رِجْلَيْهِ إِذَا سَجَدَ وَيَسْجُدُ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ وَيَرْفَعُ رَأْسَهُ وَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا حَتَّى يَرْجِعَ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ ثُمَّ يَصْنَعُ فِي الْأُخْرَى مِثْلَ ذَلِكَ ثُمَّ إِذَا قَامَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا كَبَّرَ عِنْدَ افْتِتَاحِ الصَّلَاةِ ثُمَّ يَصْنَعُ ذَلِكَ فِي بَقِيَّةِ صَلَاتِهِ حَتَّى إِذَا كَانَتْ السَّجْدَةُ الَّتِي فِيهَا التَّسْلِيمُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَقَعَدَ مُتَوَرِّكًا عَلَى شِقِّهِ الْأَيْسَرِ قَالُوا صَدَقْتَ هَكَذَا كَانَ يُصَلِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو الْعَامِرِيِّ قَالَ كُنْتُ فِي مَجْلِسٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَذَاكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ فَذَكَرَ بَعْضَ هَذَا الْحَدِيثِ وَقَالَ فَإِذَا رَكَعَ أَمْكَنَ كَفَّيْهِ مِنْ رُكْبَتَيْهِ وَفَرَّجَ بَيْنَ أَصَابِعِهِ ثُمَّ هَصَرَ ظَهْرَهُ غَيْرَ مُقْنِعٍ رَأْسَهُ وَلَا صَافِحٍ بِخَدِّهِ وَقَالَ فَإِذَا قَعَدَ فِي الرَّكْعَتَيْنِ قَعَدَ عَلَى بَطْنِ قَدَمِهِ الْيُسْرَى وَنَصَبَ الْيُمْنَى فَإِذَا كَانَ فِي الرَّابِعَةِ أَفْضَى بِوَرِكِهِ الْيُسْرَى إِلَى الْأَرْضِ وَأَخْرَجَ قَدَمَيْهِ مِنْ نَاحِيَةٍ وَاحِدَةٍ حَدَّثَنَا عِيسَى بْنُ إِبْرَاهِيمَ الْمِصْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ يَزِيدَ بْنِ مُحَمَّدٍ الْقُرَشِيِّ وَيَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ نَحْوَ هَذَا قَالَ فَإِذَا سَجَدَ وَضَعَ يَدَيْهِ غَيْرَ مُفْتَرِشٍ وَلَا قَابِضِهِمَا وَاسْتَقْبَلَ بِأَطْرَافِ أَصَابِعِهِ الْقِبْلَةَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا أَبُو بَدْرٍ حَدَّثَنِي زُهَيْرٌ أَبُو خَيْثَمَةَ حَدَّثَنَا الْحَسَنُ بْنُ الْحُرِّ حَدَّثَنِي عِيسَى بْنُ عَبْدِ اللَّهِ بْنِ مَالِكٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ أَحَدِ بَنِي مَالِكٍ عَنْ عَبَّاسٍ أَوْ عَيَّاشِ بْنِ سَهْلٍ السَّاعِدِيِّ أَنَّهُ كَانَ فِي مَجْلِسٍ فِيهِ أَبُوهُ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْمَجْلِسِ أَبُو هُرَيْرَةَ وَأَبُو حُمَيْدٍ السَّاعِدِيُّ وَأَبُو أُسَيْدٍ بِهَذَا الْخَبَرِ يَزِيدُ أَوْ يَنْقُصُ قَالَ فِيهِ ثُمَّ رَفَعَ رَأْسَهُ يَعْنِي مِنْ الرُّكُوعِ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ وَرَفَعَ يَدَيْهِ ثُمَّ قَالَ اللَّهُ أَكْبَرُ فَسَجَدَ فَانْتَصَبَ عَلَى كَفَّيْهِ وَرُكْبَتَيْهِ وَصُدُورِ قَدَمَيْهِ وَهُوَ سَاجِدٌ ثُمَّ كَبَّرَ فَجَلَسَ فَتَوَرَّكَ وَنَصَبَ قَدَمَهُ الْأُخْرَى ثُمَّ كَبَّرَ فَسَجَدَ ثُمَّ كَبَّرَ فَقَامَ وَلَمْ يَتَوَرَّكْ ثُمَّ سَاقَ الْحَدِيثَ قَالَ ثُمَّ جَلَسَ بَعْدَ الرَّكْعَتَيْنِ حَتَّى إِذَا هُوَ أَرَادَ أَنْ يَنْهَضَ لِلْقِيَامِ قَامَ بِتَكْبِيرَةٍ ثُمَّ رَكَعَ الرَّكْعَتَيْنِ الْأُخْرَيَيْنِ وَلَمْ يَذْكُرْ التَّوَرُّكَ فِي التَّشَهُّدِ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو أَخْبَرَنِي فُلَيْحٌ حَدَّثَنِي عَبَّاسُ بْنُ سَهْلٍ قَالَ اجْتَمَعَ أَبُو حُمَيْدٍ وَأَبُو أُسَيْدٍ وَسَهْلُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مَسْلَمَةَ فَذَكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بَعْضَ هَذَا قَالَ ثُمَّ رَكَعَ فَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ كَأَنَّهُ قَابِضٌ عَلَيْهِمَا وَوَتَّرَ يَدَيْهِ فَتَجَافَى عَنْ جَنْبَيْهِ قَالَ ثُمَّ سَجَدَ فَأَمْكَنَ أَنْفَهُ وَجَبْهَتَهُ وَنَحَّى يَدَيْهِ عَنْ جَنْبَيْهِ وَوَضَعَ كَفَّيْهِ حَذْوَ مَنْكِبَيْهِ ثُمَّ رَفَعَ رَأْسَهُ حَتَّى رَجَعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ حَتَّى فَرَغَ ثُمَّ جَلَسَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَأَقْبَلَ بِصَدْرِ الْيُمْنَى عَلَى قِبْلَتِهِ وَوَضَعَ كَفَّهُ الْيُمْنَى عَلَى رُكْبَتِهِ الْيُمْنَى وَكَفَّهُ الْيُسْرَى عَلَى رُكْبَتِهِ الْيُسْرَى وَأَشَارَ بِأُصْبُعِهِ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ عُتْبَةُ بْنُ أَبِي حَكِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ الْعَبَّاسِ بْنِ سَهْلٍ لَمْ يَذْكُرْ التَّوَرُّكَ وَذَكَرَ نَحْوَ حَدِيثِ فُلَيْحٍ وَذَكَرَ الْحَسَنُ بْنُ الْحُرِّ نَحْوَ جِلْسَةِ حَدِيثِ فُلَيْحٍ وَعُتْبَةَ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي عُتْبَةُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عِيسَى عَنْ الْعَبَّاسِ بْنِ سَهْلٍ السَّاعِدِيِّ عَنْ أَبِي حُمَيْدٍ بِهَذَا الْحَدِيثِ قَالَ وَإِذَا سَجَدَ فَرَّجَ بَيْنَ فَخِذَيْهِ غَيْرَ حَامِلٍ بَطْنَهُ عَلَى شَيْءٍ مِنْ فَخِذَيْهِ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ الْمُبَارَكِ حَدَّثَنَا فُلَيْحٌ سَمِعْتُ عَبَّاسَ بْنَ سَهْلٍ يُحَدِّثُ فَلَمْ أَحْفَظْهُ فَحَدَّثَنِيهِ أُرَاهُ ذَكَرَ عِيسَى بْنَ عَبْدِ اللَّهِ أَنَّهُ سَمِعَهُ مِنْ عَبَّاسِ بْنِ سَهْلٍ قَالَ حَضَرْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ بِهَذَا الْحَدِيثِ حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْحَدِيثِ قَالَ فَلَمَّا سَجَدَ وَقَعَتَا رُكْبَتَاهُ إِلَى الْأَرْضِ قَبْلَ أَنْ تَقَعَ كَفَّاهُ قَالَ فَلَمَّا سَجَدَ وَضَعَ جَبْهَتَهُ بَيْنَ كَفَّيْهِ وَجَافَى عَنْ إِبِطَيْهِ قَالَ حَجَّاجٌ وَقَالَ هَمَّامٌ و حَدَّثَنَا شَقِيقٌ حَدَّثَنِي عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا وَفِي حَدِيثِ أَحَدِهِمَا وَأَكْبَرُ عِلْمِي أَنَّهُ حَدِيثُ مُحَمَّدِ بْنِ جُحَادَةَ وَإِذَا نَهَضَ نَهَضَ عَلَى رُكْبَتَيْهِ وَاعْتَمَدَ عَلَى فَخِذِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abu 'Ashim Adalah Dlahak bin Makhlad] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dan ini adalah hadits (riwayat) Ahmad, dia berkata; telah mengabarkan kepada kami [Abdul Hamid yaitu Ibnu Ja'far] telah mengabarkan kepadaku [Muhammad bin Umar bin 'Atha`] dia berkata; saya mendengar [Abu Humaid As Sa'idi] berkata di tengah-tengah sepuluh sahabat Rasulullah shallallahu 'alaihi wasallam di antaranya adalah [Abu Qatadah], Abu Humaid berkata; \"Aku lebih mengetahui tentang shalat Rasulullah shallallahu 'alaihi wasallam.\" Mereka berkata; \"Kenapa demikian, demi Allah, padahal kamu bukanlah orang yang sering menyertai beliau dan bukan pula orang yang paling dahulu menjadi sahabat beliau daripada kami.\" Dia berkata; \"Ya, benar.\" Mereka berkata; \"Jika demikian, jelaskanlah.\" Abu Humaid berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak memulai shalatnya, beliau mengangkat kedua tangan hingga sejajar dengan kedua bahunya, kemudian beliau bertakbir sehingga semua tulang beliau kembali pada tempat semula dengan lurus, lalu beliau membaca (bacaan shalat) kemudian beliau bertakbir sambil mengangkat kedua tangan sampai sejajar dengan kedua bahu, lalu ruku' dengan meletakkan kedua telapak tangan di atas kedua lutut, kemudian meluruskan (punggung dan kepala) tidak menundukkan kepala dan juga tidak menengadah. Setelah itu beliau mengangkat kepala sambil mengucapkan: \"Sami'allahu liman hamidah.\" Kemudian beliau mengangkat kedua tangan sehingga sejajar dengan kedua bahu sampai lurus, lalu mengucapkan: \"Allahu akbar.\" Setelah itu beliau turun ke lantai, lalu merenggangkan kedua tangannya dari kedua lambungnya, kemudian beliau mengangkat kepala dan melipat kaki kirinya dan mendudukinya, dengan membuka kedua jari-jari kakinya apabila bersujud, kemudian mengucapkan: \"Allahu akbar.\" Setelah itu, beliau mengangkat kepala dan melipat kaki kirinya serta mendudukinya, sehingga tulang beliau kembali ke posisinya, kemudian beliau mengerjakan seperti itu di raka'at yang lain. Apabila beliau berdiri setelah dua rakaat, beliau bertakbir dan mengangkat kedua tangan sampai sejajar dengan kedua bahu, sebagaimana beliau bertakbir ketika memulai shalat, beliau melakukan cara seperti itu pada shalat-shalat yang lain, dan ketika beliau duduk (tahiyyat) yang terdapat salam, beliau merubah posisi kaki kiri dan duduk secara tawaruk (duduk dengan posisi kaki kiri masuk ke kaki kanan).\" Setelah itu sepuluh sahabat tersebut berkata; \"Benar kamu, demikianlah Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid yaitu Ibnu Abu Habib] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru Al 'Amiri] dia berkata; \"Aku berada di majlis para sahabat Nabi shallallahu 'alaihi wasallam, lalu mereka membicarakan shalat Rasulullah shallallahu 'alaihi wasallam.\" Abu Humaid mengatakan; \"…kemudian ia menyebutkan sebagian dari hadits ini.\" kata Abu Humaid selanjutnya; \"Apabila ruku', beliau merapatkan kedua telapak tangan pada kedua lututnya, merenggangkan jari jemarinya lalu membungkukkan punggung (secara rata), tidak menengadah dan tidak pula menundukkan kepalanya.\" Abu Humaid melanjutkan; \"Apabila beliau duduk dalam dua raka'at, beliau duduk di atas punggung telapak kaki kiri, dan menegakkan telapak kaki kanan. Sedangkan pada raka'at yang ke empat, beliau merapatkan pangkal paha yang kiri ke lantai, dan mengeluarkan kedua telapak kakinya menuju satu arah (yaitu di sebelah kanan).\" Telah menceritakan kepada kami [Isa bin Ibrahim Al Mishri] telah menceritakan kepada kami [Ibnu Wahb] dari [Al Laits bin Sa'd] dari [Yazid bin Muhammad Al Qurasyi] dan [Yazid bin Abu Habib] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru bin 'Atha`] seperti hadits ini, dia mengatakan; \"Apabila beliau sujud, beliau meletakkan kedua tangannya tanpa menghamparkan dan tidak pula merapatkan dan beliau menghadapkan jari-jari (kakinya) ke arah kiblat.\" Telah menceritakan kepada kami [Ali bin Al Husain bin Ibrahim] telah menceritakan kepada kami [Abu Badr] telah menceritakan kepadaku [Zuhair Abu Khaitsamah] telah menceritakan kepada kami [Al Hasan bin Al Hurr] telah menceritakan kepadaku [Isa bin Abdullah bin Malik] dari [Muhammad bin 'Amru bin 'Atha`] salah seorang dari Bani Malik, dari [Abbas atau 'Ayyasy bin Sahl As Sa'idi] bahwa dia menghadiri majlis yang terdapat ayahnya dan beberapa sahabat Nabi shallallahu 'alaihi wasallam, di dalam majlis itu pula terdapat Abu Hurairah, Abu Humaid As Sa'idi serta Abu Usaid dengan khabar (hadits) ini, dengan adanya penambahan atau pengurangan, dalam (riwayat itu), dia mengatakan; \"Kemudian beliau mengangkat kepalanya yaitu dari ruku' sambil mengucapkan; \"Sami'allahu liman hamidah, Allaumma rabbani walakal hamdu (Allah Maha mendengar terhadap siapa saja yang memuji-Nya, wahai rabb kami, hanya kepada-Mu lah segala puji-pujian).\" Dan mengangkat kedua tangannya sambil mengucapkan; \"Allahu akbar.\" Kemudian beliau sujud sambil menegakkan di atas telapak tangan dan kedua lututnya serta kedua telapak kakinya ketika beliau sedang sujud. Kemudian beliau bertakbir dan duduk tawaruk (duduk dengan posisi kaki kiri masuk ke kaki kanan) dan menegakkan telapak kakinya yang satu, kemudian beliau bertakbir lantas bersujud, lalu takbir yang di lanjutkan dengan berdiri, tidak duduk tawaruk (sebagaimana di awal) …\" kemudian dia melanjutkan redaksi haditsnya, dia melanjutkan; \"Kemudian beliau duduk setelah dua raka'at, sehingga ketika beliau hendak berdiri, beliau bertakbir terlebih dahulu, kemudian beliau menyempurnakan dua raka'at yang terakhir, dan tidak menyebutkan duduk tawaruk dalam tasyahud.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah mengabarkan kepadaku [Fualaih] telah menceritakan kepadaku ['Abbas bin Sahl] dia berkata; \"Abu Humaid, Abu Usaid, Sahl bin Sa'd dan Muhammad bin Maslamah bermajlis dan menyebutkan tata cara shalat Rasulullah shallallahu 'alaihi wasallam, [Abu Humaid] mengatakan; \"Aku adalah orang yang paling mengetahui tata cara shalat Rasulullah shallallahu 'alaihi wasallam.\" lalu dia menyebutkan sebagian dari hadits ini, katanya; \"Kemudian beliau ruku' dengan meletakkan kedua tangannya pada kedua lututnya seakan-akan beliau menggenggamnya, dan mengikatkan kedua tangannya seperti tali lalu merenggangkannya dari kedua lambungnya.\" Selanjutnya dia berkata; \"kemudian beliau sujud, dengan merapatkan hidung dan dahinya (ke lantai), dan merenggangkan kedua tangannya dari kedua lambungnya serta meletakkan kedua telapak tangan sejajar dengan kedua pundak. Setelah itu beliau mengangkat kepalanya (duduk di antara dua sujud) sehingga tulang beliau kembali ke posisi semula, seusainya (sujud) beliau duduk iftirasy (duduk di atas kaki kiri) dengan menghadapkan punggung kaki kanan ke arah kiblat, dan meletakkan kaki kanan di atas lutut kanan, dan telapak tangan kiri di atas lutut kiri, sambil menunjuk dengan jari (telunjuk) nya.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan oleh ['Utbah bin Abu Hakim] dari [Abdullah bin Isa] dari ['Abbas bin Sahl], namun dia tidak menyebutkan (duduk) tawaruk, lalu dia menyebutkan sebagaimana hadits (riwayat) Fulaih.\" Sedangkan Al Hasan bin Al Hur menyebutkan posisi duduk sebagaimana hadits (riwayatnya) Fulaih dan 'Utbah.\" Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [Baqiyah] telah menceritakan kepadaku [Utbah] telah menceritakan kepadaku [Abdullah bin Isa] dari [Al 'Abbas bin Sahl As Sa'idi] dari [Abu Humaid] dengan hadits seperti ini, katanya; \"Apabila beliau sujud, beliau merenggangkan kedua pahanya tanpa memikul beban perutnya.\" Abu Daud mengatakan; \"Hadits ini juga di riwayatka oleh [Ibnu Mubarrak], telah menceritakan kepada kami [Fulaih] saya mendengar ['Abbas bin Sahl] menceritakan (hadits ini), namun aku tidak hafal. Dan telah menceritakan kepadaku sepertinya ia menyebut Isa bin Abdullah bahwa dia pernah mendengar dari Abbas bin Sahl dia berkata; \"Aku memaparkan hadits ini kepada Abu Humaid As Sa'idi, telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Abdul Jabbar bin Wa`il] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam mengenai hadits ini, katanya; \"Ketika beliau sujud, beliau menempelkan kedua lututnya ke lantai sebelum meletakkan kedua telapak tangannya (ke lantai), katanya lagi; \"Ketika beliau sujud, beliau meletakkan mukanya di antara kedua telapak tangannya dan merenggangkan kedua ketiaknya.\" Telah berkata [Hajjaj]; [Hammam] berkata; dan telah menceritakan kepada kami [Syaqiq] telah menceritakan kepadaku ['Ashim bin Kulaib] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti (hadits) ini, dan di antara salah satu dari hadits tersebut yang lebih aku yakini adalah hadits Muhammad bin Juhadah yaitu; \"Apabila beliau hendak bangkit (untuk berdiri), beliau bangkit di atas kedua lututnya dengan bersandarkan pada kedua pahanya.\""},"615":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ فِطْرٍ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ إِبْهَامَيْهِ فِي الصَّلَاةِ إِلَى شَحْمَةِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] dari [Fithr] dari [Abdul Jabbar bin Wa'il] dari [ayahnya] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua jempol jarinya sejajar dengan kedua telinga ketika shalat.\""},"616":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عَبْدِ الْمَلِكِ بْنِ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَبَّرَ لِلصَّلَاةِ جَعَلَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَإِذَا رَكَعَ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ لِلسُّجُودِ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ فَعَلَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] telah menceritakan kepadaku [ayahku] dari [kakekku] dari [Yahya bin Ayyub] dari [Abdul Malik bin Abdul Aziz bin Juraij] dari [Ibnu Syihab] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam bertakbir untuk melaksanakan shalat, beliau mengangkat kedua tangannya hingga sejajar dengan kedua bahunya, begitu juga ketika hendak ruku', beliau juga melakukan seperti itu, apabila hendak sujud, juga apabila berdiri dari raka'at kedua, beliau juga melakukan seperti itu.\""},"617":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي هُبَيْرَةَ عَنْ مَيْمُونٍ الْمَكِّيِّأَنَّهُ رَأَى عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ وَصَلَّى بِهِمْ يُشِيرُ بِكَفَّيْهِ حِينَ يَقُومُ وَحِينَ يَرْكَعُ وَحِينَ يَسْجُدُ وَحِينَ يَنْهَضُ لِلْقِيَامِ فَيَقُومُ فَيُشِيرُ بِيَدَيْهِ فَانْطَلَقْتُ إِلَى ابْنِ عَبَّاسٍ فَقُلْتُ إِنِّي رَأَيْتُ ابْنَ الزُّبَيْرِ صَلَّى صَلَاةً لَمْ أَرَ أَحَدًا يُصَلِّيهَا فَوَصَفْتُ لَهُ هَذِهِ الْإِشَارَةَ فَقَالَ إِنْ أَحْبَبْتَ أَنْ تَنْظُرَ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْتَدِ بِصَلَاةِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Hubairah] dari [Maimun Al Makki] bahwa dirinya melihat Maimun bin Zubair mengerjakan shalat bersama mereka (orang-orang) seraya mengangkat kedua tangannya ketika berdiri, ruku', sujud, lalu berdiri sambil mengangkat kedua tangannya. Lalu aku menemui Ibnu Abbas, kataku; \"Aku pernah melihat Ibnu Zubair mengerjakan shalat yang aku belum pernah melihat seseorang mengerjakan shalat seperti dirinya.\" Sambil mengisyaratkan dengan mengangkat tangan ini kepada Ibnu Abbas, maka [Ibnu Abbas] menjawab; \"Jika kamu ingin melihat tata cara shalat Rasulullah shallallahu 'alaihi wasallam, maka ikutilah tata cara shalat Abdullah bin Zubair.\""},"618":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ أَبَانَ الْمَعْنَى قَالَا حَدَّثَنَا النَّضْرُ بْنُ كَثِيرٍ يَعْنِي السَّعْدِيَّ قَالَصَلَّى إِلَى جَنْبِي عَبْدُ اللَّهِ بْنُ طَاوُسٍ فِي مَسْجِدِ الْخَيْفِ فَكَانَ إِذَا سَجَدَ السَّجْدَةَ الْأُولَى فَرَفَعَ رَأْسَهُ مِنْهَا رَفَعَ يَدَيْهِ تِلْقَاءَ وَجْهِهِ فَأَنْكَرْتُ ذَلِكَ فَقُلْتُ لِوُهَيْبِ بْنِ خَالِدٍ فَقَالَ لَهُ وُهَيْبُ بْنُ خَالِدٍ تَصْنَعُ شَيْئًا لَمْ أَرَ أَحَدًا يَصْنَعُهُ فَقَالَ ابْنُ طَاوُسٍ رَأَيْتُ أَبِي يَصْنَعُهُ وَقَالَ أَبِي رَأَيْتُ ابْنَ عَبَّاسٍ يَصْنَعُهُ وَلَا أَعْلَمُ إِلَّا أَنَّهُ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Aban] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [An Nadlr bin Katsir yaitu As Sa'di] dia berkata; Abdullah bin Thawus shalat di sampingku di masjid Khaif, apabila dia sujud pada sujud pertama, lalu bangkit dari sujudnya, dia mengangkat kedua tangannya ke depan mukanya, lalu aku pun mengingkari perbuatannya, setelah itu aku adukan hal tersebut kepada Wuhaib bin Khalid, maka Wuhaib bin khalid berkata kepadanya; \"Kamu telah melakukan sesuatu yang belum pernah aku melihat seorangpun melakukannya.\" [Ibnu Thawus] menjawab; \"Aku pernah melihat ayahku melakukannya, kata [ayahku]; \"Aku melihat [Ibnu Abbas] melakukan hal itu, namun aku tidak mengetahui kecuali dia berkata bahwa Nabi shallallahu 'alaihi wasallam juga melakukan hal itu.\""},"619":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ إِذَا دَخَلَ فِي الصَّلَاةِ كَبَّرَ وَرَفَعَ يَدَيْهِ وَإِذَا رَكَعَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ رَفَعَ يَدَيْهِ وَيَرْفَعُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد الصَّحِيحُ قَوْلُ ابْنِ عُمَرَ لَيْسَ بِمَرْفُوعٍ قَالَ أَبُو دَاوُد وَرَوَى بَقِيَّةُ أَوَّلَهُ عَنْ عُبَيْدِ اللَّهِ وَأَسْنَدَهُ وَرَوَاهُ الثَّقَفِيُّ عَنْ عُبَيْدِ اللَّهِ وَأَوْقَفَهُ عَلَى ابْنِ عُمَرَ قَالَ فِيهِ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ يَرْفَعُهُمَا إِلَى ثَدْيَيْهِ وَهَذَا هُوَ الصَّحِيحُ قَالَ أَبُو دَاوُد وَرَوَاهُ اللَّيْثُ بْنُ سَعْدٍ وَمَالِكٌ وَأَيُّوبُ وَابْنُ جُرَيْجٍ مَوْقُوفًا وَأَسْنَدَهُ حَمَّادُ بْنُ سَلَمَةَ وَحْدَهُ عَنْ أَيُّوبَ وَلَمْ يَذْكُرْ أَيُّوبُ وَمَالِكٌ الرَّفْع�� إِذَا قَامَ مِنْ السَّجْدَتَيْنِ وَذَكَرَهُ اللَّيْثُ فِي حَدِيثِهِ قَالَ ابْنُ جُرَيْجٍ فِيهِ قُلْتُ لِنَافِعٍ أَكَانَ ابْنُ عُمَرَ يَجْعَلُ الْأُولَى أَرْفَعَهُنَّ قَالَ لَا سَوَاءً قُلْتُ أَشِرْ لِي فَأَشَارَ إِلَى الثَّدْيَيْنِ أَوْ أَسْفَلَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Nahsr bin Ali] telah mengabarkan kepada kami [Abdul A'laa] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa apabila dia hendak melaksanakan shalat, dia bertakbir sambil mengangkat kedua tangannya, (begitu juga) ketika ruku', ketika mengucapkan sami'allahu liman hamidah, ketika berdiri dari raka'at kedua beliau juga mengangkat kedua tangannya.\" Dia merafa'kan (mengangkat hadits ini) kepada Rasulullah shallallahu 'alaihi wasallam.\" Abu Daud mengatakan; \"Yang shahih adalah perkataannya Ibnu Umar, bukan sampai kepada Nabi shallallahu 'alaihi wasallam. ' Abu Daud mengatakan; \"Sedangkan di awal-awal hadits (yaitu tanpa menyebutkan \"Apabila berdiri dari raka'at kedua -pent) telah di riwayatkan oleh [Baqiyyah] dari ['Ubaidullah] dan ia merafa'kannya (bersambung sampai kepada Nabi -pent) kepada Nabi shallallahu 'alaihi wasallam. Dan di riwayatkan pula oleh [Ats Tsaqafi] dari ['Ubaidullah], namun ia hanya mewaqafkan sampai kepada [Ibnu Umar], katanya; \"Apabila beliau hendak berdiri di raka'at kedua, beliau mengangkat kedua tangannya sampai kedua susunya (dadanya), inilah (di antara riwayat) yang shahih.\" Abu Daud berkata; \"Dan di riwayatkan pula oleh [Al Laits bin Sa'd], [Malik], [Ayyub] serta [Ibnu Juraij] secara mauquf, namun [Hammad bin Salamah] saja yang menyambungnya (hingga kepada Nabi) dari [Ayyub], sedangkan Malik dan Ayyub tidak merafa'kan lafadz; \"Apabila beliau hendak bangkit dari sujud kedua.\" Al Laits juga menyebutkan dalam haditsnya seperti ini.\" Ibnu Juraij juga mengatakan; kataku kepada Nafi'; \"Apakah ibnu Umar mengangkat (kedua tangannya) lebih tinggi (dari dada)?\" jawabnya; \"Tidak, namun sejajar (dengan dada).\" Kataku; \"Jelaskanlah padaku!.\" Kemudian Nafi' memberi isyarat pada kedua susunya (dadanya) atau lebih rendah darinya.\""},"620":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَانَ إِذَا ابْتَدَأَ الصَّلَاةَ يَرْفَعُ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا دُونَ ذَلِكَقَالَ أَبُو دَاوُد لَمْ يَذْكُرْ رَفَعَهُمَا دُونَ ذَلِكَ أَحَدٌ غَيْرُ مَالِكٍ فِيمَا أَعْلَمُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] bahwa; \"Apabila [Ibnu Umar] hendak memulai shalatnya, dia mengangkat kedua tangannya sejajar dengan kedua bahunya, apabila mengangkat kepalanya dari ruku' (i'tidal), dia juga mengangkat kedua tangannya lebih rendah dari itu.\" Abu Daud mengatakan; 'yang saya ketahui, tidak ada Perawi satu pun yang menyebutkan; \"Mengangkat keduanya lebih rendah dari itu\" selain Malik.\""},"621":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin 'Ubaid Al Muharibi] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Ashim bin Kulaib] dari [Muharib bin Ditsar] dari [Ibnu Umar] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam bangkit dari raka'at kedua, beliau bertakbir sambil mengangkat kedua tangannya.\""},"622":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ بْنِ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ الْمَكْتُوبَةِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَيَصْنَعُ مِثْلَ ذَلِكَ إِذَا قَضَى قِرَاءَتَهُ وَأَرَادَ أَنْ يَرْكَعَ وَيَصْنَعُهُ إِذَا رَفَعَ مِنْ الرُّكُوعِ وَلَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ صَلَاتِهِ وَهُوَ قَاعِدٌ وَإِذَا قَامَ مِنْ السَّجْدَتَيْنِ رَفَعَ يَدَيْهِ كَذَلِكَ وَكَبَّرَقَالَ أَبُو دَاوُد فِي حَدِيثِ أَبِي حُمَيْدٍ السَّاعِدِيِّ حِينَ وَصَفَ صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا كَبَّرَ عِنْدَ افْتِتَاحِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Sulaiman bin Daud Al Hasyimi] telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinnad] dari [Musa bin 'Uqbah] dari [Abdullah bin Al Fadl bin Rabi'ah bin Al Harits bin Abdul Mutthalib] dari [Abdurrahman bin Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam; bahwa apabila beliau berdiri untuk melaksanakan shalat wajib, beliau bertakbir dengan mengangkat kedua tangannya sejajar dengan kedua bahunya, beliau melakukan seperti itu apabila selesai membaca surat dan hendak ruku', demikian juga apabila bangkit dari ruku'. Beliau tidak pernah sama sekali mengangkat kedua tangannya dalam ketika mengerjakan shalat dengan posisi duduk. Apabila bangkit dari sujud kedua, beliau mengangkat kedua tangannya lagi sambil mengucapkan takbir.\" Abu Daud berkata; \"Dalam hadits Abu Humaid As Sa'idi ketika dia mensifati sifat shalat Nabi shallallahu 'alaihi wasallam, yaitu; \"Apabila beliau berdiri dari raka'at kedua, beliau bertakbir sambil mengangkat kedua tangannya hingga sejajar dengan kedua bahunya, sebagaimana beliau takbir ketika memulai shalat.\""},"623":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا كَبَّرَ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ حَتَّى يَبْلُغَ بِهِمَا فُرُوعَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] dia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam mengangkat kedua tangannya ketika bertkbir, ruku', dan ketika mengangkat kepalanya dari ruku' (i'tidal) hingga mencapai kedua ujung telinganya.\""},"624":{"ar":"حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ حَدَّثَنَا شُعَيْبٌ يَعْنِي ابْنَ إِسْحَقَ الْمَعْنَى عَنْ عِمْرَانَ عَنْ لَاحِقٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ قَالَ قَالَ أَبُو هُرَيْرَةَلَوْ كُنْتُ قُدَّامَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَرَأَيْتُ إِبِطَيْهِ زَادَ عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ قَالَ يَقُولُ لَاحِقٌ أَلَا تَرَى أَنَّهُ فِي الصَّلَاةِ وَلَا يَسْتَطِيعُ أَنْ يَكُونَ قُدَّامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَادَ مُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ يَعْنِي إِذَا كَبَّرَ رَفَعَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Mu'adz] telah menceritakan kepada kami [ayahku], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musa bin Marwan] telah menceritakan kepada kami [Syu'aib yaitu Ibnu Ishaq] sedangkan ma'na haditsnya dari ['Imran] dari [Lahiq] dari [Basyir bin Nahik] dia berkata; [Abu Hurairah] berkata; \"Sekiranya aku berada di depan Nabi shallallahu 'alaihi wasallam (sewaktu mengangkat kedua tangan), niscaya ketiak beliau akan terlihat olehku.\" 'Ubaidullah bin Mu'adz menambahkan; Lahiq berkata; \"Tidakkah kamu tahu bahwa dia itu sedang shalat, oleh karena itu dia tidak bisa berada di depan Rasulullah shallallahu 'alaihi wasallam?.\" Marwan bin Ar Raqi menambahkan; \"yang di maksud ketika beliau bertakbir dan mengangkat kedua tangannya.\""},"625":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ فَلَمَّا رَكَعَ طَبَّقَ يَدَيْهِ بَيْنَ رُكْبَتَيْهِ قَالَ فَبَلَغَ ذَلِكَ سَعْدًا فَقَالَ صَدَقَ أَخِي قَدْ كُنَّا نَفْعَلُ هَذَا ثُمَّ أَمَرَنَا بِهَذَا يَعْنِي الْإِمْسَاكَ عَلَى الرُّكْبَتَيْنِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Idris] dari ['Ashim bin Kulaib] dari [Abdurrahman bin Al Aswad] dari ['Alqamah] dia berkata; [Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam mengajari kami shalat, beliau takbir sambil mengangkat kedua tangannya, dan ketika ruku', beliau mencengkramkan kedua tangannya pada kedua lututnya.\" Kata 'Alqamah; \"ternyata hal itu sampai kepada Sa'd, maka dia berkata; \"Saudaraku benar, kami memang melakukan hal itu, kemudian kami diperintahkan untuk mengerjakannya yaitu memegang kedua lutut.\""},"626":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمٍ يَعْنِي ابْنَ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍأَلَا أُصَلِّي بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَصَلَّى فَلَمْ يَرْفَعْ يَدَيْهِ إِلَّا مَرَّةًقَالَ أَبُو دَاوُد هَذَا حَدِيثٌ مُخْتَصَرٌ مِنْ حَدِيثٍ طَوِيلٍ وَلَيْسَ هُوَ بِصَحِيحٍ عَلَى هَذَا اللَّفْظِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Ashim yaitu Ibnu Kuliab] dari [Abdurrahman bin Al Aswad] dari ['Alqamah] dia berkata; [Abdullah bin Mas'ud] berkata: \"Maukah kalian aku ajarkan bersama kalian shalat Rasulullah shallallahu 'alaihi wasallam?\" lalu dia shalat dan tidak mengangkat kedua tangannya kecuali hanya sekali saja.\" Abu Daud berkata; \"Hadits ini adalah ringkasan dari hadits yang panjang dan di pandang tidak shahih dari redaksi tersebut.\""},"627":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا شَرِيكٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ إِلَى قَرِيبٍ مِنْ أُذُنَيْهِ ثُمَّ لَا يَعُودُحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ نَحْوَ حَدِيثِ شَرِيكٍ لَمْ يَقُلْ ثُمَّ لَا يَعُودُ قَالَ سُفْيَانُ قَالَ لَنَا بِالْكُوفَةِ بَعْدُ ثُمَّ لَا يَعُودُ قَالَ أَبُو دَاوُد وَرَوَى هَذَا الْحَدِيثَ هُشَيْمٌ وَخَالِدٌ وَابْنُ إِدْرِيسَ عَنْ يَزِيدَ لَمْ يَذْكُرُوا ثُمَّ لَا يَعُودُ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا مُعَاوِيَةُ وَخَالِدُ بْنُ عَمْرٍو وَأَبُو حُذَيْفَةَ قَالُوا حَدَّثَنَا سُفْيَانُ بِإِسْنَادِهِ بِهَذَا قَالَ فَرَفَعَ يَدَيْهِ فِي أَوَّلِ مَرَّةٍ وَقَالَ بَعْضُهُمْ مَرَّةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah Al Bazzaz] telah menceritakan kepada kami [Syarik] dari [Yazid bin Abu Ziyad] dari [Abdurrahman bin Abu Laila] dari [Al Barra`] bahwa; \"Apabila Rasulullah shallallahu 'alaihi wasallam memulai shalat, beliau mengangkat kedua tangannya sampai mendekati kedua telinganya, dan tidak mengulanginya lagi (hanya sekali).\" Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri] telah menceritakan kepada kami [Sufyan] dari [Yazid] seperti haditsnya Syarik, namun dia tidak mengatakan; \"Dan beliau tidak mengulanginya lagi.\" Sufyan mengatakan; \"Setelah itu dia mengatakan kepada kami; \"Dan beliau tidak mengulanginya lagi\" ketika berada di Kufah.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan pula oleh [Husyaim], [Khalid] dan [Ibdu Idris] dari [Yazid], namun mereka tidak menyebutkan; \"Dan beliau tidak mengulanginya lagi.\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Mu'awiyah] dan [Khalid bin 'Amru] serta [Abu Hudzaifah] mereka mengatakan; telah menceritakan kepada kami [Sufyan] dengan isnad seperti ini, katanya; \"Beliau mengangkat kedua tangannya di awal kali.\" sebagian yang lain mengatakan; \"Satu kali.\""},"628":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا وَكِيعٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفَعَ يَدَيْهِ حِينَ افْتَتَحَ الصَّلَاةَ ثُمَّ لَمْ يَرْفَعْهُمَا حَتَّى انْصَرَفَقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ لَيْسَ بِصَحِيحٍ","id":"Telah menceritakan kepada kami [Husain bin Abdurrahman] telah mengabarkan kepada kami [Waki'] dari [Ibnu Abu Laila] dari [Saudaranya yaitu Isa] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Al Barra` bin 'Azib] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya ketika memulai shalat, kemudian beliau tidak mengangkatnya hingga selesai shalat.\" Abu Daud mengakata; \"Hadits ini tidak shahih.\""},"629":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ سَمْعَانَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ مَدًّا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Abu Dzi`b] dari [Sa'id bin Sam'an] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam telah masuk shalat, beliau mengangkat tinggi-tinggi kedua tangannya.\""},"630":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا أَبُو أَحْمَدَ عَنْ الْعَلَاءِ بْنِ صَالِحٍ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ ابْنَ الزُّبَيْرِ يَقُولُصَفُّ الْقَدَمَيْنِ وَوَضْعُ الْيَدِ عَلَى الْيَدِ مِنْ السُّنَّةِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Abu Ahmad] dari [Al 'Ala` bin Shalih] dari [Zur'ah bin Abdurrahman] dia berkata; aku mendengar [Ibnu Zubair] berkata; \"Meluruskan kedua kaki dan meletekkan tangan (kanan) diatas tangan yang lain (kiri) adalah bagian dari sunnah.\""},"631":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ الرَّيَّانِ عَنْ هُشَيْمِ بْنِ بَشِيرٍ عَنْ الْحَجَّاجِ بْنِ أَبِي زَيْنَبَ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ ابْنِ مَسْعُودٍأَنَّهُ كَانَ يُصَلِّي فَوَضَعَ يَدَهُ الْيُسْرَى عَلَى الْيُمْنَى فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى الْيُسْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Bakkar bin Ar Rayyan] dari [Husyaim bin Basyir] dari [Al Hajjaj bin Abu Zainab] dari [Abu Utsman An Nahdi] dari [Ibnu Mas'ud] bahwa dia shalat dengan meletakkan tangan kirinya diatas tangan kanannya, ternyata dia dilihat Nabi shallallahu 'alaihi wasallam, kontan beliau meletakkan tangan kanannya diatas tangan kirinya.\""},"632":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ زِيَادِ بْنِ زَيْدٍ عَنْ أَبِي جُحَيْفَةَ أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ قَالَمِنْ السُّنَّةِ وَضْعُ الْكَفِّ عَلَى الْكَفِّ فِي الصَّلَاةِ تَحْتَ السُّرَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Abdurrahman bin Ishaq] dari [Ziyad bin Zaid] dari [Abu Juhaifah] bahwa [Ali radliallahu 'anhu] berkata; \"Termasuk dari sunnah adalah meletakkan telapak tangan di atas telapak tangan yang lain di bawah pusar dalam shalat.\""},"633":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ يَعْنِي ابْنَ أَعْيَنَ عَنْ أَبِي بَدْرٍ عَنْ أَبِي طَالُوتَ عَبْدِ السَّلَامِ عَنْ ابْنِ جَرِيرٍ الضَّبِّيِّ عَنْ أَبِيهِ قَالَ رَأَيْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُيُمْسِكُ شِمَالَهُ بِيَمِينِهِ عَلَى الرُّسْغِ فَوْقَ السُّرَّةِقَالَ أَبُو دَاوُد وَرُوِيَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ فَوْقَ السُّرَّةِ قَالَ أَبُو مِجْلَزٍ تَحْتَ السُّرَّةِ وَرُوِيَ عَنْ أَبِي هُرَيْرَةَ وَلَيْسَ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah yaitu Ibnu A'yan] dari [Abu Badr] dari [Abu Thalut Abdussalam] dari [Ibnu Jarir Ad Dhabbi] dari [ayahnya] dia berkata; \"Aku melihat tangan kanan [Ali radliallahu 'anhu] memegang tangan kirinya pada pergelangannya diatas pusar.\" Abu Daud berkata; \"Dan diriwayatkan dari Sa'id bin Jubair \"diatas pusar\". Abu Mijlaz mengatakan; \"dibawah pusar.\" Dan di riwayatkan dari Abu Hurairah, namun sanadnya tidak kuat.\""},"634":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ الْكُوفِيِّ عَنْ سَيَّارٍ أَبِي الْحَكَمِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ أَبُو هُرَيْرَةَأَخْذُ الْأَكُفِّ عَلَى الْأَكُفِّ فِي الصَّلَاةِ تَحْتَ السُّرَّةِقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يُضَعِّفُ عَبْدَ الرَّحْمَنِ بْنَ إِسْحَقَ الْكُوفِيَّ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Abdurrahman bin Ishaq Al Kuffi] dari [Sayyar Abu Al Hakam] dari [Abu Wa'il] dia berkata; [Abu Hurairah] berkata; \"Letakkanlah telapak tangan di atas telapak tangan yang lain di bawah pusar ketika shalat.\" Abu Daud berkata; \"Aku mendengar Ahmad bin Hambal melemahkan Abdurrahman bin Ishak Al Kufi.\""},"635":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا الْهَيْثَمُ يَعْنِي ابْنَ حُمَيْدٍ عَنْ ثَوْرٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ طَاوُسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ يَدَهُ الْيُمْنَى عَلَى يَدِهِ الْيُسْرَى ثُمَّ يَشُدُّ بَيْنَهُمَا عَلَى صَدْرِهِ وَهُوَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Al Haitsam yaitu Ibnu Humaid] dari [Tsaur] dari [Sulaiman bin Musa] dari [Thawus] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam meletakkan tangan kanannya diatas tangan kiri, kemudian menarik keduanya diatas dada ketika shalat.\""},"636":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عَمِّهِ الْمَاجِشُونِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ كَبَّرَ ثُمَّ قَالَ{ وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا }مُسْلِمًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ{ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا أَوَّلُ الْمُسْلِمِينَ }اللَّهُمَّ أَنْتَ الْمَلِكُ لَا إِلَهَ لِي إِلَّا أَنْتَ أَنْتَ رَبِّي وَأَنَا عَبْدُكَ ظَلَمْتُ نَفْسِي وَاعْتَرَفْتُ بِذَنْبِي فَاغْفِرْ لِي ذُنُوبِي جَمِيعًا إِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ وَاهْدِنِي لِأَحْسَنِ الْأَخْلَاقِ لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ وَاصْرِفْ عَنِّي سَيِّئَهَا لَا يَصْرِفُ سَيِّئَهَا إِلَّا أَنْتَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ كُلُّهُ فِي يَدَيْكَ وَالشَّرُّ لَيْسَ إِلَيْكَ أَنَا بِكَ وَإِلَيْكَ تَبَارَكْتَ وَتَعَالَيْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ وَإِذَا رَكَعَ قَالَ اللَّهُمَّ لَكَ رَكَعْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ خَشَعَ لَكَ سَمْعِي وَبَصَرِي وَمُخِّي وَعِظَامِي وَعَصَبِي وَإِذَا رَفَعَ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَالْأَرْضِ وَمِلْءَ مَا بَيْنَهُمَا وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ وَإِذَا سَجَدَ قَالَ اللَّهُمَّ لَكَ سَجَدْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَصَوَّرَهُ فَأَحْسَنَ صُورَتَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ وَتَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ وَإِذَا سَلَّمَ مِنْ الصَّلَاةِ قَالَ اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَسْرَفْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي أَنْتَ الْمُقَدِّمُ وَالْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ بْنِ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ الْمَكْتُوبَةِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَيَصْنَعُ مِثْلَ ذَلِكَ إِذَا قَضَى قِرَاءَتَهُ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَيَصْنَعُهُ إِذَا رَفَعَ مِنْ الرُّكُوعِ وَلَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ صَلَاتِهِ وَهُوَ قَاعِدٌ وَإِذَا قَامَ مِنْ السَّجْدَتَيْنِ رَفَعَ يَدَيْهِ كَذَلِكَ وَكَبَّرَ وَدَعَا نَحْوَ حَدِيثِ عَبْدِ الْعَزِيزِ فِي الدُّعَاءِ يَزِيدُ وَيَنْقُصُ الشَّيْءَ وَلَمْ يَذْكُرْ وَالْخَيْرُ كُلُّهُ فِي يَدَيْكَ وَالشَّرُّ لَيْسَ إِلَيْكَ وَزَادَ فِيهِ وَيَقُولُ عِنْدَ انْصِرَافِهِ مِنْ الصَّلَاةِ اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَأَعْلَنْتُ أَنْتَ إِلَهِي لَا إِلَهَ إِلَّا أَنْتَ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحُ بْنُ يَزِيدَ حَدَّثَنِي شُعَيْبُ بْنُ أَبِي حَمْزَةَ قَالَ قَالَ لِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ وَابْنُ أَبِي فَرْوَةَ وَغَيْرُهُمَا مِنْ فُقَهَاءِ أَهْلِ الْمَدِينَةِ فَإِذَا قُلْتَ أَنْتَ ذَاكَ فَقُلْ وَأَنَا مِنْ الْمُسْلِمِينَ يَعْنِي قَوْلَهُ{ وَأَنَا أَوَّلُ الْمُسْلِمِينَ }","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] dari [pamannya yaitu Al Majisun bin Abu Salamah] dari [Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib radliallahu 'anhu] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak mengerjakan shalat, beliau bertakbir kemudian membaca; \"WAJJAHTU WAJHIYA LILLADZII FATHARAS SAMAAWAATI WAL ARDLI HANIIFAM MUSLIMA WAMAA ANA MINAL MUSYRIKIN, INNA SHALAATI WA NUSUKII WA MAHYAAYA WA MAMAATI LILLAHI RABBIL 'AALAMIN, LAA SYARIIKALAHU WA BIDZAALIKA UMIRTU WA ANAA AWWALUL MUSLIMIN. ALLAHUMMA ANTAL MALIK LAAILAAHA ILLA ANTA, ANTA RABBI WA ANAA 'ABDUKA DLALAMTU NAFSII WA'TARAFTU BIDZANBII FAGHFIRLII DZUNUUBI JAMII'A INNAHU LAA YAGHFIRUD DZUNUUBA ILLA ANTA WAHDINII LIAHSANIL AHLAAQI LAA YAHDII LI AHSANIHAA ILLA ANTA WASHRIF 'ANNI SAYYI`AHAA LAA YASHRIF SAYYI`AHAA ILLA ANTA. LABBAIKA WA SA'DAIKA WAL KHAIRU KULLUHU FII YADAIKA WASS SYARRU LAISA ILAIKA ANA BIKA WA ILAIKA TABAARAKTA WA TA'AALAITA ASTAGHFIRUKA WA ATUUBU ILAIKA. (Aku hadapkan muka-Ku ke hadirat Allah yang telah menciptakan langit dan bumi dengan tunduk dan menyerahkan diri, dan tidaklah aku termasuk golongan orang-orang Musyrik. Sesungguhnya shalatku, ibadahku, hidup dan matiku adalah untuk Allah Penguasa seluruh alam, tidak ada sekutu bagi-Nya dan dengan demikian aku di perintah, dan aku adalah dari golongan orang-orang Islam (yang menyerah diri). Ya Allah, Enkau adalah Rabbku dan aku dalah hamba-Mu, aku telah berbuat aniaya terhadap diriku sendiri dan mengakui kesalahanku, maka amnpunilah dosaku semuanya, dan tiadalah yang dapat mengampuni dosaku itu melainkan Engkau. Tunjukilah aku kepada akhlak yang baik, dan tak ada yang dapat menunjuki kepada akhlak yang terbaik melainkan Engkau. Dan jauhkanlah aku dari akhlak yang tercela, karena tidak ada yang dapat menjauhkanku dari akhlak yang tercela melainkan Engkau, Ya Allah, aku penuhi panggilan-Mu, aku patuhi perintah-Mu, kebaikan seluruhnya berada dalam kekuasaan-Mu, sedangkan kejahatan tidak dapat di pakai untuk mendekatkan diri kepada-Mu. Aku ini hanya dapat hidup dengan-Mu dan akan kembali kepada-Mu, Maha Berkah Engakau dan Maha Tinggi, aku meohon ampunan dan bertaubat kepada-Mu).\" Apabila ruku', beliau membaca; \"ALLAHUMMA LAKA RAKA'TU WABIKA AAMANTU WALAKA ASLAMTU KHASYA'A LAKA SAM'II WA BASHARII WA MUKHHII WA 'IDZAAMII WA 'ASHABII (Ya Allah, kepada-Mu lah aku ruku', kepada-Mu lah aku beriman, kepada-Mu lah aku tunduk, dan kepada-Mu lah pendengaranku, penglihatanku, otakku, tulang belulangku dan urat sarafku tunduk).\" Apabila i'tidal beliau mengucapkan; \"SAMI'ALLAHU LIMAN HAMIDAH, RABBANAA WALAKAL HAMDU MIL`US SAMAAWAATI WAL ARDLI WA MIL`U MAA BAINAHUMAA WAMIL`U MAA SYI`TA MIN SYAI`IN BA'DU (Maha Mendengar Allah terhadap siapa saja yang memuji-Nya, Wahai Rabb kami, hanya bagi Engkau jua segala pujian, sepenuh langit, bumi, dan sepenuh isi langit dan bumi dan sepenuh apa yang Engkau kehendaki setelah itu).\" Apabila sujud, beliau mengucapkan; \"ALLAHUMMA LAKA SAJADTU WA BIKA AAMANTU WALAKA ASLAMTU, SAJADA WAJHIYA LILLADZII KHALAQAHU WA SHAWWARAHU FA AHSANA SHUURATAHU WA SYAQQA SAM'AHU WA BASHARAHU WA TABAARAKALLAHU AHSANUL KHAALIQIN (Ya Allah, kepada-Mu lah aku bersujud, kepada-Mu lah aku beriman, kepada-Mu lah aku tunduk, wajahku bersujud kepada Dzat yang telah menciptakannya dan membentuknya dengan sebaik-baik bentuk, membuat pendengaran dan penglihatannya, dan Maha Barakah Allah, sebaik-baik pencipta).\" Apabila selesai salam, beliau mengucapkan; \"ALLAHUMMAGHFIRLII MAA QADDAMTU WA MAA AKHHARTU WAMAA ASRARTU WAMAA A'LANTU WAMAA ASRAFTU WAMAA ANTA A'LAMU BIHI MINNI ANTAL MUQADDIM WAL MU`AKHHIR LAA ILAAHA ILLA ANTA (Ya Allah, ampunilah daku, dan dosa-dosa yang telah lalu, dosa yang akan datang, dosa yang samar dan dosa yang jelas, serta dosa yang hanya Engkau saja yang mengetahuinya, Engkau lah yang mendahulukan dan mengundurkan, tiada ilah selain Engkau).\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Sulaiman bin Daud Al Hasyimi] telah mengabarkan kepada kami [Abdurrahman bin Abu Az Zinnad] dari [Musa bin 'Uqbah] dari [Abdullah bin Al Fadl bin Rabi'ah bin Al Harits bin Abdul Mutthalib] dari [Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] dari Rasulullah shallallahu 'alaihi wasallam bahwa; \"Apabila beliau hendak mengerjakan shalat wajib, beliau mengangkat kedua tangannya sejajar dengan kedua bahunya, beliau melakukan semacam itu ketika telah usai dari membaca (surat Al Qur'an) yaitu ketika hendak ruku', beliau mengerjakan seperti itu pula ketika bangun dari ruku' (i'tidal), dan beliau tidak pernah mengangkat kedua tangannya waktu duduk dalam shalat, ketika beliau hendak bangkit dari sujud kedua, beliau juga mengangkat kedua tangannya dan bertakbir lalu berdo'a …\" sebagaimana hadits (riwayat) Abdul Aziz. Dalam do'anya terdapat penambahan dan pengurangan, namun tidak menyebutkan; \"WAL KHAIRU KULLUHU FII YADAIKA WAS SYARRU LAISA ILAIKA\" pada lafadznya ada tambahan; \"Ketika telah selesai, beliau mengucapkan: \"ALLAHUMMAGHFIRLII MAA QADDAMTU WA MAA AKHHARTU WAMAA ASRARTU WAMAA A'LANTU ANTA ILAAHI LAAILAAHA ILLA ANTA (Ya Allah, ampunilah daku, dan dosa-dosa yang telah lalu, dosa yang akan datang, dosa yang samar dan dosa yang jelas, serta dosa yang hanya Engkau saja yang mengetahuinya, Engkau lah yang mendahulukan dan mengundurkan, tiada ilah selain Engkau).\" Telah menceritakan kepada kami 'Amru bin Utsman telah menceritakan kepada kami Syuraih bin Yazid telah menceritakan kepadaku Syu'aib bin Abu Hamzah dia berkata; Muhammad bin Al Munkadir, Ibnu Abu Farwah dan yang lain dari fuqaha' Madinah telah berkata kepadaku; \"Jika kamu mengucapkan (do'a iftitah) tersebut, maka ucapkanlah \"WA ANA MINAL MUSLIMIN yaitu (sebagai pengganti) pada lafadz \"WA ANA AWWALUL MUSLIMIN.\""},"637":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ أَخْبَرَنَا حَمَّادٌ عَنْ قَتَادَةَ وَثَابِتٍ وَحُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا جَاءَ إِلَى الصَّلَاةِ وَقَدْ حَفَزَهُ النَّفَسُ فَقَالَ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ أَيُّكُمْ الْمُتَكَلِّمُ بِالْكَلِمَاتِ فَإِنَّهُ لَمْ يَقُلْ بَأْسًا فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ جِئْتُ وَقَدْ حَفَزَنِيَ النَّفَسُ فَقُلْتُهَا فَقَالَ لَقَدْ رَأَيْتُ اثْنَيْ عَشَرَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَرْفَعُهَا وَزَادَ حُمَيْدٌ فِيهِ وَإِذَا جَاءَ أَحَدُكُمْ فَلْيَمْشِ نَحْوَ مَا كَانَ يَمْشِي فَلْيُصَلِّ مَا أَدْرَكَهُ وَلْيَقْضِ مَا سَبَقَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah mengabarkan kepada kami [Hammad] dari [Qatadah], [tsabit] dan [Humaid] dari [Anas bin Malik] bahwa seorang laki-laki datang untuk menunaikan shalat, sedangkan lafadznya terengah-engah sambil mengucapkan; \"ALLAHU AKBAR, AL HAMDU LILLAHI HAMDAN KATSIRAN THAYYIBAN MUBAARAKAN FIIHI (Allah Maha Besar, segala puji bagi Allah, pujian yang banyak, baik dan penuh berkah).\" Ketika Rasulullah shallallahu 'alaihi wasallam selesai mengerjakan shalat, beliau bersabda: \"Siapakah di antara kalian yang mengucapkan beberapa kalimat tadi? Sungguh dia telah mengucapkan kalimat yang tidak di larang.\" Laki-laki tiu menjawab; \"Saya wahai Rasulullah, aku datang dengan tergesa-gesa, sehingga nafasku terengah-engah, lalu saya ucapkan do'a seperti tadi.\" Beliau bersabda: \"Sungguh, saya melihat dua belas Malaikat yang masing-masing dari mereka berlomba-lomba untuk mengangkat (kalimat tersebut).\" Dalam riwayatnya Humaid menambahkan; \"Apabila salah seorang dari kalian datang, hendaknya ia berjalan seperti biasa, lalu mengerjakan shalat sesuai raka'at yang ia dapat, dan mengganti raka'at yang tertinggal.\""},"638":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَاصِمٍ الْعَنَزِيِّ عَنْ ابْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةً قَالَ عَمْرٌو لَا أَدْرِي أَيَّ صَلَاةٍ هِيَ فَقَالَ اللَّهُ أَكْبَرُ كَبِيرًا اللَّهُ أَكْبَرُ كَبِيرًا اللَّهُ أَكْبَرُ كَبِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَسُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا ثَلَاثًا أَعُوذُ بِاللَّهِ مِنْ الشَّيْطَانِ مِنْ نَفْخِهِ وَنَفْثِهِ وَهَمْزِهِقَالَ نَفْثُهُ الشِّعْرُ وَنَفْخُهُ الْكِبْرُ وَهَمْزُهُ الْمُوتَةُ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ مِسْعَرٍ عَنْ مِسْعَرٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ رَجُلٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي التَّطَوُّعِ ذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari ['Ashim Al 'Anazi] dari [Ibnu Jubair bin Muth'im] dari [ayahnya] bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, -'Amru mengatakan; Aku tidak tahu shalat apa yang sedang di kerjakan beliau- beliau mengucapkan; \"ALLAHU AKBAR KABIIRA, ALLAHU AKBAR KABIIRA, ALLAHU AKBAR KABIIRAW WAL HAMDU LILLAAHI KATSIRA WAL HAMDU LILLAHI KATSIIRA WAL HAMDU LILLAHI KATSIRA WA SUBHAANALLAHI BUKRATA WA ASHIILA -tiga kali- A'UUDZU BILLAHI MINAS SYAITHAANI MIN NAFKHIHI WA NAFSIHI WA HAMAZIHI (Allah Maha Besar sungguh Maha Besar, Allah Maha Besar sungguh Maha Besar, Allah Maha Besar sungguh Maha Besar, dan segala puji bagi Allah dengan pujian yang banyak, segala puji bagi Allah dengan pujian yang banyak, segala puji bagi Allah dengan pujian yang banyak, dan Maha suci Allah pada pagi hari dan sore -sebanyak tiga kali- Aku berlindung kepada Allah dari godaan syetan, dari nafkh-nya, nafts-nya serta hamz-nya.\" Perawi berkata; nafts adalah syairnya, an-nafkh adalah kesombongannya sedangkan hamznya adalah kegilaan.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Mis'ar] dari [Mis'ar] dari ['Amru bin Murrah] dari [seorang laki-laki] dari [Nafi' bin Jubair] dari [ayahnya] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam mengucapkan dalam shalat sunnahnya…\" kemudian dia menyebutkan hadits yang serupa.\""},"639":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَخْبَرَنِي مُعَاوِيَةُ بْنُ صَالِحٍ أَخْبَرَنِي أَزْهَرُ بْنُ سَعِيدٍ الْحَرَازِيُّ عَنْ عَاصِمِ بْنِ حُمَيْدٍ قَالَ سَأَلْتُ عَائِشَةَبِأَيِّ شَيْءٍ كَانَ يَفْتَتِحُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيَامَ اللَّيْلِ فَقَالَتْ لَقَدْ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ قَبْلَكَ كَانَ إِذَا قَامَ كَبَّرَ عَشْرًا وَحَمِدَ اللَّهَ عَشْرًا وَسَبَّحَ عَشْرًا وَهَلَّلَ عَشْرًا وَاسْتَغْفَرَ عَشْرًا وَقَالَ اللَّهُمَّ اغْفِرْ لِي وَاهْدِنِي وَارْزُقْنِي وَعَافِنِي وَيَتَعَوَّذُ مِنْ ضِيقِ الْمَقَامِ يَوْمَ الْقِيَامَةِقَالَ أَبُو دَاوُد وَرَوَاهُ خَالِدُ بْنُ مَعْدَانَ عَنْ رَبِيعَةَ الْجُرَشِيِّ عَنْ عَائِشَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Zaid bin Al Hubbab] telah mengabarkan kepadaku [Mu'awiyah bin Shalih] telah mengabarkan kepadaku [Azhar bin Sa'id Al Harazi] dari ['Ashim bin Humaid] dia berkata; \"Aku bertanya kepada [Aisyah]; \"Dengan apakah Rasulullah shallallahu 'alaihi wasallam memulai shalat malamnya?\" Aisyah menjawab; \"Sungguh kamu telah menanyakan kepadaku sesuatu yang belum pernah di tanyakan seseorang sebelummu, apabila beliau mengerjakan (shalat malam) beliau memulai dengan takbir sepuluh kali, memuji Allah sepuluh kali, bertasbih sepuluh kali, lalu beliau mengucapkan; \"ALLAHUMMAGHFIRLII WAHDINII WARZUQNII WA'AAFINII (Ya Allah, ampunilah daku, berilah aku petunjuk, berilah aku rizki dan anugerahkanlah kesehatan padaku), kemudian beliau juga berlindung dari sempitnya kedudukan pada hari Kiamat.\" Abu Daud mengatakan; \"Dan di riwayatkan pula oleh [Khalid bin Ma'dan] dari [Rabi'ah Al Jurasyi] dari [Aisyah] seperti hadits di atas.\""},"640":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَ سَأَلْتُ عَائِشَةَبِأَيِّ شَيْءٍ كَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ صَلَاتَهُ إِذَا قَامَ مِنْ اللَّيْلِ قَالَتْ كَانَ إِذَا قَامَ مِنْ اللَّيْلِ يَفْتَتِحُ صَلَاتَهُ اللَّهُمَّ رَبَّ جِبْرِيلَ وَمِيكَائِيلَ وَإِسْرَافِيلَ فَاطِرَ السَّمَوَاتِ وَالْأَرْضِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ أَنْتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِيمَا كَانُوا فِيهِ يَخْتَلِفُونَ اهْدِنِي لِمَا اخْتُلِفَ فِيهِ مِنْ الْحَقِّ بِإِذْنِكَ إِنَّكَ أَنْتَ تَهْدِي مَنْ تَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو نُوحٍ قُرَادٌ حَدَّثَنَا عِكْرِمَةُ بِإِسْنَادِهِ بِلَا إِخْبَارٍ وَمَعْنَاهُ قَالَ كَانَ إِذَا قَامَ بِاللَّيْلِ كَبَّرَ وَيَقُولُ حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ قَالَ لَا بَأْسَ بِالدُّعَاءِ فِي الصَّلَاةِ فِي أَوَّلِهِ وَأَوْسَطِهِ وَفِي آخِرِهِ فِي الْفَرِيضَةِ وَغَيْرِهَا","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami ['Ikrimah] telah menceritakan kepadaku [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Salamah bin Abdurrahman bin 'Auf] dia berkata; saya bertanya kepada Aisyah; \"Dengan apakah Nabi Allah shallallahu 'alaihi wasallam berdo'a sebagai pembukaan shalat malam?\" [Aisyah] menjawab; \"Sebagai pembukaan shalat malamnya, beliau memulai dengan do'a; \"ALLAHUMMA RABBI JIBRIIL WA MIIKAAIIL WA ISRAAFIIL FAATHIRIS SAMAAWATI WAL ARDLI 'AALIMIL GHAIBI WAS SYAHAADAH ANTA TAHKUMU BAINA 'IBAADIKA FIIMA KAANUU FIIHI YAKHTALIFUUN, IHDINII LIMAKHTULIFA FIIHI MINAL HAQQI BI IDZNIKA INNAKA ANTA TAHDI MANTASYAA`U ILAA SHIRAATHAL MUSTAQIIM (Ya Allah, Tuhan Jibril, Mika`il dan Israfil yang telah menciptakan langit dan bumi, yang mengetahui hal yang ghaib maupun yang nyata. Engkau lah dzat yang akan mengadili hamba-hamba-Mu mengenai apa yang mereka perselisihkan. Berilah aku petunjuk dengan keizinan-Mu terhadap kebenaran yang diperselisihkan, sesungguhnya Engkau memberi petunjuk kepada siapa yang Engkau kehendaki ke jalan yang lurus).\" Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Nuh Qurad] telah menceritakan kepada kami ['Ikrimah] dengan isnad dan makna yang sama tanpa adanya pengabaran (telah mengabarkan kepada kami), katanya; \"Apabila beliau hendak mengerjakan shalat malam, beliau bertakbir dan mengucapkan…\" telah menceritakan kepada kami Al Qa'nabi dari Malik dia berkata; \"Tidak mengapa mengucapkan do'a dalam shalat, apakah di awal shalat, pertengahan ataupun di akhir shalat, baik shalat wajib atau sunnah.\""},"641":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَكُنَّا يَوْمًا نُصَلِّي وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْمُتَكَلِّمُ بِهَا آنِفًا فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nu'aim bin Abdullah Al Mujmir] dari [Ali bi Yahya Az Zuraqi] dari [ayahnya] dari [Rifa'ah bin Rafi' Az Zuraqi] dia berkata; \"Suatu hari kami pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam, ketika Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari ruku' (i'tidal), tiba-tiba seorang laki-laki di belakang Rasulullah shallallahu 'alaihi wasallam mengucapkan; \"ALLAHUMMA RABBANA WALAKAL HAMDU HAMDAN KATSIIRA THAYYIBA MUBAARAKAN FIIH (Allah Maha Besar, segala puji bagi Allah, pujian yang banyak, baik dan penuh berkah).\" Ketika Rasulullah shallallahu 'alaihi wasallam selesai menunaikan shalat, beliau bersabda: \"Siapakah di antara kalian yang mengucapkan beberapa kalimat tadi?\" laki-laki itu menjawab; \"Saya wahai Rasulullah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah melihat lebih dari tiga puluh malaikat yang berlomba-lomba untuk mencatat kalimat tersebut lebih dulu.\""},"642":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ مِنْ جَوْفِ اللَّيْلِ يَقُولُ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ قَيَّامُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ أَنْتَ الْحَقُّ وَقَوْلُكَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَأَخَّرْتُ وَأَسْرَرْتُ وَأَعْلَنْتُ أَنْتَ إِلَهِي لَا إِلَهَ إِلَّا أَنْتَحَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا عِمْرَانُ بْنُ مُسْلِمٍ أَنَّ قَيْسَ بْنَ سَعْدٍ حَدَّثَهُ قَالَ حَدَّثَنَا طَاوُسٌ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي التَّهَجُّدِ يَقُولُ بَعْدَ مَا يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ ذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] bahwa; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak mengerjakan shalat malam, beliau berdo'a; \"ALLAHUMMA LAKAL HAMDU ANTA NUURUS SAMAAWAATI WAL ARDLI WALAKAL HAMDU ANTA QAYYAMAS SAMAAWAATI WAL ARDLI WALAKAL HAMDU ANTA RABBUS SAMAAWAATI WAL ARDLI WAMAN FIIHINNA, ANTAL HAQQU WAQAULUKAL HAQQU WAWA'DUKAL HAQQU WANNAARU HAQQUN, WAS SAA'ATU HAQQUN, ALLAHUMMA LAKA ASLAMTU WABIKA AAMANTU WA'ALAIKA TAWAKKALTU WA ILAIKA ANABTU WABIKA KHAASHAMTU WA ILAIKA HAAKAMTU, FAGHFIRLII MAA QADDAMTU WA AKKHARTU WA ASRARTU WA A'LANTU ANTA ILAAHI LAA ILAAHA ILLA ANTA (Ya Allah, hanya untuk Engkau segala pujian, Engkau lah cahaya langit dan bumi, hanya untuk Engkau lah segala pujian, Engkau lah pemelihara langit dan bumi, dan hanya untuk Engkau-lah segala pujian, Engkau Maha pengatur langit dan bumi serta segala isinya, Engkau lah Al Haqq, firman-Mu juga Haqq, surga itu haq, janji Engkau juga haq, hari kiamat itu haq, Ya Allah, kepada Engkau lah aku berserah diri, kepada-Mu aku beriman, kepada-Mu aku bertawakkal, kepada-Mu aku akan kembali, dan aku berjuang bersama-Mu, dan aku berpedoman kepada hukum-hukum-Mu, maka ampunilah dosa-dosaku yang telah lalu dan yang akan datang, baik yang samar maupun yang terang, Engkau lah Rabb ku tidak ada ilah selain Engkau).\" Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] telah menceritakan kepada kami ['Imran bin Muslim] bahwa [Qais bin Sa'd] telah menceritakan kepadanya, katanya; telah menceritakan kepada kami [Thawus] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam dalam shalat tahajjud, yaitu setelah mengucapkan \"Allahu akbar\" beliau biasa mengucapkan do'a…\" kemudian dia menyebutkan makna haditsnya.\""},"643":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَسَعِيدُ بْنُ عَبْدِ الْجَبَّارِ نَحْوَهُ قَالَ قُتَيْبَةُ حَدَّثَنَا رِفَاعَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ عَمِّ أَبِيهِ مُعَاذِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَطَسَ رِفَاعَةُ لَمْ يَقُلْ قُتَيْبَةُ رِفَاعَةُ فَقُلْتُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ مُبَارَكًا عَلَيْهِ كَمَا يُحِبُّ رَبُّنَا وَيَرْضَى فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَقَالَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِثُمَّ ذَكَرَ نَحْوَ حَدِيثِ مَالِكٍ وَأَتَمَّ مِنْهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Sa'id bin Abdul Jabbar] seperti sanad semisal. Qutaibah berkata; telah menceritakan kepada kami [Rifa'ah bin Yahya bin Abdullah bin Rifa'ah bin Rafi'] dari [paman ayahnya Mu'adz bin Rifa'ah bin Rafi'] dari [ayahnya] dia berkata; \"Saya shalat di belakang Rasulullah shallallahu 'alaihi wasallam, lalu Rifa'ah bersin -namun Qutaibah tidak menyebutkan \"Rifa'ah\"- maka aku mengucapkan; \"ALHAMDULILLAAHI HAMDAN KATSIRA THAYYIBAN MUBAARAKAN FIIHI MUBAARAKAN 'ALAIHI KAMAA YUHIBBU RABBUNA WAYARDLAA (Segala puji bagi Allah dengan pujian yang banyak, baik lagi penuh berkah, seperti yang di cintai dan di ridlai oleh Rabb kami).\" Seusai shalat, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa tadi yang mengucapkan (do'a) dalam shalat?\" kemudian dia menyebutkan seperti hadits Malik dan yang lebih sempurna dari hadits di atas.\""},"644":{"ar":"حَدَّثَنَا ��لْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَعَطَسَ شَابٌّ مِنْ الْأَنْصَارِ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَقَالَ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ حَتَّى يَرْضَى رَبُّنَا وَبَعْدَمَا يَرْضَى مِنْ أَمْرِ الدُّنْيَا وَالْآخِرَةِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْقَائِلُ الْكَلِمَةَ قَالَ فَسَكَتَ الشَّابُّ ثُمَّ قَالَ مَنْ الْقَائِلُ الْكَلِمَةَ فَإِنَّهُ لَمْ يَقُلْ بَأْسًا فَقَالَ يَا رَسُولَ اللَّهِ أَنَا قُلْتُهَا لَمْ أُرِدْ بِهَا إِلَّا خَيْرًا قَالَ مَا تَنَاهَتْ دُونَ عَرْشِ الرَّحْمَنِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Al 'Abbas bin Abdul 'Adzim] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari ['Ashim bin 'Ubaidullah] dari ['Abdullah bin 'Amir bin Rabi'ah] dari [ayahnya] dia berkata; \"Seorang pemuda dari Anshar bersin dalam shalat di belakang Rasulullah shallallahu 'alaihi wasallam, lalu dia mengucapkan: \"ALHAMDULILLAHI HAMDAN KATSIRAN THAYYIBAN MUBARAKAN FIIH HATTA YARDHA RABBUNA WA BA'DA MA YARDHA MIN AMRID DUN-YAA WAL AKHIRAH\" (Segala puji bagi Allah dengan pujian yang banyak, baik, lagi penuh berkah. hingga Rabb kami ridha setelah Dia ridha terhadap urusan dunia dan akhirat).\" Seusai shalat, Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah yang mengucapkan kalimat tadi?\" Pemuda itu terdiam, lalu beliau bertanya lagi: \"Siapakah yang mengucapkan kalimat tadi? Sesungguhnya dia tidak mengatakan sesuatu yang salah!\" Maka laki-laki itu menjawab: \"Akulah yang mengatakannya wahai Rasulullah! Aku tidak bermaksud kecuali hanya kebaikan.\" Beliau bersabda: \"Tidak ada yang dapat menghalangi kalimat tersebut untuk sampai ke Arsy Ar Rahman Tabaraka wa Ta'ala.\""},"645":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ حَدَّثَنَا جَعْفَرٌ عَنْ عَلِيِّ بْنِ عَلِيٍّ الرِّفَاعِيِّ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ كَبَّرَ ثُمَّ يَقُولُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرَكَ ثُمَّ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ ثَلَاثًا ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ كَبِيرًا ثَلَاثًا أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْخِهِ وَنَفْثِهِ ثُمَّ يَقْرَأُقَالَ أَبُو دَاوُد وَهَذَا الْحَدِيثُ يَقُولُونَ هُوَ عَنْ عَلِيِّ بْنِ عَلِيٍّ عَنْ الْحَسَنِ مُرْسَلًا الْوَهْمُ مِنْ جَعْفَرٍ","id":"Telah menceritakan kepada kami [Abdussalam bin Mutthahir] telah menceritakan kepada kami [Ja'far] dari [Ali bin Ali Ar Rifa'i] dari [Abu Al Mutawakkil An Naji] dari [Abu Sa'id Al Khudri] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam bangun untuk shalat malam, beliau bertakbir kemudian mengucapkan: \"SUBHAANAKA ALLAHUMMA WABIHAMDIKA WATABAARAKASMUKA WA TA'AALA JADDUKA WALAA ILAAHA GHAIRAKA (Maha suci Engkau, ya Allah, aku sucikan nama-Mu dengan memuji-Mu, Maha berkah nama-Mu, Maha luhur keluhuran-Mu dan tidak ilah selain Engkau).\" kemudian membaca: \"LAA ILAAHA ILLALLAH (tidak ada ilah selain Allah) sebanyak tiga kali, kemudian membaca: \"ALLAHU AKBAR KABIIRA (Allah Maha besar benar-benar Maha besar).\" sebanyak tiga kali- (kemudian membaca): A'UUDZU BILLAHIS SAMII'IL 'ALIIM MINAS SYAITHAANIR RAJIIM MIN HAMZIHII WANAFKHIHI WA NAFTSIHI (Aku berlindung kepada Allah, dzat yang Maha mendengar lagi Maha mengetahui dari goda'an syetan yang terkutuk, dari kegilaannya, dari kesombongannya dan syairnya yang jelek).\" kemudian beliau membaca (surat Al Qur'an).\" Abu Daud berkata; \"Mereka (para perawi) mengatakan; Hadits ini dari Ali bin Ali dari Al Hasan secara mursal, dan wahm (keraguan) dari Ja'far.\""},"646":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عِيسَى حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ الْمُلَائِيُّ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَفْتَحَ الصَّلَاةَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرَكَقَالَ أَبُو دَاوُد وَهَذَا الْحَدِيثُ لَيْسَ بِالْمَشْهُورِ عَنْ عَبْدِ السَّلَامِ بْنِ حَرْبٍ لَمْ يَرْوِهِ إِلَّا طَلْقُ بْنُ غَنَّامٍ وَقَدْ رَوَى قِصَّةَ الصَّلَاةِ عَنْ بُدَيْلٍ جَمَاعَةٌ لَمْ يَذْكُرُوا فِيهِ شَيْئًا مِنْ هَذَا","id":"Telah menceritakan kepada kami [Husain bin Isa] telah menceritakan kepada kami [Thalq bin Ghannam] telah menceritakan kepada kami [Abdussalam bin Harb Al Mula`i] dari [Budail bin Maisarah] dari [Abu Jauza`] dari [Aisyah] dia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam hendak memulai shalat, beliau mengucapkan: \"SUBHANAKA ALLAHUMMA WA BIHAMDIKA WA TABARAKAS-MUKA WA TA'ALA JADDUKA WA LA ILAHA GHAIRAKA\" (Maha suci Engkau, ya Allah, aku sucikan nema-Mu dengan memuji-Mu, Maha berkah nama-Mu, Maha luhur keluhuran-Mu dan tidak ilah selain Engkau). Abu Daud berkata: \"Hadits ini tidak masyhur (di kenal) dari Abdullah bin Salam bin Harb, dan tidak ada yang meriwayatkan hadits ini kecuali Thalq bin Ghannam, namun dia telah meriwayatkan hadits tentang kisah shalat dari Budair, sedangkan para pakar hadits tidak menyebutkan sedikitpun hadits seperti ini.\""},"647":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْمَعِيلُ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ قَالَ سَمُرَةُحَفِظْتُ سَكْتَتَيْنِ فِي الصَّلَاةِ سَكْتَةً إِذَا كَبَّرَ الْإِمَامُ حَتَّى يَقْرَأَ وَسَكْتَةً إِذَا فَرَغَ مِنْ فَاتِحَةِ الْكِتَابِ وَسُورَةٍ عِنْدَ الرُّكُوعِ قَالَ فَأَنْكَرَ ذَلِكَ عَلَيْهِ عِمْرَانُ بْنُ حُصَيْنٍ قَالَ فَكَتَبُوا فِي ذَلِكَ إِلَى الْمَدِينَةِ إِلَى أُبَيٍّ فَصَدَّقَ سَمُرَةَقَالَ أَبُو دَاوُد كَذَا قَالَ حُمَيْدٌ فِي هَذَا الْحَدِيثِ وَسَكْتَةً إِذَا فَرَغَ مِنْ الْقِرَاءَةِ حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَسْكُتُ سَكْتَتَيْنِ إِذَا اسْتَفْتَحَ وَإِذَا فَرَغَ مِنْ الْقِرَاءَةِ كُلِّهَا فَذَكَرَ مَعْنَى حَدِيثِ يُونُسَ","id":"Telah menceritakan kepada kami [Ya'kub bin Ibrahim] telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Al Hasan] dia berkata; [Samurah] berkata; \"Aku hafal dua tempat diam sejenaknya beliau dalam shalat, pertama ketika imam bertakbir sampai membaca (Al Fatihah) dan diamnya yang kedua apabila selesai membaca surat Al Fatihah dan surat Al Qur'an sebelum ruku'.\" Al Hasan mengatakan; \"Ternyata hal itu di ingkari oleh 'Imran bin Hushain.\" Kata Al Hasan selanjutnya; \"Lantas mereka (orang-orang) menulis surat mengenai hal itu kepada [Ubay] di Madinah, namun Ubay membenarkan Samurah.\" Abu Daud mengatakan; \"Demikianlah kata Humaid dalam hadits ini, yaitu; \"Diam sejenaknya beliau ketika selesai membaca (surat Al Qur'an).\" Telah menceritakan kepada kami [Abu Bakr bin Khallad] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Asy'ats] dari [Al Hasan] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam bahwa beliau diam sejenak di dua tempat, yaitu; Ketika mulai (shalat, yaitu setelah takbir -pent) dan ketika selesai membaca (surat).\" Kemudian perawi menyebutkan makna hadits Yunus.\""},"648":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ حَدَّثَنَا سَعِيدٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ أَنَّ سَمُرَةَ بْنَ جُنْدُبٍ وَعِمْرَانَ بْنَ حُصَيْنٍ تَذَاكَرَافَحَدَّثَ سَمُرَةُ بْنُ جُنْدُبٍ أَنَّهُ حَفِظَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَكْتَتَيْنِ سَكْتَةً إِذَا كَبَّرَ وَسَكْتَةً إِذَا فَرَغَ مِنْ قِرَاءَةِ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَحَفِظَ ذَلِكَ سَمُرَةُ وَأَنْكَرَ عَلَيْهِ عِمْرَانُ بْنُ حُصَيْنٍ فَكَتَبَا فِي ذَلِكَ إِلَى أُبَيِّ بْنِ كَعْبٍ فَكَانَ فِي كِتَابِهِ إِلَيْهِمَا أَوْ فِي رَدِّهِ عَلَيْهِمَا أَنَّ سَمُرَةَ قَدْ حَفِظَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Sa'id] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] bahwa Samurah bin Jundab dan 'Imran bin Hushain saling mengingatkan (sesuatu), maka [Samurah bin Jundab] menceritakan bahwa dirinya hafal dari Rasulullah shallallahu 'alaihi wasallam dua tempat diam sejenaknya beliau (dalam shalat), pertama setelah takbir dan yang satunya ketika selesai dari membaca \"GHAIRIL MAGHDLUUBI 'ALAIHIM WALADL DLLAALLIN\", Samurah hafal yang demikian itu, namun Imran bin Hushain mengingkarinya, lantas keduanya menulis surat kepada Ubay bin Ka'b, maka [Ubay] membalas suratnya atau balasan dari surat mereka berdua bahwa Samurah memang telah hafal (dari Nabi).\""},"649":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ بِهَذَا قَالَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَسَكْتَتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيهِ قَالَ سَعِيدٌ قُلْنَا لِقَتَادَةَ مَا هَاتَانِ السَّكْتَتَانِ قَالَ إِذَا دَخَلَ فِي صَلَاتِهِ وَإِذَا فَرَغَ مِنْ الْقِرَاءَةِ ثُمَّ قَالَ بَعْدُ وَإِذَا قَالَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dengan redaksi ini, katanya; dari [Qatadah] dari [Al Hasan] dari [Samurah] dia berkata; \"Dua tempat pemberhentian sejenak yang pernah saya hafal dari Rasulullah shallallahu 'alaihi wasallam, (Abdul A'la) mengatakan dalam hadits tersebut, Sa'id berkata; kami berkata kepada Qatadah; \"Di manakah dua tempat pemberhentian sejenak tersebut?\" jawabnya; \"Apabila telah masuk shalat (setelah takbir -pent) dan ketika selesai dari membaca (surat Al Qur'an).\" Setelah itu Qatadah mengatakan; \"Ketika selesai membaca; \"GHAIRIL MAGHDLUUBI 'ALAIHIM WALADL DLLAALLIN.\""},"650":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ ح و حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ عُمَارَةَ الْمَعْنَى عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَبَّرَ فِي الصَّلَاةِ سَكَتَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ فَقُلْتُ لَهُ بِأَبِي أَنْتَ وَأُمِّي أَرَأَيْتَ سُكُوتَكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ أَخْبِرْنِي مَا تَقُولُ قَالَ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ أَنْقِنِي مِنْ خَطَايَايَ كَالثَّوْبِ الْأَبْيَضِ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْنِي بِالثَّلْجِ وَالْمَاءِ وَالْبَرَدِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Umarah]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Abdul Wahid] dari ['Umarah] sedangkan ma'na haditsnya dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam mengucapkan takbir dalam shalat, maka beliau akan diam sejenak antara takbir dan qira'ah (membaca surat Al Fatihah), maka kataku kepadanya; \"Demi ayah dan ibuku sebagai tebusanmu, beritahukanlah kepadaku, apa yang anda baca sewaktu anda diam antara takbir dan membaca Al Fatihah?\" beiau menjawab: \"ALLAHUMMA BAA'ID BAINI WA BAINA KHATHAAYAYA KAMAA BAA'ATTA BAINAL MASYRIQI WAL MAGHRIB, ALLAHUMMA ANQINII MIN KHATHAAYAAYA KATSSAUBIL ABYADLI MINAD DANAS, ALLAHUMMAGH SILNII BIS TSALJI WAL MAA`I WAL BARAD (Ya Allah, jauhkanlah antara aku dengan dosa-dosaku, sebagaimana Engkau jauhkan jarak antara timur dan barat, ya Allah bersihkanlah kesalahan-kesalahanku sebagaimana bersihnya kain putih dari kotoran, ya Allah cucilah diriku dengan salju, air dan embun).\""},"651":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ كَ��نُوا يَفْتَتِحُونَ الْقِرَاءَةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman, mereka semua memulai bacaannya dengan \"ALHAMDULILLAHI RABBIL 'AALAMIN.\""},"652":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ الصَّلَاةَ بِالتَّكْبِيرِ وَالْقِرَاءَةِ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }وَكَانَ إِذَا رَكَعَ لَمْ يُشَخِّصْ رَأْسَهُ وَلَمْ يُصَوِّبْهُ وَلَكِنْ بَيْنَ ذَلِكَ وَكَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ لَمْ يَسْجُدْ حَتَّى يَسْتَوِيَ قَائِمًا وَكَانَ يَقُولُ فِي كُلِّ رَكْعَتَيْنِ التَّحِيَّاتُ وَكَانَ إِذَا جَلَسَ يَفْرِشُ رِجْلَهُ الْيُسْرَى وَيَنْصِبُ رِجْلَهُ الْيُمْنَى وَكَانَ يَنْهَى عَنْ عَقِبِ الشَّيْطَانِ وَعَنْ فَرْشَةِ السَّبُعِ وَكَانَ يَخْتِمُ الصَّلَاةَ بِالتَّسْلِيمِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Husain Al Mu'allim] dari [Budail bin Maisarah] dari [Abu Al Jauza`] dari [Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memulai shalatnya dengan takbir dan membaca \"AL HAMDULILLAHI RABBIL 'AALAMIIN\", dan apabila hendak ruku', beliau tidak menengadah dan tidak pula terlalu menunduk, akan tetapi pertengahan antara keduanya. Apabila mengangkat kepala dari ruku' (i'tidal), beliau tidak langsung sujud sehingga diri beliau berdiri tegap, dan di setiap dua raka'at beliau biasa membaca; \"AT TAHIYYAT.\" Apabila duduk, beliau duduk di atas kaki kiri dan menegakkan kaki kanannya, beliau juga melarang duduknya syetan (yaitu duduk di atas tumit) dan melarang menghamparkan kedua telapak tangan dan hasta seperti binatang buas (ketika sujud), beliau menutup shalatnya dengan salam.\""},"653":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنْزِلَتْ عَلَيَّ آنِفًا سُورَةٌ فَقَرَأَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ إِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ حَتَّى خَتَمَهَا قَالَ هَلْ تَدْرُونَ مَا الْكَوْثَرُ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ نَهْرٌ وَعَدَنِيهِ رَبِّي فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami [Ibnu Fudlail] dari [Al Mukhtar bin Fulful] dia berkata; saya mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tadi telah di turunkan suatu surat kepadaku.\" Lalu beliau membaca: \"BISMILLAHIRRAHMAANIRRAHIM, INNAA A'THAINAAKAL KAUTSAR …\" hingga akhir ayat. Beliau bersabda: \"Apakah kalian tahu Al Kautsar?\" para sahabat menjawab; \"Allah dan rasul-Nya yang lebih mengetahui.\" Beliau bersabda: \"Ia adalah sungai di dalam surga yang telah di janjikan oleh Rabbku kepadaku kelak.\""},"654":{"ar":"حَدَّثَنَا قَطَنُ بْنُ نُسَيْرٍ حَدَّثَنَا جَعْفَرٌ حَدَّثَنَا حُمَيْدٌ الْأَعْرَجُ الْمَكِّيُّ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَوَذَكَرَ الْإِفْكَ قَالَتْ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَشَفَ عَنْ وَجْهِهِ وَقَالَ أَعُوذُ بِالسَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ{ إِنَّ الَّذِينَ جَاءُوا بِالْإِفْكِ عُصْبَةٌ مِنْكُمْ }الْآيَةَقَالَ أَبُو دَاوُد وَهَذَا حَدِيثٌ مُنْكَرٌ قَدْ رَوَى هَذَا الْحَدِيثَ جَمَاعَةٌ عَنْ الزُّهْرِيِّ لَمْ يَذْكُرُوا هَذَا الْكَلَامَ عَلَى هَذَا الشَّرْحِ وَأَخَافُ أَنْ يَكُونَ أَمْرُ الِاسْتِعَاذَةِ مِنْ كَلَامِ حُمَيْدٍ","id":"Telah menceritakan kepada kami [Qathn bin Nusair] telah menceritakan kepada kami [Ja'far] telah menceritakan kepada kami [Humaid Al A'raj Al Makki] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] -kemudian 'Urwah menyebutkan tentang haditsul ifki (berita kebohongan terhadap diri Aisyah) - Aisyah berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam duduk dan mengusap wajahnya sambil mengucapkan: \"A'UUDZU BILLAHIS-SAMI'IL 'ALIM MINASY-SYAITHANIR RAJIM. INNAL LADZINA JAA-U BIL IFKI 'USHBATUN MINKUM\" (Sesungguhnya orang-orang yang membawa berita bohong itu adalah dari golongan kamu juga).\" QS. An Nur: 11. Abu Daud berkata; \"Ini adalah hadits munkar, dan hadits ini juga di riwayatkan oleh beberapa orang dari Az Zuhri, namun mereka tidak menyebutkan perkataan ini sebagai penjelas, dan aku khawatir \"istiadzah\" pada redaksi ini dari perkataan Humaid.\""},"655":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ عَوْفٍ عَنْ يَزِيدَ الْفَارِسِيِّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَقُلْتُ لِعُثْمَانَ بْنِ عَفَّانَ مَا حَمَلَكُمْ أَنْ عَمَدْتُمْ إِلَى بَرَاءَةَ وَهِيَ مِنْ الْمِئِينَ وَإِلَى الْأَنْفَالِ وَهِيَ مِنْ الْمَثَانِي فَجَعَلْتُمُوهُمَا فِي السَّبْعِ الطِّوَالِ وَلَمْ تَكْتُبُوا بَيْنَهُمَا سَطْرَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ قَالَ عُثْمَانُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا تَنَزَّلُ عَلَيْهِ الْآيَاتُ فَيَدْعُو بَعْضَ مَنْ كَانَ يَكْتُبُ لَهُ وَيَقُولُ لَهُ ضَعْ هَذِهِ الْآيَةَ فِي السُّورَةِ الَّتِي يُذْكَرُ فِيهَا كَذَا وَكَذَا وَتَنْزِلُ عَلَيْهِ الْآيَةُ وَالْآيَتَانِ فَيَقُولُ مِثْلَ ذَلِكَ وَكَانَتْ الْأَنْفَالُ مِنْ أَوَّلِ مَا أُنْزِلَ عَلَيْهِ بِالْمَدِينَةِ وَكَانَتْ بَرَاءَةُ مِنْ آخِرِ مَا نَزَلَ مِنْ الْقُرْآنِ وَكَانَتْ قِصَّتُهَا شَبِيهَةً بِقِصَّتِهَا فَظَنَنْتُ أَنَّهَا مِنْهَا فَمِنْ هُنَاكَ وَضَعْتُهَا فِي السَّبْعِ الطِّوَالِ وَلَمْ أَكْتُبْ بَيْنَهُمَا سَطْرَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِحَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ مُعَاوِيَةَ أَخْبَرَنَا عَوْفٌ الْأَعْرَابِيُّ عَنْ يَزِيدَ الْفَارِسِيِّ حَدَّثَنَا ابْنُ عَبَّاسٍ بِمَعْنَاهُ قَالَ فِيهِ فَقُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُبَيِّنْ لَنَا أَنَّهَا مِنْهَا قَالَ أَبُو دَاوُد قَالَ الشَّعْبِيُّ وَأَبُو مَالِكٍ وَقَتَادَةُ وَثَابِتُ بْنُ عُمَارَةَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكْتُبْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَتَّى نَزَلَتْ سُورَةُ النَّمْلِ هَذَا مَعْنَاهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari ['Auf] dari [Yazid Al Farisi] dia berkata; saya mendengar [Ibnu Abbas] berkata; aku bertanya kepada Utsman bin 'Affan; \"Apa yang menyebabkan kalian sengaja meletakkan surat surat Bara'ah (At Taubah) padahal dia termasuk dari mi`in (surat yang ayatnya sampai seratus) dan surat Al Anfal padahal dia termasuk dari al matsani (surat yang ayatnya kurang dari seratus) kemudian kalian menyatukan keduanya termasuk dari tujuh surat panjang, dan belum kalian tulis antara keduanya dengan batas \"bismillaahir rahmaanir rahim?\" [Utsman] berkata; \"Ketika beberapa ayat turun kepada Nabi shallallahu 'alaihi wasallam, maka beliau memanggil beberapa orang yang akan menuliskan di sisinya, kemudian beliau bersabda kepadanya: \"Letakkan ayat ini dalam surat yang disebutkan di dalamnya begini dan begini, \" Ketika turun kepada beliau satu ayat atau dua ayat, maka beliau akan mengatakan seperti itu. Surat Al Anfal termasuk dari surat yang pertama diturunkan di Madinah, sedangkan Bara'ah (At Taubah) termasuk dari surat yang terakhir diturunkan di Madinah, sementara kandungannya mirip dengan kandungan yang ada dalam surat Al Anfal, maka perkiraanku, surat Al Bara'ah bagian dari surat Al Anfal, oleh karena itu aku meletakkan surat tersebut termasuk dari tujuh surat yang panjang, sehingga aku tidak menulis dengan batasan \"Bismillahir rahmanir rahim.\" Telah menceritakan kepada kami [Ziyad bin Ayyub] telah menceritakan kepada kami [Marwan yaitu Ibnu Mu'awiyah] telah mengabarkan kepada kami ['Auf Al A'Rabi'ah] dari [Yazid Al Farisi] telah menceritakan kepada kami [Ibnu Abbas] semakna dengan hadits di atas, dalam hadits tersebut dia mengatakan; \"Rasulullah shallallahu 'alaihi wasallam telah wafat, namun beliau belum menjelaskan kepada kami jika surat Al Anfal bagian dari surat Al Bara'ah.\" Abu Daud berkata; As Sya'bi, Abu Malik, Qatadah dan Tsabit bin 'Umarah mengatakan; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam tidak menulis \"Bismillahir rahmaanir rahim\" hingga turun surat An Naml, demikian makna dari hadits tersebut.\""},"656":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ وَابْنُ السَّرْحِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُتَيْبَةُ فِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَعْرِفُ فَصْلَ السُّورَةِ حَتَّى تَنَزَّلَ عَلَيْهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِوَهَذَا لَفْظُ ابْنِ السَّرْحِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ahmad bin Muhammad Al Marwazi] serta [Ibnu Sarh] mereka mengatakan telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Sa'id bin Jubair] -Qutaibah mengatakan dalam riwayat tersebut- dari [Ibnu Abbas] dia berkata; \"Nabi shallallahu 'alaihi wasallam tidak mengetahui pemisah antar surat hingga diturunkan kepada beliau \"Bismillahir Rahmanir Rahim\" (dengan menyebut nama Allah yang maha pengasih lagi maha penyayang). Lafadz ini dari Ibnu As Sarh.\""},"657":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ وَبِشْرُ بْنُ بَكْرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَقُومُ إِلَى الصَّلَاةِ وَأَنَا أُرِيدُ أَنْ أُطَوِّلَ فِيهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ كَرَاهِيَةَ أَنْ أَشُقَّ عَلَى أُمِّهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Umar bin Abdul Wahid] dan [Bisr bin Bakr] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku hendak memanjangkan (bacaan) ketika aku mengerjakan shalat, lalu aku mendengar tangisan anak kecil, maka aku mempersingkat (bacaan shalat) karena aku tidak ingin memberatkan (hati) ibunya.\""},"658":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو وَسَمِعَهُ مِنْ جَابِرٍ قَالَكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ فَيَؤُمُّنَا قَالَ مَرَّةً ثُمَّ يَرْجِعُ فَيُصَلِّي بِقَوْمِهِ فَأَخَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً الصَّلَاةَ وَقَالَ مَرَّةً الْعِشَاءَ فَصَلَّى مُعَاذٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَ يَؤُمُّ قَوْمَهُ فَقَرَأَ الْبَقَرَةَ فَاعْتَزَلَ رَجُلٌ مِنْ الْقَوْمِ فَصَلَّى فَقِيلَ نَافَقْتَ يَا فُلَانُ فَقَالَ مَا نَافَقْتُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ مُعَاذًا يُصَلِّي مَعَكَ ثُمَّ يَرْجِعُ فَيَؤُمُّنَا يَا رَسُولَ اللَّهِ وَإِنَّمَا نَحْنُ أَصْحَابُ نَوَاضِحَ وَنَعْمَلُ بِأَيْدِينَا وَإِنَّهُ جَاءَ يَؤُمُّنَا فَقَرَأَ بِسُورَةِ الْبَقَرَةِ فَقَالَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ أَفَتَّانٌ أَنْتَ اقْرَأْ بِكَذَا اقْرَأْ بِكَذَا قَالَ أَبُو الزُّبَيْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَاللَّيْلِ إِذَا يَغْشَىفَذَكَرْنَا لِعَمْرٍو فَقَالَ أُرَاهُ قَدْ ذَكَرَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا طَالِبُ بْنُ حَبِيبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ يُحَدِّثُ عَنْ حَزْمِ بْنِ أُبَيِّ بْنِ كَعْبٍ أَنَّهُ أَتَى مُعَاذَ بْنَ جَبَلٍ وَهُوَ يُصَلِّي بِقَوْمٍ صَلَاةَ الْمَغْرِبِ فِي هَذَا الْخَبَرِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ لَا تَكُنْ فَتَّانًا فَإِنَّهُ يُصَلِّي وَرَاءَكَ الْكَبِيرُ وَالضَّعِيفُ وَذُو الْحَاجَةِ وَالْمُسَافِرُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari ['Amru] dan dia mendengarnya dari [Jabir] dia berkata; \"Mu'adz biasa shalat bersama Nabi shallallahu 'alaihi wasallam, kemudian dia kembali dan menjadi imam (shalat) bagi kami' -di lain kali Jabir mengatakan; kemudian dia kembali dan menjadi imam (shalat) bagi kaumnya-, pada suatu malam, Nabi shallallahu 'alaihi wasallam mengakhirkan shalat -di lain kali Jabir mengatakan; shalat Isya'- Mu'adz mengerjakan shalat bersama Nabi shallallahu 'alaihi wasallam, lalu kembali (ke kaumnya) menjadi imam (shalat) bagi kaumnya dengan membaca surat Al Baqarah, (karena panjangnya) maka salah seorang laki-laki memisahkan diri dari Jama'ah dan mengerjakan shalat sendirian, hingga di katakan kepadanya; \"kamu telah berbuat nifak wahai fulan.\" Laki-laki itu menimpali; \"aku tidak munafik.\" Lantas laki-laki itu pergi menghadap Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Sesungguhnya Mu'adz biasa mengerjakan shalat bersama anda, kemudian ia kembali (ke kaumnya) dan menjadi imam (shalat) bagi kami, wahai Rasulullah, kami hanya pemilik unta pengangkut air dan kami harus bekerja keras, sesungguhnya dia datang mengimami kami dengan membaca surat Al Baqarah.\" Maka beliau bersabda: \"Wahai Mu'adz, apakah kamu hendak menyebarkan fitnah, apakah kamu hendak menyebarkan fitnah, bacalah surat ini, bacalah surat ini.\" Abu Zubair mengatakan; \"(cukup) dengan membaca 'sabbihisma rabbikal a'la dan wallaili idzaa yaghsyaa.\" Kemudian aku sebutkan perkara itu kepada 'amru, maka dia berkata; \"Aku telah melihat Jabir telah menyebutkan hadits tersebut.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Thalib bin Habib] telah menceritakan kepada kami [Abdurrahman bin Jabir] dia menceritakan dari [Hazm bin Ubay bin Ka'b] bahwa dia menemui Mu'adz bin Jabal yang sedang mengerjakan shalat maghrib (menjadi imam) bersama kaumnya…\" dalam hadits ini perawi mengatakan; \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Mu'adz, janganlah kamu menjadi penyebar fitnah, karena yang mengerjakan shalat di belakangmu terdapat orang tua, orang yang lemah, orang yang memiliki keperluan dan musafir.\" "},"659":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي صَالِحٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ كَيْفَ تَقُولُ فِي الصَّلَاةِ قَالَ أَتَشَهَّدُ وَأَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَأَعُوذُ بِكَ مِنْ النَّارِ أَمَا إِنِّي لَا أُحْسِنُ دَنْدَنَتَكَ وَلَا دَنْدَنَةَ مُعَاذٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَوْلَهَا نُدَنْدِنُحَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ جَابِرٍ ذَكَرَ قِصَّةَ مُعَاذٍ قَالَ وَقَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْفَتَى كَيْفَ تَصْنَعُ يَا ابْنَ أَخِي إِذَا صَلَّيْتَ قَالَ أَقْرَأُ بِفَاتِحَةِ الْكِتَابِ وَأَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِهِ مِنْ النَّارِ وَإِنِّي لَا أَدْرِي مَا دَنْدَنَتُكَ وَلَا دَنْدَنَةُ مُعَاذٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي وَمُعَاذًا حَوْلَ هَاتَيْنِ أَوْ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Husain bin Ali] dari [Za`idah] dari [Sulaiman] dari [Abu Shalih] dari [sebagian sahabat Nabi shallallahu 'alaihi wasallam] katanya; Nabi shallallahu 'alaihi wasallam pernah bertanya kepada seorang laki-laki: \"Bagaimana kamu berdo'a dalam shalat?\" laki-laki tersebut menjawab; \"Aku membaca tasyahud dan mengucapkan; \"ALLAHUMMA INNI AS`ALUKAL JANNATA WA A'UUDZUBIKA MINANNAAR (Ya Allah, aku memohon kepada Engkau surga dan berlindung kepada Engkau dari api neraka). (Ma'af) kami tidak dapat memahami dengan baik gumam anda gumam Mu'adz (ketika berdo'a).\" maka Nabi shallallahu 'alaihi wasallam bersabda: \"Seputar itulah kami bergumam (ketika berdo'a).\" Telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari ['Ubaidullah bin Miqsam] dari [Jabir] -dia menyebutkan kisahnya Mu'adz- katanya; \"Nabi shallallahu 'alaihi wasallam bertanya kepada seorang pemuda: \"Wahai anak saudaraku, apa yang kamu perbuat (baca) ketika mengerjakan shalat?\" pemuda itu menjawab; \"Aku membaca surat Al Fatihah dan memohon surga-Nya Allah dan berlindung dari api nerakanya Allah, sesungguhnya aku tidak dapat mendengar gumam anda begitu juga dengan gumam Mu'adz.\" Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku dan Mu'adz (juga berdo'a) sekitar dua hal itu atau seperti itu.\""},"660":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ لِلنَّاسِ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ الضَّعِيفَ وَالسَّقِيمَ وَالْكَبِيرَ وَإِذَا صَلَّى لِنَفْسِهِ فَلْيُطَوِّلْ مَا شَاءَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian mengerjakan shalat dengan orang banyak, maka peringanlah, karena di antara mereka terdapat orang yang lemah, sakit dan lanjut usia, namun apabila dia shalat sendirian, maka ia boleh memanjangkan sesuka hati.\""},"661":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيِّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ لِلنَّاسِ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ السَّقِيمَ وَالشَّيْخَ الْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Musayyib] dan [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian shalat bersama orang banyak, hendaknya ia meringankannya, karena di antara mereka ada orang yang sakit, usia lanjut dan orang yang memiliki keperluan.\""},"662":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ بَكْرٍ يَعْنِي ابْنَ مُضَرَ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عُمَرَ بْنِ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ عَنَمَةَ الْمُزَنِيِّ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرَّجُلَ لَيَنْصَرِفُ وَمَا كُتِبَ لَهُ إِلَّا عُشْرُ صَلَاتِهِ تُسْعُهَا ثُمْنُهَا سُبْعُهَا سُدْسُهَا خُمْسُهَا رُبْعُهَا ثُلُثُهَا نِصْفُهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Bakr yaitu ibnu mudlar] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari ['Umar bin Hakam] dari [Abdullah bin 'Anamah Al Muzanni] dari ['Ammar bin Yasir] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ada seseorang yang benar-benar mengerjakan shalat, namun pahala shalat yang tercatat baginya hanyalah sepersepuluh (dari) shalatnya, sepersembilan, seperdelapan, sepetujuh, seperenam, seperlima, seperempat, sepertiga, dan seperduanya saja.\""},"663":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسِ بْنِ سَعْدٍ وَعُمَارَةَ بْنِ مَيْمُونٍ وَحَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ أَنَّ أَبَا هُرَيْرَةَ قَالَفِي كُلِّ صَلَاةٍ يُقْرَأُ فَمَا أَسْمَعَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْمَعْنَاكُمْ وَمَا أَخْفَى عَلَيْنَا أَخْفَيْنَا عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Qais bin Sa'd] dan ['Umarah bin Maimun] serta [Habib] dari ['Atha` bin Abu Rabah] bahwa [Abu Hurairah] berkata; \"Di dalam shalat itu ada yang di baca, dan apa yang Rasulullah shallallahu 'alaihi wasallam perdengarkan kepada kami, maka kami pun akan perdengarkan kepada kalian, dan apa yang beliau samarkan (dalam bacaan) kepada kami, maka kami pun akan menyamarkan kepada kalian.\""},"664":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ الْحَجَّاجِ وَهَذَا لَفْظُهُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ قَالَ ابْنُ الْمُثَنَّى وَأَبِي سَلَمَةَ ثُمَّ اتَّفَقَا عَنْ أَبِي قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا فَيَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِفَاتِحَةِ الْكِتَابِ وَسُورَتَيْنِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطَوِّلُ الرَّكْعَةَ الْأُولَى مِنْ الظُّهْرِ وَيُقَصِّرُ الثَّانِيَةَ وَكَذَلِكَ فِي الصُّبْحِ قَالَ أَبُو دَاوُد لَمْ يَذْكُرْ مُسَدَّدٌ فَاتِحَةَ الْكِتَابِ وَسُورَةًحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ وَأَبَانُ بْنُ يَزِيدَ الْعَطَّارُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ بِبَعْضِ هَذَا وَزَادَ فِي الْأُخْرَيَيْنِ بِفَاتِحَةِ الْكِتَابِ وَزَادَ عَنْ هَمَّامٍ قَالَ وَكَانَ يُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى مَا لَا يُطَوِّلُ فِي الثَّانِيَةِ وَهَكَذَا فِي صَلَاةِ الْعَصْرِ وَهَكَذَا فِي صَلَاةِ الْغَدَاةِ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ فَظَنَنَّا أَنَّهُ يُرِيدُ بِذَلِكَ أَنْ يُدْرِكَ النَّاسُ الرَّكْعَةَ الْأُولَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam bin Abu Abdullah], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Al Hajjaj] -dan ini adalah lafadz hadits darinya- dari [Yahya] dari [Abdullah bin Abu Qatadah], berkata [Ibnu Al Mutsanna] dan [Abu Salamah], kemudian keduanya sepakat dari [Abu Qotadah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat mengimami kami, beliau membaca Al Fatihah dan dua surat pada dua raka'at pertama dalam shalat Dhuhur dan Ashar. Kadang-kadang beliau memperdengarkan bacaan ayat kepada kami, dan biasanya beliau memanjangkan raka'at pertama pada shalat dzuhur dan memperpendek pada raka'at keduanya, begitu juga pada waktu shalat subuh.\" Abu Daud berkata; Musaddad tidak menyebutkan Al Fatihah dan surat. Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dan [Aban bin Yazid Al 'Atthar] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dengan menambahkan pada sebagian hadits ini; \"… Pada dua raka'at terakhir dengan membaca Al Fatihah…\" Dan dia menambahkan dari Hammam katanya; \"… Dan beliau memanjangkan berdirinya pada raka'at pertama, tidak sepanjang pada raka'at kedua, demikian juga pada shalat Ashar dan shalat subuh...\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dia berkata; \"Hingga kami menyangka beliau memanjangkan bacaannya karena ingin menunggu supaya orang-orang mendapatkan raka'at pertama.\""},"665":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَ قُلْنَا لِخَبَّابٍهَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قُلْنَا بِمَ كُنْتُمْ تَعْرِفُونَ ذَاكَ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dia berkata; kami bertanya kepada [Khabbab]; \"Apakah Rasulullah shallallahu 'alaihi wasallam membaca (surat al Fatihah) dalam shalat dluhur dan Ashar?\" jawabnya; \"Ya, benar.\" Kami bertanya; \"Dengan apa kalian mengetahuinya?\" jawabnya; \"Dengan gerakan jenggot beliau.\""},"666":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ رَجُلٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُومُ فِي الرَّكْعَةِ الْأُولَى مِنْ صَلَاةِ الظُّهْرِ حَتَّى لَا يُسْمَعَ وَقْعُ قَدَمٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [seorang laki-laki] dari [Abdullah bin Abu Aufa] bahwa Nabi shallallahu 'alaihi wasallam berdiri pada raka'at pertama dalam shalat dluhur hingga tidak terdengar suara pijakan kaki.\""},"667":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ أَبِي عَوْنٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَقَالَ عُمَرُ لِسَعْدٍ قَدْ شَكَاكَ النَّاسُ فِي كُلِّ شَيْءٍ حَتَّى فِي الصَّلَاةِ قَالَ أَمَّا أَنَا فَأَمُدُّ فِي الْأُولَيَيْنِ وَأَحْذِفُ فِي الْأُخْرَيَيْنِ وَلَا آلُو مَا اقْتَدَيْتُ بِهِ مِنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَاكَ الظَّنُّ بِكَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Ubaidullah Abu 'Aun] dari [Jabir bin Samurah] dia berkata; Umar berkata kepada Sa'd; \"Orang-orang mengadukan segala sesuatu kepadamu sampai dalam masalah shalat, [Sa'd] menjawab; \"Aku suka memanjangkan shalatku pada dua raka'at pertama dan memendekkannya pada dua raka'at yang terakhir, aku tidak akan mengurangi sedikitpun apa yang telah aku dapatkan dari tata cara shalat Rasulullah shallallahu 'alaihi wasallam.\" Umar berkata; \"Demikianlah dugaan saya tentang dirimu!.\""},"668":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ يَعْنِي النُّفَيْلِيَّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ عَنْ الْوَلِيدِ بْنِ مُسْلِمٍ الْهُجَيْمِيِّ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَحَزَرْنَا قِيَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الظُّهْرِ وَالْعَصْرِ فَحَزَرْنَا قِيَامَهُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ الظُّهْرِ قَدْرَ ثَلَاثِينَ آيَةً قَدْرَ الم تَنْزِيلُ السَّجْدَةِ وَحَزَرْنَا قِيَامَهُ فِي الْأُخْرَيَيْنِ عَلَى النِّصْفِ مِنْ ذَلِكَ وَحَزَرْنَا قِيَامَهُ فِي الْأُولَيَيْنِ مِنْ الْعَصْرِ عَلَى قَدْرِ الْأُخْرَيَيْنِ مِنْ الظُّهْرِ وَحَزَرْنَا قِيَامَهُ فِي الْأُخْرَيَيْنِ مِنْ الْعَصْرِ عَلَى النِّصْفِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad yaitu An Nufaili] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur] dari [Al Walid bin Muslim Al Hujaimi] dari [Abu As Shiddiq An Najji] dari [Abu Sa'id Al Khudri] dia berkata; \"Kami pernah memperkirakan berapa lama Rasulullah shallallahu 'alaihi wasallam berdiri ketika shalat Dzuhur dan Ashar, yaitu perkirakan kami pada dua raka'at pertama shalat Dzuhur seperti lamanya membaca kira-kira tiga puluh ayat, seperti membaca; \"Alif Lam Mim Tanziilul (surat as Sajadah), dan kami memperkirakan lama berdiri beliau pada dua raka'at terakhir, seperti setengah dari dua raka'at yang pertama. Lalu kami memperkirakan lama berdiri beliau dalam dua raka'at pertama shalat Ashar, sama dengan lama berdiri beliau dalam dua raka'at terakhir shalat Dzuhur, dan kami memperkirakan lama berdiri beliau dalam dua raka'at yang terakhir dalam shalat Ashar seperti separuh dari lamanya pada dua raka'at pertama.\""},"669":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ بِالسَّمَاءِ وَالطَّارِقِ وَالسَّمَاءِ ذَاتِ الْبُرُوجِ وَنَحْوِهِمَا مِنْ السُّوَرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Simak bin Harb] dari [Jabir bin Samurah] bahwa pada waktu shalat Dhuhur dan Ashar Rasulullah shallallahu 'alaihi wasallam membaca (surat) \"WAS SAMAA`I WAT THAARIQ dan WAS SAMAA`I DZAATIL BURUUJ serta surat-surat seperti itu.\""},"670":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ سَمِعَ جَابِرَ بْنَ سَمُرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَحَضَتْ الشَّمْسُ صَلَّى الظُّهْرَ وَقَرَأَ بِنَحْوٍ مِنْ وَاللَّيْلِ إِذَا يَغْشَى وَالْعَصْرَ كَذَلِكَ وَالصَّلَوَاتِ كَذَلِكَ إِلَّا الصُّبْحَ فَإِنَّهُ كَانَ يُطِيلُهَا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Simak] dia mendengar [Jabir bin Samurah] berkata; \"Apabila matahari telah condong ke barat, beliau melaksanakan shalat dhuhur dan membaca (surat) seperti surat WALLAILI IDZAA YAGHSYAA, demikian juga dalam shalat-shalat yang lain kecuali shalat subuh, beliau memanjangkan bacaannya.\""},"671":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ وَيَزِيدُ بْنُ هَارُونَ وَهُشَيْمٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أُمَيَّةَ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي صَلَاةِ الظُّهْرِ ثُمَّ قَامَ فَرَكَعَ فَرَأَيْنَا أَنَّهُ قَرَأَ تَنْزِيلَ السَّجْدَةِقَالَ ابْنُ عِيسَى لَمْ يَذْكُرْ أُمَيَّةَ أَحَدٌ إِلَّا مُعْتَمِرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dan [Yazid bin Harun] serta [Husyaim] dari [Sulaiman At Taimi] dari [Umayyah] dari [Abu Mijlas] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam sujud pada waktu shalat Dluhur, kemudian beliau berdiri (dari sujud) lalu ruku', maka kami mengetahui bahwa beliau membaca surat As Sajdah.\" Ibnu Isa mengatakan; \"Umayyah tidak menyebutkan seorang pun kecuali hanya menyebutkan Mu'tamir.\""},"672":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ مُوسَى بْنِ سَالِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ قَالَدَخَلْتُ عَلَى ابْنِ عَبَّاسٍ فِي شَبَابٍ مِنْ بَنِي هَاشِمٍ فَقُلْنَا لِشَابٍّ مِنَّا سَلْ ابْنَ عَبَّاسٍ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ فَقَالَ لَا لَا فَقِيلَ لَهُ فَلَعَلَّهُ كَانَ يَقْرَأُ فِي نَفْسِهِ فَقَالَ خَمْشًا هَذِهِ شَرٌّ مِنْ الْأُولَى كَانَ عَبْدًا مَأْمُورًا بَلَّغَ مَا أُرْسِلَ بِهِ وَمَا اخْتَصَّنَا دُونَ النَّاسِ بِشَيْءٍ إِلَّا بِثَلَاثِ خِصَالٍ أَمَرَنَا أَنْ نُسْبِغَ الْوُضُوءَ وَأَنْ لَا نَأْكُلَ الصَّدَقَةَ وَأَنْ لَا نُنْزِيَ الْحِمَارَ عَلَى الْفَرَسِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Musa bin Salim] telah menceritakan kepada kami [Abdullah bin 'Ubaidullah] dia berkata; aku menemui Ibnu Abbas ketika dia berada di tengah-tengah pemuda Bani Hasyim, lalu kami berkata kepada seorang pemuda di antara kami; \"Tanyakanlah kepada Ibnu Abbas, apakah Rasulullah shallallahu 'alaihi wasallam membaca (surat) dalam shalat Dluhur dan Ashar?\" [Ibnu Abbas] menjawab; \"Tidak, tidak membaca.\" Maka di katakan kepadanya lagi; \"Barangkali dia membaca dalam hati.\" Maka Ibnu Abbas berkata; \"Sungguh ini lebih jelek dari (dugaan) yang pertama, beliau adalah seorang hamba yang di perintahkan untuk menyampaikan apa yang di tugaskan kepada beliau, beliau tidak pernah mengistimewakan kami dengan sesuatu pun di banding orang lain, kecuali tiga perkara; beliau memerintahkan kami untuk menyempurnakan wudlu`, kami tidak boleh makan uang zakat dan tidak boleh menjadikan keledai untuk menjantani kuda.\" "},"673":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَا أَدْرِي أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ أَمْ لَا","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata; \"Aku tidak tahu, apakah Rasulullah shallallahu 'alaihi wasallam membaca (surat Al Qur'an) pada waktu shalat Dluhur dan Ashar ataukah tidak.\""},"674":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ أُمَّ الْفَضْلِ بِنْتَ الْحَارِثِ سَمِعَتْهُ وَهُوَ يَقْرَأُ وَالْمُرْسَلَاتِ عُرْفًا فَقَالَتْ يَا بُنَيَّ لَقَدْ ذَكَّرْتَنِي بِقِرَاءَتِكَ هَذِهِ السُّورَةِ إِنَّهَا لَآخِرُ مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهَا فِي الْمَغْرِبِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa Ummu Fadl binti Al Harits mendengarnya ketika dia membaca surat \"WAL MURSALAATI 'URFAA\" maka Ummu Fadl berkata; \"Wahai anakku, kamu telah mengingatkanku dengan bacaan suratmu itu, yaitu akhir bacaan Rasulullah shallallahu 'alaihi wasallam yang pernah aku dengar pada shalat Maghrib.\""},"675":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِالطُّورِ فِي الْمَغْرِبِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Muhammad bin Jubair bin Muth'im] dari [ayahnya] bahwa dia berkata; aku mendengr Rasulullah shallallahu 'alaihi wasallam membaca surat At Thur pada waktu shalat Maghrib.\""},"676":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ قَالَ قَالَ لِي زَيْدُ بْنُ ثَابِتٍمَا لَكَ تَقْرَأُ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِطُولَى الطُّولَيَيْنِقَالَ قُلْتُ مَا طُولَى الطُّولَيَيْنِ قَالَ الْأَعْرَافُ وَالْأُخْرَى الْأَنْعَامُ قَالَ وَسَأَلْتُ أَنَا ابْنَ أَبِي مُلَيْكَةَ فَقَالَ لِي مِنْ قِبَلِ نَفْسِهِ الْمَائِدَةُ وَالْأَعْرَافُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] dari [Ibnu Juraij] telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari ['Urwah bin Zubair] dari [Marwan bin Al Hakam] dia berkata; [Zaid bin Tsabit] berkata kepadaku; \"Kenapa anda biasa membaca surat-surat pendek pada saat shalat Maghrib? Padahal aku melihat Rasulullah shallallahu 'alaihi wasallam membaca dua surat panjang dari surat-surat panjang dalam shalat Maghrib?.\" Ibnu Abu Mulaikah berkata; \"Kataku; \"Apakah dua surat panjang dari surat-surat panjang tersebut?\" Urwah menjawab; \"Yaitu Al A'raf dan Al An'am.\" Ibnu Juraij berkata; Aku bertanya kepada Ibnu Abu Mulaikah, lalu menurut dirinya adalah surat Al Maidah dan Al A'raf.\""},"677":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ أَنَّ أَبَاهُكَانَ يَقْرَأُ فِي صَلَاةِ الْمَغْرِبِ بِنَحْوِ مَا تَقْرَءُونَ وَالْعَادِيَاتِ وَنَحْوِهَا مِنْ السُّوَرِقَالَ أَبُو دَاوُد هَذَا يَدُلُّ عَلَى أَنَّ ذَاكَ مَنْسُوخٌ قَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Hisyam bin 'Urwah] bahwa dalam shalat Maghrib [ayahnya (Urwah)] biasa membaca (surat) sebatas kalian membaca surat \"WAL 'ADIYAT\" dan surat semisalnya.\" Abu Daud berkata; \"Ini menunjukkan bahwa hadits yang diatas terhapus, sedangkan hadits ini lebih shahih.\""},"678":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ السَّرْخَسِيُّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ يُحَدِّثُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُ قَالَمَا مِنْ الْمُفَصَّلِ سُورَةٌ صَغِيرَةٌ وَلَا كَبِيرَةٌ إِلَّا وَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ النَّاسَ بِهَا فِي الصَّلَاةِ الْمَكْتُوبَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id As Sarkhasi] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [ayahku] dia berkata; saya mendengar [Muhammad bin Ishaq] menceritakan dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa dia berkata; \"Tidak ada suatu surat yang pendek ataupun yang panjang melainkan aku telah mendengar Rasulullah shallallahu 'alaihi wasallam membacanya ketika mengimami orang-orang dalam shalat wajib.\""},"679":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا قُرَّةُ عَنْ النَّزَّالِ بْنِ عَمَّارٍ عَنْ أَبِي عُث��مَانَ النَّهْدِيِّ أَنَّهُصَلَّى خَلْفَ ابْنِ مَسْعُودٍ الْمَغْرِبَ فَقَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] dari [Qurrah] dari [An Nazal bin 'Ammar] dari [Abu Utsman An Nahdi] bahwa dia shalat Maghrib di belakang Ibnu Mas'ud, maka [Ibnu Mas'ud] membaca surat Al Ikhlash \"Qul Huwallahu Ahad\". "},"680":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ ابْنِ أَبِي هِلَالٍ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ الْجُهَنِيِّ أَنَّ رَجُلًا مِنْ جُهَيْنَةَ أَخْبَرَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الصُّبْحِ إِذَا زُلْزِلَتْ الْأَرْضُ فِي الرَّكْعَتَيْنِ كِلْتَيْهِمَا فَلَا أَدْرِي أَنَسِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ قَرَأَ ذَلِكَ عَمْدًا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru] dari [Ibnu Abu Hilal] dari [Mu'adz bin Abdullah Al Juhani] bahwa [seseorang laki-laki dari Juhainah] memberitahukan kepadanya bahwa dirinya telah mendengar Nabi shallallahu 'alaihi wasallam membaca dalam shalat subuh \"IDZA ZULZILATIL-ARDHU ZILZALAHA\" di kedua rakaatnya, aku tidak tahu apakah Rasulullah shallallahu 'alaihi wasallam lupa ataukah beliau memang sengaja.\""},"681":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ عَنْ إِسْمَعِيلَ عَنْ أَصْبَغَ مَوْلَى عَمْرِو بْنِ حُرَيْثٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَكَأَنِّي أَسْمَعُ صَوْتَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةِ الْغَدَاةِ فَلَا أُقْسِمُ بِالْخُنَّسِ الْجَوَارِي الْكُنَّسِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Isa yaitu Ibnu Yunus] dari [Isma'il] dari [Asbagh bekas budak 'Amru bin Huraits] dari [Amru bin Huraits] dia berkata; Pada waktu shalat shubuh, seakan-akan aku mendengar suara Nabi shallallahu 'alaihi wasallam membaca; \"FALAA UQSIMU BIL KHUNNAS, AL JAWAARIL KUNNAS.\" (Sebagian bacaan dari surat Attakwir) "},"682":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَأُمِرْنَا أَنْ نَقْرَأَ بِفَاتِحَةِ الْكِتَابِ وَمَا تَيَسَّرَ","id":"Telah menceritakan kepada kami [Abu Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata; \"Kami di perintahkan untuk membaca surat Al Fatihah dan surat yang mudah (kami baca).\""},"683":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى عَنْ جَعْفَرِ بْنِ مَيْمُونٍ الْبَصْرِيِّ حَدَّثَنَا أَبُو عُثْمَانَ النَّهْدِيُّ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْرُجْ فَنَادِ فِي الْمَدِينَةِ أَنَّهُ لَا صَلَاةَ إِلَّا بِقُرْآنٍ وَلَوْ بِفَاتِحَةِ الْكِتَابِ فَمَا زَادَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Isa] dari [Ja'far bin Maimun Al Bashri] telah menceritakan kepada kami [Abu Utsman An Nahdi] dia berkata; telah menceritakan kepadaku [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Keluarlah dan serukan di (penjuru) Madinah bahwa tidak sah shalat seseorang, kecuali dengan bacaan alquran sekalipun Fatihatul Kitab (Al Fatihah) dan selebihnya.\""},"684":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا جَعْفَرٌ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُنَادِيَ أَنَّهُ لَا صَلَاةَ إِلَّا بِقِرَاءَةِ فَاتِحَةِ الْكِتَابِ فَمَا زَادَ","id":"Telah menceritakan kepada kami [Ibnu Basyar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ja'far] dari [Abu Utsman] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanku supaya aku menyerukan bahwa tidak sah shalat seseorang kecuali dengan membaca Al Fatihah dan selebihnya.\""},"685":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَبَا السَّائِبِ مَوْلَى هِشَامِ بْنِ زَهْرَةَ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ فَهِيَ خِدَاجٌ فَهِيَ خِدَاجٌ غَيْرُ تَمَامٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Al 'Ala` bin Abdurrahman] bahwa dia mendengar [Abu As Sa`ib bekas budak Hisyam bin Zahrah] berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat tanpa membaca Ummul Qur'an (Al Fatihah) maka shalatnya kurang, kurang, kurang dan tidak sempurna.\""},"686":{"ar":"قَالَ فَقُلْتُ يَا أَبَا هُرَيْرَةَ إِنِّي أَكُونُ أَحْيَانًا وَرَاءَ الْإِمَامِ قَالَ فَغَمَزَ ذِرَاعِي وَقَالَ اقْرَأْ بِهَا يَا فَارِسِيُّ فِي نَفْسِكَفَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ تَعَالَى قَسَمْتُ الصَّلَاةَ بَيْنِي وَبَيْنَ عَبْدِي نِصْفَيْنِ فَنِصْفُهَا لِي وَنِصْفُهَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا يَقُولُ الْعَبْدُ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ حَمِدَنِي عَبْدِي يَقُولُ{ الرَّحْمَنِ الرَّحِيمِ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَثْنَى عَلَيَّ عَبْدِي يَقُولُ الْعَبْدُ{ مَالِكِ يَوْمِ الدِّينِ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ مَجَّدَنِي عَبْدِي يَقُولُ الْعَبْدُ{ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ }يَقُولُ اللَّهُ هَذِهِ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ يَقُولُ الْعَبْدُ{ اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }يَقُولُ اللَّهُ فَهَؤُلَاءِ لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ","id":"(Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Al 'Ala` bin Abdurrahman] bahwa dia mendengar) \n\n[Abu As Sa'ib] berkata; tanyaku; \"Wahai Abu Hurairah, terkadang aku (shalat) berada di belakang imam.\" Abu As Sa'ib berkata; \"Lalu [Abu Hurairah] memegang hastaku seraya berkata; \"Bacalah dengan suara lirih wahai Farisi, karena aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman; \"Aku membagi shalat antara Aku dan hamba-Ku setengah-setengah, setengahnya untuk-Ku dan setengahnya lagi untuk hamba-Ku dan untuk hamba-Ku apa yang ia mohon.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah oleh kalian, (ketika) hamba itu membaca; \"Al-hamdu lillaahi rabbiil 'aalamin, \" Allah Azza wa Jalla akan menjawab; \"Hamba-Ku telah memuji-Ku.\" (ketika) seorang hamba membaca; \"Arrahmaanir rahiim, \" Allah Azza wa Jalla berfirman; \"Hamba-Ku telah menyanjung-Ku.\" (ketika) seorang hamba membaca; \"Maaliki yaumid diin.\" Allah Azza wa Jalla berfirman; \"Hamba-Ku telah mengagungkan-Ku.\" (ketika) seorang hamba membaca; \"Iyyaaka na'budu wa iyyaka nasta'iin.\" Allah Azza wa Jalla berfirman; \"Inilah bagian-Ku dan bagian hamba-Ku, sedangkan bagi hamba-Ku apa yang di mintanya.\" (ketika) seorang hamba membaca; \"Ihdinash shiraathal mustaqiim, shiraathal ladziina an'amta 'alaihim ghairil maghdluubi 'alaihim waladl dllaallliin.\" Allah Azza wa Jalla berfirman; \"Inilah bagian dari hamba-Ku, dan baginya apa yang di minta.\""},"687":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ السَّرْحِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ فَصَاعِدًاقَالَ سُفْيَانُ لِمَنْ يُصَلِّي وَحْدَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ibnu Sarh] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin As Shamit] yang sampai kepada Nabi shallallahu 'alaihi wasallam (sabdanya): \"Tidak sah shalat bagi siapa yang tidak membaca fatihatul kitab (surat Al Fatihah) dan selebihnya.\" Sufyan berkata; \"Bagi siapa yang shalat sendirian.\""},"688":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَكُنَّا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْفَجْرِ فَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَثَقُلَتْ عَلَيْهِ الْقِرَاءَةُ فَلَمَّا فَرَغَ قَالَ لَعَلَّكُمْ تَقْرَءُونَ خَلْفَ إِمَامِكُمْ قُلْنَا نَعَمْ هَذًّا يَا رَسُولَ اللَّهِ قَالَ لَا تَفْعَلُوا إِلَّا بِفَاتِحَةِ الْكِتَابِ فَإِنَّهُ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Makhul] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin As Shamit] dia berkata; \"Kami shalat shubuh di belakang Rasulullah shallallahu 'alaihi wasallam, sepertinya bacaan beliau terasa berat. Seusai shalat, beliau bersabda: \"Sepengetahuanku, kalian membaca di belakang imam kalian.\" Mereka menjawab; \"Ya, wahai Rasulullah! (hingga) Kami menyusul bacaanmu dengan cepat.\" Beliau bersabda: \"Jangan kalian lakukan kecuali Fatihatul Kitab (Al Fatihah) karena tidak sah shalat seseorang yang tidak membacanya.\""},"689":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ الْأَزْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ أَخْبَرَنِي زَيْدُ بْنُ وَاقِدٍ عَنْ مَكْحُولٍ عَنْ نَافِعِ بْنِ مَحْمُودِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّقَالَ نَافِعٌ أَبْطَأَ عُبَادَةُ بْنُ الصَّامِتِ عَنْ صَلَاةِ الصُّبْحِ فَأَقَامَ أَبُو نُعَيْمٍ الْمُؤَذِّنُ الصَّلَاةَ فَصَلَّى أَبُو نُعَيْمٍ بِالنَّاسِ وَأَقْبَلَ عُبَادَةُ وَأَنَا مَعَهُ حَتَّى صَفَفْنَا خَلْفَ أَبِي نُعَيْمٍ وَأَبُو نُعَيْمٍ يَجْهَرُ بِالْقِرَاءَةِ فَجَعَلَ عُبَادَةُ يَقْرَأُ أُمَّ الْقُرْآنِ فَلَمَّا انْصَرَفَ قُلْتُ لِعُبَادَةَ سَمِعْتُكَ تَقْرَأُ بِأُمِّ الْقُرْآنِ وَأَبُو نُعَيْمٍ يَجْهَرُ قَالَ أَجَلْ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ الصَّلَوَاتِ الَّتِي يَجْهَرُ فِيهَا بِالْقِرَاءَةِ قَالَ فَالْتَبَسَتْ عَلَيْهِ الْقِرَاءَةُ فَلَمَّا انْصَرَفَ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ وَقَالَ هَلْ تَقْرَءُونَ إِذَا جَهَرْتُ بِالْقِرَاءَةِ فَقَالَ بَعْضُنَا إِنَّا نَصْنَعُ ذَلِكَ قَالَ فَلَا وَأَنَا أَقُولُ مَا لِي يُنَازِعُنِي الْقُرْآنُ فَلَا تَقْرَءُوا بِشَيْءٍ مِنْ الْقُرْآنِ إِذَا جَهَرْتُ إِلَّا بِأُمِّ الْقُرْآنِحَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ جَابِرٍ وَسَعِيدِ بْنِ عَبْدِ الْعَزِيزِ وَعَبْدِ اللَّهِ بْنِ الْعَلَاءِ عَنْ مَكْحُولٍ عَنْ عُبَادَةَ نَحْوَ حَدِيثِ الرَّبِيعِ بْنِ سُلَيْمَانَ قَالُوا فَكَانَ مَكْحُولٌ يَقْرَأُ فِي الْمَغْرِبِ وَالْعِشَاءِ وَالصُّبْحِ بِفَاتِحَةِ الْكِتَابِ فِي كُلِّ رَكْعَةٍ سِرًّا قَالَ مَكْحُولٌ اقْرَأْ بِهَا فِيمَا جَهَرَ بِهِ الْإِمَامُ إِذَا قَرَأَ بِفَاتِحَةِ الْكِتَابِ وَسَكَتَ سِرًّا فَإِنْ لَمْ يَسْكُتْ اقْرَأْ بِهَا قَبْلَهُ وَمَعَهُ وَبَعْدَهُ لَا تَتْرُكْهَا عَلَى كُلِّ حَالٍ","id":"Telah menceritakan kepada kami [Ar Rabi'ah' bin Sulaiman Al Azdi] telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Haitsam bin Humaid] telah mengabarkan kepadaku [Zaid bin Waqid] dari [Makhul] dari [Nafi' bin Mahmud bin Ar Rabi'ah' Al Anshari], Nafi' berkata; ['Ubadah bin Shamit] terlambat dari shalat shubuh, maka Abu Nu'aim seorang Mu'adzin mengumandangkan adzan untuk shalat, lalu Abu Nu'aim mengimami shalat orang banyak, tidak lama kemudian Ubadah datang bersamaku hingga kami mengambil shaf di belakang Abu Nu'aim, sedangkan Abu Nu'aim mengeraskan bacaannya, sementara 'Ubadah membaca Al Fatihah. Ketika shalat selesai, aku bertanya kepada Ubadah; \"Aku mendengar kamu membaca Al Fatihah ketika Abu Nu'aim mengeraskan bacaannya.\" Dia menjawab; \"Ya, kami juga pernah melakukan ketika shalat bersama Rasulullah shallallahu 'alaihi wasallam di sebagian shalat yang bacaannya di keraskan.\" Katanya melanjutkan; \"Hingga bacaannya bercampur, selepas shalat, beliau menghadap kami sambil bersabda: \"Apakah kalian juga ikut membaca ketika aku mengeraskan bacaanku?\" sebagian kami menjawab; \"Kami melakukan hal itu.\" Beliau bersabda: \"Oleh karenanya aku berkata (dalam hati), kenapa ada yang membaca bersamaku dan mendahuluiku dalam membaca Al Qur'an?, janganlah kalian membaca sesuatu pun ketika aku mengeraskan bacaan, kecuali bacaan Al Fatihah.\" Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli] telah menceritakan kepada kami [Al Walid] dari [Ibnu Jabir] dan [Sa'id bin Abdul Aziz] dan [Abdullah bin Al 'Ala`] dari [Makhul] dari ['Ubadah] seperti haditsnya Ar Rabi'ah' bin Sulaiman, mereka berkata; \"Mak-hul biasa membaca Al Fatihah dengan suara lirih pada waktu shalat Maghrib, Isya' dan Shubuh, di setiap raka'atnya. Kata Mak-hul; \"Bacalah Al Fatihah dengan suara lirih (pelan) ketika imam mengeraskan bacaannya ketika berhenti dari membaca Al Fatihah, apabila imam tidak berhenti (diam), maka bacalah sebelum imam membaca atau membaca bersamanya atau setelah imam membacanya, yang penting, janganlah kamu meninggalkannya (tidak membaca Al Fatihah).\""},"690":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ أُكَيْمَةَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ صَلَاةٍ جَهَرَ فِيهَا بِالْقِرَاءَةِ فَقَالَ هَلْ قَرَأَ مَعِيَ أَحَدٌ مِنْكُمْ آنِفًا فَقَالَ رَجُلٌ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ إِنِّي أَقُولُ مَالِي أُنَازَعُ الْقُرْآنَقَالَ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا جَهَرَ فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقِرَاءَةِ مِنْ الصَّلَوَاتِ حِينَ سَمِعُوا ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد رَوَى حَدِيثَ ابْنِ أُكَيْمَةَ هَذَا مَعْمَرٌ وَيُونُسُ وَأُسَامَةُ بْنُ زَيْدٍ عَنْ الزُّهْرِيِّ عَلَى مَعْنَى مَالِكٍ حَدَّثَنَا مُسَدَّدٌ وَأَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ وَمُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ وَعَبْدِ اللَّهِ بْنِ مُحَمَّدٍ الزُّهْرِيِّ وَابْنِ السَّرْحِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ سَمِعْتُ ابْنَ أُكَيْمَةَ يُحَدِّثُ سَعِيدَ بْنَ الْمُسَيِّبِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً نَظُنُّ أَنَّهَا الصُّبْحُ بِمَعْنَاهُ إِلَى قَوْلِهِ مَا لِي أُنَازَعُ الْقُرْآنَ قَالَ مُسَدَّدٌ فِي حَدِيثِهِ قَالَ مَعْمَرٌ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ فِيمَا جَهَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ ابْنُ السَّرْحِ فِي حَدِيثِهِ قَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَبُو هُرَيْرَةَ فَانْتَهَى النَّاسُ و قَالَ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ مِنْ بَيْنِهِمْ قَالَ سُفْيَانُ وَتَكَلَّمَ الزُّهْرِيُّ بِكَلِمَةٍ لَمْ أَسْمَعْهَا فَقَالَ مَعْمَرٌ إِنَّهُ قَالَ فَانْتَهَى النَّاسُ قَالَ أَبُو دَاوُد وَرَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ وَانْتَهَى حَدِيثُهُ إِلَى قَوْلِهِ مَا لِي أُنَازَعُ الْقُرْآنَ وَرَوَاهُ الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ قَالَ فِيهِ قَالَ الزُّهْرِيُّ فَاتَّعَظَ الْمُسْلِمُونَ بِذَلِكَ فَلَمْ يَكُونُوا يَقْرَءُونَ مَعَهُ فِيمَا جَهَرَ بِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد سَمِعْت مُحَمَّدَ بْنَ يَحْيَى بْنِ فَارِسٍ قَالَ قَوْلُهُ فَانْتَهَى النَّاسُ مِنْ كَلَامِ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Ibnu Ukaimah Al Laitsi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam selesai dari shalat yang di baca Jahr (jelas), lalu beliau bersabda; \"Apakah ada seseorang yang membaca (ayat) bersamaku tadi?\" seorang laki-laki berkata; \"Ya, wahai Rasulullah.\" Beliau bersabda: \"Sungguh, aku berkata (dalam hati) kenapa ia membaca bersamaku dan mendahuluiku dalam membaca Al Qur'an?\" Az Zuhri berkata; \"Seketika itu orang-ornag yang membaca bersama Nabi shallallahu 'alaihi wasallam dalam shalat-shalat yang di baca nyaring pun berhenti, setelah mendengar hal itu dari Rasulullah shallallahu 'alaihi wasallam.\" Abu Daud berkata; \"Hadits Ibnu Ukaimah ini juga telah di riwayatkan pula oleh [Ma'mar] dan [Yunus] serta [Usamah bin Zaid] dari [Az Zuhri] dengan makna haditsnya Malik. Telah menceritakan kepada kami [Musaddad], [Ahmad bin Muhammad Al Marwazi], [Muhammad bin Ahmad bin Abu Khalaf], [Abdullah bin Muhammad Az Zuhri] dan [Ibnu Sarh], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] saya mendengar [Ibnu Ukaimah] menceritakan kepada Sa'id bin Musayyib katanya; saya mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami -kami mengira shalat tersebut adalah shalat shubuh- semakna dengan hadits di atas, sampai pada sabdanya; kenapa ia membaca bersamaku dan mendahuluiku dalam membaca Al Qur'an?\" Musaddad berkata dalam haditsnya; Ma'mar mengatakan; \"Seketika itu orang-orang berhenti dari membaca dalam shalat yang bacaannya di baca jahr (jelas, nyaring) oleh Rasulullah shallallahu 'alaihi wasallam.\" Ibnu As Sarh mengatakan dalam haditsnya; Ma'mar berkata dari Az Zuhri, Abu Hurairah berkata; \"Orang-orang pun berhenti…\" sedangkan Abdullah bin Muhammad Az Zuhri di antara mereka juga Sufyan berkata; lalu Az Zuhri mengatakan suatu perkataan yang tidak aku dengar.\" Ma'mar mengatakan; Bahwa az Zuhri mengatakan; \"Orang-orang berhenti.\" Abu Daud mengatakan; \"Hadits ini juga di riwayatkan [Abdurrahman bin Ishaq] dari [Az Zuhri] dan haditsnya berhenti sampai sabdanya; kenapa ia membaca bersamaku dan mendahuluiku dalam membaca Al Qur'an?\" Dan di riwayatkan pula oleh [Al Auza'i] dari [Az Zuhri] dia mengatakan dalam masalah itu; \"Maka kaum Muslimin pun mengambil pelajaran dari hal itu, sehingga mereka tidak lagi membaca bersama beliau shallallahu 'alaihi wasallam dalam shalat yang bacaannya di baca jahr.\" Abu Daud mengatakan; \"saya mendengar Muhammad bin Yahya bin Faris berkata; \"Mengenai perkataannya \"orang-orang pun berhenti\" merupakan perkataan Az Zuhri.\""},"691":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْعَبْدِيُّ أَخْبَرَنَا شُعْبَةُ الْمَعْنَى عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ فَجَاءَ رَجُلٌ فَقَرَأَ خَلْفَهُ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فَلَمَّا فَرَغَ قَالَ أَيُّكُمْ قَرَأَ قَالُوا رَجُلٌ قَالَ قَدْ عَرَفْتُ أَنَّ بَعْضَكُمْ خَالَجَنِيهَاقَالَ أَبُو دَاوُد قَالَ الْوَلِيدُ فِي حَدِيثِهِ قَالَ شُعْبَةُ فَقُلْتُ لِقَتَادَةَ أَلَيْسَ قَوْلُ سَعِيدٍ أَنْصِتْ لِلْقُرْآنِ قَالَ ذَاكَ إِذَا جَهَرَ بِهِ قَالَ ابْنُ كَثِيرٍ فِي حَدِيثِهِ قَالَ قُلْتُ لِقَتَادَةَ كَأَنَّهُ كَرِهَهُ قَالَ لَوْ كَرِهَهُ نَهَى عَنْهُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Katsir Al 'Abdi] telah mengabarkan kepada kami [Syu'bah] sedangkan ma'na haditsnya dari [Qatadah] dari [Zurarah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam menunaikan shalat Dluhur, tiba-tiba seorang laki-laki datang sambil membaca \"Sabbihisma rabbikal a'la.\" di belakang beliau, ketika selesai shalat, beliau bersabda: \"Siapakah tadi yang membaca (surat)?\" para sahabat menjawab; \"Laki-laki ini.\" beliau bersabda: \"Sungguh aku telah mengetahui, bahwa sebagian dari kalian telah mengalahkan bacaanku.\" Abu Daud berkata; Al Walid berkata dalam haditsnya, Syu'bah berkata; kataku kepada Qatadah; 'tidakkah perkataannya Sa'id; \"Diamlah (untuk mendengarkan) bacaan Al Qur'an (imam).\" Qatadah berkata; \"Hal itu jika (imam) mengeraskan bacaannya.\" Ibnu Katsir berkata dalam haditsnya; dia berkata; kataku kepada Qatadah; \"Sepertinya beliau hanya membenci.\" Qatadah menimpali; \"Jika beliau membencinya, berarti beliau melarang yang demikian.\""},"692":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ الظُّهْرَ فَلَمَّا انْفَتَلَ قَالَ أَيُّكُمْ قَرَأَ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فَقَالَ رَجُلٌ أَنَا فَقَالَ عَلِمْتُ أَنَّ بَعْضَكُمْ خَالَجَنِيهَا","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sa'id] dari [Qatadah] dari [Zurarah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam shalat Dluhur bersama mereka, setelah selesai shalat beliau bersabda: \"Siapakah di antara kalian yang membca \"sabbihisma rabbikal a'la?\" maka laki-laki itu menjawab; \"saya.\" Beliau bersabda: \"Aku tahu, bahwa sebagian dari kalian telah mengalahkan bacaanku.\""},"693":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَقْرَأُ الْقُرْآنَ وَفِينَا الْأَعْرَابِيُّ وَالْأَعْجَمِيُّ فَقَالَ اقْرَءُوا فَكُلٌّ حَسَنٌ وَسَيَجِيءُ أَقْوَامٌ يُقِيمُونَهُ كَمَا يُقَامُ الْقِدْحُ يَتَعَجَّلُونَهُ وَلَا يَتَأَجَّلُونَهُ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyah] telah mengabarkan kepada kami [Khalid] dari [Humaid Al A'raj] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam menemui kami, ketika itu kami sedang membaca Al Qur'an, sedangkan di antara kami ada seorang arab Badui dan orang Asing, maka beliau bersabda: \"Bacalah oleh kalian dengan bacaan yang baik, akan datang suatu kaum yang membaca dengan melurus-luruskannya (benar) sebagaimana anak panah di luruskan, namun mereka hanyalah mengharap-harap balasan yang disegerakan (materi-duniawi) dan mereka tidak mengharap pahala yang ditangguhkan (di akhirat).\""},"694":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو وَابْنُ لَهِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ وَفَاءِ بْنِ شُرَيْحٍ الصَّدَفِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا وَنَحْنُ نَقْتَرِئُ فَقَالَ الْحَمْدُ لِلَّهِ كِتَابُ اللَّهِ وَاحِدٌ وَفِيكُمْ الْأَحْمَرُ وَفِيكُمْ الْأَبْيَضُ وَفِيكُمْ الْأَسْوَدُ اقْرَءُوهُ قَبْلَ أَنْ يَقْرَأَهُ أَقْوَامٌ يُقِيمُونَهُ كَمَا يُقَوَّمُ السَّهْمُ يُتَعَجَّلُ أَجْرُهُ وَلَا يُتَأَجَّلُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru] dan [Ibnu Lahi'ah] dari [Bakr bin Sawadah] dari [Wafa' bin Syuraikh Ash Shadafi] dari [Sahl bin Sa'ad As Sa'idi] dia berkata; Rasulullah shallallahu 'alaihi wasallam menemui kami, sementara kami sedang membaca Al Qur'an, maka beliau bersabda: \"Segala puji bagi Allah kitab Allah hanya satu, padahal di antara kalian ada bangsa yang berkulit merah, putih dan hitam, bacalah Al Qur'an tersebut, sebelum di baca oleh suatu kaum, mereka membacanya dengan lurus sebagaimana meluruskan anak panah, mereka mengharap pahalanya yang disegerakan di dunia, dan tidak mengharap pahala yang ditangguhkan di akhirat.\""},"695":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي خَالِدٍ الدَّالَانِيِّ عَنْ إِبْرَاهِيمَ السَّكْسَكِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَا أَسْتَطِيعُ أَنْ آخُذَ مِنْ الْقُرْآنِ شَيْئًا فَعَلِّمْنِي مَا يُجْزِئُنِي مِنْهُ قَالَ قُلْ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ الْعَلِيِّ الْعَظِيمِ قَالَ يَا رَسُولَ اللَّهِ هَذَا لِلَّهِ عَزَّ وَجَلَّ فَمَا لِي قَالَ قُلْ اللَّهُمَّ ارْحَمْنِي وَارْزُقْنِي وَعَافِنِي وَاهْدِنِي فَلَمَّا قَامَ قَالَ هَكَذَا بِيَدِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَقَدْ مَلَأَ يَدَهُ مِنْ الْخَيْرِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Al Jarrah] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Abu Khalid Ad Dalani] dari [Ibrahim As Saksaki] dari [Abdullah bin Abu Aufa] dia berkata; seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; \"Sesungguhnya aku tidak dapat mempelajari Al Qur'an sedikit pun, maka ajarilah aku sesuatu yang dapat memadai untukku sebagai gantinya.\" Beliau bersabda: \"Ucapkanlah; \"SUBHANALLAH WAL HAMDULILLAH WALAA ILAAHA ILLALLAH WALLAAHU AKBAR WALAA HAULAA WALAA QUWWATA ILLA BILLAHIL 'ALIYYIL 'AZHIIM (Maha suci Allah, segala puji bagi Allah, tidak ada ilah yang hak kecuali Allah dan Allah Maha besar, tidak ada daya dan upaya kecuali kecuali dengan pertolongan Allah yang Maha Luhur lagi Maha Agung).\" Laki-laki itu berkata; \"wahai Rasulullah, ungkapan ini untuk Allah Azza Wa Jalla, lantas (ungkapan) manakah yang untuk saya?\" beliau bersabda: \"katakanlah; \"ALLAHUMMARHAMNII WARZUQNII WA'AAFINII WAHDINII (Ya Allah, rahmatilah aku, berilah aku rizki, kesejahteraan, dan petunjuk.\" Ketika orang itu berdiri (shalat), maka dia memberi isyarat dengan tangannya seperti ini (yaitu membaca sambil menghitungnya) maka Rasulullah shallallahu 'alaihi wasallam bersabda: \" Orang ini tangannya telah di penuhi dengan kebaikan.\""},"696":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ أَخْبَرَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نُصَلِّي التَّطَوُّعَ نَدْعُو قِيَامًا وَقُعُودًا وَنُسَبِّحُ رُكُوعًا وَسُجُودًاحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ مِثْلَهُ لَمْ يَذْكُرْ التَّطَوُّعَ قَالَ كَانَ الْحَسَنُ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ إِمَامًا أَوْ خَلْفَ إِمَامٍ بِفَاتِحَةِ الْكِتَابِ وَيُسَبِّحُ وَيُكَبِّرُ وَيُهَلِّلُ قَدْرَ ق وَالذَّارِيَاتِ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah mengabarkan kepada kami [Abu Ishaq yaitu Al Fazari] dari [Humaid] dari [Al Hasan] dari [Jabir bin Abdullah] dia berkata: \"Kami shalat sunnah dengan membaca do'a baik ketika berdiri ataupun duduk, dan kami mengucapkan tasbih pada waktu ruku' dan sujud.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Humaid] seperti hadits tersebut dengan tidak menyebutkan shalat sunnah. Humiad berkata; \"Al Hasan membaca Al Fatihah dalam shalat Zhuhur dan Ashar baik ketika menjadi Imam atau di belakang imam dan bertasbih, bertakbir, serta bertahlil sepanjang membaca surat Qaaf dan Adz Dzariyat.\""},"697":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ مُطَرِّفٍ قَالَصَلَّيْتُ أَنَا وَعِمْرَانُ بْنُ حُصَيْنٍ خَلْفَ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ فَكَانَ إِذَا سَجَدَ كَبَّرَ وَإِذَا رَكَعَ كَبَّرَ وَإِذَا نَهَضَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ فَلَمَّا انْصَرَفْنَا أَخَذَ عِمْرَانُ بِيَدِي وَقَالَ لَقَدْ صَلَّى هَذَا قَبْلُ أَوْ قَالَ لَقَدْ صَلَّى بِنَا هَذَا قَبْلَ صَلَاةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ghailan bin Jarir] dari [Mutharif] dia berkata; \"Aku dan Imran bin Hushain shalat di belakang Ali bin Abu Thalib radliallahu 'anhu, dia bertakbir ketika sujud, ruku' dan bangkit dari raka'at kedua. Ketika kami selesai melaksanakan shalat, [Imran bin Hushain] memegang tanganku dan berkata; \"Sungguh sebelum ini, dia juga melaksanakan shalat seperti ini, -atau dia berkata- sungguh dia telah melaksanakan shalat bersama kami seperti ini sebelumnya, maksudnya seperti shalatnya Muhammad shallallahu 'alaihi wasallam.\""},"698":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا أُبَيٌّ وَبَقِيَّةُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَكَانَ يُكَبِّرُ فِي كُلِّ صَلَاةٍ مِنْ الْمَكْتُوبَةِ وَغَيْرِهَا يُكَبِّرُ حِينَ يَقُومُ ثُمَّ يُكَبِّرُ حِينَ يَرْكَعُ ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ يَقُولُ رَبَّنَا وَلَكَ الْحَمْدُ قَبْلَ أَنْ يَسْجُدَ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ حِينَ يَهْوِي سَاجِدًا ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ ثُمَّ يُكَبِّرُ حِينَ يَسْجُدُ ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ ثُمَّ يُكَبِّرُ حِينَ يَقُومُ مِنْ الْجُلُوسِ فِي اثْنَتَيْنِ فَيَفْعَلُ ذَلِكَ فِي كُلِّ رَكْعَةٍ حَتَّى يَفْرُغَ مِنْ الصَّلَاةِ ثُمَّ يَقُولُ حِينَ يَنْصَرِفُ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَقْرَبُكُمْ شَبَهًا بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَتْ هَذِهِ لَصَلَاتُهُ حَتَّى فَارَقَ الدُّنْيَاقَالَ أَبُو دَاوُد هَذَا الْكَلَامُ الْأَخِيرُ يَجْعَلُهُ مَالِكٌ وَالزُّبَيْدِيُّ وَغَيْرِهِمَا عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ وَوَافَقَ عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ شُعَيْبَ بْنَ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [Ubay] dan [Baqiyah] dari [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Bakar bin Abdurrahman] dan [Abu Salamah] bahwa [Abu Hurairah] selalu bertakbir di setiap shalat wajib maupun shalat sunnah, dia bertakbir ketika berdiri, bertakbir ketika ruku' kemudian mengucapkan; \"SAMI'ALLAAHU LIMAN HAMIDAH\" Lalu mengucapkan; \"RABBANA WALAKAL HAMDU (wahai Rabb kami, bagi-Mu lah segala pujian) \" yaitu sebelum sujud, setelah itu dia mengucapkan; \"Allahu akbar\" ketika tersungkur sujud, bertakbir ketika bangun dari sujud, bertakbir ketika sujud (kedua), bertakbir ketika bangun dari sujud, bertakbir ketika bangun dari duduknya pada raka'at kedua, yang demikian itu di lakukannya pada setiap raka'at hingga selesai shalat. seusai shalat dia mengucapkan; \"Demi dzat yang jiwaku berada di tangan-Nya, sesungguhnya shalatku lah yang paling menyerupai shalat Rasulullah shallallahu 'alaihi wasallam, Sesungguhnya shalat yang seperti ini merupakan shalat Rasulullah shallallahu 'alaihi wasallam sehingga beliau meninggal dunia.\" Abu Daud berkata; \"Ini adalah perkataan terakhir yang di jadikan oleh [Malik] dan [Zubaidi] serta yang lain sebagai (perkataannya) Az Zuhri dari [Ali bin Husain] yang di sepakati oleh [Abdul A'la] dari [Ma'mar Syu'aib bin Abu Hamzah] dari [Az Zuhri]. "},"699":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَابْنُ الْمُثَنَّى قَالَا حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَسَنِ بْنِ عِمْرَانَ قَالَ ابْنُ بَشَّارٍ الشَّامِيِّ و قَالَ أَبُو دَاوُدَ أَبُو عَبْدِ اللَّهِ الْعَسْقَلَانِيُّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ لَا يُتِمُّ التَّكْبِيرَقَالَ أَبُو دَاوُد مَعْنَاهُ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَأَرَادَ أَنْ يَسْجُدَ لَمْ يُكَبِّرْ وَإِذَا قَامَ مِنْ السُّجُودِ لَمْ يُكَبِّرْ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Ibnu Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Al Hasan bin 'Imran] dia berkata; Ibnu Basyar As Syami berkata; Abu Daud Abu Abdullah Al 'Asqalani berkata dari [Ibnu Abdurrahman bin Abza] dari [ayahnya] bahwa dia shalat bersama Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak menyempurnakan takbir. ' Abu Daud mengatakan; maknanya; 'Apabila mengangkat kepalanya dari ruku' (I'tidal) dan hendak sujud, maka beliau tidak bertakbir, begitu juga ketika bangkit dari sujud, beliau tidak bertakbir.\""},"700":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَحُسَيْنُ بْنُ عِيسَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَضَعَ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِحَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ حَدِيثَ الصَّلَاةِ قَالَ فَلَمَّا سَجَدَ وَقَعَتَا رُكْبَتَاهُ إِلَى الْأَرْضِ قَبْلَ أَنْ تَقَعَ كَفَّاهُ قَالَ هَمَّامٌ وَحَدَّثَنِي شَقِيقٌ قَالَ حَدَّثَنِي عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا وَفِي حَدِيثِ أَحَدِهِمَا وَأَكْبَرُ عِلْمِي أَنَّهُ فِي حَدِيثِ مُحَمَّدِ بْنِ جُحَادَةَ وَإِذَا نَهَضَ نَهَضَ عَلَى رُكْبَتَيْهِ وَاعْتَمَدَ عَلَى فَخِذِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Husain bin Isa] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Wa'il bin Hujr] dia berkata; saya melihat apabila Nabi shallallahu 'alaihi wasallam sujud, beliau meletakkan kedua lututnya sebelum kedua tangannya, dan apabila bangkit, beliau mengangkat kedua tangannya sebelum kedua lututnya.\" Telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Abdul Jabbar bin Wa`il] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam…\" kemudian dia melanjutkan hadits tentang shalat. katanya; \"Ketika beliau sujud, beliau meletakkan kedua lututnya ke lantai sebelum meletakkan kedua telapak tangannya. ' Hammam mengatakan; telah menceritakan kepadaku [Syaqiq] dia berkata; telah menceritakan kepadaku ['Ashim bin Kulaib] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini. sedangkan dalam hadits salah satu dari keduanya (Muhammad bin Juhadah dan Syaqiq) yang lebih tahu daripadaku adalah hadits yang (di riwayatkan) oleh Muhammad bin Juhadah; \"Apabila beliau bangkit, maka beliau bangkit dengan menumpu kedua lututnya dengan bersandarkan pada kedua pahanya.\""},"701":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَسَنٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ أَحَدُكُمْ فَلَا يَبْرُكْ كَمَا يَبْرُكُ الْبَعِيرُ وَلْيَضَعْ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah menceritakan kepadaku [Muhammad bin Abdullah bin Hasan] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian sujud, maka janganlah menderum sebagaimana unta menderum, akan tetapi hendaknya ia meletakkan kedua tangannya sebelum kedua lututnya.\""},"702":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ حَسَنٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمِدُ أَحَدُكُمْ فِي صَلَاتِهِ فَيَبْرُكُ كَمَا يَبْرُكُ الْجَمَلُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdullah bin Nafi'] dari [Muhammad bin Abdullah bin Hasan] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Apakah) salah seorang dari kalian sengaja dalam shalatnya menderum sebagaimana unta menderum (ketika hendak sujud -pent)?\""},"703":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَجَاءَنَا أَبُو سُلَيْمَانَ مَالِكُ بْنُ الْحُوَيْرِثِ إِلَى مَسْجِدِنَا فَقَالَ وَاللَّهِ إِنِّي لَأُصَلِّي بِكُمْ وَمَا أُرِيدُ الصَّلَاةَ وَلَكِنِّي أُرِيدُ أَنْ أُرِيَكُمْ كَيْفَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ قُلْتُ لِأَبِي قِلَابَةَ كَيْفَ صَلَّى قَالَ مِثْلَ صَلَاةِ شَيْخِنَا هَذَا يَعْنِي عَمْرَو بْنَ سَلَمَةَ إِمَامَهُمْ وَذَكَرَ أَنَّهُ كَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الْآخِرَةِ فِي الرَّكْعَةِ الْأُولَى قَعَدَ ثُمَّ قَامَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il yaitu Ibnu Ibrahim] dari [Ayyub] dari [Abu Qilabah] dia berkata; [Abu Sulaiman Malik bin Al Huraits] datang menemui kami di masjid, dia berkata; \"Demi Allah, sungguh aku akan mengerjakan shalat bersama kalian, sebenarnya aku tidak bermaksud untuk shalat (bersama kalian), namun aku hendak memperlihatkan kepada kalian bagaimana Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat.\" Abu Ayyub berkata; \"Kataku kepada Abu Qilabah; 'Bagaimana dia (Malik) mengerjakan shalat?\" jawabnya; \"Seperti cara shalatnya syaikh kita yaitu 'Amru bin Salamah, imam mereka. Abu Qilabah menyebutkan; apabila Malik bin Huwairits bangkit dari sujud terakhir pada raka'at pertama, dia duduk sesaat kemudian berdiri.\""},"704":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَجَاءَنَا أَبُو سُلَيْمَانَ مَالِكُ بْنُ الْحُوَيْرِثِ إِلَى مَسْجِدِنَا فَقَالَ وَاللَّهِ إِنِّي لَأُصَلِّي وَمَا أُرِيدُ الصَّلَاةَ وَلَكِنِّي أُرِيدُ أَنْ أُرِيَكُمْ كَيْفَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ فَقَعَدَ فِي الرَّكْعَةِ الْأُولَى حِينَ رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الْآخِرَةِ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Qilabah] dia berkata; [Abu Sulaiman Malik bin Al Huwairits] datang ke masjid kami seraya berkata; \"Sesungguhnya aku akan shalat, dan sebenarnya aku tidak bermaksud untuk shalat (bersama kalian), akan tetapi aku hendak memperlihatkan kepada kalian bagaimana Rasulullah shallallahu 'alaihi wasallam shalat.\" Abu Qilabah berkata; \"Maka (Malik) duduk sejenak di raka'at pertama setelah mengangkat kepala dari sujud kedua.\""},"705":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ فِي وِتْرٍ مِنْ صَلَاتِهِ لَمْ يَنْهَضْ حَتَّى يَسْتَوِيَ قَاعِدًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Husyaim] dari [Khalid] dari [Abu Qilabah] dari [Malik bin Al Huwairits] bahwa dia melihat Nabi shallallahu 'alaihi wasallam ketika mengerjakan shalat witir, beliau tidak bangkit hingga beliau benar-benar dalam keadaan duduk sejenak.\""},"706":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ طَاوُسًا يَقُولُقُلْنَا لِابْنِ عَبَّاسٍ فِي الْإِقْعَاءِ عَلَى الْقَدَمَيْنِ فِي السُّجُودِ فَقَالَ هِيَ السُّنَّةُ قَالَ قُلْنَا إِنَّا لَنَرَاهُ جُفَاءً بِالرَّجُلِ فَقَالَ ابْنُ عَبَّاسٍ هِيَ سُنَّةُ نَبِيِّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Thawus] berkata; kami bertanya kepada [Ibnu Abbas] mengenai duduk iq`a' (duduk bersimpuh) di atas kedua tumit di antara sujud.\" Ibnu Abbas menjawab; \"itu termasuk sunnah.\" Kata Thawus; \"kami berkata; \"Sesungguhnya kami melihatnya kurang sopan.\" Ibnu Abbas menjawab; \"Itu adalah sunnah Nabimu shallallahu 'alaihi wasallam.\""},"707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ وَمُحَمَّدُ بْنُ عُبَيْدٍ كُلُّهُمْ عَنْ الْأَعْمَشِ عَنْ عُبَيْدِ بْنِ الْحَسَنِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءُ السَّمَوَاتِ وَمِلْءُ الْأَرْضِ وَمِلْءُ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُقَالَ أَبُو دَاوُد قَالَ سُفْيَانُ الثَّوْرِيُّ وَشُعْبَةُ بْنُ الْحَجَّاجِ عَنْ عُبَيْدٍ أَبِي الْحَسَنِ هَذَا الْحَدِيثُ لَيْسَ فِيهِ بَعْدَ الرُّكُوعِ قَالَ سُفْيَانُ لَقِينَا الشَّيْخَ عُبَيْدًا أَبَا الْحَسَنِ بَعْدُ فَلَمْ يَقُلْ فِيهِ بَعْدَ الرُّكُوعِ قَالَ أَبُو دَاوُد وَرَوَاهُ شُعْبَةُ عَنْ أَبِي عِصْمَةَ عَنْ الْأَعْمَشِ عَنْ عُبَيْدٍ قَالَ بَعْدَ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah], [Waki'], dan [Muhammad bin 'Ubaid] semuanya dari [Al A'masy] dari ['Ubaid bin Al Hasan] dia berkata; saya mendengar [Abdullah bin Abu Aufa] berkata; Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari ruku' (i'tidal) beliau mengucapkan: \"SAMI'ALLAHU LIMAN HAMIDAH, RABBANAA LAKAL HAMDU MIL`US SAMAAWATI WAMIL`UL ARDLI WAMIL`U MAASYI`TA MIN SYAI`IN BA'DU (Maha mendengar Allah kepada siapa saja yang memuji-Nya, Ya Allah Rabb kami, hanya untuk Engkau lah segala pujian sepenuh langit dan bumi dan sepenuh apa saja yang Engkau kehendaki).\" Abu Daud mengatakan; setelah itu [Sufyan Ats Tsauri] dan [Syu'bah bin Al Hajjaj] mengatakan dari ['Ubaid Abu Al Hasan], tanpa menyebutkan; \"Setelah ruku'\" Abu Daud mengatakan; sedangkan (hadits) yang telah di riwayatkan [Syu'bah] dari [Abu 'Ishmah] dari [Al A'masy] dari ['Ubaid] dia berkata; \"Setelah ruku'.\""},"708":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا الْوَلِيدُ ح و حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو مُسْهِرٍ ح و حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ كُلُّهُمْ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَطِيَّةَ بْنِ قَيْسٍ عَنْ قَزَعَةَ بْنِ يَحْيَى عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ حِينَ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَاءِ قَالَ مُؤَمَّلٌ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْء�� بَعْدُ أَهْلَ الثَّنَاءِ وَالْمَجْدِ أَحَقُّ مَا قَالَ الْعَبْدُ وَكُلُّنَا لَكَ عَبْدٌ لَا مَانِعَ لِمَا أَعْطَيْتَ زَادَ مَحْمُودٌ وَلَا مُعْطِيَ لِمَا مَنَعْتَ ثُمَّ اتَّفَقُوا وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ وَقَالَ بِشْرٌ رَبَّنَا لَكَ الْحَمْدُ لَمْ يَقُلْ اللَّهُمَّ لَمْ يَقُلْ مَحْمُودٌ اللَّهُمَّ قَالَ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Mu`ammal bin Al Fadl Al Harrani] telah menceritakan kepada kami [Al Walid]. dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Abu Mushir]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Ibnu As Sarh] telah menceritakan kepada kami [Bisyr bin Bakr]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Mahmud bin Mush'ab] telah menceritakan kepada kami [Abdullah bin Yusuf] semuanya dari [Sa'id bin Abdul Aziz] dari ['Athiyah bin Qais] dari [Qaza'ah bin Yahya] dari [Abu Sa'id Al Khudri] bahwa ketika Rasulullah shallallahu 'alaihi wasallam mengucapkan; \"Sami'allaahu liman hamidah\" maka beliau melanjutkan dengan \"RABBANAA LAKAL HAMDU MIL`US SAMAA`I -Mu`ammil mengatakan; MIL`US SAMAAWATI- WAMIL`UL ARDLI WAMIL`U MAASYI`TA MIN SYAI`IN BA'DU AHLUTS TSANAA`I WAL MAJDI AHAQQU MAA QAALAL 'ABDU WA KULLANAA MAA QAALAL 'ABDU WA KULLANAA LAKAL 'ABDU LAA MAANI'A LIMAA A'THAITA (Ya Allah Rabb kami, hanya untuk Engkau lah segala pujian sepenuh langit dan bumi dan sepenuh apa saja yang Engkau kehendaki, wahai Allah yang berhak menerima sanjungan dan kehormatan, Ucapan yang paling pantas di ucapkan oleh seorang hamba, dan kami semua adalah hamba-Mu, tak seorang pun yang dapat melarang apa yang telah Engkau berikan).\" -Mahmud menambahkan- WALAA MU'THIYA LIMAA MANA'TA (begitu pula tak seorang pun yang dapat memberikan apa yang Engkau cegah).\" -kemudian riwayat mereka bersambung lagi- WALAA YANFA'U DZAL JADDI MINKAL JADDU (dan sekali-kali tidak bermanfa'at bagi orang yang mempunyai kebesaran, dari Engkau lah kebesaran itu).\" Bisyr mengatakan; \"RABBANAA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu lah segala pujian) \" tidak menyebutkan; \"ALLAHUMMA.\" Begitu juga dalam riwayatnya Mahmud, dia tidak mengatakan; \"ALLAHUMMA\" namun hanya mengatakan; \"RABBANAA WA LAKAL HAMDU.\""},"709":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Sumayyi] dari [Abu Shalih As Samman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila imam mengucapkan \"Sami'allahu liman hamidah\" maka ucapkanlah oleh kalian; \"ALLAHUMMA RABBANA LAKAL HAMDU\" (Ya Allah Rabb kami, hanya untuk Engkau lah segala pujian), barangsiapa ucapannya bersamaan dengan ucapan Mala'ikat, maka dosa-dosanya yang telah lalu akan terampuni.\""},"710":{"ar":"حَدَّثَنَا بِشْرُ بْنُ عَمَّارٍ حَدَّثَنَا أَسْبَاطٌ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ قَالَلَا يَقُولُ الْقَوْمُ خَلْفَ الْإِمَامِ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَلَكِنْ يَقُولُونَ رَبَّنَا لَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Bisyr bin 'Ammar] telah menceritakan kepada kami [Asbath] dari [Mutharrif] dari ['Amir] dia berkata; \"Makmum tidak mengucapkan \"Sami'allahu liman hamidah\" dibelakang imam, akan tetapi hendaknya ia mengucapkan \"Rabbana lakal hamdu (Wahai Rabb kami, hanya untuk Engkau lah segala pujian).\""},"711":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَسْعُودٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا كَامِلٌ أَبُو الْعَلَاءِ حَدَّثَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَعَافِنِي وَاهْدِنِي وَارْزُقْنِي","id":"Telah menceritakan kepada kami [Muhammad bin Mas'ud] telah menceritakan kepada kami [Zaid bin Al Khubbab] telah menceritakan kepada kami [Kamil Abu Al 'Ala`] telah menceritakan kepadaku [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam mengucapkan diantara dua sujudnya \"ALLAHUMMA GHFIR LI WARHAMNI WA'AFINI WAHDINI WARZUQNI\" (ya Allah anugerahkanlah untukku ampunan, rahmat, kesejahteraan, petunjuk dan rizki).\""},"712":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ أَخِي الزُّهْرِيِّ عَنْ مَوْلًى لِأَسْمَاءَ ابْنَةِ أَبِي بَكْرٍ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ مِنْكُنَّ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا تَرْفَعْ رَأْسَهَا حَتَّى يَرْفَعَ الرِّجَالُ رُءُوسَهُمْ كَرَاهَةَ أَنْ يَرَيْنَ مِنْ عَوْرَاتِ الرِّجَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutawakkil Al 'Asqalani] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Abdullah bin Muslim saudaranya Az Zuhri] dari [Bekas budaknya Asma` binti Abu Bakar] dari [Asma` binti Abu Bakar] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian (para wanita) beriman kepada Allah dan hari akhir, janganlah mengangkat kepalanya terlebih dahulu sehingga kaum laki-laki mengangkat kepala mereka, karena di khawatirkan mereka melihat aurat kaum laki-laki.\""},"713":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ سُجُودُهُ وَرُكُوعُهُ وَقُعُودُهُ وَمَا بَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Al Barra`] bahwa lama sujud, ruku' dan duduk di antara dua sujudnya Rasulullah shallallahu 'alaihi wasallam hampir sama.\""},"714":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ وَحُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا صَلَّيْتُ خَلْفَ رَجُلٍ أَوْجَزَ صَلَاةً مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَمَامٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَامَ حَتَّى نَقُولَ قَدْ أَوْهَمَ ثُمَّ يُكَبِّرُ وَيَسْجُدُ وَكَانَ يَقْعُدُ بَيْنَ السَّجْدَتَيْنِ حَتَّى نَقُولَ قَدْ أَوْهَمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dan [Humaid] dari [Anas bin Malik] dia berkata; \"Aku tidak pernah shalat di belakang seseorang yang paling singkat dan paling sempurna shalatnya daripada shalatnya Rasulullah shallallahu 'alaihi wasallam, apabila Rasulullah shallallahu 'alaihi wasallam mengucapkan; \"Sami'allahu liman hamidah\" beliau berdiri (agak lama) sampai kami menyangka beliau lupa, kemudian beliau bertakbir dan sujud, beliau duduk di antara dua sujud sehingga kami menyangka bahwa beliau lupa.\""},"715":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو كَامِلٍ دَخَلَ حَدِيثُ أَحَدِهِمَا فِي الْآخَرِ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ هِلَالِ بْنِ أَبِي حُمَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَرَمَقْتُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَبُو كَامِلٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ فَوَجَدْتُ قِيَامَهُ كَرَكْعَتِهِ وَسَجْدَتِهِ وَاعْتِدَالَهُ فِي الرَّكْعَةِ كَسَجْدَتِهِ وَجِلْسَتَهُ بَيْنَ السَّجْدَتَيْنِ وَسَجْدَتَهُ مَا بَيْنَ التَّسْلِيمِ وَالِانْصِرَافِ قَرِيبًا مِنْ السَّوَاءِ قَالَ أَبُو دَاوُد قَالَ مُسَدَّدٌ فَرَكْعَتُهُ وَاعْتِدَالُهُ بَيْنَ الرَّكْعَتَيْنِ فَسَجْدَتُهُ فَجِلْسَتُهُ بَيْنَ السَّجْدَتَيْنِ فَسَجْدَتُهُ فَجِلْسَتَهُ بَيْنَ التَّسْلِيمِ وَالِانْصِرَافِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Kamil], hadits riwayat mereka berdua saling melengkapi antara yang satu dengan yang lain, keduanya berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Hilal bin Abu Humaid] dari [Abdurrahman bin Abu Laila] dari [Al Barra` bin 'Azib] dia berkata; \"Aku memperhatikan Muhammad shallallahu 'alaihi wasallam -Abu Kamil mengatakan; \"Rasulullah shallallahu 'alaihi wasallam\"- ketika beliau shalat, maka aku mendapati (lama) berdirinya seperti ketika ruku', sujud dan sujudnya, dan aku dapati i'tidal dari ruku' sujud dan duduk di antara dua sujud serta duduk beliau antara salam dan selesai shalat hampir sama lamanya.\" Abu Daud mengatakan; Musaddad mengatakan; \"Maka ruku'nya, i'tidal beliau antara dua raka'at, sujudnya, duduk di antara dua sujud, sujudnya, dan duduk antara salam dan selesai dari shalat (lamanya) hampir sama.\""},"716":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ الْبَدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةُ الرَّجُلِ حَتَّى يُقِيمَ ظَهْرَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari ['Umarah bin Umair] dari [Abu Ma'mar] dari [Abu Mas'ud Al Badri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sempurna shalat seseorang sehingga ia meluruskan punggungnya ketika ruku' dan sujud.\""},"717":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا أَنَسٌ يَعْنِي ابْنَ عَيَّاضٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ وَهَذَا لَفْظُ ابْنِ الْمُثَنَّى حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ السَّلَامَ وَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ الرَّجُلُ فَصَلَّى كَمَا كَانَ صَلَّى ثُمَّ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ السَّلَامُ ثُمَّ قَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ حَتَّى فَعَلَ ذَلِكَ ثَلَاثَ مِرَارٍ فَقَالَ الرَّجُلُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أُحْسِنُ غَيْرَ هَذَا فَعَلِّمْنِي قَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَكَبِّرْ ثُمَّ اقْرَأْ مَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ اجْلِسْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَاقَالَ الْقَعْنَبِيُّ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ وَقَالَ فِي آخِرِهِ فَإِذَا فَعَلْتَ هَذَا فَقَدْ تَمَّتْ صَلَاتُكَ وَمَا انْتَقَصْتَ مِنْ هَذَا شَيْئًا فَإِنَّمَا انْتَقَصْتَهُ مِنْ صَلَاتِكَ وَقَالَ فِيهِ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَأَسْبِغْ الْوُضُوءَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ عَنْ عَمِّهِ أَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ فَذَكَرَ نَحْوَهُ قَالَ فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَا تَتِمُّ صَلَا��ٌ لِأَحَدٍ مِنْ النَّاسِ حَتَّى يَتَوَضَّأَ فَيَضَعَ الْوُضُوءَ يَعْنِي مَوَاضِعَهُ ثُمَّ يُكَبِّرُ وَيَحْمَدُ اللَّهَ جَلَّ وَعَزَّ وَيُثْنِي عَلَيْهِ وَيَقْرَأُ بِمَا تَيَسَّرَ مِنْ الْقُرْآنِ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ يَرْكَعُ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ حَتَّى يَسْتَوِيَ قَائِمًا ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ يَسْجُدُ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ وَيَرْفَعُ رَأْسَهُ حَتَّى يَسْتَوِيَ قَاعِدًا ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ يَسْجُدُ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيُكَبِّرُ فَإِذَا فَعَلَ ذَلِكَ فَقَدْ تَمَّتْ صَلَاتُهُ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ وَالْحَجَّاجُ بْنُ مِنْهَالٍ قَالَا حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَةَ بْنِ رَافِعٍ بِمَعْنَاهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَا تَتِمُّ صَلَاةُ أَحَدِكُمْ حَتَّى يُسْبِغَ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ عَزَّ وَجَلَّ فَيَغْسِلَ وَجْهَهُ وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ وَيَمْسَحَ بِرَأْسِهِ وَرِجْلَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ يُكَبِّرَ اللَّهَ عَزَّ وَجَلَّ وَيَحْمَدَهُ ثُمَّ يَقْرَأَ مِنْ الْقُرْآنِ مَا أَذِنَ لَهُ فِيهِ وَتَيَسَّرَ فَذَكَرَ نَحْوَ حَدِيثِ حَمَّادٍ قَالَ ثُمَّ يُكَبِّرَ فَيَسْجُدَ فَيُمَكِّنَ وَجْهَهُ قَالَ هَمَّامٌ وَرُبَّمَا قَالَ جَبْهَتَهُ مِنْ الْأَرْضِ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ وَتَسْتَرْخِيَ ثُمَّ يُكَبِّرَ فَيَسْتَوِيَ قَاعِدًا عَلَى مَقْعَدِهِ وَيُقِيمَ صُلْبَهُ فَوَصَفَ الصَّلَاةَ هَكَذَا أَرْبَعَ رَكَعَاتٍ حَتَّى تَفْرُغَ لَا تَتِمُّ صَلَاةُ أَحَدِكُمْ حَتَّى يَفْعَلَ ذَلِكَ حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ عَمْرٍو عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ بِهَذِهِ الْقِصَّةِ قَالَ إِذَا قُمْتَ فَتَوَجَّهْتَ إِلَى الْقِبْلَةِ فَكَبِّرْ ثُمَّ اقْرَأْ بِأُمِّ الْقُرْآنِ وَبِمَا شَاءَ اللَّهُ أَنْ تَقْرَأَ وَإِذَا رَكَعْتَ فَضَعْ رَاحَتَيْكَ عَلَى رُكْبَتَيْكَ وَامْدُدْ ظَهْرَكَ وَقَالَ إِذَا سَجَدْتَ فَمَكِّنْ لِسُجُودِكَ فَإِذَا رَفَعْتَ فَاقْعُدْ عَلَى فَخِذِكَ الْيُسْرَى حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عَلِيُّ بْنُ يَحْيَى بْنِ خَلَّادِ بْنِ رَافِعٍ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ قَالَ إِذَا أَنْتَ قُمْتَ فِي صَلَاتِكَ فَكَبِّرْ اللَّهَ تَعَالَى ثُمَّ اقْرَأْ مَا تَيَسَّرَ عَلَيْكَ مِنْ الْقُرْآنِ وَقَالَ فِيهِ فَإِذَا جَلَسْتَ فِي وَسَطِ الصَّلَاةِ فَاطْمَئِنَّ وَافْتَرِشْ فَخِذَكَ الْيُسْرَى ثُمَّ تَشَهَّدْ ثُمَّ إِذَا قُمْتَ فَمِثْلَ ذَلِكَ حَتَّى تَفْرُغَ مِنْ صَلَاتِكَ حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ أَخْبَرَنِي يَحْيَى بْنُ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادِ بْنِ رَافِعٍ الزُّرَقِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَّ هَذَا الْحَدِيثَ قَالَ فِيهِ فَتَوَضَّأْ كَمَا أَمَرَكَ اللَّهُ جَلَّ وَعَزَّ ثُمَّ تَشَهَّدْ فَأَقِمْ ثُمَّ كَبِّرْ فَإِنْ كَانَ مَعَكَ قُرْآنٌ فَاقْرَأْ بِهِ وَإِلَّا فَاحْمَدْ اللَّهَ وَكَبِّرْهُ وَهَلِّلْهُ وَقَالَ فِيهِ وَإِنْ انْتَقَصْتَ مِنْهُ شَيْئًا انْتَقَصْتَ مِنْ صَلَاتِكَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Anas yaitu Ibnu 'Ayyadl]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepadaku [Yahya bin Sa'id] dari ['Ubaidullah] sedangkan lafadz hadits ini berasal dari Al Mutsanna telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam masuk masjid, bersamaan dengan itu seorang laki-laki masuk masjid lalu shalat, seusai shalat, dia datang sambil memberi salam kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam menjawab salamnya dan bersabda: \"Kembali dan shalatlah, karena kamu belum mengerjakan shalat.\" laki-laki itu kembali mengerjakan shalat sebagaimana ia shalat, kemudian dia datang kepada Nabi shallallahu 'alaihi wasallam dan memberi salam kepada beliau, maka Rasulullah shallallahu 'alaihi wasallam menjawab salamnya, sabdanya; \"Alaikas salam.\" kemudian bersabda: \"Shalatlah kamu, sesungguhnya kamu belum mengerjakan shalat.\" hal itu di ulanginya sampai tiga kali. Laki-laki itu berkata; \"Demi dzat yang telah mengutus-Mu dengan kebenaran, aku tidak dapat mengerjakan yang lebih baik selain cara ini, oleh karena itu ajarilah aku.\" Beliau bersabda: \"Apabila kamu hendak mengerjakan shalat, bertakbirlah, kemudian bacalah ayat Al Qur'an yang mudah bagimu, lalu ruku'lah hingga kamu benar-benar (tenang) dalam posisi ruku', setelah itu bangkitlah sampai berdiri lurus kembali, kemudian sujudlah hingga benar-benar dalam posisi sujud, lalu duduklah hingga benar-benar dalam posisi duduk, lalu sujud kembali hingga benar-benar sujud, kemudian lakukanlah hal itu di setiap shalatmu.\" [Al Qa'nabi] mengatakan; dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] …' di akhir haditsnya ia mengatakan; \"Jika kamu melakukan seperti ini, maka shalatmu menjadi sempurna, dan apabila kamu mengurangi dari cara ini, berarti kesempurnaan shalatmu juga akan terkurangi.\" Dalam hadits ini juga di sebutkan; \"Apabila kamu hendak mengerjakan shalat, maka sempurnakanlah wudlu'mu.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Ali bin Yahya bin Khallad] dari [pamannya] bahwa seorang laki-laki masuk masjid…\" selanjutnya dia melanjutkan seperti hadits di atas, lalu dia berkata; \"Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya tidak sempurna shalat seseorang sehingga dia berwudlu' yaitu membasuh anggota wudlu'nya (dengan sempurna) kemudian bertakbir, memuji Allah Jalla wa 'Azza, menyanjung-Nya dan membaca AL Qur'an yang mudah baginya. Setelah itu mengucapkan Allahu Akbar, kemudian ruku' sampai tenang semua persendiannya, lalu mengucapkan \"Sami'allahu liman hamidah\" sampai berdiri lurus, kemudian mengucapkan Allahu Akbar, lalu sujud sehingga semua persendiannya tenang. Setelah itu mengangkat kepalanya sambil bertakbir. Apabila dia telah mengerjakan seperti demikian, maka shalatnya menjadi sempurna.\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Hisyam bin Abdul Malik] dan [Hajjaj bin Minhal] keduanya berkata; telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] dari [Ali bin Yahya bin Khallad] dari [ayahnya] dari [pamannya yaitu Rifa'ah bin Rafi'] dengan makna yang sama, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sempurna shalat salah seorang dari kalian sehingga dirinya menyempurnakan wudlu' sebagaimana yang di perintahkan Allah Azza wa Jalla, yaitu membasuh mukanya dan kedua tangannya sampai kedua sikunya, dan membasuh kepalanya dan kedua kakinya hingga kedua mata kakinya, kemudian mengucapkan takbir, memuji Allah dan membaca Al Qur'an yang mudah baginya…\" kemudian ia menyebutkan seperti haditsnya Hammad, katanya; \"…Kemudian bertakbir, bersujud dengan meletakkan muka -Hammam mengatakan; sepertinya dia mengatakan- atau keningnya ke tanah, sehingga semua persendiannya tenang dan menjadi rileks, lalu bertakbir dan duduk pada tempat duduknya hingga lurus tulang punggungnya, maka beliau mempraktekkan cara shalat tersebut hingga empat kali sampai selesai, tidak sempurna shalat seseorang di antara kalian, sehingga ia mengerjakan cara shalat yang seperti ini.\" telah menceritakan kepada kami [Wahb bin Baqiyah] dari [Khalid] dari [Muhammad yaitu Ibnu 'Amru] dari [Ali bin Yahya bin Khallad] dari [ayahnya] dari [Rifa'ah bin Rafi'] dengan kisah seperti ini, sabdanya: \"Apabila kamu hendak mengerjakan shalat, dan wajahmu telah menghadap ke arah kiblat, maka bertakbirlah lalu bacalah Ummul Qur'an dan surat sesuka hatimu, dan sesuai kehendak Allah untuk kamu baca, apabila kamu ruku', maka letakkanlah kedua telapak tanganmu di atas kedua lututmu dan hamparkanlah punggungmu.\" Setelah itu beliau bersabda: \"Apabila kamu hendak sujud, maka kuatkanlah (kedua tangan) untuk menyangga sujudmu, dan apabila kamu mengangkat (kepala dari sujud) maka duduklah di atas pahamu yang kiri.\" Telah menceritakan kepada kami [Mu'ammal bin Hisyam] telah menceritakan kepada kami [Isma'il] dari [Muhammad bin ishaq] telah menceritakan kepadaku [Ali bin Yahya bin Khallad bin Rafi'] dari [ayahnya] dari [pamannya yaitu Rifa'ah bin Rafi'] dari Nabi shallallahu 'alaihi wasallam dengan kisah seperti ini, beliau bersabda: \"Apabila kamu hendak mengerjakan shalat, bertakbirlah kepada Allah Ta'ala, kemudian bacalah Al Qur'an yang mudah bagimu.\" -dalam hadits tersebut beliau juga bersabda- Apabila kamu duduk di tengah mengerjakan shalat, maka tenangkanlah dirimu dan duduklah di atas paha kirimu, kemudian bacalah tasyahud. Setelah itu, apabila kamu berdiri, kerjakanlah seperti itu pula, sehingga kamu selesai dari shalat.\" Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah menceritakan kepada kami [Isma'il yaitu Ibnu Ja'far] telah mengabarkan kepadaku [Yahya bin Ali bin Yahya bin Khallad bin Rafi' Az Zuraqi] dari [ayahnya] dari [kakeknya] dari [Rifa'ah bin Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam -lalu di ceritakannya hadits tersebut, di antaranya beliau bersabda: \"Maka berwudlu'lah sebagaimana yang di perintahkan oleh Allah Jalla wa Azza kepadamu, kemudian bacalah Tasyahud (setelah wudlu), dan dirikanlah (shalat) kemudian bertakbirlah, jika kamu bisa membaca (hafal) dari surat Al Qur'an, maka bacalah, jika tidak (bisa membaca), maka bertahmid (membaca Al Hamdulillah), bertakbir (membaca Allahu Akbar) dan bertahlil (membaca Laa ilaaha illallah) lah kepada Allah.\" -dalam hadits itu pula beliau bersabda; \"…Jika kamu mengurangi sedikit dari cara tersebut, berarti kamu mengurangi (kesempurnaan) shalatmu.\""},"718":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرِ بْنِ الْحَكَمِ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَقْرَةِ الْغُرَابِ وَافْتِرَاشِ السَّبْعِ وَأَنْ يُوَطِّنَ الرَّجُلُ الْمَكَانَ فِي الْمَسْجِدِ كَمَا يُوَطِّنُ الْبَعِيرُهَذَا لَفْظُ قُتَيْبَةَ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Ja'far bin Al Hakam]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Abdullah Al Anshari] dari [Tamim bin Mahmud] dari [Abdurrahman bin Syibl] dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang (sujud dengan cepat) seperti burung gagak mematuk dan (menghamparkan lengan ketika sujud) seperti binatang buas yang sedang membentangkan kakinya dan melarang seseorang mengambil lokasi khusus di Masjid (untuk ibadatnya) sebagaimana unta menempati tempat berderumnya.\" Ini adalah lafadz yang berasal dari Qutaibah.\" "},"719":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَالِمٍ الْبَرَّادِ قَالَأَتَيْنَا عُقْبَةَ بْنَ عَمْرٍو الْأَنْصَارِيَّ أَبَا مَسْعُودٍ فَقُلْنَا لَهُ حَدِّثْنَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ بَيْنَ أَيْدِينَا فِي الْمَسْجِدِ فَكَبَّرَ فَلَمَّا رَكَعَ وَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَجَعَلَ أَصَابِعَهُ أَسْفَلَ مِنْ ذَلِكَ وَجَافَى بَيْنَ مِرْفَقَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقَامَ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ كَبَّرَ وَسَجَدَ وَوَضَعَ كَفَّيْهِ عَلَى الْأَرْضِ ثُمَّ جَافَى بَيْنَ مِرْفَقَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ رَفَعَ رَأْسَهُ فَجَلَسَ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ فَفَعَلَ مِثْلَ ذَلِكَ أَيْضًا ثُمَّ صَلَّى أَرْبَعَ رَكَعَاتٍ مِثْل�� هَذِهِ الرَّكْعَةِ فَصَلَّى صَلَاتَهُ ثُمَّ قَالَ هَكَذَا رَأَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari ['Atha` bin As Sa`ib] dari [Salim Al Barrad] dia berkata; aku menemui ['Uqbah bin 'Amru Al Anshari yaitu Abu Mas'ud] maka kau berkata kepadanya; \"Jelaskanlah kepada kami tata cara shalat Rasulullah shallallahu 'alaihi wasallam!.\" maka dia berdiri di depan kami di masjid, lalu bertakbir. Ketika ruku', dia meletakkan kedua tangannya di atas kedua lututnya dan meletakkan jemarinya lebih rendah dari itu, sedangkan kedua sikunya di renggangkan, sehingga semua anggota tubuhnya tenang (thuma'ninah), kemudian bertakbir dan sujud, setelah itu ia meletakkan kedua telapak tangannya ke tanah, dan merenggangkan antara kedua sikunya sampai semua anggota tubuhnya tenang (thuma'ninah). Dia mengerjakan yang demikian itu, dan shalat empat raka'at sebagaimana raka'at ini, setelah mengerjakan shalatnya, dia berkata; \"Demikianlah kami pernah melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat.\""},"720":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ حَكِيمٍ الضَّبِّيِّ قَالَخَافَ مِنْ زِيَادٍ أَوْ ابْنِ زِيَادٍ فَأَتَى الْمَدِينَةَ فَلَقِيَ أَبَا هُرَيْرَةَ قَالَ فَنَسَبَنِي فَانْتَسَبْتُ لَهُ فَقَالَ يَا فَتَى أَلَا أُحَدِّثُكَ حَدِيثًا قَالَ قُلْتُ بَلَى رَحِمَكَ اللَّهُ قَالَ يُونُسُ وَأَحْسَبُهُ ذَكَرَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَوَّلَ مَا يُحَاسَبُ النَّاسُ بِهِ يَوْمَ الْقِيَامَةِ مِنْ أَعْمَالِهِمْ الصَّلَاةُ قَالَ يَقُولُ رَبُّنَا جَلَّ وَعَزَّ لِمَلَائِكَتِهِ وَهُوَ أَعْلَمُ انْظُرُوا فِي صَلَاةِ عَبْدِي أَتَمَّهَا أَمْ نَقَصَهَا فَإِنْ كَانَتْ تَامَّةً كُتِبَتْ لَهُ تَامَّةً وَإِنْ كَانَ انْتَقَصَ مِنْهَا شَيْئًا قَالَ انْظُرُوا هَلْ لِعَبْدِي مِنْ تَطَوُّعٍ فَإِنْ كَانَ لَهُ تَطَوُّعٌ قَالَ أَتِمُّوا لِعَبْدِي فَرِيضَتَهُ مِنْ تَطَوُّعِهِ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى ذَاكُمْحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ رَجُلٍ مِنْ بَنِي سَلِيطٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ تَمِيمٍ الدَّارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْمَعْنَى قَالَ ثُمَّ الزَّكَاةُ مِثْلُ ذَلِكَ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Yunus] dari [Al Hasan] dari [Anas bin Hakim Adl Dlabbi] dia berkata; \"Dirinya pernah takut kepada Ziyad atau Ibnu Ziyad kemudian pergi ke Madinah, di sana ia bertemu dengan Abu Hurairah, katanya; dia menasabkan aku kepadanya dan aku pun menyatakan nasab kepadanya.\" [Abu Hurairah] berkata; \"Wahai anak muda, maukah kamu kuceritakan suatu hadits?\" kata Anas; kataku; \"Ya, semoga Allah merahmati anda.\" Yunus berkata; \"Aku kira dia menyebutkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya yang pertama kali akan di hisab dari amal perbuatan manusia pada hari kiamat adalah shalatnya, Allah Jalla wa 'Azza berfirman kepada Malaikat -Dan Dia lebih mengetahui (amalan seseorang) -; \"Periksalah shalat hamba-Ku, sempurnakah atau justru kurang? Sekiranya sempurna, maka catatlah baginya dengan sempurna, dan jika terdapat kekurangan, Allah berfirman; \"Periksalah lagi, apakah hamba-Ku memiliki amalan shalat sunnah? Jikalau terdapat shalat sunnahnya, Allah berfirman; \"Cukupkanlah kekurangan yang ada pada shalat wajib hamba-Ku itu dengan shalat sunnahnya.\" Selanjutnya semua amal manusia di hisab dengan cara demikian.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Al Hasan] dari [seorang laki-laki dari Bani Salith] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Daud bin Abu Hind] dari [Zurarah bin Aufa] dari [Tamim Ad Dari] dari Nabi shallallahu 'alaihi wasallam dengan makna seperti ini, beliau bersabda: \"Kemudian zakat, (di hisab) seperti itu juga, kemudian semua amalan di hisab seperti itu.\""},"721":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي يَعْفُورٍ قَالَ أَبُو دَاوُد وَاسْمُهُ وَقْدَانُ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَصَلَّيْتُ إِلَى جَنْبِ أَبِي فَجَعَلْتُ يَدَيَّ بَيْنَ رُكْبَتَيَّ فَنَهَانِي عَنْ ذَلِكَ فَعُدْتُ فَقَالَ لَا تَصْنَعْ هَذَا فَإِنَّا كُنَّا نَفْعَلُهُ فَنُهِينَا عَنْ ذَلِكَ وَأُمِرْنَا أَنْ نَضَعَ أَيْدِيَنَا عَلَى الرُّكَبِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ya'fur]. Abu Daud mengatakan; namanya adalah Waqdan, dari [Mush'ab bin Sa'd] dia berkata; \"Aku mengerjakan shalat di samping ayahku, lalu aku meletakkan kedua tanganku antara kedua lututku, maka dia melarangku mengerjakan cara yang demikian, lalu saya mengulanginya, maka [ayahku] berkata; \"Janganlah kamu melakukan cara yang seperti ini, karena sesungguhnya kami pernah melakukan cara seperti ini, lalu kami dilarang melakukannya dan kami di perintahkan supaya meletakkan tangan di atas lutut.\""},"722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَإِذَا رَكَعَ أَحَدُكُمْ فَلْيَفْرِشْ ذِرَاعَيْهِ عَلَى فَخِذَيْهِ وَلْيُطَبِّقْ بَيْنَ كَفَّيْهِ فَكَأَنِّي أَنْظُرُ إِلَى اخْتِلَافِ أَصَابِعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dan [Al Aswad] dari [Abdullah] dia berkata; \"Apabila salah seorang dari kalian ruku', maka hamparkanlah kedua hastanya di atas pahanya dan ratakanlah antara kedua telapak tangannya, seakan-akan aku melihat jemari Rasulullah shallallahu 'alaihi wasallam bersilang.\""},"723":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ وَمُوسَى بْنُ إِسْمَعِيلَ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مُوسَى قَالَ أَبُو سَلَمَةَ مُوسَى بْنِ أَيُّوبَ عَنْ عَمِّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَلَمَّا نَزَلَتْ{ فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيمِ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوهَا فِي رُكُوعِكُمْ فَلَمَّا نَزَلَتْ{ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى }قَالَ اجْعَلُوهَا فِي سُجُودِكُمْحَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا اللَّيْثُ يَعْنِي ابْنَ سَعْدٍ عَنْ أَيُّوبَ بْنِ مُوسَى أَوْ مُوسَى بْنِ أَيُّوبَ عَنْ رَجُلٍ مِنْ قَوْمِهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ بِمَعْنَاهُ زَادَ قَالَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ قَالَ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَبِحَمْدِهِ ثَلَاثًا وَإِذَا سَجَدَ قَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى وَبِحَمْدِهِ ثَلَاثًا قَالَ أَبُو دَاوُد وَهَذِهِ الزِّيَادَةُ نَخَافُ أَنْ لَا تَكُونَ مَحْفُوظَةً قَالَ أَبُو دَاوُد انْفَرَدَ أَهْلُ مِصْرَ بِإِسْنَادِ هَذَيْنِ الْحَدِيثَيْنِ حَدِيثِ الرَّبِيعِ وَحَدِيثِ أَحْمَدَ بْنِ يُونُسَ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Tsaubah] dan [Musa bin Isma'il] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Ibnu Al Mubarrak] dari [Musa]. Abu Salamah Musa bin Ayyub mengatakan; dari [pamannya] dari ['Uqbah bin 'Amir] dia berkata; Ketika turun; \"FASABBIH BISMIRABBIKAL 'ADZIIM (maka sucikanlah dengan nama Rabbmu yang Maha Agung).\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah ia sebagai bacaan ruku' kalian.\" dan ketika turun; \"SABBIHISMA RABBIKAL A'LA (Sucikanlah dengan nama Rabbmu yang Maha tinggi) \" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah ia sebagai bacaan sujud kalian.\" telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Al Laits yaitu Ibnu Sa'd] dari [Ayyub bin Musa atau Musa bin Ayyub] dari [seorang laki-laki dari Kaumnya] dari ['Uqbah bin 'Amir] dengan makna yang sama, dia menambahkan; Uqbah berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam ruku' beliau mengucapkan; \"Subhaana rabbiyal 'azhiim wa bihamdihi (Maha suci Rabbku yang Maha Agung dengan pujian-Nya) \" sebanyak tiga kali, dan apabila sujud beliau mengucapkan; \"Subhaana rabbiyal a'la wa bihamdih (Maha suci Rabbku yang Maha Tinggi dengan segala pujian-Nya) \" sebanyak tiga kali.\" Abu Daud mengatakan; \"Saya khawatir tambahan ini tidak dari tambahan yang benar-benar terjaga (kebenarannya).\" Abu Daud mengatakan; \"Penduduk Mesir meriwayatkan dengan periwayatan tunggal mengenai dua isnad hadits ini yaitu hadits Rabi' dan hadits Ahmad bin Yunus. "},"724":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ قُلْتُ لِسُلَيْمَانَ أَدْعُو فِي الصَّلَاةِ إِذَا مَرَرْتُ بِآيَةِ تَخَوُّفٍ فَحَدَّثَنِي عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ مُسْتَوْرِدٍ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى وَمَا مَرَّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ عِنْدَهَا فَسَأَلَ وَلَا بِآيَةِ عَذَابٍ إِلَّا وَقَفَ عِنْدَهَا فَتَعَوَّذَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dia berkata; saya berkata kepada Sulaiman; apabila aku membaca ayat yang mengandung ketakutan apakah aku harus berdoa dalam shalat?\" maka [Sulaiman] menceritakan kepadaku dari [Sa'd bin 'Ubaidah] dari [Mustaurid] dari [Shilah bin Zufar] dari [Hudzaifah] bahwa dia shalat bersama Nabi shallallahu 'alaihi wasallam, ketika ruku' beliau membaca: \"Subhaana rabbiyal 'azhiimi (Maha suci Rabbku yang Maha Agung) \" dan ketika sujud beliau membaca: \"Subhaana Rabbiyal a'la (Maha suci Rabbku yang Maha Tinggi).\" Dan beliau tidak melewati ayat tentang rahmat melainkan beliau akan berhenti pada ayat tersebut, lalu berdo'a. dan tidaklah beliau melewati ayat tentang adzab (siksa) melainkan beliau akan berhenti pada ayat tersebut lalu memohon perlindungan.\""},"725":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ مُطَرِّفٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبُّوحٌ قُدُّوسٌ رَبُّ الْمَلَائِكَةِ وَالرُّوحِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Mutharif] dari [Aisyah] bahwa ketika Nabi shallallahu 'alaihi wasallam ruku' dan sujudnya, beliau mengucapkan: \"Subbuhun quddusun rabbul Malaaikati war ruuhi (Maha suci (Allah), Rabb kami, para Malaikat dan Jibril).\""},"726":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَاصِمِ بْنِ حُمَيْدٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَقُمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَامَ فَقَرَأَ سُورَةَ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ فَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ فَتَعَوَّذَ قَالَ ثُمَّ رَكَعَ بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ قِيَامِهِ ثُمَّ قَالَ فِي سُجُودِهِ مِثْلَ ذَلِكَ ثُمَّ قَامَ فَقَرَأَ بِآلِ عِمْرَانَ ثُمَّ قَرَأَ سُورَةً سُورَةً","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari ['Amru bin Qais] dari ['Ashim bin Humaid] dari ['Auf bin Malik Al Asyja'i] dia berkata; \"Di suatu malam, aku mengerjakan shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau kemudian berdiri dan membaca surat Al Baqarah, tidaklah beliau melewati ayat tentang rahmat, pasti beliau berhenti dan memohon kepada-Nya, dan tidaklah melewati ayat tentang adzab, melainkan beliau berhenti dan meminta perlindungan darinya.\" katanya melanjutkan; \"Kemudian beliau ruku' yang lamanya seperti beliau berdiri, dalam ruku'nya beliau mengucapkan: \"subahaana dzil jabaruuti wal malakuuti wal kibriyaa`i wal 'azhamati (Maha suci dzat yang memiliki sifat kekuasaan, kerajaan, kebesaran dan keagungan).\" Kemudian beliau sujud yang lamanya seperti beliau berdiri, dalam sujudnya beliau mengucapkan seperti itu juga, sesudah itu beliau berdiri, lalu membaca surat Ali Imran, kemudian membaca surat demi surat.\""},"727":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَعَلِيُّ بْنُ الْجَعْدِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي حَمْزَةَ مَوْلَى الْأَنْصَارِ عَنْ رَجُلٍ مِنْ بَنِي عَبْسٍ عَنْ حُذَيْفَةَأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَكَانَ يَقُولُ اللَّهُ أَكْبَرُ ثَلَاثًا ذُو الْمَلَكُوتِ وَالْجَبَرُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ اسْتَفْتَحَ فَقَرَأَ الْبَقَرَةَ ثُمَّ رَكَعَ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ وَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَكَانَ قِيَامُهُ نَحْوًا مِنْ رُكُوعِهِ يَقُولُ لِرَبِّيَ الْحَمْدُ ثُمَّ سَجَدَ فَكَانَ سُجُودُهُ نَحْوًا مِنْ قِيَامِهِ فَكَانَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى ثُمَّ رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَكَانَ يَقْعُدُ فِيمَا بَيْنَ السَّجْدَتَيْنِ نَحْوًا مِنْ سُجُودِهِ وَكَانَ يَقُولُ رَبِّ اغْفِرْ لِي رَبِّ اغْفِرْ لِي فَصَلَّى أَرْبَعَ رَكَعَاتٍ فَقَرَأَ فِيهِنَّ الْبَقَرَةَ وَآلَ عِمْرَانَ وَالنِّسَاءَ وَالْمَائِدَةَ أَوْ الْأَنْعَامَ شَكَّ شُعْبَةُ","id":"Telah menceritakan kepada kami [Abu Walid Ath Thayalisi] dan [Ali bin Al Ja'd] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abu Hamzah bekas budak Al Anshari] dari [seorang laki-laki dari Bani 'Absi] dari [Hudzaifah] bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam shalat malam, dalam shalatnya beliau mengucapkan; \"Allahu Akbar\" tiga kali dzul malakuuti wal Jabaruuri wal kibriyaa`i wal 'adzamati (Maha suci dzat yang memiliki kerajaan, kekuasaan, kebesaran dan keagungan).\" Kemudian beliau membaca do'a iftitah, lalu membaca surat Al Baqarah, kemudian beliau ruku, lama beliau ruku' hampir sama ketika beliau berdiri, dalam ruku'nya beliau mengucapkan; \"Subhaana rabbiyal 'azhiimi, Subhaana rabbiyal 'azhiimi (Maha suci Rabbku yang Maha Agung, Maha suci Rabbku yang Maha Agung).\" Kemudian beliau mengangkat kepalanya dari ruku', sedangkan lamanya beliau berdiri (i'tidal) seperti ketika beliau ruku', beliau mengucapkan; \"Lirabbiyal hamdu (Bagi rabbku segala puji-pujian).\" Kemudian beliau sujud, sedangkan lamanya beliau sujud seperti ketika beliau berdiri, dalam sujudnya beliau mengucapkan; \"Subhaana rabbiyal a'la (Maha suci Rabbku yang Maha tinggi).\" Kemudian beliau mengangkat kepalanya dari sujud, lama beliau duduk di antara dua sujud seperti ketika beliau sujud, dan dalam duduk di antara dua sujudnya beliau mengucapkan: \"Rabbighfirlii, Rabbighfirlii\" kemudian beliau shalat empat raka'at, dalam shalatnya itu beliau membaca surat Al Baqarah, Ali Imran, An Nisa', Al Maidah atau Al An'am -Syu'bah ragu (dalam lafadznya).\""},"728":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَمُحَمَّدُ بْنُ سَلَمَةَ قَالُوا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ أَنَّهُ سَمِعَ أَبَا صَالِحٍ ذَكْوَانَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَبُ مَا يَكُونُ الْعَبْدُ مِنْ رَبِّهِ وَهُوَ سَاجِدٌ فَأَكْثِرُوا الدُّعَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], [Ahmad bin 'Amru bin As Sarh] dan [Muhammad bin Salamah] mereka mengatakan; telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami ['Amru yaitu Ibnu Al Harits] dari ['Umarah bin Ghaziyah] dari [Sumayya bekas budak Abu Bakr] bahwa dia mendengar [Abu Shalih Dzakwan] menceritakan dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat paling dekat bagi seorang hamba dengan Rabbnya adalah ketika dia sujud, karena itu perbanyaklah berdo'a ketika sujud.\""},"729":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَشَفَ السِّتَارَةَ وَالنَّاسُ صُفُوفٌ خَلْفَ أَبِي بَكْرٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّهُ لَمْ يَبْقَ مِنْ مُبَشِّرَاتِ النُّبُوَّةِ إِلَّا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ وَإِنِّي نُهِيتُ أَنْ أَقْرَأَ رَاكِعًا أَوْ سَاجِدًا فَأَمَّا الرُّكُوعُ فَعَظِّمُوا الرَّبَّ فِيهِ وَأَمَّا السُّجُودُ فَاجْتَهِدُوا فِي الدُّعَاءِ فَقَمِنٌ أَنْ يُسْتَجَابَ لَكُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Sulaiman bin Suhaim] dari [Ibrahim bin Abdullah bin Ma'bad] dari [ayahnya] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam menyingkap tirai (kamarnya) sementara orang-orang sedang berbaris di belakang Abu Bakar, maka beliau bersabda: \"Wahai sekalian manusia, sesungguhnya berita gembira kenabian telah tiada, kecuali mimpi yang shalih (benar) yang di mimpikan oleh seorang muslim atau yang di perlihatkan kepadanya, ketahuilah aku di larang membaca Al Qur'an ketika ruku' dan sujud, oleh karena itu, ketika ruku', hendaklah kalian mengagungkan Rabb (Allah), sedangkan ketika sujud, hendaklah kalian bersungguh-sungguh dalam berdo'a, karena besar kemungkinan do'a kalian akan di kabulkan oleh Allah.\""},"730":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] dia berkata; \"Dalam ruku' dan sujudnya Rasulullah shallallahu 'alaihi wasallam sering memperbanyak bacaan \"Subhaanaka Allahumma Rabbana wa bihamdika Allahummaghfir li\" (Maha suci Engkau ya Allah wahai Rabb kami segala puji bagi-Mu, ya Allah ampunilah aku).\" beliau menta'wilkan Al Qur'an. "},"731":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي سُجُودِهِ اللَّهُمَّ اغْفِرْ لِي ذَنْبِي كُلَّهُ دِقَّهُ وَجِلَّهُ وَأَوَّلَهُ وَآخِرَهُ زَادَ ابْنُ السَّرْحِ عَلَانِيَتَهُ وَسِرَّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yahya bin Ayyub] dari ['Umarah bin Ghaziyah] dari [Sumayya bekas budak Abu Bakar] dari [Abu Shalih] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam dalam sujudnya membaca: \"Allahummaghfir li dzanbi kulluhu diqqahu wa jillahu wa awwalahu wa akhirahu\" (ya Allah ampunilah dosaku semuanya, baik yang kecil maupun yang besar, dan dari yang pertama sampai yang terakhir).\" Ibnu Siraj menambahkan \"Alaniyatahu wa sirrahu\" (baik yang nampak ataupun yang tersembunyi).\""},"732":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَلَمَسْتُ الْمَسْجِدَ فَإِذَا هُوَ سَاجِدٌ وَقَدَمَاهُ مَنْصُوبَتَانِ وَهُوَ يَقُولُ أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَأَعُوذُ بِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami ['Abdah] dari ['Ubaidullah] dari [Muhammad Ibnu Yahya bin Habban] dari [Abdurrahman Al A'raj] dari [Abu Huraiah] dari [Aisyah radliallahu 'anha] dia berkata; \"Suatu malam aku kehilangan Rasulullah shallallahu 'alaihi wasallam, maka tersentuhlah beliau olehku di masjid, ternyata beliau sedang sujud dengan kedua telapak kakinya yang tegak ke atas, dan beliau mengucapkan; \"A'uudzu biridlaaka min sukhtika wa a'uudzu bi mu'aafatika min 'uquubatika wa a'uudzubika minka laa uhshii tsanaa'a 'alaika anta kamaa atsnaita 'alaa nafsika (Aku berlindung dengan keridlaan-Mu dari murka-Mu, aku berlindung dengan ampunan-Mu dari siksa-Mu, aku berlindung kepada-Mu dari pada-Mu, tidaklah terhitung puji-pujianku kepada-Mu, engkau adalah Dzat sebagaimana di pujikan oleh diri-Mu sendiri).\""},"733":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي صَلَاتِهِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْمَأْثَمِ وَالْمَغْرَمِ فَقَالَ لَهُ قَائِلٌ مَا أَكْثَرَ مَا تَسْتَعِيذُ مِنْ الْمَغْرَمِ فَقَالَ إِنَّ الرَّجُلَ إِذَا غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [Baqiyah] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] dari ['Urwah] bahwa [Aisyah] telah mengabarkan kepadanya bahwa dalam shalatnya, Rasulullah shallallahu 'alaihi wasallam sering berdo'a; \"Allahumma inni 'auudzubika min 'adzaabil qabri wa a'uudzubika min fitnatil masiihid dajjal wa a'uudzubika min fitnatil mahya wal mamaati, allahumma inni a'uudzubika minal ma`tsmi wal maghrami (Ya Allah, aku berlindung kepada-Mu dari siksa kubur, aku berlindung dari fitnah Dajjal, aku berlindung kepada-Mu dari fitnah kehidupan dan kematian, ya Allah aku berlindung kepada-Mu dari perbuatan dosa dan lilitan hutang).\" Maka seseorang bertanya kepada beliau; 'alangkah seringnya anda memohon perlindungan diri dari lilitan hutang.\" Beliau bersabda: \"Sesungguhnya apabila seseorang sudah sering berhutang, maka dia akan berbicara dan berbohong, dan apabila berjanji, maka dia akan mengingkari.\""},"734":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ قَالَصَلَّيْتُ إِلَى جَنْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ تَطَوُّعٍ فَسَمِعْتُهُ يَقُولُ أَعُوذُ بِاللَّهِ مِنْ النَّارِ وَيْلٌ لِأَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] dari [Ibnu Abu Laila] dari [Tsabit Al Banani] dari [Abdurrahman bin Abu Laila] dari [ayahnya] dia berkata; \"Aku shalat sunnah di samping Rasulullah shallallahu 'alaihi wasallam, dan terdengar olehku beliau memohon perlindungan kepada Allah dari api neraka dan kesengsaraan penduduk Neraka.\""},"735":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ وَقُمْنَا مَعَهُ فَقَالَ أَعْرَابِيٌّ فِي الصَّلَاةِ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تَرْحَمْ مَعَنَا أَحَدًا فَلَمَّا سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْأَعْرَابِيِّ لَقَدْ تَحَجَّرْتَ وَاسِعًا يُرِيدُ رَحْمَةَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam berdiri untuk mengerjakan shalat, lantas kami pun berdiri bersama beliau, tiba-tiba seorang arab badui berkata dalam shalatnya; \"Allahummar hamnii wa muhammadan walaa tarham ma'adaa ahadan (Ya Allah, rahmatilah aku dan Muhammad dan janganlah Engkau merahmati seorang pun yang bersama kami).\" Setelah Rasulullah shallallahu 'alaihi wasallam salam, beliau bersabda kepada arab badui tersebut: 'Kamu telah mempersempit sesuatu yang luas.\" Maksud beliau adalah rahmat Allah Azza Wa Jalla.\""},"736":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَرَأَ{ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى }قَالَ سُبْحَانَ رَبِّيَ الْأَعْلَىقَالَ أَبُو دَاوُد خُولِفَ وَكِيعٌ فِي هَذَا الْحَدِيثِ وَرَوَاهُ أَبُو وَكِيعٍ وَشُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ مَوْقُوفًا","id":"Telah menceritakan kepada kami [Zuhair bin harb] telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Abu Ishaq] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa apabila Nabi shallallahu 'alaihi wasallam membaca; \"Sabbihisma rabbikal a'la.\" Maka beliau mengucapkan; \"Subhaana rabbiyal a'la (Maha suci Rabbku yang Maha tinggi.\" Abu Daud mengatakan; riwayat Waki' di perselisihkan dalam hadits ini, hadits ini juga di riwayatkan oleh [Abu Waki'] dan [Syu'bah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] secara mauquf. "},"737":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ قَالَكَانَ رَجُلٌ يُصَلِّي فَوْقَ بَيْتِهِ وَكَانَ إِذَا قَرَأَ{ أَلَيْسَ ذَلِكَ بِقَادِرٍ عَلَى أَنْ يُحْيِيَ الْمَوْتَى }قَالَ سُبْحَانَكَ فَبَكَى فَسَأَلُوهُ عَنْ ذَلِكَ فَقَالَ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد قَالَ أَحْمَدُ يُعْجِبُنِي فِي الْفَرِيضَةِ أَنْ يَدْعُوَ بِمَا فِي الْقُرْآنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Musa bin Abu Aisyah] dia berkata; \" [Seseorang] shalat diatas rumahnya, apabila ia selesai membaca ayat \"alaisa dzaalika bi qaadirin 'ala an yuhyiyal mauta\" (Bukankah Dzat yang demikian itu lebih mampu untuk menghidupkan yang mati)?\" maka dia mengucapkan \"subhanaka\" lalu menangis. Mereka bertanya kepada laki-laki tersebut tentang perbuatannya itu, dia menjawab bahwa dirinya pernah mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\" Abu Daud berkata: Ahmad berkata: \"Aku lebih suka dalam shalat wajib membaca do'a-do'a yang ada dalam Al Qur'an.\""},"738":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ السَّعْدِيِّ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ قَالَرَمَقْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاتِهِ فَكَانَ يَتَمَكَّنُ فِي رُكُوعِهِ وَسُجُودِهِ قَدْرَ مَا يَقُولُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid bin Abdullah] telah menceritakan kepada kami [Sa'id Al Jurairi] dari [As Sa'di] dari [ayahnya] atau dari [pamannya] dia berkata; \"Aku memperhatikan Nabi shallallahu 'alaihi wasallam pada waktu shalat, maka beliau tenang dalam ruku' dan sujudnya sebatas membaca; 'Subhanallah wa bihamdihi (Maha suci Allah dengan segala puji-pujian-Nya).\" sebanyak tiga kali. "},"739":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ الْأَهْوَازِيُّ حَدَّثَنَا أَبُو عَامِرٍ وَأَبُو دَاوُدَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ إِسْحَقَ بْنِ يَزِيدَ الْهُذَلِيِّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ أَحَدُكُمْ فَلْيَقُلْ ثَلَاثَ مَرَّاتٍ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَذَلِكَ أَدْنَاهُ وَإِذَا سَجَدَ فَلْيَقُلْ سُبْحَانَ رَبِّيَ الْأَعْلَى ثَلَاثًا وَذَلِكَ أَدْنَاهُقَالَ أَبُو دَاوُد هَذَا مُرْسَلٌ عَوْنٌ لَمْ يُدْرِكْ عَبْدَ اللَّهِ","id":"Telah menceritakan kepada kami [Abdul Malik bin Marwan Al Ahwazi] telah menceritakan kepada kami [Abu 'Amir] dan [Abu Daud] dari [Ibnu Abu Dzi`b] dari [Ishaq bin Yazid Al Hudzali] dari ['Aun bin Abdullah] dari [Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian ruku' maka ucapkanlah \"Subhaana Rabbiyal 'adziim\" sebanyak tiga kali. Apabila sujud, maka ucapkanlah \"subhaana Rabbiyal a'la\" sebanyak tiga kali.\" Abu Daud berkata: \"Ini adalah hadits mursal, sebab 'Aun tidak pernah bertemu dengan Abdullah. "},"740":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ سَمِعْتُ أَعْرَابِيًّا يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ مِنْكُمْ{ وَ��لتِّينِ وَالزَّيْتُونِ }فَانْتَهَى إِلَى آخِرِهَا{ أَلَيْسَ اللَّهُ بِأَحْكَمِ الْحَاكِمِينَ }فَلْيَقُلْ بَلَى وَأَنَا عَلَى ذَلِكَ مِنْ الشَّاهِدِينَ وَمَنْ قَرَأَ{ لَا أُقْسِمُ بِيَوْمِ الْقِيَامَةِ }فَانْتَهَى إِلَى{ أَلَيْسَ ذَلِكَ بِقَادِرٍ عَلَى أَنْ يُحْيِيَ الْمَوْتَى }فَلْيَقُلْ بَلَى وَمَنْ قَرَأَ{ وَالْمُرْسَلَاتِ }فَبَلَغَ{ فَبِأَيِّ حَدِيثٍ بَعْدَهُ يُؤْمِنُونَ }فَلْيَقُلْ آمَنَّا بِاللَّهِقَالَ إِسْمَعِيلُ ذَهَبْتُ أُعِيدُ عَلَى الرَّجُلِ الْأَعْرَابِيِّ وَأَنْظُرُ لَعَلَّهُ فَقَالَ يَا ابْنَ أَخِي أَتَظُنُّ أَنِّي لَمْ أَحْفَظْهُ لَقَدْ حَجَجْتُ سِتِّينَ حَجَّةً مَا مِنْهَا حَجَّةٌ إِلَّا وَأَنَا أَعْرِفُ الْبَعِيرَ الَّذِي حَجَجْتُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Isma'il bin Umayyah] saya mendengar [seorang arab badui] berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian membaca; \"WAT TIIN WAZ ZAITUN (Demi (buah) Tin dan (buah) Zaitun), \" sampai akhir ayat \"ALAISALLAHU BI AHKAMIL HAAKIMIIN (Bukankah Allah hakim yang seadil-adilnya?) \" hendaknya ia mengucapkan; \"Benar, dan kami menjadi saksi untuk itu.\" Dan barangsiapa membaca; \"LAA UQSIMU BIYAUMIL QIYAAMAH (Aku bersumpah demi hari kiamat), hingga akhir ayat \"ALAISA DZAALIKA BI QAADIRIN `ALAA AIYYUHYIYAL MAUTA (Bukankah (Allah yang berbuat) demikian berkuasa (pula) menghidupkan orang mati?), maka hendaklah ia mengatakan; benar.\" Dan barangsiapa membaca; WAL MURSALAATI `URFA (Demi malaikat-malaikat yang diutus untuk membawa kebaikan) sampai dengan; FA BIAIYYI HADITSIN BA`DAHU YU`MINUN (Maka kepada perkataan apakah sesudah Al Quraan ini mereka akan beriman?), maka hendaknya ia mengatakan; aku beriman kepada Allah.\" Isma'il berkata: aku pergi untuk melihat apakah dia menjaganya, Dan dia adalah seorang badui, dia berkata; \"wahai saudaraku, apakah kamu mengira bahwa aku tidak menjaganya, sungguh aku telah berhaji sebanyak enam puluh kali, tidaklah ada pada satu tahun pun kecuali aku mengetahui unta yang dulu aku pakai untuk berhaji.\""},"741":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَابْنُ رَافِعٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِبْرَاهِيمَ بْنِ عُمَرَ بْنِ كَيْسَانَ حَدَّثَنِي أَبِي عَنْ وَهْبِ بْنِ مَانُوسَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُمَا صَلَّيْتُ وَرَاءَ أَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْبَهَ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ هَذَا الْفَتَى يَعْنِي عُمَرَ بْنَ عَبْدِ الْعَزِيزِ قَالَ فَحَزَرْنَا فِي رُكُوعِهِ عَشْرَ تَسْبِيحَاتٍ وَفِي سُجُودِهِ عَشْرَ تَسْبِيحَاتٍقَالَ أَبُو دَاوُد قَالَ أَحْمَدُ بْنُ صَالِحٍ قُلْتُ لَهُ مَانُوسُ أَوْ مَابُوسُ قَالَ أَمَّا عَبْدُ الرَّزَّاقِ فَيَقُولُ مَابُوسُ وَأَمَّا حِفْظِي فَمَانُوسُ وَهَذَا لَفْظُ ابْنِ رَافِعٍ قَالَ أَحْمَدُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Ibnu Rafi'] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Ibrahim bin Umar bin Kaisan] telah menceritakan kepadaku [ayahku] dari [Wahb bin Manus] dia berkata; saya mendengar [Sa'id bin Jubair] berkata; saya mendengar [Anas bin Malik] berkata; saya tidak pernah shalat di belakang seorang pun setelah Rasulullah shallallahu 'alaihi wasallam yang shalatnya menyerupai shalat Rasulullah shallallahu 'alaihi wasallam selain pemuda ini -yaitu Umar bin Abdul Aziz- Anas mengatakan; 'Kami memperkirakan dalam ruku'nya beliau mengucapkan sepuluh kali tasbih.\" Abu Daud mengatakan; Ahmad bin Shalih mengatakan; kataku kepada Manus atau Mabus -perawi berkata; Abdurrazaq mengatakan \"Mabus\" sedangkan yang ku hafal adalah Manus, ini adalah lafadznya Ibnu Rafi'. Ahmad mengatakan; dari Sa'id bin Jubair dari Anas bin Malik.\""},"742":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ قَالَ حَمَّادٌ أُمِرَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةٍ وَلَا يَكُفَّ شَعْرًا وَلَا ثَوْبًا","id":"Telah menceritakan kepada kami [Musaddad] dan [Sulaiman bin Harb] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"aku di perintah\" sedangkan Hammad mengatakan; Nabi kalian shallallahu 'alaihi wasallam di perintah supaya melakukan sujud atas tujuh anggota badan, dan supaya seseorang tidak menahan rambut dan kainnya ketika sujud.\""},"743":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ وَرُبَّمَا قَالَ أُمِرَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ آرَابٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Syu'bah] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Aku di perintah\" atau sepertinya bersabda: \"Nabi kalian shallallahu 'alaihi wasallam telah di perintahkan supaya melakukan sujud atas tujuh macam anggota badan.\""},"744":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ ابْنِ الْهَادِي عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدَمَاهُ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakr yaitu Ibnu Mudlar] dari [Ibnu Al Hadi] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'd] dari [Abbas bin Abdul Mutthalib] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang hamba melakukan sujud, hendaknya ia sujud bersama tujuh anggota badannya, yaitu; keningnya (wajahnya), kedua telapak tangannya, kedua lututnya dan kedua kakinya.\""},"745":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَرَفَعَهُ قَالَ إِنَّ الْيَدَيْنِ تَسْجُدَانِ كَمَا يَسْجُدُ الْوَجْهُ فَإِذَا وَضَعَ أَحَدُكُمْ وَجْهَهُ فَلْيَضَعْ يَدَيْهِ وَإِذَا رَفَعَهُ فَلْيَرْفَعْهُمَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Isma'il yuitu Ibnu Ibrahim] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] yang ia marfu'kan kepada Nabi, \"Sesungguhnya kedua tangan bersujud sebagaimana wajah bersujud, apabila salah seorang dari kalian meletakkan wajah, hendaklah dia meletakkan kedua (telapak) tangannya dan apabila mengangkat wajahnya, hendaklah dia mengangkat kedua (telapak) tangannya.\""},"746":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَنَّ سَعِيدَ بْنَ الْحَكَمِ حَدَّثَهُمْ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ حَدَّثَنِي يَحْيَى بْنُ أَبِي سُلَيْمَانَ عَنْ زَيْدِ بْنِ أَبِي الْعَتَّابِ وَابْنِ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جِئْتُمْ إِلَى الصَّلَاةِ وَنَحْنُ سُجُودٌ فَاسْجُدُوا وَلَا تَعُدُّوهَا شَيْئًا وَمَنْ أَدْرَكَ الرَّكْعَةَ فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] bahwa [Sa'id bin Al Hakam] telah menceritakan kepada mereka, telah mengabarkan kepada kami [Nafi' bin Yazid] telah menceritakan kepadaku [Yahya bin Abu Sulaiman] dari [Zaid bin Abu Al 'Attab] dan [Ibnu Al Maqburi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian datang untuk menunaikan shalat, sedangkan kami dalam keadaan sujud, maka ikutlah bersujud, dan janganlah kalian menghitungnya satu raka'at, dan barangsiapa mendapatkan ruku', berarti dia telah mendapatkan shalat (satu raka'at -pent).\""},"747":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُئِيَ عَلَى جَبْهَتِهِ وَعَلَى أَرْنَبَتِهِ أَثَرُ طِينٍ مِنْ صَلَاةٍ صَلَّاهَا بِالنَّاسِحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Sufwan bin Isa] telah menceritakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam terlihat pada dahi dan ujung hidung beliau terdapat bekas tanah dari mengerjakan shalat bersama orang-orang.\" Telah menceritakan kepada kami [Muhamad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] seperti hadits di atas.\""},"748":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ قَالَوَصَفَ لَنَا الْبَرَاءُ بْنُ عَازِبٍ فَوَضَعَ يَدَيْهِ وَاعْتَمَدَ عَلَى رُكْبَتَيْهِ وَرَفَعَ عَجِيزَتَهُ وَقَالَ هَكَذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ","id":"Telah menceritakan kepada kami [Ar Rabi'ah' bin Nafi' Abu Taubah] telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dia berkata; [Al Barra` bin 'Azib] menjelaskan sujud kepada kami, maka ia meletakkan kedua tangannya dan mengangkat perutnya dari menempel tanah. Al Barra berkata; Beginilah Rasulullah Shalallahu 'Alaihi Wa sallam sujud.\""},"749":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَفْتَرِشْ أَحَدُكُمْ ذِرَاعَيْهِ افْتِرَاشَ الْكَلْبِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'sempurnakanlah ketika kalian sujud dan janganlah salah seorang dari kalian membentangkan kedua lengannya seperti seekor anjing.\""},"750":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَمِّهِ يَزِيدَ بْنِ الْأَصَمِّ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ جَافَى بَيْنَ يَدَيْهِ حَتَّى لَوْ أَنَّ بَهْمَةً أَرَادَتْ أَنْ تَمُرَّ تَحْتَ يَدَيْهِ مَرَّتْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Abdullah] dari [pamannya Yazid bin Al Asham] dari [Maimunah] bahwa apabila Nabi shallallahu 'alaihi wasallam sujud, beliau merenggangkan antara kedua tangannya sehingga seandainya ada seekor anak kambing yang hendak lewat di bawah kedua tangan beliau, tentu ia akan melewatinya.\""},"751":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ التَّمِيمِيِّ الَّذِي يُحَدِّثُ بِالتَّفْسِيرِ عَنْ ابْنِ عَبَّاسٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَلْفِهِ فَرَأَيْتُ بَيَاضَ إِبِطَيْهِ وَهُوَ مُجَخٍّ قَدْ فَرَّجَ بَيْنَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] dari [At Taimi] yang menceritakan dengan tafsir, dari [Ibnu Abbas] dia berkata; saya menemui Nabi shallallahu 'alaihi wasallam dari belakang beliau, lalu aku melihat putih ketiaknya ketika beliau menungging (sujud), beliau merenggangkan antara kedua tangannya.\""},"752":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا أَحْمَرُ بْنُ جَزْءٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَ�� سَجَدَ جَافَى عَضُدَيْهِ عَنْ جَنْبَيْهِ حَتَّى نَأْوِيَ لَهُ","id":"telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami ['Abbad bin Rasyid] telah menceritakan kepada kami [Al Hasan] telah menceritakan kepada kami [Ahmar bin Juz`in] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam bahwa apabila Rasulullah shallallahu 'alaihi wasallam sujud, beliau merenggangkan kedua lengannya dari kedua rusuk beliau sehingga kami amat kasihan terhadap beliau.\""},"753":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا اللَّيْثُ عَنْ دَرَّاجٍ عَنْ ابْنِ حُجَيْرَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَجَدَ أَحَدُكُمْ فَلَا يَفْتَرِشْ يَدَيْهِ افْتِرَاشَ الْكَلْبِ وَلْيَضُمَّ فَخْذَيْهِ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Al Laits] dari [Darraj] dari [Ibnu Hujairah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian sujud, janganlah ia membentangkan kedua tangannya ke lantai sebagaimana seekor anjing, dan hendaklah ia meletakkan di kedua pahanya.\""},"754":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَاشْتَكَى أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَشَقَّةَ السُّجُودِ عَلَيْهِمْ إِذَا انْفَرَجُوا فَقَالَ اسْتَعِينُوا بِالرُّكَبِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; para sahabat Nabi shallallahu 'alaihi wasallam mengadu kepada beliau tentang sulitnya sujud mereka jika harus menjauhkan kedua tangan dari kedua rusuk dan menjauhkan perut dari kedua paha, maka beliau bersabda: \"Gunakanklah lutut-lutut kalian.\""},"755":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ سَعِيدِ بْنِ زِيَادٍ عَنْ زِيَادِ بْنِ صَبِيحٍ الْحَنَفِيِّ قَالَصَلَّيْتُ إِلَى جَنْبِ ابْنِ عُمَرَ فَوَضَعْتُ يَدَيَّ عَلَى خَاصِرَتَيَّ فَلَمَّا صَلَّى قَالَ هَذَا الصَّلْبُ فِي الصَّلَاةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] dari [Waki'] dari [Sa'id bin Ziyad] dari [Ziyad bin Shabih Al Hanafi] dia berkata; saya shalat di samping [Ibnu Umar], lalu aku meletakkan kedua tanganku pada kedua lambungku (bertolak pinggang), seusainya shalat, dia berkata; \"Ini adalah salib dalam shalat, dan Rasulullah shallallahu 'alaihi wasallam melarang perbuatan seperti ini.\""},"756":{"ar":"حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ هَارُونَ أَخْبَرَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ ثَابِتٍ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَفِي صَدْرِهِ أَزِيزٌ كَأَزِيزِ الرَّحَى مِنْ الْبُكَاءِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Muhammad bin Salam] telah menceritakan kepada kami [Yazid yaitu Ibnu Harun] telah mengabarkan kepada kami [Hammad yaitu Ibnu Salamah] dari [Tsabit] dari [Mutharif] dari [ayahnya] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, sedang dalam dada beliau terdengar bunyi seperti batu penggiling gandum karena tangisan beliau shallallahu 'alaihi wasallam.\""},"757":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا هِشَامٌ يَعْنِي ابْنَ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ فَأَحْسَنَ وُضُوءَهُ ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يَسْهُو فِيهِمَا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah menceritakan kepada kami [Hisyam yaitu Ibnu Sa'd] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Zaid bin Khalid Al Juhani] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu dan menyempurnakan wudlunya, kemudian shalat dua raka'at, tidak berbuat lalai, maka dosa-dosanya yang telah lalu akan terampuni.\""},"758":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ يَتَوَضَّأُ فَيُحْسِنُ الْوُضُوءَ وَيُصَلِّي رَكْعَتَيْنِ يُقْبِلُ بِقَلْبِهِ وَوَجْهِهِ عَلَيْهِمَا إِلَّا وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dari [Jubair bin Nufair Al Hadlrami] dari ['Uqbah bin 'Amir Al Juhani] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah salah seorang dari kalian yang berwudlu, dan menyempurnakan wudlunya kemudian shalat (sunnah) dua raka'at dengan menghadapkan hati dan mukanya (khusyu' dan ikhlas) melainkan ia berhak mendapatkan surga.\""},"759":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَسُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ قَالَا أَخْبَرَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَحْيَى الْكَاهِلِيِّ عَنْ الْمُسَوَّرِ بْنِ يَزِيدَ الْأَسَدِيِّ الْمَالِكِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَحْيَى وَرُبَّمَا قَالَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الصَّلَاةِ فَتَرَكَ شَيْئًا لَمْ يَقْرَأْهُ فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ تَرَكْتَ آيَةَ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَّا أَذْكَرْتَنِيهَا قَالَ سُلَيْمَانُ فِي حَدِيثِهِ قَالَ كُنْتُ أُرَاهَا نُسِخَتْو قَالَ سُلَيْمَانُ قَالَ حَدَّثَنِي يَحْيَى بْنُ كَثِيرٍ الْأَزْدِيُّ قَالَ حَدَّثَنَا الْمُسَوَّرُ بْنُ يَزِيدَ الْأَسَدِيُّ الْمَالِكِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] dan [Sulaiman bin Abdurrahman Ad Dimasyqi] keduanya berkata; telah mengabarkan kepada kami [Marwan bin Mu'awiyah] dari [Yahya Al Kahili] dari [Al Musawwir bin Yazid Al Asadi Al Maliki] bahwa Rasulullah shallallahu 'alaihi wasallam -Yahya mengatakan; \"dan sepertinya Musawir mengatakan; \"Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam membaca surat Al Qur'an dalam shalat, kemudian beliau meninggalkan suatu ayat, dan tidak di bacanya. Maka ada seseorang berkata kepada beliau; \"Wahai Rasulullah, Anda telah meninggalkan ayat ini dan ini.\" lantas Rasulullah shallallahu 'alaihi wasallam bersabda; \"Mengapa kamu tidak mengingatkan aku tentang ayat itu?\" Sulaiman berkata dalam haditsnya; Pendapatku bahwa ayat tersebut telah di nasakh (di hapus).\" Sulaiman mengatakan; telah menceritakan kepadaku Yahya bin Katsir Al Azdi dia berkata; telah menceritakan kepada kami Al Musawwar bin Yazid Al Asadi Al Maliki.\""},"760":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ مُحَمَّدٍ الدِّمَشْقِيُّ حَدَّثَنَا هِشَامُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ بْنِ زَبْرٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةً فَقَرَأَ فِيهَا فَلُبِسَ عَلَيْهِ فَلَمَّا انْصَرَفَ قَالَ لِأُبَيٍّ أَصَلَّيْتَ مَعَنَا قَالَ نَعَمْ قَالَ فَمَا مَنَعَكَ","id":"Telah menceritakan kepada kami [Yazid bin Muhammad Ad Dimasyqi] telah menceritakan kepada kami [Hisyam bin Isma'il] telah menceritakan kepada kami [Muhammad bin Syu'aib] telah mengabarkan kepada kami [Abdullah bin Al 'Ala` bin Zabr] dari [Salim bin Abdullah] dari [Abdullah bin Umar] bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat dan membaca (beberapa ayat Al Qur'an) dalam shalatnya, dan beliau terbalik-balik dalam bacaannya, seusai shalat beliau bersabda kepada Ubay: \"Apakah kamu tadi ikut shalat bersama kami?\" Ubay menjawab; \"Ya.\" Sabda beliau: \"Apa yang mencegahmu (untuk tidak membenarkan tentang ayat tadi)?\""},"761":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ لَا تَفْتَحْ عَلَى الْإِمَامِ فِي الصَّلَاةِقَالَ أَبُو دَاوُد أَبُو إِسْحَقَ لَمْ يَسْمَعْ مِنْ الْحَارِثِ إِلَّا أَرْبَعَةَ أَحَادِيثَ لَيْسَ هَذَا مِنْهَا","id":"Telah menceritakan kepada kami [Abdul Wahab bin Najdah] telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyabi] dari [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari [Al Harits] dari [Ali radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ali, janganlah kamu mendahului imam dalam shalat.\" Abu Daud mengatakan; \"Abu Ishaq belum pernah mendengar dari Al Harits kecuali hanya empat hadits, padahal hadits ini tidak termasuk dari yang empat itu.\""},"762":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ يُحَدِّثُنَا فِي مَجْلِسِ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ قَالَ أَبُو ذَرٍّقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ اللَّهُ عَزَّ وَجَلَّ مُقْبِلًا عَلَى الْعَبْدِ وَهُوَ فِي صَلَاتِهِ مَا لَمْ يَلْتَفِتْ فَإِذَا الْتَفَتَ انْصَرَفَ عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; saya mendengar [Abu Al Ahwash] telah menceritakan kepada kami ketika di Majlis Ibnu Al Musayyab, dia berkata; [Abu Dzar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla senantiasa menghadap kepada seorang hamba dalam shalatnya selama dia tidak menoleh, apabila ia menoleh, maka Allah pun berpaling darinya.\""},"763":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَشْعَثِ يَعْنِي ابْنَ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْتِفَاتِ الرَّجُلِ فِي الصَّلَاةِ فَقَالَ إِنَّمَا هُوَ اخْتِلَاسٌ يَخْتَلِسُهُ الشَّيْطَانُ مِنْ صَلَاةِ الْعَبْدِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al Asy'ats yaitu Ibnu Sulaim] dari [ayahnya] dari [Masruq] dari [Aisyah radliallahu 'anha] dia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam perihal menolehnya seseorang dalam shalatnya, beliau menjawab: \"Itu merupakan suatu bentuk perampasaan yang di kerjakan syetan terhadap shalat seorang hamba.\""},"764":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا عِيسَى عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُئِيَ عَلَى جَبْهَتِهِ وَعَلَى أَرْنَبَتِهِ أَثَرُ طِينٍ مِنْ صَلَاةٍ صَلَّاهَا بِالنَّاسِقَالَ أَبُو عَلِيٍّ هَذَا الْحَدِيثُ لَمْ يَقْرَأْهُ أَبُو دَاوُدَ فِي الْعَرْضَةِ الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Mu'ammal bin Al Fadl] telah menceritakan kepada kami [Isa] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam terlihat pada dahi dan ujung hidung beliau ada bekas tanah, setelah mengerjakan shalat bersama orang-orang.\" Abu Ali mengatakan; \"Hadits ini tidak di baca oleh Abu Daud di pemaparan yang ke empat.\""},"765":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ وَهَذَا حَدِيثُهُ وَهُوَ أَتَمُّ عَنْ الْأَعْمَشِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ الطَّائِيِّ عَنْ جَابِرِ بْنِ سَمُرَةَقَالَ عُثْمَانُ قَالَ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ فَرَأَى فِيهِ نَاسًا يُصَلُّونَ رَافِعِي أَيْدِيهِمْ إِلَى السَّمَاءِ ثُمَّ اتَّفَقَا فَقَالَ لَيَنْتَهِيَنَّ رِجَالٌ يَشْخَصُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ قَالَ مُسَدَّدٌ فِي الصَّلَاةِ أَوْلَا تَرْجِعُ إِلَيْهِمْ أَبْصَارُهُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Mu'awiyah]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dan ini merupakan hadits darinya dan lebih sempurna, dari [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim bin Tharafah Ath Tha`i] dari [Jabir bin Samurah] dia berkata; -Utsman berkata; \"Rasulullah shallallahu 'alaihi wasallam masuk masjid, lalu beliau melihat orang-orang tengah mengerjakan shalat sambil mengangkat tangan mereka (menengadah) ke langit, -kemudian riwayat Utsman dan Musaddad bersambung- beliau bersabda: \"Hendaklah orang-orang berhenti mengangkat pandangan mereka ke langit pada waktu shalat,.\" -Musaddad menambahkan; \"ataukah (mereka) ingin penglihatan mereka tidak dikembalikan lagi?\""},"766":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ أَقْوَامٍ يَرْفَعُونَ أَبْصَارَهُمْ فِي صَلَاتِهِمْ فَاشْتَدَّ قَوْلُهُ فِي ذَلِكَ فَقَالَ لَيَنْتَهُنَّ عَنْ ذَلِكَ أَوْ لَتُخْطَفَنَّ أَبْصَارُهُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sa'id bin Abu 'Arubah] dari [Qatdah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengapa orang-orang masih saja mengangkat pandangan mereka (ke atas) pada waktu shalat?\" dan ucapan beliau (terdengar) sangat mengecam perbuatan tersebut, lalu beliau bersabda: \"Hendaklah mereka berhenti melakukan hal itu atau mereka ingin penglihatan mereka di hilangkan?\""},"767":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَمِيصَةٍ لَهَا أَعْلَامٌ فَقَالَ شَغَلَتْنِي أَعْلَامُ هَذِهِ اذْهَبُوا بِهَا إِلَى أَبِي جَهْمٍ وَأْتُونِي بِأَنْبِجَانِيَّتِهِحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ أَبِي الزِّنَادِ قَالَ سَمِعْتُ هِشَامًا يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَائِشَةَ بِهَذَا الْخَبَرِ قَالَ وَأَخَذَ كُرْدِيًّا كَانَ لِأَبِي جَهْمٍ فَقِيلَ يَا رَسُولَ اللَّهِ الْخَمِيصَةُ كَانَتْ خَيْرًا مِنْ الْكُرْدِيِّ","id":"Telah menceritakan kepada kami [Utsman bin Abu syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat dengan memakai pakaian bergambar, kemudian beliau bersabda: \"Gambar-gambar pada pakaian ini telah mengganggu perhatianku, kembalikanlah ia kepada Abu Jahm dan tukarlah dengan pakaian bulu kasar yang tidak bergambar.\" Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abdurrahman yaitu Ibnu Abu Az Zannad] dia berkata; saya mendengar [Hisyam] menceritakan dari [ayahnya] dari [Aisyah] dengan hadits seperti ini, katanya; \"Dan beliau mengambil kain Kurdi milik Abu Jahm, lalu di katakan; \"Wahai Rasulullah, kain yang bergambar tadi lebih bagus dari kain Kurdi.\""},"768":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي السَّلُولِيُّ هُوَ أَبُو كَبْشَةَ عَنْ سَهْلِ ابْنِ الْحَنْظَلِيَّةِ قَالَثُوِّبَ بِالصَّلَاةِ يَعْنِي صَلَاةَ الصُّبْحِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ يَلْتَفِتُ إِلَى الشِّعْبِقَالَ أَبُو دَاوُد وَكَانَ أَرْسَلَ فَارِسًا إِلَى الشِّعْبِ مِنْ اللَّيْلِ يَحْرُسُ","id":"Telah menceritakan kepada kami [Ar Rabi' bin nafi'] telah menceritakan kepada kami [Mu'awiyah yaitu Ibnu Sallam] dari [Zaid] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [As Saluli yaitu Abu Kabsyah] dari [Sahl bin Handzaliyah] dia berkata; \"Iqamat shalat subuh telah di kumandangkan, lalu Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan shalat, (dalam shalatnya) beliau menoleh ke arah jalan setapak di bukit.\" -Abu Daud berkata; Waktu itu beliau mengutus pasukan penunggang kuda ke jalan setapak di bukit untuk berjaga-jaga pada malam hari.\""},"769":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهُوَ حَامِلٌ أُمَامَةَ بِنْتَ زَيْنَبَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا سَجَدَ وَضَعَهَا وَإِذَا قَامَ حَمَلَهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Malik] dari ['Amir bin Abdullah bin Az Zubair] dari ['Amru bin Sulaim] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sambil menggendong Umamah binti Zainab binti Rasulullah shallallahu 'alaihi wasallam, apabila beliau sujud, beliau menaruh Umamah, dan apabila berdiri beliau menggendongnya.\""},"770":{"ar":"حَدَّثَنَا قُتَيْبَةُ يَعْنِي ابْنَ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ أَنَّهُ سَمِعَ أَبَا قَتَادَةَ يَقُولُبَيْنَا نَحْنُ فِي الْمَسْجِدِ جُلُوسٌ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُ أُمَامَةَ بِنْتَ أَبِي الْعَاصِ بْنِ الرَّبِيعِ وَأُمُّهَا زَيْنَبُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ صَبِيَّةٌ يَحْمِلُهَا عَلَى عَاتِقِهِ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ عَلَى عَاتِقِهِ يَضَعُهَا إِذَا رَكَعَ وَيُعِيدُهَا إِذَا قَامَ حَتَّى قَضَى صَلَاتَهُ يَفْعَلُ ذَلِكَ بِهَا","id":"Telah menceritakan kepada kami [Qutaibah yaitu Ibnu Sa'id] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari ['Amru bin Sulaim Az Zuraqi] bahwa dia mendengar [Abu Qatadah] berkata; \"Ketika kami duduk-duduk di Masjid, Rasulullah shallallahu 'alaihi wasallam muncul menemui kami sambil menggendong Umamah binti Abu Al 'Ash bin Ar Rabi' -ibunya adalah Zainab binti Rasulullah shallallahu 'alaihi wasallam- ketika itu Umamah masih kacil, beliau menggendongnya di atas pundak, kemudian Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, sedangkan Umamah masih di atas pundak beliau, apabila ruku' beliau meletakkan Umamah, jika berdiri, beliau menggendongnya kembali. beliau melakukan yang demikian itu hingga selesai shalat.\""},"771":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ مَخْرَمَةَ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ قَالَ سَمِعْتُ أَبَا قَتَادَةَ الْأَنْصَارِيَّ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لِلنَّاسِ وَأُمَامَةُ بِنْتُ أَبِي الْعَاصِ عَلَى عُنُقِهِ فَإِذَا سَجَدَ وَضَعَهَاقَالَ أَبُو دَاوُد وَلَمْ يَسْمَعْ مَخْرَمَةُ مِنْ أَبِيهِ إِلَّا حَدِيثًا وَاحِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Ibnu Wahb] dari [Makhramah] dari [ayahnya] dari ['Amru bin Sulaim Az Zuraqi] dia berkata; saya mendengar [Abu Qatadah Al Anshari] berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam shalat bersama orang-orang, sedangkan Umamah binti Abu Al 'Ash berada di tengkuk beliau, apabila sujud, beliau meletakkannya.\" Abu Daud berkata; \"Al Makhramah tidak pernah mendengar hadits dari Ayahnya kecuali hanya satu hadits.\""},"772":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَبَيْنَمَا نَحْنُ نَنْتَظِرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ فِي الظُّهْرِ أَوْ الْعَصْرِ وَقَدْ دَعَاهُ بِلَالٌ لِلصَّلَاةِ إِذْ خَرَجَ إِلَيْنَا وَأُمَامَةُ بِنْتُ أَبِي الْعَاصِ بِنْتُ ابْنَتِهِ عَلَى عُنُقِهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مُصَلَّاهُ وَقُمْنَا خَلْفَهُ وَهِيَ فِي مَكَانِهَا الَّذِي هِيَ فِيهِ قَالَ فَكَبَّرَ فَكَبَّرْنَا قَالَ حَتَّى إِذَا أَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَرْكَعَ أَخَذَهَا فَوَضَعَهَا ثُمَّ رَكَعَ وَسَجَدَ حَتَّى إِذَا فَرَغَ مِنْ سُجُودِهِ ثُمَّ قَامَ أَخَذَهَا فَرَدَّهَا فِي مَكَانِهَا فَمَا زَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ بِهَا ذَلِكَ فِي كُلِّ رَكْعَةٍ حَتَّى فَرَغَ مِنْ صَلَاتِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Muhammad yakni Ibnu Ishaq] dari [Sa'id bin Abu Sa'id Al Maqburi] dari ['Amru bin Sulaim Az Zuraqi] dari [Abu Qatadah] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, katanya; \"Katika kami menunggu Rasulullah shallallahu 'alaihi wasallam untuk mengerjakan shalat dluhur atau shalat Ashar (berjama'ah), dan Bilal pun telah mengumandangkan iqamah untuk shalat, tiba-tiba beliau muncul menggendong Umamah anak putrinya (Zainab) di tengkuk beliau, kemudian Rasulullah shallallahu 'alaihi wasallam shalat sedangkan kami berada di belakang beliau, sementara Umamah masih dalam posisinya semula.\" Abu Qatadah berkata; \"Kamudian beliau bertakbir, kami pun bertakbir, sehingga ketika beliau hendak ruku', beliau mengambil dari tengkuknya dan meletakkannya, lalu beliau ruku' dan sujud, seusainya sujud dan hendak berdiri, beliau mengambilnya lagi dan meletakkan kembali di posisi semula, Rasulullah shallallahu 'alaihi wasallam melakukan yang demikian itu di setiap raka'atnya hingga selesai dari shalatnya shallallahu 'alaihi wasallam.\""},"773":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ ضَمْضَمِ بْنِ جَوْسٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوا الْأَسْوَدَيْنِ فِي الصَّلَاةِ الْحَيَّةَ وَالْعَقْرَبَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Ali bin Al Mubarrak] dari [Yahya bin Abu Katsir] dari [Dlamdlam bin Jaus] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah dua binatang hitam dalam shalat, yaitu ular dan kalajengking.\""},"774":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ وَهَذَا لَفْظُهُ قَالَ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ حَدَّثَنَا بُرْدٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْمَدُ يُصَلِّي وَالْبَابُ عَلَيْهِ مُغْلَقٌ فَجِئْتُ فَاسْتَفْتَحْتُ قَالَ أَحْمَدُ فَمَشَى فَفَتَحَ لِي ثُمَّ رَجَعَ إِلَى مُصَلَّاهُوَذَكَرَ أَنَّ الْبَابَ كَانَ فِي الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] sedangkan ini adalah lafadznya Musaddad, katanya; telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadlal] telah menceritakan kepada kami [Burd] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam -Ahmad berkata- Sedang mengerjakan shalat, sementara pintu dalam keadaan tertutup, ketika aku datang, aku minta dibukakan pintu -Ahmad berkata- maka beliau berjalan dan membukakan pintu untukku lalu beliau kembali lagi ketempat shalatnya.\" disebutkan ketika itu pintu berada di arah kiblatnya. "},"775":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نُسَلِّمُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَيَرُدُّ عَلَيْنَا فَلَمَّا رَجَعْنَا مِنْ عِنْدِ النَّجَاشِيِّ سَلَّمْنَا عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْنَا وَقَالَ إِنَّ فِي الصَّلَاةِ لَشُغْلًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ibnu Fudlail] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata; \"Kami memberi salam kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang shalat, lalu beliau menjawab salam kami, ketika kami tiba dari negeri Najasyi, kami memberi salam kepada beliau, namun beliau tidak menjawab salam kami, setelah itu beliau bersabda: \"Sesunggunya dalam shalat benar-benar ada kesibukan.\""},"776":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نُسَلِّمُ فِي الصَّلَاةِ وَنَأْمُرُ بِحَاجَتِنَا فَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ السَّلَامَ فَأَخَذَنِي مَا قَدُمَ وَمَا حَدُثَ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ إِنَّ اللَّهَ يُحْدِثُ مِنْ أَمْرِهِ مَا يَشَاءُ وَإِنَّ اللَّهَ جَلَّ وَعَزَّ قَدْ أَحْدَثَ مِنْ أَمْرِهِ أَنْ لَا تَكَلَّمُوا فِي الصَّلَاةِ فَرَدَّ عَلَيَّ السَّلَامَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami ['Ashim] dari [Abu Wa'il] dari [Abdullah] dia berkata; \"Kami pernah memberi salam dalam shalat dan memerintahkan supaya hajat kami di penuhi, kemudian kami datang menemui Rasulullah shallallahu 'alaihi wasallam, ketika itu beliau sedang mengerjakan shalat, lantas aku pun memberi salam kepadanya, namun beliau tidak menjawab salamku, sehingga aku teringat dengan masa laluku dan masa sekarang,. Ketika shalat selesai, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menetapkan perintah-Nya sesuai kehendak-Nya, dan Allah Jalla wa 'Azza telah menetapkan perintah-Nya yaitu janganlah kamu berbicara ketika sedang shalat.\" kemudian beliau menjawab salamku.\""},"777":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ أَنَّ اللَّيْثَ حَدَّثَهُمْ عَنْ بُكَيْرٍ عَنْ نَابِلٍ صَاحِبِ الْعَبَاءِ عَنْ ابْنِ عُمَرَ عَنْ صُهَيْبٍ أَنَّهُ قَالَمَرَرْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَرَدَّ إِشَارَةً قَالَ وَلَا أَعْلَمُهُ إِلَّا قَالَ إِشَارَةً بِأُصْبُعِهِوَهَذَا لَفْظُ حَدِيثِ قُتَيْبَةَ","id":"telah menceritakan kepada kami [Yazid bin Khalid bin Mauhab] dan [Qutaibah bin Sa'id] bahwa [Al Laitsi] telah menceritakan kepada meeka dari [Bukair] dari [Nabil sahabatnya 'Aba`] dari [Ibnu Umar] dari [Suhaib] dia berkata; \"Aku melewati Rasulullah shallallahu 'alaihi wasallam, sementara beliau dalam keadaan shalat, lalu aku mengucapkan salam kepadanya, dan beliau menjawabnya dengan isyarat.\" Nabil berkata; \"Aku tidak mengetahui kecuali Ibnu Umar berkata; 'Bahwa isyarat beliau dengan menggunakan jari jemarinya.\" Lafadz hadits ini dari Qutaibah. "},"778":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَرْسَلَنِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَنِى الْمُصْطَلَقِ فَأَتَيْتُهُ وَهُوَ يُصَلِّي عَلَى بَعِيرِهِ فَكَلَّمْتُهُ فَقَالَ لِي بِيَدِهِ هَكَذَا ثُمَّ كَلَّمْتُهُ فَقَالَ لِي بِيَدِهِ هَكَذَا وَأَنَا أَسْمَعُهُ يَقْرَأُ وَيُومِئُ بِرَأْسِهِ فَلَمَّا فَرَغَ قَالَ مَا فَعَلْتَ فِي الَّذِي أَرْسَلْتُكَ فَإِنَّهُ لَمْ يَمْنَعْنِي أَنْ أُكَلِّمَكَ إِلَّا أَنِّي كُنْتُ أُصَلِّي","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] dia berkata; Nabi Allah shallallahu 'alaihi wasallam pernah mengutusku menuju (perkampungan) Bani Mushthaliq, lalu aku menemui beliau, sedangkan beliau tengah mengerjakan shalat di atas kendaraannya, aku pun berbicara kepadanya, maka beliau memberi isyarat dengan tangannya seperti ini, aku berbicara lagi, namun beliau hanya memberi isyarat dengan tangannya seperti ini, sedangkan aku mendengar bacaan shalat beliau, dan beliau menganggukkan kepalanya. Seusai shalat, beliau bersabda: \"Bagaimana dengan tugas yang telah aku tugaskan kepadamu? Sebenarnya tidak ada halangan buatku untuk membalas perkataanmu itu, hanya saja waktu itu aku sedang mengerjakan shalat.\""},"779":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ عِيسَى الْخُرَاسَانِيُّ الدَّامِغَانِيُّ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ حَدَّثَنَا نَافِعٌ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قُبَاءَ يُصَلِّي فِيهِ قَالَ فَجَاءَتْهُ الْأَنْصَارُ فَسَلَّمُوا عَلَيْهِ وَهُوَ يُصَلِّي قَالَ فَقُلْتُ لِبِلَالٍ كَيْفَ رَأَيْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُدُّ عَلَيْهِمْ حِينَ كَانُوا يُسَلِّمُونَ عَلَيْهِ وَهُوَ يُصَلِّي قَالَ يَقُولُ هَكَذَا وَبَسَطَ كَفَّهُ وَبَسَطَ جَعْفَرُ بْنُ عَوْنٍ كَفَّهُ وَجَعَلَ بَطْنَهُ أَسْفَلَ وَجَعَلَ ظَهْرَهُ إِلَى فَوْقٍ","id":"Telah menceritakan kepada kami [Al Husain bin Isa Al Khurasani Ad Damighani] telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Hisyam bin Sa'd] telah menceritakan kepada kami [Nafi'] dia berkata; saya mendengar [Abdullah bin Umar] berkata; Rasulullah shallallahu 'alaihi wasallam berangkat menuju Quba` dan shalat di sana, lantas orang-orang Anshar datang menemui beliau sambil mengucapkan salam, sedangkan beliau tengah mengerjakan shalat.\" Abdullah berkata; \"Aku bertanya kepada Bilal; \"Bagaimana kamu melihat Rasulullah shallallahu 'alaihi wasallam menjawab salam ketika mereka memberi salam kepada beliau yang sedang shalat?\" Bilal menjawab; \"Seperti ini, sambil membuka telapak tangannya. dan Ja'far bin 'Aun membuka telapak tangannya dengan menjadikan bagian dalamnya di bawah dan bagian luarnya di atas.\""},"780":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا غِرَارَ فِي صَلَاةٍ وَلَا تَسْلِيمٍقَالَ أَحْمَدُ يَعْنِي فِيمَا أَرَى أَنْ لَا تُسَلِّمَ وَلَا يُسَلَّمَ عَلَيْكَ وَيُغَرِّرُ الرَّجُلُ بِصَلَاتِهِ فَيَنْصَرِفُ وَهُوَ فِيهَا شَاكٌّ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Malik Al Asyja'i] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak boleh ada pengurangan dalam hal shalat maupun salam.\" Ahmad berkata; \"Menurutku baik anda mengucap salam maupun menjawab salam. Dan maksud seseorang mengurangi shalatnya, adalah ia berhenti, padahal dia masih ragu (sudah sempurna ataukah belum).\" "},"781":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ أَبِي مَالِكٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَأُرَاهُ رَفَعَهُ قَالَ لَا غِرَارَ فِي تَسْلِيمٍ وَلَا صَلَاةٍقَالَ أَبُو دَاوُد وَرَوَاهُ ابْنُ فُضَيْلٍ عَلَى لَفْظِ ابْنِ مَهْدِيٍّ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah mengabarkan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Abu Malik] dari [Abu Hazim] dari [Abu Hurairah] dia berkata; -sepertinya Sufyan merafa'kan hadits ini kepada Nabi- beliau bersabda: \"Tidak boleh ada ghirar (pengurangan) dalam hal salam, maupun shalat.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan pula oleh [Ibnu Fudlail] dengan lafadz Ibnu Mahdi, namun dia tidak merafa'kan kepada Nabi.\""},"782":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْمَعْنَى عَنْ حَجَّاجٍ الصَّوَّافِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ فَرَمَانِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَاثُكْلَ أُمِّيَاهُ مَا شَأْنُكُمْ تَنْظُرُونَ إِلَيَّ فَجَعَلُوا يَضْرِبُونَ بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَعَرَفْتُ أَنَّهُمْ يُصَمِّتُونِي فَقَالَ عُثْمَانُ فَلَمَّا رَأَيْتُهُمْ يُسَكِّتُونِي لَكِنِّي سَكَتُّ قَالَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي وَأُمِّي مَا ضَرَبَنِي وَلَا كَهَرَنِي وَلَا سَبَّنِي ثُمَّ قَالَ إِنَّ هَذِهِ الصَّلَاةَ لَا يَحِلُّ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ هَذَا إِنَّمَا هُوَ التَّسْبِيحُ وَالتَّكْبِيرُ وَقِرَاءَةُ الْقُرْآنِ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ وَقَدْ جَاءَنَا اللَّهُ بِالْإِسْلَامِ وَمِنَّا رِجَالٌ يَأْتُونَ الْكُهَّانَ قَالَ فَلَا تَأْتِهِمْ قَالَ قُلْتُ وَمِنَّا رِجَالٌ يَتَطَيَّرُونَ قَالَ ذَاكَ شَيْءٌ يَجِدُونَهُ فِي صُدُورِهِمْ فَلَا يَصُدُّهُمْ قُلْتُ وَمِنَّا رِجَالٌ يَخُطُّونَ قَالَ كَانَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ يَخُطُّ فَمَنْ وَافَقَ خَطَّهُ فَذَاكَ قَالَ قُلْتُ جَارِيَةٌ لِي كَانَتْ تَرْعَى غُنَيْمَاتٍ قِبَلَ أُحُدٍ وَالْجَوَّانِيَّةِ إِذْ اطَّلَعْتُ عَلَيْهَا اطِّلَاعَةً فَإِذَا الذِّئْبُ قَدْ ذَهَبَ بِشَاةٍ مِنْهَا وَأَنَا مِنْ بَنِي آدَمَ آسَفُ كَمَا يَأْسَفُونَ لَكِنِّي صَكَكْتُهَا صَكَّةً فَعَظُمَ ذَاكَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَفَلَا أُعْتِقُهَا قَالَ ائْتِنِي بِهَا قَالَ فَجِئْتُهُ بِهَا فَقَالَ أَيْنَ اللَّهُ قَالَتْ فِي السَّمَاءِ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya], dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin Ibrahim] sedangkan makna haditsnya dari [Hajjaj Ash Shawaf] telah menceritakan kepadaku [Yahya bi Abu Katsir] dari [Hilal bi Abu Maimunah] dari ['Atha` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] dia berkata; saya shalat bersama Rasulullah shallallahu 'alaihi wasallam, lalu ada seseorang yang bersin, maka aku mengucapkan; \"Yarhamukalah (semoga Allah merahmatimu) \" karena itu orang-rang mengalihkan pandangannya kepadaku, maka aku berkata; \"Celaka, kenapa kalian memandang kepadaku?\" kemudian mereka menepukkan tangan ke paha mereka, sehingga aku tahu bahwa mereka bermaksud menyuruh aku diam. Utsman mengatakan; \"ketika aku tahu mereka menyuruhku diam, maka aku pun diam. Kata Mu'awiyah; \"demi ayah dan ibuku, ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau tidak memukulku dan tidak pula membentakku serta tidak memakiku.\" Kemudian beliau bersabda: \"Sesungguhnya shalat ini, tidak halal di dalamnya bercampur dengan sesuatu perkataan manusia, akan tetapi yang ada hanyalah tasbih, takbir dan membaca Al Qur'an atau sebagaimana sabda Rasulullah shallallahu 'alaihi wasallam.\" Aku berkata; \"Wahai Rasulullah, kami adalah suatu kaum yang baru keluar dari kejahiliyahan, lalu Allah menganugerahkan kepada kami agama Islam, namun di antara kami masih ada yang suka mendatangi para normal.\" Beliau menjawab: \"Janganlah kalian mendatangi mereka.\" Mu'awiyah berkata; kataku; \"Dan di antara kami masih ada yang suka tathayyur (meramal nasib dengan burung dan yang lain).\" Beliau bersabda: \"itu hanya ilustrasi hati saja, karena itu janganlah mereka di halangi oleh hal itu.\" Aku bertanya; \"Di antara kami ada juga beberapa yang meramal nasib dengan membuat garis (tharq).\" Beliau bersabda: \"Ada di antara para Nabi yang memperaktekkan cara itu, maka siapa saja yang garisnya tepat dengan garis nabi itu, tepatlah ia.\" Mu'awiyah berkata; aku berkata; \"Aku memiliki seorang budak perempuan yang menggembalakan beberapa ekor kambingku ke arah Uhud dan Jawaniyah, suatu ketika aku pergi menemuinya, tiba-tiba waktu itu ada seekor serigala yang menerkam dan membawa lari seekor kambingku, sebenarnya aku adalah anak Adam yang memiliki belas kasihan kepada orang lain sebagaimana mereka (orang lain). Akan tetapi aku (tidak mampu lagi menahan diri) dan memukul budak perempuan itu, ternyata kejadian itu terasa berat bagiku, akhirnya aku mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu aku berkata; \"Tidakkah aku memerdekakannya saja?\" beliau bersabda: \"Bawalah ia kepadaku.\" Mu'awiyah berkata; \"Lalu aku bawa dia menghadap beliau, kemudian beliau bersabda: \"Siapakah saya?\" Budak wanita itu menjawab; \"Anda adalah Rasulullah.\" Beliau bersabda: \"Merdekakanlah dia, karena dia wanita yang beriman.\""},"783":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا فُلَيْحٌ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَلَمَّا قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِمْتُ أُمُورًا مِنْ أُمُورِ الْإِسْلَامِ فَكَانَ فِيمَا عَلِمْتُ أَنْ قَالَ لِي إِذَا عَطَسْتَ فَاحْمَدْ اللَّهَ وَإِذَا عَطَسَ الْعَاطِسُ فَحَمِدَ اللَّهَ فَقُلْ يَرْحَمُكَ اللَّهُ قَالَ فَبَيْنَمَا أَنَا قَائِمٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ إِذْ عَطَسَ رَجُلٌ فَحَمِدَ اللَّهَ فَقُلْتُ يَرْحَمُكَ اللَّهُ رَافِعًا بِهَا صَوْتِي فَرَمَانِي النَّاسُ بِأَبْصَارِهِمْ حَتَّى احْتَمَلَنِي ذَلِكَ فَقُلْتُ مَا لَكُمْ تَنْظُرُونَ إِلَيَّ بِأَعْيُنٍ شُزْرٍ قَالَ فَسَبَّحُوا فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْمُتَكَلِّمُ قِيلَ هَذَا الْأَعْرَابِيُّ فَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي إِنَّمَا الصَّلَاةُ لِقِرَاءَةِ الْقُرْآنِ وَذِكْرِ اللَّهِ جَلَّ وَعَزَّ فَإِذَا كُنْتَ فِيهَا فَلْيَكُنْ ذَلِكَ شَأْنُكَ فَمَا رَأَيْتُ مُعَلِّمًا قَطُّ أَرْفَقَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yunus An Nasa`i] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah menceritakan kepada kami [Fulaih] dari [Hilal bin Ali] dari ['Atha` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] dia berkata; Ketika aku tiba datang menemui Rasulullah shallallahu 'alaihi wasallam, maka aku tahu beberapa perkara Islam, di antara yang aku ketahui adalah, beliau bersabda kepadaku: \"Apabila kamu bersin, maka ucapkanlah \"Al hamdulillah\" dan apabila seseorang bersin, kemudian ia mengucapkan \"Al hamdulillah\" maka katakanlah \"Yarhamukallah (semoga Allah merahmatimu) \" Mu'awiyah melanjutkan; \"Ketika kami mengerjakan shalat bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba seseorang bersin dan mengucapkan \"Al Hamdulillah\", maka sambil mengeraskan suaraku, aku berkata; \"Yarhamukallah.\" Dengan itu, orang-orang mengalihkan pandangan ke arahku, sehingga aku gugup karenanya, kataku; \"Kenapa kalian memandangku dengan pandangan marah.\" Katanya; \"Bertasbihlah kalian.\" ketika Rasulullah shallallahu 'alaihi wasallam selesai dari shalatnya, beliau bersabda: \"Siapakah yang berbicara tadi?\" di jawab; \"Orang arab badui ini.\" lalu Rasulullah shallallahu 'alaihi wasallam memanggilku dan bersabda: \"Sesungguhnya shalat itu untuk membaca Al Qur'an dan berdzikir kepada Allah Jalla wa 'Azza, apabila kamu sedang shalat, maka kamu harus seperti itu (membaca Al Qur'an dan berdzikir).\" Maka aku belum pernah melihat seorang pengajar yang lebih lembut dari Rasulullah shallallahu 'alaihi wasallam.\""},"784":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ حُجْرٍ أَبِي الْعَنْبَسِ الْحَضْرَمِيِّ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَرَأَ{ وَلَا الضَّالِّينَ }قَالَ آمِينَ وَرَفَعَ بِهَا صَوْتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Salamah] dari [Hujr Abu Al 'Anbas Al Hadlrami] dari [Wa'il bin Hujr] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam membaca; \"Walaadl dlaallin, beliau mengucapkan; \"Amiin\" Sambil mengangkat suaranya.\""},"785":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ الشَّعِيرِيُّ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا عَلِيُّ بْنُ صَالِحٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرِ بْنِ عَنْبَسٍ عَنْ وَائِلِ بْنِ حُجْرٍأَنَّهُ صَلَّى خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَهَرَ بِآمِينَ وَسَلَّمَ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ حَتَّى رَأَيْتُ بَيَاضَ خَدِّهِ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid As Sya'iri] telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ali bin Shalih] dari [Salamah bin Kuhail] dari [Hujr bin 'Anbas] dari [Wa`il bin Hujr] bahwa dia shalat di belakang Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengeraskan suara bacaan \"Amin\" dan memberi salam ke kanan dan ke kiri sehingga aku melihat putihnya pipi beliau.\""},"786":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا صَفْوَانُ بْنُ عِيسَى عَنْ بِشْرِ بْنِ رَافِعٍ عَنْ أَبِي عَبْدِ اللَّهِ ابْنِ عَمِّ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَلَا{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }قَالَ آمِينَ حَتَّى يَسْمَعَ مَنْ يَلِيهِ مِنْ الصَّفِّ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Shafwan bin Isa] dari [Bisyr bin Rafi'] dari [Abu Abdullah anak paman Abu Hurairah] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam membaca \"Ghairil maghdluubi 'alaihim waladl dlaallin\", beliau mengucapkan; \"Amin\" sehingga orang yang berada di belakang beliau di shaf pertama mendengar beliau ucapan beliau.\""},"787":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Sumayy bekas budak Abu Bakar] dari [Abu Shalih As Saman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila imam mengucapkan; \"Ghairil maghdluubi 'alaihim waladl dlaallin\" maka ucapkanlah 'Amiin\" karena barangsiapa bacaan aminnya bersamaan dengan Malaikat, maka dosanya yang telah lalu akan terampuni.\""},"788":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُمَا أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْإِمَامُ فَأَمِّنُوا فَإِنَّهُ مَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ قَالَ ابْنُ شِهَابٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ آمِينَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyib] dan [Abu Salamah bin Abdurrahman] bahwa keduanya telah mengabarkan dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang imam mengucapkan \"Amin\" maka ucapkanlah \"Amin\" barangsiapa yang bacaan aminnya bersamaan dengan Malaikat, maka dosa-dosanya yang telah lalu akan terampuni.\" Ibnu Syihab mengatakan; \"Rasulullah shallallahu 'alaihi wasallam juga mengucapkan amiin.\""},"789":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ رَاهَوَيْهِ أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ بِلَالٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ لَا تَسْبِقْنِي بِآمِينَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Rahawaih] telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari ['Ashim] dari [Abu Utsman] dari [Bilal] bahwa dia berkata; \"Wahai Rasulullah, janganlah anda mendahului kami dengan ucapan amin.\""},"790":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عُتْبَةَ الدِّمَشْقِيُّ وَمَحْمُودُ بْنُ خَالِدٍ قَالَا حَدَّثَنَا الْفِرْيَابِيُّ عَنْ صُبَيْحِ بْنِ مُحْرِزٍ الْحِمْصِيِّ حَدَّثَنِي أَبُو مُصَبِّحٍ الْمَقْرَائِيُّ قَالَكُنَّا نَجْلِسُ إِلَى أَبِي زُهَيْرٍ النُّمَيْرِيِّ وَكَانَ مِنْ الصَّحَابَةِ فَيَتَحَدَّثُ أَحْسَنَ الْحَدِيثِ فَإِذَا دَعَا الرَّجُلُ مِنَّا بِدُعَاءٍ قَالَ اخْتِمْهُ بِآمِينَ فَإِنَّ آمِينَ مِثْلُ الطَّابَعِ عَلَى الصَّحِيفَةِ قَالَ أَبُو زُهَيْرٍ أُخْبِرُكُمْ عَنْ ذَلِكَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَأَتَيْنَا عَلَى رَجُلٍ قَدْ أَلَحَّ فِي الْمَسْأَلَةِ فَوَقَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَمِعُ مِنْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْجَبَ إِنْ خَتَمَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ بِأَيِّ شَيْءٍ يَخْتِمُ قَالَ بِآمِينَ فَإِنَّهُ إِنْ خَتَمَ بِآمِينَ فَقَدْ أَوْجَبَ فَانْصَرَفَ الرَّجُلُ الَّذِي سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى الرَّجُلَ فَقَالَ اخْتِمْ يَا فُلَانُ بِآمِينَ وَأَبْشِرْ وَهَذَا لَفْظٌ مَحْمُودٌقَالَ أَبُو دَاوُد الْمَقْرَاءُ قَبِيلٌ مِنْ حِمْيَرَ","id":"Telah menceritakan kepada kami [Al Walid bin 'Utbah Ad Dimasyqi] dan [Mahmud bin Khalid] keduanya berkata; telah menceritakan kepadaku [Al Firyabi] dari [Shubaih bin Muhriz Al Himshi] telah menceritakan kepadaku [Abu Mushabbih Al Maqra`i] dia berkata; \"Kami bermajlis kepada [Abu Zuhair An Numairi] -dia termasuk salah seorang sahabat-, dia berbicara kepada kami dengan pembicaraan yang bagus: apabila seseorang dari kami berdo'a maka dia berkata: \"Tutuplah dengan \"Amiin\" karena \"amiin\" seperti setempel pada lembaran.\" Abu Zuhair berkata; aku beritahukan kalian tentang itu; \"Pada suatu malam, kami keluar bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami menemui seseorang yang bersungguh-sungguh dalam meminta (berdo'a), maka Nabi shallallahu 'alaihi wasallam berhenti untuk mendengarkan ucapan orang tersebut, lalu beliau bersabda: \"(Do'anya) akan dikabulkan apabila ditutup.\" Seseorang betanya; \"Dengan apa ia menutupnya? Beliau menjawab: \"Dengan \"amiin\" sesungguhnya apabila dia menutupnya dengan \"amiin\" pasti (do'nay) akan dikabulkan.\" Orang yang bertanya tadi pergi dan bergegas menemui orang yang berdo'a tadi sambil mengatakan: \"Wahai fulan, tutuplah do'a kamu dengan \"amiin\" ini adalah kabar gembira!.\" Lafdz hadits ini dari Mahmud. Abu Daud berkata; Al Maqra` merupakan salah satu kabilah Himyar. "},"791":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tasbih (mengucapkan subhanallah) untuk laki-laki dan tepuk tangan untuk wanita.\""},"792":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ إِلَى بَنِي عَمْرِو بْنِ عَوْفٍ لِيُصْلِحَ بَيْنَهُمْ وَحَانَتْ الصَّلَاةُ فَجَاءَ الْمُؤَذِّنُ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَتُصَلِّي بِالنَّاسِ فَأُقِيمَ قَالَ نَعَمْ فَصَلَّى أَبُو بَكْرٍ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ فِي الصَّلَاةِ فَتَخَلَّصَ حَتَّى وَقَفَ فِي الصَّفِّ فَصَفَّقَ النَّاسُ وَكَانَ أَبُو بَكْرٍ لَا يَلْتَفِتُ فِي الصَّلَاةِ فَلَمَّا أَكْثَرَ النَّاسُ التَّصْفِيقَ الْتَفَتَ فَرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشَارَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ امْكُثْ مَكَانَكَ فَرَفَعَ أَبُو بَكْرٍ يَدَيْهِ فَحَمِدَ اللَّهَ عَلَى مَا أَمَرَهُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذَلِكَ ثُمَّ اسْتَأْخَرَ أَبُو بَكْرٍ حَتَّى اسْتَوَى فِي الصَّفِّ وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا انْصَرَفَ قَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تَثْبُتَ إِذْ أَمَرْتُكَ قَالَ أَبُو بَكْرٍ مَا كَانَ لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لِي رَأَيْتُكُمْ أَكْثَرْتُمْ مِنْ التَّصْفِيحِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيُسَبِّحْ فَإِنَّهُ إِذَا سَبَّحَ الْتُفِتَ إِلَيْهِ وَإِنَّمَا التَّصْفِيحُ لِلنِّسَاءِقَالَ أَبُو دَاوُد وَهَذَا فِي الْفَرِيضَةِ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ كَانَ قِتَالٌ بَيْنَ بَنِي عَمْرِو بْنِ عَوْفٍ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُمْ لِيُصْلِحَ بَيْنَهُمْ بَعْدَ الظُّهْرِ فَقَالَ لِبِلَالٍ إِنْ حَضَرَتْ صَلَاةُ الْعَصْرِ وَلَمْ آتِكَ فَمُرْ أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَلَمَّا حَضَرَتْ الْعَصْرُ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ ثُمَّ أَمَرَ أَبَا بَكْرٍ فَتَقَدَّمَ قَالَ فِي آخِرِهِ إِذَا نَابَكُمْ شَيْءٌ فِي الصَّلَاةِ فَلْيُسَبِّحْ الرِّجَالُ وَلْيُصَفِّحْ النِّسَاءُ حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْوَلِيدُ عَنْ عِيسَى بْنِ أَيُّوبَ قَالَ قَوْلُهُ التَّصْفِيحُ لِلنِّسَاءِ تَضْرِبُ بِأُصْبُعَيْنِ مِنْ يَمِينِهَا عَلَى كَفِّهَا الْيُسْرَى","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berkunjung kepada Bani 'Amr bin 'Auf untuk mendamaikan perselisihan yang terjadi di antara mereka, sementara waktu shalat telah tiba. Mu'adzin datang menemui Abu Bakar radliallahu 'anhu, lalu berkata; \"Inginkah anda mengimami orang-orang, nanti aku akan kumandangkan iqamah.\" Abu Bakar menjawab; \"Ya, ' Abu Bakar mengerjakan shalat, lalu Rasulullah shallallahu 'alaihi wasallam datang, dan orang-orang pun tengah mengerjakan shalat, lalu beliau menelusuri shaf sampai sampai beliau berdiri dalam shaf, lalu orang-orang bertepuk tangan, tapi Abu Bakar tetap saja tidak menoleh dalam shalat. setelah banyak orang yang bertepuk tangan, baru dia menoleh dan langsung melihat Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepadanya supaya tetap di tempat, namun Abu Bakar mengangkat kedua tangannya (sebagai isyarat untuk menolak), seraya memuji kepada Allah atas apa yang di perintahkan oleh Rasulullah shallallahu 'alaihi wasallam kepadanya. Setelah itu Abu Bakar mundur, sampai berdiri lurus dengan shaf, maka Rasulullah shallallahu 'alaihi wasallam maju (sebagai imam). Selesai shalat, beliau bersabda: \"Apakah yang menghalangimu tidak mau tetap berada di tempat (jadi imam) sewaktu aku perintahkan?\" Abu Bakar menjawab; \"Tidak layak bagi anak Abu Quhafah mengerjakan shalat di depan Rasulullah shallallahu 'alaihi wasallam.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kenapa aku melihat kalian bertepuk tangan? Barangsiapa terjadi sesuatu (kesalahan) pada dirinya dalam shalat, maka bacalah tasbih, sebab apabila dia telah membaca tasbih, orang lain akan menoleh kepadanya, dan tepuk tangan hanya bagi kaum wanita.\" Abu Daud berkata; \"Ini kalau dalam shalat fardlu.\" Telah menceritakan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Pernah terjadi suatu persengketaan di kalangan Bani 'Amru bin 'Auf, lalu berita itu sampai kepada Nabi shallallahu 'alaihi wasallam, lantas beliau menemui mereka setelah shalat Dzuhur untuk mendamaikan mereka. beliau bersabda kepada Bilal: \"Apabila waktu shalat ashar telah tiba, sedang aku belum datang kepadamu, maka suruhlah Abu Bakar mengerjakan shalat bersama orang-orang.\" Setelah waktu Ashar tiba, Bilal mengumandangkan adzan dan menyerukan iqamah, setelah itu menyuruh Abu Bakar untuk maju (jadi imam).\" Pada akhir hadits ini, beliau bersabda: \"apabila terjadi sesuatu padamu dalam shalat, hendaklah kaum laki-laki membaca tasbih dan kaum wanita bertepuk tangan.\" Telah menceritakan kepada kami Mahmud bin Khalid telah menceritakan kepada kami Al Walid dari Isa bin Ayyub dia berkata; sabdanya: \"Bertepuk tangan bagi kaum wanita\" yaitu; menepukan dua jari-jarinya yang sebelah kanan di atas telapak tangan kirinya.\""},"793":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ شَبُّوَيْهِ الْمَرْوَزِيُّ وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُشِيرُ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Syubawaih al Marwazi] dan [Muhammad bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam pernah memberi isyarat dalam shalat.\""},"794":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ بْنِ الْأَخْنَسِ عَنْ أَبِي غَطَفَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ لِلرِّجَالِ يَعْنِي فِي الصَّلَاةِ وَالتَّصْفِيقُ لِلنِّسَاءِ مَنْ أَشَارَ فِي صَلَاتِهِ إِشَارَةً تُفْهَمُ عَنْهُ فَلْيَعُدْ لَهَا يَعْنِي الصَّلَاةَقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ وَهْمٌ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Ya'qub bin 'Utbah bin Al Akhnas] dari [Abu Ghathafan] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tasbih (mengucapkan Subhanallah) untuk kaum laki-laki, dan bertepuk tangan untuk kaum wanita, dan barangsiapa memberi isyarat dalam shalatnya sedangkan ia faham isyarat tersebut, hendaklah ia mengulanginya yakni shalat.\" Abu Daud mengatakan; \"Hadits ini adalah hadits wahm (tidak jelas).\""},"795":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْأَحْوَصِ شَيْخٌ مِنْ أَهْلِ الْمَدِينَةِ أَنَّهُ سَمِعَ أَبَا ذَرٍّ يَرْوِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ أَحَدُكُمْ إِلَى الصَّلَاةِ فَإِنَّ الرَّحْمَةَ تُوَاجِهُهُ فَلَا يَمْسَحْ الْحَصَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Al Ahwash] -seorang syaikh dari penduduk Madinah- bahwa dia mendengar [Abu Dzar] meriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seseorang dari kalian sedang mengerjakan shalat, maka rahmat berada di hadapannya, oleh karena itu janganlah ia menyingkirkan kerikil yang ada di hadapannya!.\""},"796":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ مُعَيْقِيبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَمْسَحْ وَأَنْتَ تُصَلِّي فَإِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَوَاحِدَةٌ تَسْوِيَةَ الْحَصَى","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Mu'aiqib] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu mengusap (kerikil) sementara kamu sedang shalat, namun apabila kamu terpaksa melakukan hal itu, maka cukuplah kamu meratakannya sekali.\""},"797":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ كَعْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الِاخْتِصَارِ فِي الصَّلَاةِقَالَ أَبُو دَاوُد يَعْنِي يَضَعُ يَدَهُ عَلَى خَاصِرَتِهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ka'b] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Hisyam] dari [Muhammad bin Sirin] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang bertolak pinggang dalam shalat.\" Abu Daud mengatakan; \"Maksudnya meletakkan tangan di pinggangnya.\""},"798":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَبْدِ الرَّحْمَنِ الْوَابِصِيُّ حَدَّثَنَا أَبِي عَنْ شَيْبَانَ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ هِلَالِ بْنِ يَسَافٍ قَالَقَدِمْتُ الرَّقَّةَ فَقَالَ لِي بَعْضُ أَصْحَابِي هَلْ لَكَ فِي رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ غَنِيمَةٌ فَدَفَعْنَا إِلَى وَابِصَةَ قُلْتُ لِصَاحِبِي نَبْدَأُ فَنَنْظُرُ إِلَى دَلِّهِ فَإِذَا عَلَيْهِ قَلَنْسُوَةٌ لَاطِئَةٌ ذَاتُ أُذُنَيْنِ وَبُرْنُسُ خَزٍّ أَغْبَرُ وَإِذَا هُوَ مُعْتَمِدٌ عَلَى عَصًا فِي صَلَاتِهِ فَقُلْنَا بَعْدَ أَنْ سَلَّمْنَا فَقَالَ حَدَّثَتْنِي أُمُّ قَيْسٍ بِنْتُ مِحْصَنٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أَسَنَّ وَحَمَلَ اللَّحْمَ اتَّخَذَ عَمُودًا فِي مُصَلَّاهُ يَعْتَمِدُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdussalam bin Abdurrahman al wabishi] telah menceritakan kepada kami [ayahku] dari [Syaiban] dari [Hushain bin Abdurrahman] dari [Hilal bin Yasaf] dia berkata; \"Aku pergi ke negeri Raqqah, lalu sebagian sahabatku berkata kepadaku; \"Apakah kamu mempunyai keinginan untuk bertemu salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam?\" Hilal berkata; jawabku: \"ya! ini suatu keberuntungan, \" lalu kami menuju [Wabishah] (seorang sahabat Rasulullah), aku berkata kepada sahabatku; \"Kita mulai pandangi dulu karakternya, ternyata dia mengenakan peci bertelinga dua yang selalu melekat dan mengenakan jubah yang bertopi yang terbuat dari bahan sutera berwarna abu-abu, dan dia tengah mengerjakan shalat sambil bersandar kepada tongkatnya. Kami tanyakan hal itu kepadanya setelah kami memberi salam, dia menjawab: \" [Ummu Qais binti Mihshan] pernah menyampaikan kepadaku, bahwa setelah berusia lanjut dan lemah Rasulullah shallallahu 'alaihi wasallam membuat tiang di tempat shalatnya untuk bersandar.\""},"799":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكَانَ أَحَدُنَا يُكَلِّمُ الرَّجُلَ إِلَى جَنْبِهِ فِي الصَّلَاةِ فَنَزَلَتْ{ وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ وَنُهِينَا عَنْ الْكَلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari [Al Harits bin Syubail] dari [Abu 'Amru As Syaibani] dari [Zaid bin Arqam] dia berkata; \"Salah seorang dari kami pernah mengajak bicara kepada orang yang ada di sampingnya ketika shalat, lalu turunlah ayat; \"WA QUUMUU LILLAAHI QAANITIIN (berdirilah karena Allah (dalam shalatmu) dengan khusyu') QS Al Baqarah; 238. maka kami di perintahkan untuk diam dan di larang untuk berbicara.\""},"800":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ بْنِ أَعْيَنَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالٍ يَعْنِي ابْنَ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ حُدِّثْتُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ قَاعِدًا نِصْفُ الصَّلَاةِ فَأَتَيْتُهُ فَوَجَدْتُهُ يُصَلِّي جَالِسًا فَوَضَعْتُ يَدَيَّ عَلَى رَأْسِي فَقَالَ مَا لَكَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو قُلْتُ حُدِّثْتُ يَا رَسُولَ اللَّهِ أَنَّكَ قُلْتَ صَلَاةُ الرَّجُلِ قَاعِدًا نِصْفُ الصَّلَاةِ وَأَنْتَ تُصَلِّي قَاعِدًا قَالَ أَجَلْ وَلَكِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah bin A'yan] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal yaitu Ibnu Yasaf] dari [Abu Yahya] dari [Abdullah bin 'Amru] dia berkata; pernah di sampaikan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatnya seseorang dengan duduk itu mendapatkan pahala separuh shalat.\" Maka aku pergi menemui beliau dan aku dapati beliau tengah mengerjakan shalat dengan duduk, maka aku meletakkan kedua tangan di atas kepalaku, maka beliau bersabda: \"Kenapa denganmu wahai Abdullah bin 'Amru?\" jawabku; \"Telah sampai kepadaku wahai Rasulullah, bahwa anda bersabda: \"Shalatnya seseorang dengan duduk itu mendapatkan pahala separuh shalat, sementara anda mengerjakan shalat dengan posisi duduk.\" beliau bersabda: \"Benar, akan tetapi aku tidak sebagaimana salah seorang dari kalian.\""},"801":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الرَّجُلِ قَاعِدًا فَقَالَ صَلَاتُهُ قَائِمًا أَفْضَلُ مِنْ صَلَاتِهِ قَاعِدًا وَصَلَاتُهُ قَاعِدًا عَلَى النِّصْفِ مِنْ صَلَاتِهِ قَائِمًا وَصَلَاتُهُ نَائِمًا عَلَى النِّصْفِ مِنْ صَلَاتِهِ قَاعِدًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Husain Al Mu'allim] dari [Abdullah bin Buraidah] dari [Imran bin Hushain] bahwa dia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai shalatnya seseorang dengan duduk.\" beliau bersabda: \"Shalatnya seseorang dengan berdiri itu lebih utama dari shalatnya seseorang dengan duduk, dan shalatnya seseorang dengan duduk itu mendapatkan separuh pahala dari shalat dengan berdiri, dan shalatnya seseorang dengan tidur itu mendapatkan pahala separuh dari shalat dengan duduk.\""},"802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ ابْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَكَانَ بِي النَّاصُورُ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلِّ قَائِمًا فَإِنْ لَمْ تَسْتَطِعْ فَقَاعِدًا فَإِنْ لَمْ تَسْتَطِعْ فَعَلَى جَنْبٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Thahman] dari [Husain Al Mu'allim] dari [Ibnu Buraidah] dari [Imran bin Hushain] dia berkata; \"Aku menderita penyakit wasir, lalu aku tanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Shalatlah dengan berdiri, dan apabila kamu tidak mampu, maka dengan duduk, jika tidak mampu, maka dengan berbaring.\""},"803":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي شَيْءٍ مِنْ صَلَاةِ اللَّيْلِ جَالِسًا قَطُّ حَتَّى دَخَلَ فِي السِّنِّ فَكَانَ يَجْلِسُ فِيهَا فَيَقْرَأُ حَتَّى إِذَا بَقِيَ أَرْبَعُونَ أَوْ ثَلَاثُونَ آيَةً قَامَ فَقَرَأَهَا ثُمَّ سَجَدَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] dia berkata; \"Aku tidak pernah melihat sama sekali Rasulullah shallallahu 'alaihi wasallam membaca dalam shalat malam sambil duduk sehingga beliau memasuki usia lanjut, di masa itu, barulah beliau membaca sambil duduk, apabila ayat yang belum di baca tinggal sekitar empat puluh atau tiga puluh ayat, beliau membacanya sambil berdiri kemudian sujud.\""},"804":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَأَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي جَالِسًا فَيَقْرَأُ وَهُوَ جَالِسٌ وَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ قَدْرُ مَا يَكُونُ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَهَا وَهُوَ قَائِمٌ ثُمَّ رَكَعَ ثُمَّ سَجَدَ ثُمَّ يَفْعَلُ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَقَالَ أَبُو دَاوُد رَوَاهُ عَلْقَمَةُ بْنُ وَقَّاصٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abdullah bin Yazid] dan [Abu An Nadlr] dari [Abu Salamah bin Abdurrahman] dari [Aisyah istri Nabi shallallahu 'alaihi wasallam] bahwa Nabi shallallahu 'alaihi wasallam shalat dengan duduk, beliau membaca sambil duduk. dan apabila bacaan beliau tinggal sekitar tiga puluh atau empat puluh ayat, maka beliau berdiri dan membacanya sambil berdiri, kemudian beliau ruku' lalu sujud, beliau mengerjakan seperti itu pada raka'at yang kedua.\" Abu Daud mengatakan; \"Hadits ini juga di riwayatkan oleh ['Alqamah bin Waqash] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"805":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ قَالَ سَمِعْتُ بُدَيْلَ بْنَ مَيْسَرَةَ وَأَيُّوبَ يُحَدِّثَانِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا وَلَيْلًا طَوِيلًا قَاعِدًا فَإِذَا صَلَّى قَائِمًا رَكَعَ قَائِمًا وَإِذَا صَلَّى قَاعِدًا رَكَعَ قَاعِدًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dia berkata; saya mendengar [Budail bin Maisarah] dan [Ayyub] keduanya menceritakan dari [Abdullah bin Syaqiq] dari [Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat beberapa malam dengan berdiri dan beberapa malam dengan duduk, apabila beliau mengerjakan shalat dengan berdiri, maka beliau ruku' dalam keadaan berdiri, dan apabila beliau mengerjakan shalat dengan duduk, maka beliau ruku' dengan posisi duduk.\""},"806":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ سَأَلْتُ عَائِشَةَأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ السُّورَةَ فِي رَكْعَةٍ قَالَتْ الْمُفَصَّلَ قَالَ قُلْتُ فَكَانَ يُصَلِّي قَاعِدًا قَالَتْ حِينَ حَطَمَهُ النَّاسُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Kahmas bin Al Hasan] dari [Abdullah bin Syaqiq] dia berkata; saya bertanya kepada [Aisyah]; \"Apakah Rasulullah shallallahu 'alaihi wasallam membaca surat dalam satu raka'at?\" Aisyah menjawab; \"(ya) Surat Al Mufashal (Qaaf, atau Al Hujurat hingga akhir Al Qur'an).\" Abdullah bin Syaqiq berkata; tanyaku; \"Apakah beliau juga pernah shalat dengan duduk?\" jawabnya; \"Ketika beliau memasuki usia lanjut.\""},"807":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَقُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَقْبَلَ الْقِبْلَةَ فَكَبَّرَ فَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا بِأُذُنَيْهِ ثُمَّ أَخَذَ شِمَالَهُ بِيَمِينِهِ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَهُمَا مِثْلَ ذَلِكَ قَالَ ثُمَّ جَلَسَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَحَدَّ مِرْفَقَهُ الْأَيْمَنَ عَلَى فَخِذِهِ الْيُمْنَى وَقَبَضَ ثِنْتَيْنِ وَحَلَّقَ حَلْقَةً وَرَأَيْتُهُ يَقُولُ هَكَذَا وَحَلَّقَ بِشْرٌ الْإِبْهَامَ وَالْوُسْطَى وَأَشَارَ بِالسَّبَّابَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Wa'il bin Hujr] dia berkata; kataku; \"Sungguh aku melihat bagaimana tata cara shalat Rasulullah shallallahu 'alaihi wasallam!.\" yaitu Rasulullah shallallahu 'alaihi wasallam berdiri, lalu menghadap kiblat, bertakbir, mengangkat kedua tangan sehingga sejajar dengan kedua telinga, setelah itu tangan kanan beliau memegang tangan kirinya, sewaktu beliau hendak ruku', beliau mengangkat kedua tangannya seperti tadi.\" Katanya melanjutkan; \"Kemudian beliau duduk, yaitu menduduki kaki kirinya dan meletakkan tangan kiri di atas paha kirinya sambil merenggangkan siku yang kanan terhadap paha sebelah kanan dan menggenggam kedua jari (kelingking dan manis) dan membentuk suatu lingkaran. Aku melihat beliau melakukan seperti ini Bisyr membentuk lingkaran dengan ibu jari dan jari tengah serta menunjuk dengan jari telunjuk.\""},"808":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَسُنَّةُ الصَّلَاةِ أَنْ تَنْصِبَ رِجْلَكَ الْيُمْنَى وَتَثْنِيَ رِجْلَكَ الْيُسْرَى","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdurrahman bin Al Qasim] dari [Abdullah bin Abdullah] dari [Abdullah bin Umar] dia berkata; \"Di antara sunnah dalam shalat adalah kamu menegakkan kaki kananmu dan melipat kaki kirimu (dalam posisi duduk).\""},"809":{"ar":"حَدَّثَنَا ابْنُ مُعَاذٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى قَالَ سَمِعْتُ الْقَاسِمَ يَقُولُ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُمِنْ سُنَّةِ الصَّلَاةِ أَنْ تُضْجِعَ رِجْلَكَ الْيُسْرَى وَتَنْصِبَ الْيُمْنَىحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ يَحْيَى بِإِسْنَادِهِ مِثْلَهُ قَالَ أَبُو دَاوُد قَالَ حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى أَيْضًا مِنْ السُّنَّةِ كَمَا قَالَ جَرِيرٌ حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ أَرَاهُمْ الْجُلُوسَ فِي التَّشَهُّدِ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibnu Mu'adz] telah menceritakan kepada kami [Abdul Wahab] dia berkata; saya mendengar [Yahya] berkata; saya mendengar [Al Qasim] berkata; telah mengabarkan kepadaku [Abdullah bin Abdullah] bahwa dia mendengar [Abdullah bin Umar] berkata; \"Di antara sunnah shalat adalah kamu baringkan kaki kirimu dan menegakkan kaki kanan.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Yahya] dengan isnad seperti di atas, dia berkata; Abu Daud berkata; [Hammad bin Zaid] berkata; dari [Yahya] juga (katanya); \"Di antara sunnah…\" sebagaimana perkataan Jarir. Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Yahya bin Sa'id] bahwa [Al Qasim bin Muhammad] pernah memperlihatkan kepada mereka (cara) duduk tasyahud…\" lalu dia menyebutkan hadits tersebut.\""},"810":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ إِبْرَاهِيمَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ فِي الصَّلَاةِ افْتَرَشَ رِجْلَهُ الْيُسْرَى حَتَّى اسْوَدَّ ظَهْرُ قَدَمِهِ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] dari [Waki'] dari [Sufyan] dari [Az Zubair bin 'Adi] dari [Ibrahim] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam duduk pada waktu shalat, maka telapak kaki kirinya beliau duduki hingga bagian atas kakinya menjadi hitam.\""},"811":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ أَخْبَرَنَا عَبْدُ الْحَمِيدِ يَعْنِي ابْنَ جَعْفَرٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا عَبْدُ الْحَمِيدِ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَ سَمِعْتُهُ فِي عَشَرَةٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَحْمَدُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ فِي عَشَرَةٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو قَتَادَةَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا فَاعْرِضْ فَذَكَرَ الْحَدِيثَ قَالَ وَيَفْتَحُ أَصَابِ��َ رِجْلَيْهِ إِذَا سَجَدَ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ وَيَرْفَعُ وَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا ثُمَّ يَصْنَعُ فِي الْأُخْرَى مِثْلَ ذَلِكَ فَذَكَرَ الْحَدِيثَ قَالَ حَتَّى إِذَا كَانَتْ السَّجْدَةُ الَّتِي فِيهَا التَّسْلِيمُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَقَعَدَ مُتَوَرِّكًا عَلَى شِقِّهِ الْأَيْسَرِزَادَ أَحْمَدُ قَالُوا صَدَقْتَ هَكَذَا كَانَ يُصَلِّي وَلَمْ يَذْكُرَا فِي حَدِيثِهِمَا الْجُلُوسَ فِي الثِّنْتَيْنِ كَيْفَ جَلَسَ حَدَّثَنَا عِيسَى بْنُ إِبْرَاهِيمَ الْمِصْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ عَنْ يَزِيدَ بْنِ مُحَمَّدٍ الْقُرَشِيِّ وَيَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ أَنَّهُ كَانَ جَالِسًا مَعَ نَفَرٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ وَلَمْ يَذْكُرْ أَبَا قَتَادَةَ قَالَ فَإِذَا جَلَسَ فِي الرَّكْعَتَيْنِ جَلَسَ عَلَى رِجْلِهِ الْيُسْرَى فَإِذَا جَلَسَ فِي الرَّكْعَةِ الْأَخِيرَةِ قَدَّمَ رِجْلَهُ الْيُسْرَى وَجَلَسَ عَلَى مَقْعَدَتِهِ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو الْعَامِرِيِّ قَالَ كُنْتُ فِي مَجْلِسٍ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَإِذَا قَعَدَ فِي الرَّكْعَتَيْنِ قَعَدَ عَلَى بَطْنِ قَدَمِهِ الْيُسْرَى وَنَصَبَ الْيُمْنَى فَإِذَا كَانَتْ الرَّابِعَةُ أَفْضَى بِوَرِكِهِ الْيُسْرَى إِلَى الْأَرْضِ وَأَخْرَجَ قَدَمَيْهِ مِنْ نَاحِيَةٍ وَاحِدَةٍ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا أَبُو بَدْرٍ حَدَّثَنِي زُهَيْرٌ أَبُو خَيْثَمَةَ حَدَّثَنَا الْحَسَنُ بْنُ الْحُرِّ حَدَّثَنَا عِيسَى بْنُ عَبْدِ اللَّهِ بْنِ مَالِكٍ عَنْ عَبَّاسٍ أَوْ عَيَّاشِ بْنِ سَهْلٍ السَّاعِدِيِّ أَنَّهُ كَانَ فِي مَجْلِسٍ فِيهِ أَبُوهُ فَذَكَرَ فِيهِ قَالَ فَسَجَدَ فَانْتَصَبَ عَلَى كَفَّيْهِ وَرُكْبَتَيْهِ وَصُدُورِ قَدَمَيْهِ وَهُوَ جَالِسٌ فَتَوَرَّكَ وَنَصَبَ قَدَمَهُ الْأُخْرَى ثُمَّ كَبَّرَ فَسَجَدَ ثُمَّ كَبَّرَ فَقَامَ وَلَمْ يَتَوَرَّكْ ثُمَّ عَادَ فَرَكَعَ الرَّكْعَةَ الْأُخْرَى فَكَبَّرَ كَذَلِكَ ثُمَّ جَلَسَ بَعْدَ الرَّكْعَتَيْنِ حَتَّى إِذَا هُوَ أَرَادَ أَنْ يَنْهَضَ لِلْقِيَامِ قَامَ بِتَكْبِيرٍ ثُمَّ رَكَعَ الرَّكْعَتَيْنِ الْأُخْرَيَيْنِ فَلَمَّا سَلَّمَ سَلَّمَ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ قَالَ أَبُو دَاوُد لَمْ يَذْكُرْ فِي حَدِيثِهِ مَا ذَكَرَ عَبْدُ الْحَمِيدِ فِي التَّوَرُّكِ وَالرَّفْعِ إِذَا قَامَ مِنْ ثِنْتَيْنِ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو أَخْبَرَنِي فُلَيْحٌ أَخْبَرَنِي عَبَّاسُ بْنُ سَهْلٍ قَالَ اجْتَمَعَ أَبُو حُمَيْدٍ وَأَبُو أُسَيْدٍ وَسَهْلُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مَسْلَمَةَ فَذَكَرَ هَذَا الْحَدِيثَ وَلَمْ يَذْكُرْ الرَّفْعَ إِذَا قَامَ مِنْ ثِنْتَيْنِ وَلَا الْجُلُوسَ قَالَ حَتَّى فَرَغَ ثُمَّ جَلَسَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَأَقْبَلَ بِصَدْرِ الْيُمْنَى عَلَى قِبْلَتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abu 'Ashim Adl Dlahak bin Makhlad] telah mengabarkan kepada kami [Abdul Hamid yaitu Ibnu Ja'far]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Abdul Hamid yaitu Ibnu Ja'far] telah menceritakan kepadaku [Muhammad bin 'Amru] dari [Abu Humaid As Sa'idi] dia berkata; saya pernah mendengarnya berkata di tengah-tengah sepuluh sahabat Rasulullah shallallahu 'alaihi wasallam -Ahmad berkata; telah mengabarkan kepadaku Muhammad bin 'Amru bin 'Atha` dia berkata; aku mendengar Abu Humaid As Sa'idi berkata di tengah-tengah sepuluh sahabat Rasulullah shallallahu 'alaihi wasallam di antaranya adalah [Abu Qatadah], Abu Humaid berkata; \"Aku lebih mengetahui tentang shalat Rasulullah shallallahu 'alaihi wasallam.\" Mereka berkata; \"kalau demikian, jelaskanlah.\" Kemudian Abu Humaid menyebutkan hadits tersebut, katanya; \"… kemudian beliau membuka jari-jari kedua tangannya apabila sujud, lalu mengucapkan: \"Allahu Akbar\" Setelah itu, beliau mengangkat kepala dan melipat kaki kirinya serta mendudukinya, beliau mengerjakan seperti itu di raka'at yang lain.\" Kemudian dia menyebutkan lanjutan dari hadits tersebut, katanya; \"…dan ketika beliau duduk (tahiyyat) yang terdapat salam, beliau merubah posisi kaki kiri dan duduk secara tawaruk (duduk dengan posisi kaki kiri masuk ke kaki kanan) di atas betis kiri.\" Ahmad menambahkan; \"Sepuluh sahabat tersebut berkata; \"Benar kamu, demikianlah beliau biasa melaksanakan shalat.\" keduanya tidak menyebutkan dalam kedua hadits tersebut tentang cara duduk dalam rala'at kedua.\" Telah menceritakan kepada kami [Isa bin Ibrahim Al Mishri] telah menceritakan kepada kami [Ibnu Wahb] dari [Al Laits] dari [Yazid bin Muhammad Al Qurasyi] dan [Yazid bin Abu Habib] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru bin 'Atha`] bahwa dia duduk-duduk bersama dengan beberapa sahabat Rasulullah shallallahu 'alaihi wasallam…\" seperti hadits ini, namun dia tidak menyerbutkan Abu Qatadah, katanya; \"Apabila beliau duduk pada raka'at kedua, beliau duduk di atas kaki kirinya, dan apabila duduk pada raka'at terakhir, beliau memajukan kaki kirinya dan duduk di atas tempat duduknya. ' Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru Al 'Amiri] dia berkata; \"Aku pernah menghadiri suatu majlis…\"seperti hadits ini\" di dalam hadits tersebut, dia berkata; \"Apabila duduk pada raka'at kedua, beliau duduk di atas telapak kaki kirinya dan menegakkan kaki kanannya, dan apabila duduk di raka'at ke empat (terakhir), beliau merapatkan pantatnya ke lantai dan mengeluarkan kedua telapak kakinya dari satu arah.\" Telah menceritakan kepada kami [Ali bin Al Husain bin Ibrahim] telah menceritakan kepada kami [Abu Badr] telah menceritakan kepadaku [Zuhair Abu Khaitsamah] telah menceritakan kepada kami [Al Hasan bin Al Hurr] telah menceritakan kepada kami [Isa bin Abdullah bin Malik] dari ['Abbas atau 'Ayyasy bin Sahl As Sa'idi] bahwa dia pernah menghadiri suatu majlis yang di dalamnya terdapat ayahnya, kemudian dia menyebutkan sebagian hadits, katanya; \"Kemudian beliau sujud sambil tegak di atas telapak tangan dan kedua lututnya serta kedua telapak kakinya, kemudian beliau bertakbir dan sujud, setelah itu beliau bertakbir dan langsung berdiri tidak duduk tawaruk, kemudian beliau kembali (berdiri), kemudian beliau ruku' di raka'at yang lain (raka'at terakhir) sambil bertakbir seperti itu, kemudian beliau duduk setelah dua raka'at, sehingga ketika beliau hendak berdiri, beliau bertakbir terlebih dahulu, kemudian beliau menyempurnakan dua raka'at yang terakhir, ketika memberi salam, beliau memberi salam ke kanan dan ke arah kiri.\" Abu Daud mengatakan; \"Dalam haditsnya Isa bin Abdullah tidak disebutkan seperti apa yang di sebutkan oleh Abdul Hamid dalam duduk tawaruk dan mengangkat (tangan) apabila berdiri dari dua raka'at.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah mengabarkan kepadaku [Fulaih] telah mengabarkan kepadaku ['Abbas bin Sahl] dia berkata; Abu Humaid, Abu Usaid, Sahl bin Sa'd dan Muhammad bin Maslamah pernah berkumpul…\" kemudian dia menyebutkan hadits ini, namun tidak menyebutkan tentang mengangkat (tangan) apabila berdiri dari dua raka'at dan juga pada waktu duduk\" katanya; \"Sampai beliau selesai, kemudian duduk dengan menduduki kaki kiri dan menghadapkan kiblat pada punggung kaki kanannya.\""},"812":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا يَحْيَى عَنْ سُلَيْمَانَ الْأَعْمَشِ حَدَّثَنِي شَقِيقُ بْنُ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكُنَّا إِذَا جَلَسْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ قُلْنَا السَّلَامُ عَلَى اللَّهِ قَبْلَ عِبَادِهِ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ إِذَا جَلَسَ أَحَدُكُمْ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّكُمْ إِذَا قُلْتُمْ ذَلِكَ أَصَابَ كُلَّ عَبْدٍ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَوْ بَيْنَ السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ لِيَتَخَيَّرْ أَحَدُكُمْ مِنْ الدُّعَاءِ أَعْجَبَهُ إِلَيْهِ فَيَدْعُوَ بِهِحَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ أَخْبَرَنَا إِسْحَقُ يَعْنِي ابْنَ يُوسُفَ عَنْ شَرِيكٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ كُنَّا لَا نَدْرِي مَا نَقُولُ إِذَا جَلَسْنَا فِي الصَّلَاةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عُلِّمَ فَذَكَرَ نَحْوَهُ قَالَ شَرِيكٌ وَحَدَّثَنَا جَامِعٌ يَعْنِي ابْنَ أَبِي شَدَّادٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بِمِثْلِهِ قَالَ وَكَانَ يُعَلِّمُنَا كَلِمَاتٍ وَلَمْ يَكُنْ يُعَلِّمُنَاهُنَّ كَمَا يُعَلِّمُنَا التَّشَهُّدَ اللَّهُمَّ أَلِّفْ بَيْنَ قُلُوبِنَا وَأَصْلِحْ ذَاتَ بَيْنِنَا وَاهْدِنَا سُبُلَ السَّلَامِ وَنَجِّنَا مِنْ الظُّلُمَاتِ إِلَى النُّورِ وَجَنِّبْنَا الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَبَارِكْ لَنَا فِي أَسْمَاعِنَا وَأَبْصَارِنَا وَقُلُوبِنَا وَأَزْوَاجِنَا وَذُرِّيَّاتِنَا وَتُبْ عَلَيْنَا إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ وَاجْعَلْنَا شَاكِرِينَ لِنِعْمَتِكَ مُثْنِينَ بِهَا قَابِلِيهَا وَأَتِمَّهَا عَلَيْنَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْحَسَنُ بْنُ الْحُرِّ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ قَالَ أَخَذَ عَلْقَمَةُ بِيَدِي فَحَدَّثَنِي أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ أَخَذَ بِيَدِهِ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِ عَبْدِ اللَّهِ فَعَلَّمَهُ التَّشَهُّدَ فِي الصَّلَاةِ فَذَكَرَ مِثْلَ دُعَاءِ حَدِيثِ الْأَعْمَشِ إِذَا قُلْتَ هَذَا أَوْ قَضَيْتَ هَذَا فَقَدْ قَضَيْتَ صَلَاتَكَ إِنْ شِئْتَ أَنْ تَقُومَ فَقُمْ وَإِنْ شِئْتَ أَنْ تَقْعُدَ فَاقْعُدْ","id":"Telah menceritakan kepada kami [Musaddad] telah mengabarkan kepada kami [Yahya] dari [Sulaiman Al A'masy] telah menceritakan kepadaku [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud] dia berkata; \"Apabila kami selesai duduk-duduk bersama bersama Rasulullah shallallahu 'alaihi wasallam dalam shalat, maka kami ucapkan; \"As Salaamu 'alallah qabla 'ibaadihis salaam'ala fulaanin wa fulaan (selamat sejahtera bagi Allah sebelum hamba-bamba-Nya, selamat sejahtera bagi fulan dan fulan).\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengatakan \"As Salaamu 'alaallah, karena Allah adalah dzat sumber keselamatan, akan tetapi jika salah seorang dari kalian duduk hendaklah mengucapkan; 'At Tahiyyati lillah was shalawaatu wat thayyibaat, as salaamu 'alaika ayyuhan nabiiyyu warahmatullahi wa barakaatuh as salaamu 'alaina wa 'alaa ibaadillahis shalihin (Segala kesejahteraan milik Allah semata, begitupun segala kasih-sayang dan hal-hal yang baik, selamat sejahtera kiranya terlimpah kepadamu wahai Nabi, begitupun rahmat Allah serta berkah-berkah-nya. Selamat sejahtera terlimpah pula atas kami dan atas hamba-hamba Allah yang Shalih) \" apabila kalian mengucapkan seperti ini, maka kalian dapat mencapai semua hamba yang Shalih baik yang di langit maupun yang di bumi, -atau sabdanya- di antara langit dan bumi. ' \"Asyhadu allaa ilaaha illallah wa asyhadu ann namuhammadan 'abduhu wa rasuuluh (Aku bersaksi bahwa tidak ada ilah selaian Allah, dan aku bersaksi bahwa Muhammad itu adalah hamba dan utusan-Nya) \", kemudian hendaklah salah seorang dari kalian memilih do'a yang menarik hatinya dan berdo'a dengan do'a itu.\" Telah menceritakan kepada kami [Tamim bin Al Muntashir] telah mengabarkan kepada kami [Ishaq yaitu Ibnu Yusuf] dari [Syarik] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dia berkata; \"Kami tidak tahu, apa yang harus kami baca ketika duduk dalam shalat, sedangkan Rasulullah shallallahu 'alaihi wasallam telah di ajari (oleh Allah) …\" kemudian dia menyebutkan hadits yang semisal itu.\" [Syarik] mengatakan; dan telah menceritakan kepada kami [Jami' yaitu ibnu Abu Syaddad] dari [Abu Wa'il] dari [Abdullah] seperti itu, katanya; \"Dan beliau telah mengajari kami beberapa kalimat, dan tidak mengajari kami kalimat-kalimat di atas sebagaimana beliau mengajari kami tasyahud, (sabdanya): \"Allahumma allif baina quluubina wa ashlih dzaata bainina wahdinaa subulus salaam wa najjinaa minad dlulumaati ilan nuur wa jannibnal fawaahisy maa dlahara minhaa wa maa bathana wa baarik lanaa fii asmaa'ina wa abshaarinaa wa quluubinaa wa azwaajinaa wa dzurriyyatinaa wa tub 'alainaa innaka anta tawwaabur rahim, wa ja'alna syaakiriin, lini'matika mutsniin bihaa qaabiliha wa atimmaha alainaa (Ya Allah, jinakkanlah antara hati kami, perbaikilah hubungan di antara kami, tunjukilah kami jalan yang lurus, selamatkanlah kami dari kegelapan menuju cahaya, hindarkanlah kami dari perbuatan keji baik yang nampak maupun yang tersembunyi, berkahilah kami pada pendengaran kami, penglihatan kami, hati kami, isteri-isteri kami dan anak cucu kami, terimalah taubat kami karena Engkau adalah dzat yang Maha penerima taubat dan Maha penyayang, jadikanlah kami dalam kelompok yang pandai bersyukur, terhadap nikmat-nikmat-Mu kami bersyukur, terimalah dan sempurnakanlah atas kami.\" Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al Hasan bin Al Hurr] dari [Al Qasim bin Mukhaimirah] dia berkata; ['Alqamah] memegang tanganku, lalu menceritakan kepadaku bahwa [Abdullah bin Mas'ud] pernah memegang tangannya, dan Rasulullah shallallahu 'alaihi wasallam juga pernah memegang tangan Abdullah bin Mas'ud, lalu beliau mengajarinya tasyahud dalam shalat…\" kemudian dia menyebutkan seperti do'a dalam haditsnya Al A'masy, (sabdanya): \"Apabila kamu telah mengucapkan do'a tersebut atau memenuhi do'a ini, maka kamu benar-benar telah memenuhi shalatmu, jika kamu hendak berdiri, berdirilah dan jika hendak duduk, maka duduklah.\""},"813":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنِي أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّشَهُّدِ التَّحِيَّاتُ لِلَّهِ الصَّلَوَاتُ الطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُقَالَ قَالَ ابْنُ عُمَرَ زِدْتَ فِيهَا وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ ابْنُ عُمَرَ زِدْتُ فِيهَا وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] aku mendengar [Mujahid] menceritakan dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam tentang tasyahud, yaitu: \"Attahiyyatu lillah Asshalawatut-thayyibat Assalamu 'alaika ayyuhannabiyyu warahmatullahi wabarakatuh\" Ibnu Umar berkata bahwa aku menambahkan \"wabarakatuh assalamu 'alaina wa'ala 'ibadillahis-shalihin Asyhadu alla ilaha illallah\" Ibnu Umar berkata bahwa aku menambahkan \"wahdahu la syarikalah wa asyhadu anna muhammadan abduhu warasuluhu\" (Segala penghormatan dan kebaktian yang baik hanya bagi Allah, kesejahteraan, rahmat Allah dan berkah-Nya tetap terlimpah kepadamu wahai Nabi, semoga kesejahteraan atas kami dan hamba-hamba Allah yang Shalih, aku bersaksi tidak ada ilah (yang berhak di sembah) kecuali Allah, tidak ada sekutu bagi-Nya, dan aku bersaksi bahwa Muhammad adalah Rasulullah).\""},"814":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ ح و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ قَالَصَلَّى بِنَا أَبُو مُوسَى الْأَشْعَرِيُّ فَلَمَّا جَلَسَ فِي آخِرِ صَلَاتِهِ قَالَ رَجُلٌ مِنْ الْقَوْمِ أُقِرَّتْ الصَّلَاةُ بِالْبِرِّ وَالزَّكَاةِ فَلَمَّا انْفَتَلَ أَبُو مُوسَى أَقْبَلَ عَلَى الْقَوْمِ فَقَالَ أَيُّكُمْ الْقَائِلُ كَلِمَةَ كَذَا وَكَذَا قَالَ فَأَرَمَّ الْقَوْمُ فَقَالَ أَيُّكُمْ الْقَائِلُ كَلِمَةَ كَذَا وَكَذَا فَأَرَمَّ الْقَوْمُ قَالَ فَلَعَلَّكَ يَا حِطَّانُ أَنْتَ قُلْتَهَا قَالَ مَا قُلْتُهَا وَلَقَدْ رَهِبْتُ أَنْ تَبْكَعَنِي بِهَا قَالَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَنَا قُلْتُهَا وَمَا أَرَدْتُ بِهَا إِلَّا الْخَيْرَ فَقَالَ أَبُو مُوسَى أَمَا تَعْلَمُونَ كَيْفَ تَقُولُونَ فِي صَلَاتِكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا فَعَلَّمَنَا وَبَيَّنَ لَنَا سُنَّتَنَا وَعَلَّمَنَا صَلَاتَنَا فَقَالَ إِذَا صَلَّيْتُمْ فَأَقِيمُوا صُفُوفَكُمْ ثُمَّ لِيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَرَأَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ يُحِبُّكُمْ اللَّهُ وَإِذَا كَبَّرَ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ يَسْمَعُ اللَّهُ لَكُمْ فَإِنَّ اللَّهَ تَعَالَى قَالَ عَلَى لِسَانِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَإِذَا كَبَّرَ وَسَجَدَ فَكَبِّرُوا وَاسْجُدُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ فَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ أَنْ يَقُولَ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ لَمْ يَقُلْ أَحْمَدُ وَبَرَكَاتُهُ وَلَا قَالَ وَأَشْهَدُ قَالَ وَأَنَّ مُحَمَّدًاحَدَّثَنَا عَاصِمُ بْنُ النَّضْرِ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ عَنْ أَبِي غَلَّابٍ يُحَدِّثُهُ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ بِهَذَا الْحَدِيثِ زَادَ فَإِذَا قَرَأَ فَأَنْصِتُوا وَقَالَ فِي التَّشَهُّدِ بَعْدَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ زَادَ وَحْدَهُ لَا شَرِيكَ لَهُ قَالَ أَبُو دَاوُد وَقَوْلُهُ فَأَنْصِتُوا لَيْسَ بِمَحْفُوظٍ لَمْ يَجِئْ بِهِ إِلَّا سُلَيْمَانُ التَّيْمِيُّ فِي هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Abu 'Awanah] dari [Qatadah]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Yunus bin Jubair] dari [Hithan bin Abdullah Ar Raqasyi] dia berkata; \"Abu Musa al Asy'ari shalat bersama kami, ketika dia duduk di akhir shalatnya, tiba-tiba seorang laki-laki dari suatu kaum berteriak, katanya; \"Shalat itu telah di tetapkan dengan amal kebaikan dan zakat.\" Ketika Abu Musa selesai dari shalat, dia menemui kaum tersebut tersebut seraya berkata; \"Siapakah di antara kalian tadi yang berkata demikian dan demikian?\" Hithan melanjutkan; \"Maka kaum tersebut diam menunduk. Abu Musa mengulanginya lagi; \"Siapakah di antara kalian tadi yang berkata demikian dan demikian?\" namun kaum tersebut masih diam menunduk.\" Abu Musa berkata; \"Mungkin kamu wahai Hithan, apakah kamu tadi yang mengatakannya?\" Hithan menjawab; \"Aku tidak mengatakannya, sungguh aku khawatir jika kamu mengecamku karena hal itu.\" Hithan melanjutkan; \"Maka seorang laki-laki dari suatu kaum itu berkata; \"Aku lah yang mengatakan ungkapan tadi, tidaklah aku mengatakannya kecuali untuk maksud baik.\" Maka [Abu Musa] berkata; \"Apakah kamu tahu bagaimanakah seharusnya yang kamu katakan dalam shalat? sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah di hadapan kami, beliau mengajari kami, menjelaskan ajaran kami dan mengajarkan tentang shalat kami, beliau bersabda: 'Apabila kalian hendak mengerjakan shalat, maka luruskanlah shaf kalian, dan hendaklah seseorang salah seorang dari kalian menjadi imam, apabila ia (imam) bertakbir, maka bertakbirlah kalian, apabila ia membaca \"Ghairil maghdluubi 'alaihim walad dllaallin\" maka ucapkanlah \"Amin\" niscaya Allah akan mencintai kalian, apabila ia bertakbir dan ruku', maka bertakbirlah dan ruku'lah kalian, sesungguhnya seorang imam itu ruku' sebelum kalian dan mengangkat (kepala) sebelum kalian.\" Rasulullah shallallahu 'alaihi wasallam melanjutkan: \"Maka (gerakkan kamu) itu harus setelah gerakan imam. Apabila imam membaca; \"Sami'allahu liman hamidah\" maka ucapkanlah; \"Allahumma Rabbanaa walakal hamdu\" Allah akan mendengarkan do'amu, sesungguhnya Allah Ta'ala shallallahu 'alaihi wasallam berfirman melalui lisan Nabi-Nya shallallahu 'alaihi wasallam \"sami'allahu liman hamidah\" apabila imam bertakbir dan sujud, maka bertakbir dan sujudlah kalian, karena sesungguhnya imam sujud sebelum kalian dan mengangkat kepalanya sebelum kalian.\" Rasulullah shallallahu 'alaihi wasallam melanjutkan sabdanya: \"Maka (gerakkan kamu) itu harus setelah gerakan imam, dan apabila imam telah duduk (di raka'at terakhir), maka hendaknya ucapan yang pertama kali di ucapkan oleh kalian adalah; \"Attahiyyatu lillah Asshalawatut-thayyibat Assalamu 'alaika ayyuhannabiyyu warahmatullahi wabarakatuh assalaamu 'alaina wa'ala 'ibadillahis-shalihin Asyhadu alla ilaha illallah wa asyhadu anna muhammadan abduhu warasuluhu\" (Segala penghormatan dan kebaktian yang baik hanya bagi Allah, kesejahteraan, rahmat Allah dan berkah-Nya tetap terlimpah kepadamu wahai Nabi, semoga kesejahteraan atas kami dan hamba-hamba Allah yang Shalih, aku bersaksi tidak ada ilah (yang berhak di sembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah Rasulullah).\" (dalam riwayatnya) Ahmad tidak menyebutkan \"wabarakaatuh\" tidak pula menyebutkan \"wa asyhadu\" namun dia hanya menyebutkan; \"wa anna muhammadan\" telah menceritakan kepada kami ['Ashim bin An Nadlr] telah menceritakan kepada kami [Al Mu'tamir] dia berkata; saya mendengar [ayahku], telah menceritakan kepada kami [Qatadah] dari [Abu Ghallab] telah menceritakan kepadanya, dari [Hitthan bin Abdullah Ar Raqasyi] seperti hadits tersebut, ia menambahkan; \"Apabila imam membaca (surat), maka diamlah kalian.\" Dia mengatakan setelah tasyahud setelah \"asyhadu allaa ilaaha illallah\" dia menambahkan; \"…wahdahuu laa syariikalah…\" Abu Daud mengatakan; perkataannya \"Maka diamlah kalian\" redaksi tersebut tidaklah terjaga, tidak ada dalam hadits ini, melainkan dari Sulaiman At Taimi.\""},"815":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا الْقُرْآنَ وَكَانَ يَقُولُ التَّحِيَّاتُ الْمُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Sa'id bin Jubair] dan [Thawus] dari [Ibnu Abbas] bahwa dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengajari kami sebagaimana beliau mengajari kami Al Qur'an, beliau mengucapkan: \"Attahiyyatul mubaarakatus shalawaatut thayyibaatu lillah Assalamu 'alaika ayyuhannabiyyu warahmatullahi wabarakatuh assalamu 'alaina wa'ala 'ibadillahis-shalihin Asyhadu alla ilaha illallah wa asyhadu anna muhammadan abduhu warasuluhu\" (Segala penghormatan dan kebaktian yang baik hanya bagi Allah, kesejahteraan, rahmat Allah dan berkah-Nya tetap terlimpah kepadamu wahai Nabi, semoga kesejahteraan atas kami dan hamba-hamba Allah yang Shalih, aku bersaksi tidak ada ilah (yang berhak di sembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah Rasulullah).\""},"816":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى أَبُو دَاوُدَ حَدَّثَنَا جَعْفَرُ بْنُ سَعْدِ بْنِ سَمُرَةَ بْنِ جُنْدُبٍ حَدَّثَنِي خُبَيْبُ بْنُ سُلَيْمَانَ بْنِ سَمُرَةَ عَنْ أَبِيهِ سُلَيْمَانَ بْنِ سَمُرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَمَّا بَعْدُ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ فِي وَسَطِ الصَّلَاةِ أَوْ حِينَ انْقِضَائِهَا فَابْدَءُوا قَبْلَ التَّسْلِيمِ فَقُولُوا التَّحِيَّاتُ الطَّيِّبَاتُ وَالصَّلَوَاتُ وَالْمُلْكُ لِلَّهِ ثُمَّ سَلِّمُوا عَلَى الْيَمِينِ ثُمَّ سَلِّمُوا عَلَى قَارِئِكُمْ وَعَلَى أَنْفُسِكُمْقَالَ أَبُو دَاوُد سُلَيْمَانُ بْنُ مُوسَى كُوفِيُّ الْأَصْلِ كَانَ بِدِمَشْقَ قَالَ أَبُو دَاوُد دَلَّتْ هَذِهِ الصَّحِيفَةُ عَلَى أَنَّ الْحَسَنَ سَمِعَ مِنْ سَمُرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan] telah menceritakan kepada kami [Yahya bin Hasan] telah menceritakan kepada kami [Sulaiman bin Musa Abu Daud] telah menceritakan kepada kami [Ja'far bin Sa'd bin Samurah bin Jundub] telah menceritakan kepadaku [Khubaib bin Sulaiman bin Samurah] dari [ayahnya Sulaiman bin Samurah] dari [Samurah bin Jundub] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan di saat kami sedang shalat atau ketika hendak menyelesaikannya yaitu sebelum salam, maka ucapkanlah \"Attahiyyat atthayyibat washshalawat walmulku lillah\" kemudian ucapkanlah salam terhadap golongan kanan (orang-orang Mukmin) dan ucapkanlah salam atas orang yang mengajarkan Al Qur'an kepada kalian dan atas diri kalian.\" Abu Daud berkata; \"Sulaiman bin Musa asalnya dari Kufah lalu dia menetap di Damaskus.\" Abu Daud berkata; \"Tulisan ini menunjukkan bahwa Al Hasan mendengar dari Samurah.\""},"817":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَ قُلْنَا أَوْقَالُوا يَا رَسُولَ اللَّهِ أَمَرْتَنَا أَنْ نُصَلِّيَ عَلَيْكَ وَأَنْ نُسَلِّمَ عَلَيْكَ فَأَمَّا السَّلَامُ فَقَدْ عَرَفْنَاهُ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا شُعْبَةُ بِهَذَا الْحَدِيثِ قَالَ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ عَنْ الْحَكَمِ بِإِسْنَادِهِ بِهَذَا قَالَ اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ قَالَ أَبُو دَاوُد رَوَاهُ الزُّبَيْرُ بْنُ عَدِيٍّ عَنْ ابْنِ أَبِي لَيْلَى كَمَا رَوَاهُ مِسْعَرٌ إِلَّا أَنَّهُ قَالَ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَسَاقَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Ka'b bin 'Ujrah] dia berkata; kami bertanya -atau- mereka bertanya; \"Wahai Rasulullah, Anda memerintahkan kami untuk bershalawat dan salam kepada anda, kami telah mengetahui tentang salam, lalu bagaimana cara kami bershalawat kepada anda?\" beliau bersabda: \"Ucapkanlah; 'Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim. Wabaarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim fil 'alamiina innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim. Ya Allah, curahkanlah keberkahan kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan keberkahan kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Syu'bah] seperti hadits ini, sabdanya; \"Shalli 'alaa muhammad wa 'alaa aali Muhammad kamaa shallait a'alaa ibraahiim (curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim).\" Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Ibnu Bisyr] dari [Mis'ar] dari [Al Hakam] dengan isnad ini, beliau bersabda: \"'Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim innaka hamiidum majiid. Allahumma baarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim fil 'alamiina innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim, sesungguhnya Engkau Maha Terpuji Lagi Maha Agung. Ya Allah, curahkanlah keberkahan kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan keberkahan kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\" Abu Daud berkata; \"(Hadits ini) juga di riwayatkan oleh [Az Zubair bin 'Adi] dari [Ibnu Abu Laila] sebagaimana yang di riwayatkan Mis'ar namun ia mengatakan; \"kamaa shallaita 'alaa aali Ibrahim innaka hamiidum majiid, wa baarik 'alaa Muhammad …\" kemudian ia melanjutkan hadits seperti itu. "},"818":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ أَنَّهُ قَالَ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌحَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ زَيْدٍ وَعَبْدُ اللَّهِ بْنُ زَيْدٍ هُوَ الَّذِي أُرِيَ النِّدَاءَ بِالصَّلَاةِ أَخْبَرَهُ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ أَنَّهُ قَالَ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسِ سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ بَشِيرُ بْنُ سَعْدٍ أَمَرَنَا اللَّهُ أَنْ نُصَلِّيَ عَلَيْكَ يَا رَسُولَ اللَّهِ فَكَيْفَ نُصَلِّي عَلَيْكَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمَنَّيْنَا أَنَّهُ لَمْ يَسْأَلْهُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا فَذَكَرَ مَعْنَى حَدِيثِ كَعْبِ بْنِ عُجْرَةَ زَادَ فِي آخِرِهِ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدٍ عَنْ عُقْبَةَ بْنِ عَمْرٍو بِهَذَا الْخَبَرِ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ النَّبِيِّ الْأُمِّيِّ وَعَلَى آلِ مُحَمَّدٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik] dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [ayahnya] dari ['Amru bin Sulaim Az Zuraqi] bahwa dia berkata; telah mengabarkan kepadaku [Abu Humaid As Sa'idi] bahwa mereka bertanya; \"Wahai Rasulullah, bagaimana cara kami bershalawat kepadamu?\" beliau bersabda: 'Ucapkanlah oleh kalian; \"'Allahumma shalli 'ala Muhammadin wa azwajihi wa dzurriyatihi, kamaa shallaita 'alaa aali Ibrahim. Wabaarik 'alaa Muhammad wa azwajihi wa dzurriyatihi, kamaa baarakta 'alaa aali Ibrahim fil 'alamiina innaka hamiidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad, para isterinya dan keturunannya sebagaimana Engkau curahkan kepada keluarga Ibrahim. Ya Allah, curahkanlah keberkahan kepada Muhammad, isteri-isterinya dan keturunannya, sebagaimana Engkau curahkan keberkahan kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\" Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nu'aim bin Abdullah al Mujmir] bahwa [Muhammad bin Abdullah bin Zaid], Abdullah bin Zaid yang aku ketahui dia seorang yang mengumandangkan adzan untuk shalat, dia telah mengabarkan kepadanya, dari [Abu Mas'ud Al Anshari] bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menemui kami di Majlisnya Sa'd bin 'Ubadah, maka Bisyr bin Sa'd bertanya kepada beliau; \"Wahai Rasulullah, Allah telah memerintahkan kepada kami untuk bershalawat kepada anda, lalu bagaimana caranya kami bershalawat kepada anda?\" namun Rasulullah shallallahu 'alaihi wasallam diam, sehingga kami berharap supaya Bisyr tidak bertanya ulang kepada beliau, setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ucapkanlah oleh kalian …\" kemudian ia menyebutkan makna hadits Ka'b bin 'Ujrah, di akhir hadits ia menambahkan; \"fil 'aalamiina innaka hamiidum majiid.\" Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepada kami [Muhammad bin Ibrahim bin Al Harits] dari [Muhammad bin Abdullah bin Zaid] dari ['Uqbah bin 'Amru] seperti hadits ini, beliau bersabda: \"Ucapkanlah oleh kalian; \"Allahumma shalli 'alaa Muhammad An Nabiyyil Ummi wa 'alaa aali Muhammad (Ya Allah, limpahkanlah kesejahteraan kepada Muhammad, Nabi yang Ummi (buta huruf) dan kepada keluarga Muhammad).\""},"819":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حِبَّانُ بْنُ يَسَارٍ الْكِلَابِيُّ حَدَّثَنِي أَبُو مُطَرِّفٍ عُبَيْدُ اللَّهِ بْنُ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ بْنِ كَرِيزٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَلِيٍّ الْهَاشِمِيُّ عَنْ الْمُجْمِرِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَرَّهُ أَنْ يَكْتَالَ بِالْمِكْيَالِ الْأَوْفَى إِذَا صَلَّى عَلَيْنَا أَهْلَ الْبَيْتِ فَلْيَقُلْ اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ أُمَّهَاتِ الْمُؤْمِنِينَ وَذُرِّيَّتِهِ وَأَهْلِ بَيْتِهِ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hibban bin Yasar Al Kilabi] telah menceritakan kepadaku [Abu Mutharif 'Ubaidullah bin Thlhah bin Kariz] telah menceritakan kepadaku [Muhammad bin Ali Al Hasyimi] dari [Al Mujmir] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa ingin di timbang dengan timbangan yang sempurna, maka apabila bershalawat kepada kami yaitu ahlul bait, hendaklah dia mengucapkan \"Allahumma shalli 'ala muhammadin waazwajihi ummahatul mu'minin wadzurriyyatihi wa ahla baitihi kama shallaita 'ala ali Ibrahim innaka hamidun majid\" (Ya Allah limpahkanlah kesejahteraan kepada Muhammad, para istrinya yaitu ibu bagi orang-orang yang beriman, keturunannya dan ahlu baitnya sebagaimana Engkau limpahkan kesejahteraan kepada keluarga Ibrahim, sesungguhnya Engkau Maha Terpuji lagi Maha Agung).\""},"820":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي عَائِشَةَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَرَغَ أَحَدُكُمْ مِنْ التَّشَهُّدِ الْآخِرِ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ مِنْ عَذَابِ جَهَنَّمَ وَمِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Hasan bin 'Athiyah] telah menceritakan kepadaku [Muhammad bin Abu Aisyah] bahwa dia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian selesai dari tasyahud akhir, hendaklah memohon perlindungan kepada Allah dari empat perkara, yaitu; dari siksa neraka Jahannam, dari siksa kubur, fitnah kehidupan dan kematian serta dari kejahatan Dajjal.\""},"821":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا عُمَرُ بْنُ يُونُسَ الْيَمَامِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ بَعْدَ التَّشَهُّدِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyah] telah mengabarkan kepada kami [Umar bin Yunus Al Yamami] telah menceritakan kepadaku [Muhammad bin Abdullah bin Thawus] dari [ayahnya] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bahwa setelah tasyahud beliau sering membaca do'a; \"Allahumma inni a'uudzu bika min 'adzaabi jahannam wa a'uudzu bika min 'adzzabil qabri wa a'uudzu bika min fitnatid dajjal wa a'uudzu bika min fitnatil mahyaa wal mamaati (Ya Allah aku berlindung kepada-Mu dari siksa neraka Jahannam, dari siksa kubur, dan dari fitnah Dajjal fitnah serta fitnah kehidupan dan kematian.\""},"822":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ الْمُعَلِّمُ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ حَنْظَلَةَ بْنِ عَلِيٍّ أَنَّ مِحْجَنَ بْنَ الْأَدْرَعِ حَدَّثَهُ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ فَإِذَا هُوَ بِرَجُلٍ قَدْ قَضَى صَلَاتَهُ وَهُوَ يَتَشَهَّدُ وَهُوَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ يَا أَللَّهُ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ أَنْ تَغْفِرَ لِي ذُنُوبِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ قَالَ فَقَالَ قَدْ غُفِرَ لَهُ قَدْ غُفِرَ لَهُ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abdullah bin 'Amru Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Al Husain Al Mu'allim] dari [Abdullah bin Buraidah] dari [Handlalah bin Ali] bahwa [Mihjan bin Al Adra'] telah menceritakan kepadanya, katanya Mihjan; \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid, lalu beliau mendapati seorang laki-laki membaca tasyahud seusai shalat, dia mengucapkan; \"Allahumma inni as`aluka Ya Allah Al Ahad As Shamad alladzii lam yalid wa lam yuulad walam yakul lahuu kufuwan ahad antaghfira lii dzunuubi innaka antal ghafuurur rakhiim (Ya Allah, sesungguhnya aku memohon kepada-Mu, Dzat yang Maha Esa, Dzat yang bergantung kepada-Nya segala sesuatu, tiada beranak dan tidak pula diperanakkan dan tidak ada seorangpun yang setara dengan Dia, semoga Engkau mengampuni dosa-dosaku, sesungguhnya Engkau adalah Maha Pengampun lagi Maha Penyayang.\" Kata Mihjan, maka beliau bersabda: \"Sungguh (dosa-dosa) nya telah di ampuni, Sungguh (dosa-dosa) nya telah di ampuni.\" Beliau mengucapkannya hingga tiga kali.\""},"823":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا يُونُسُ يَعْنِي ابْنَ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَمِنْ السُّنَّةِ أَنْ يُخْفَى التَّشَهُّدُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] telah menceritakan kepada kami [Yunus yaitu Ibnu Bukair] dari [Muhammad bin Ishaq] dari [Abdurrahman bin Al Aswad] dari [ayahnya] dari [Abdullah] dia berkata; \"Diantara sunnah -dalam shalat- adalah mengucapkan tasyahhud dengan samar (pelan).\""},"824":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُسْلِمِ بْنِ أَبِي مَرْيَمَ عَنْ عَلِيِّ بْنِ عَبْدِ الرَّحْمَنِ الْمُعَاوِيِّ قَالَرَآنِي عَبْدُ اللَّهِ بْنُ عُمَرَ وَأَنَا أَعْبَثُ بِالْحَصَى فِي الصَّلَاةِ فَلَمَّا انْصَرَفَ نَهَانِي وَقَالَ اصْنَعْ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ فَقُلْتُ وَكَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ قَالَ كَانَ إِذَا جَلَسَ فِي الصَّلَاةِ وَضَعَ كَفَّهُ الْيُمْنَى عَلَى فَخْذِهِ الْيُمْنَى وَقَبَضَ أَصَابِعَهُ كُلَّهَا وَأَشَارَ بِأُصْبُعِهِ الَّتِي تَلِي الْإِبْهَامَ وَوَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخْذِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Muslim bin Abu Maryam] dari [Ali bin Abdurrahman Al Mu'awi] dia berkata; [Abdullah bin Umar] melihatku, ketika aku sedang mempermainkan kerikil dalam shalat, seusai shalat, dia melarangku sambil berkata; \"Perbuatlah seperti yang di perbuat oleh Rasulullah shallallahu 'alaihi wasallam.\" kataku; 'Bagaimana yang biasa di perbuat Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab; \"Apabila beliau duduk dalam shalat, beliau meletakkan telapak tangan kanannya di atas paha kanannya dan menggenggam semua jari jemarinya seraya menunjuk dengan jari yang dekat ibu jari (jari telunjuk) dan meletakkan telapak tangan kirinya di atas paha kirinya.\""},"825":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنَا عَامِرُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَعَدَ فِي الصَّلَاةِ جَعَلَ قَدَمَهُ الْيُسْرَى تَحْتَ فَخْذِهِ الْيُمْنَى وَسَاقِهِ وَفَرَشَ قَدَمَهُ الْيُمْنَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى رُكْبَتِهِ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى فَخْذِهِ الْيُمْنَى وَأَشَارَ بِأُصْبُعِهِ وَأَرَانَا عَبْدُ الْوَاحِدِ وَأَشَارَ بِالسَّبَّابَةِ","id":"telah menceritakan kepada kami [Muhammad bin Abdurrahim Al Bazzaz] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepada kami ['Amir bin Abdullah bin Az Zubair] dari [ayahnya] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam duduk dalam shalat, beliau meletakkan telapak kaki kirinya di bawah paha dan betis kanannya, dan menghamparkan telapak kaki kanannya serta meletakkan tangan kirinya di atas lutut kiri dan meletakkan tangan kanan di atas paha kanan sambil menunjuk dengan jarinya.\" Abdul Wahid memperlihatkan kepada kami sambil menunjuk dengan jari telunjuknya.\""},"826":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ عَنْ زِيَادٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَنَّهُ ذَكَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُشِيرُ بِأُصْبُعِهِ إِذَا دَعَا وَلَا يُحَرِّكُهَاقَالَ ابْنُ جُرَيْجٍ وَزَادَ عَمْرُو بْنُ دِينَارٍ قَالَ أَخْبَرَنِي عَامِرٌ عَنْ أَبِيهِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو كَذَلِكَ وَيَتَحَامَلُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ الْيُسْرَى عَلَى فَخْذِهِ الْيُسْرَى حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ بِهَذَا الْحَدِيثِ قَالَ لَا يُجَاوِزُ بَصَرُهُ إِشَارَتَهُ وَحَدِيثُ حَجَّاجٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Hasan Al Mishhishi] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dari [Ziyad] dari [Muhammad bin 'Ajlan] dari ['Amir bin Abdullah] dari [Abdullah bin Zubair] bahwa dia menyebutkan bahwa Nabi shallallahu 'alaihi wasallam memberi isyarat dengan jarinya ketika berdo'a, tanpa menggerakkannya.\" [Ibnu Juraij] berkata; ['Amru bin Dinar] menambahkan; katanya; telah mengabarkan kepadaku ['Amir] dari [ayahnya] bahwa dia pernah melihat Nabi shallallahu 'alaihi wasallam seperti itu juga (menunjuk, dan Nabi shallallahu 'alaihi wasallam juga meletakkan tangan kirinya di atas paha kirinya.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu 'Ajlan] dari ['Amir bin Abdullah bin Az Zubair] dari [ayahnya] dengan hadits seperti ini, katanya; \"…pandangan mata beliau tidak melampaui dari telunjuk beliau…\" sedangkan hadits Hajjaj lebih sempurna. "},"827":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عُثْمَانُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِصَامُ بْنُ قُدَامَةَ مِنْ بَنِي بَجِيلَةَ عَنْ مَالِكِ بْنِ نُمَيْرٍ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا ذِرَاعَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى رَافِعًا إِصْبَعَهُ السَّبَّابَةَ قَدْ حَنَاهَا شَيْئًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Utsman yaitu Ibnu Abdurrahman] telah menceritakan kepada kami ['Isham bin Qudamah] dari Bani Bajilah, dari [Malik bin Numair Al Khuza'i] dari [ayahnya] dia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam meletakkan lengan kanannya diatas paha kanannya sambil mengangkat jari telunjuknya dengan sedikit melengkung.\""},"828":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَأَحْمَدُ بْنُ مُحَمَّدِ بْنِ شَبُّوَيْهِ وَمُحَمَّدُ بْنُ رَافِعٍ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ الْغَزَّالُ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ أَنْ يَجْلِسَ الرَّجُلُ فِي الصَّلَاةِ وَهُوَ مُعْتَمِدٌ عَلَى يَدِهِ وَقَالَ ابْنُ شَبُّوَيْهِ نَهَى أَنْ يَعْتَمِدَ الرَّجُلُ عَلَى يَدِهِ فِي الصَّلَاةِ وَقَالَ ابْنُ رَافِعٍ نَهَى أَنْ يُصَلِّيَ الرَّجُلُ وَهُوَ مُعْتَمِدٌ عَلَى يَدِهِ وَذَكَرَهُ فِي بَابِ الرَّفْعِ مِنْ السُّجُودِ وَقَالَ ابْنُ عَبْدِ الْمَلِكِ نَهَى أَنْ يَعْتَمِدَ الرَّجُلُ عَلَى يَدَيْهِ إِذَا نَهَضَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], [Ahmad bin Muhammad bin Syabuaih], [Muhammad bin Rafi'] dan [Muhammad bin Abdul Malik Al Ghazzal] mereka berkata; telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Isma'il bin Umayyah] dari [Nafi'] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang -Ahmad bin Hanbal mengatakan- seseorang duduk dalam shalat, sedangkan dia bertopang kepada kedua tangannya.\" Ibnu Syabuaih; \"Beliau melarang seseorang yang sedang shalat bertumpu pada tangannya. ' Ibnu Rafi' mengatakan; \"Beliau melarang seseorang yang shalat sambil bertumpu pada tangannya.\" Dan dia menyebutkannya pada bab \"Mengangkat (kepadal) dari sujud\", Ibnu Abdul Malik berkata; \"Beliau melarang seseorang bertumpu kepada kedua tangannya ketika bangkit (berdiri) dalam shalat.\""},"829":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ سَأَلْتُ نَافِعًاعَنْ الرَّجُلِ يُصَلِّي وَهُوَ مُشَبِّكٌ يَدَيْهِ قَالَ قَالَ ابْنُ عُمَرَ تِلْكَ صَلَاةُ الْمَغْضُوبِ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal] telah menceritakan kepada kami [Abdul Warits] dari [Isma'il bin Umayyah]; \"aku bertanya kepada [Nafi'] tentang orang yang shalat dengan menjalin jari-jari tangannya yang satu dengan yang lain.\" Jawabnya; [Ibnu Umar] pernah berkata: \"Itu adalah shalatnya orang yang dimurkai (Yahudi).\""},"830":{"ar":"حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ حَدَّثَنَا ابْنُ وَهْبٍ وَهَذَا لَفْظُهُ جَمِيعًا عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ رَأَى رَجُلًا يَتَّكِئُ عَلَى يَدِهِ الْيُسْرَى وَهُوَ قَاعِدٌ فِي الصَّلَاةِ قَالَ هَارُونُ بْنُ زَيْدٍ سَاقِطًا عَلَى شِقِّهِ الْأَيْسَرِ ثُمَّ اتَّفَقَا فَقَالَ لَهُ لَا تَجْلِسْ هَكَذَا فَإِنَّ هَكَذَا يَجْلِسُ الَّذِينَ يُعَذَّبُونَ","id":"Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa'] telah menceritakan kepada kami [ayahku], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Salamah] telah menceritakan kepada kami [Ibnu Wahb], sedangkan lafadznya dari [Hisyam bin Sa'd] dari [Nafi'] dari [Ibnu Umar] bahwa dia melihat seseorang bersandar dengan tangan kirinya ketika duduk dalam shalat- Harun bin Yazid berkata: \"condong kearah kirinya, \" kemudian keduanya sepakat pada lafadz- Maka Ibnu Umar berkata kepadanya; \"Janganlah kamu duduk seperti itu, karena itu seperti duduknya orang yang di adzab.\""},"831":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي عُبَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ كَأَنَّهُ عَلَى الرَّضْفِ قَالَ قُلْنَا حَتَّى يَقُومَ قَالَ حَتَّى يَقُومَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Abu 'Ubaidah] dari [ayahnya] bahwa ketika Nabi shallallahu 'alaihi wasallam bangkit dari dua raka'at yang pertama, beliau seperti duduk di atas batu yang di panaskan.\" Syu'bah berkata; \"Hingga beliau segera berdiri?\" Sa'd bin Ibrahim menjawab; \"Sehingga beliau bergegas untuk berdiri.\""},"832":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ وَزِيَادُ بْنُ أَيُّوبَ قَالَا حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ ح و حَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ أَخْبَرَنَا إِسْحَقُ يَعْنِي ابْنَ يُوسُفَ عَنْ شَرِيكٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْرَائِيلُ كُلُّهُمْ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ وَقَالَ إِسْرَائِيلُ عَنْ أَبِي الْأَحْوَصِ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِقَالَ أَبُو دَاوُد وَهَذَا لَفْظُ حَدِيثِ سُفْيَانَ وَحَدِيثُ إِسْرَائِيلَ لَمْ يُفَسِّرْهُ قَالَ أَبُو دَاوُد وَرَوَاهُ زُهَيْرٌ عَنْ أَبِي إِسْحَقَ وَيَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ وَعَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ أَبُو دَاوُد شُعْبَةُ كَانَ يُنْكِرُ هَذَا الْحَدِيثَ حَدِيثَ أَبِي إِسْحَقَ أَنْ يَكُونَ مَرْفُوعًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Za`idah] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Muhribi] dan [Ziyad bin Ayyub] keduanya berkata; telah menceritakan kepada kami ['Umar bin 'Ubaid Ath Thanafisi], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Tamim bin Al Muntashir] telah mengabarkan kepada kami [Ishaq yaitu Ibnu Yusuf] dari [Syarik], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Isra`il] semuanya dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah], sedangkan [Isra'il] mengatakan, dari [Abu Al Ahwash] dan [Al Aswad] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam biasa memberi salam ke arah kanan dan ke arah kiri sehingga terlihat putih pipi beliau (beliau mengucapkan): \" Assalaamu 'alaikum wa rahmatullah, Assalaamu 'alaikum wa rahmatullahi (semoga keselamatan dan rahmat Allah tetap atas kalian, semoga keselamatan dan rahmat Allah tetap atas kalian).\" Abu Daud mengatakan; \"Lafadz hadits ini berasal dari haditsnya Sufyan dan hadits Isra'il tanpa ada penafsiran.\" Abu Daud mengatakan; \"Dan di riwayatkan pula oleh [Zuhair] dari [Abu Ishaq] dan [Yahya bin Adam] dari [Isra'il] dari [Abu Ishaq] dari [Abdurrahman bin Al Aswad] dari [ayahnya] dari ['Alqamah] dari [Abdullah].\" Abu Daud berkata; \"Syu'bah mengingkari hadits ini, yaitu hadits Abu Ishaq yang di marfu'kan.\""},"833":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مُوسَى بْنُ قَيْسٍ الْحَضْرَمِيُّ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يُسَلِّمُ عَنْ يَمِينِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ وَعَنْ شِمَالِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Musa bin Qais Al Hadlrami] dari [Salamah bin Kuhail] dari ['Alqamah bin Wa`il] dari [ayahnya] dia berkata; \"Aku shalat di belakang Rasulullah shallallahu 'alaihi wasallam, beliau memberi salam ke arah kanan dengan mengucapkan \"Assalamu 'alaikum wa rahmatullahi wa barakatuh (Semoga keselamatan, rahmat dan berkah Allah tetap atas kalian), \" dan kearah kiri dengan mengucapkan \"Assalamu 'alaikum warahmatullah (Semoga keselamatan dan rahmat Allah tetap atas kalian).\""},"834":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا وَوَكِيعٌ عَنْ مِسْعَرٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ أَحَدُنَا أَشَارَ بِيَدِهِ مِنْ عَنْ يَمِينِهِ وَمِنْ عَنْ يَسَارِهِ فَلَمَّا صَلَّى قَالَ مَا بَالُ أَحَدِكُمْ يُومِي بِيَدِهِ كَأَنَّهَا أَذْنَابُ خَيْلٍ شُمْسٍ إِنَّمَا يَكْفِي أَحَدَكُمْ أَوْ أَلَا يَكْفِي أَحَدَكُمْ أَنْ يَقُولَ هَكَذَا وَأَشَارَ بِأُصْبُعِهِ يُسَلِّمُ عَلَى أَخِيهِ مِنْ عَنْ يَمِينِهِ وَمِنْ عَنْ شِمَالِهِحَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ مِسْعَرٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ أَمَا يَكْفِي أَحَدَكُمْ أَوْ أَحَدَهُمْ أَنْ يَضَعَ يَدَهُ عَلَى فَخْذِهِ ثُمَّ يُسَلِّمَ عَلَى أَخِيهِ مِنْ عَنْ يَمِينِهِ وَمِنْ عَنْ شِمَالِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Zakariya] dan [Waki'] dari [Mis'ar] dari ['Ubaidullah bin Al Qibthiyah] dari [Jabir bin Samurah] dia berkata; \"Apabila kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam, maka salah seorang dari kami memberi salam seraya memberi isyarat dengan tangannya kepada orang yang berada di kanan dan kirinya, ketika beliau selesai mengerjakan shalat, beliau bersabda: 'Kenapa salah seorang dari kalian masih saja memberi isyarat dengan tangannya seperti ekor kuda yang bergerak-gerak?, cukuplah salah seorang dari kalian -atau- tidak cukupkah salah seorang dari kalian melakukannya seperti ini saja.\" beliau memberi isyarat dengan jarinya dengan memberi salam kepada saudaranya yang ada di kanan dan kirinya.\" Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Abu Nu'aim] dari [Mis'ar] dengan isnad dan makna yang sama, sabdanya: \"Cukuplah salah seorang dari kalian -atau dari mereka- meletakkan tangannya di atas pahanya kemudian dia memberi salam kepada saudaranya yang berada di kanan dan kirinya.\""},"835":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَعْمَشُ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمٍ الطَّائِيِّ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ رَافِعُوا أَيْدِيهِمْ قَالَ زُهَيْرٌ أُرَاهُ قَالَ فِي الصَّلَاةِ فَقَالَ مَا لِي أَرَاكُمْ رَافِعِي أَيْدِيكُمْ كَأَنَّهَا أَذْنَابُ خَيْلٍ شُمْسٍ أُسْكُنُوا فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim Ath Tha`i] dari [Jabir bin Samurah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menemui kami, sedangkan orang-orang tengah mengangkat tangan -Zuhair berkata; sepengetahuanku Jabir bin Samurah mengatakan; \"ketika mereka tengah mengerjakan shalat, \" maka beliau bersabda: \"Kenapa aku melihat kalian mengangkat tangan seperti ekor kuda yang bergerak-gerak, diamlah kalian dalam shalat.\""},"836":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ أَبُو الْجَمَاهِرِ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَرُدَّ عَلَى الْإِمَامِ وَأَنْ نَتَحَابَّ وَأَنْ يُسَلِّمَ بَعْضُنَا عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Muhammad bin Utsman Abu Al Jamahir] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samurah] dia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan kami untuk menjawab salamnya imam, saling berkasih sayang dan saling mengucapkan salam antara sebagian kami dengan sebagian yang lain.\""},"837":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ يُعْلَمُ انْقِضَاءُ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتَّكْبِيرِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah mengabarkan kepada kami [Sufyan] dari ['Amru] dari [Abu Ma'bad] dari [Ibnu Abbas] dia berkata; \"Selesai shalatnya Rasulullah shallallahu 'alaihi wasallam, dapat di ketahui dengan takbir.\""},"838":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنِي ابْنُ جُرَيْجٍ أَخْبَرَنَا عَمْرُو بْنُ دِينَارٍ أَنَّ أَبَا مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ أَخْبَرَهُ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَفْعَ الصَّوْتِ لِلذِّكْرِ حِينَ يَنْصَرِفُ النَّاسُ مِنْ الْمَكْتُوبَةِ كَانَ ذَلِكَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَنَّ ابْنَ عَبَّاسٍ قَالَ كُنْتُ أَعْلَمُ إِذَا انْصَرَفُوا بِذَلِكَ وَأَسْمَعُهُ","id":"Telah menceritakan kepada kami [Yahya bin Musa al Balhi] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepadaku [Ibnu Juraij] telah mengabarkan kepada kami ['Amru bin Dinar] bahwa [Abu Ma'bad] bekas budak Ibnu Abbas telah mengabarkan kepadanya, bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwa \"Mengeraskan suara dzikir ketika orang-orang selesai dari shalat fardlu itu telah di lakukan di masa Rasulullah shallallahu 'alaihi wasallam, dan Ibnu Abbas mengatakan; \"Aku mengetahuinya ketika mereka selesai melakukan itu dan aku juga mendengarnya.\""},"839":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنِي مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ قُرَّةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَذْفُ السَّلَامِ سُنَّةٌقَالَ عِيسَى نَهَانِي ابْنُ الْمُبَارَكِ عَنْ رَفْعِ هَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد سَمِعْت أَبَا عُمَيْرٍ عِيسَى بْنَ يُونُسَ الْفَاخُورِيَّ الرَّمْلِيَّ قَالَ لَمَّا رَجَعَ الْفِرْيَابِيُّ مِنْ مَكَّةَ تَرَكَ رَفْعَ هَذَا الْحَدِيثِ وَقَالَ نَهَاهُ أَحْمَدُ بْنُ حَنْبَلٍ عَنْ رَفْعِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] telah menceritakan kepadaku [Muhammad bin Yusuf Al Firyabi] telah menceritakan kepada kami [Al Auza'i] dari [Qurrah bin Abdurrahman] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak memanjangkan lafadz salam adalah sunnah.\" Isa berkata; Ibnu Mubarrak melarangku untuk merafa'kan hadits ini, Abu Daud mengatakan; \"aku mendengar Abu 'Umair Isa bin Yunus Al Fahuri Ar Ramli dia berkata; \"Ketika Al Firyabi kembali dari Makkah, dia meninggalkan untuk merafa'kan hadits ini, katanya; \"Ahmad bin Hanbal telah melarang untuk merafa'kannya.\""},"840":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عِيسَى بْنِ حِطَّانَ عَنْ مُسْلِمِ بْنِ سَلَّامٍ عَنْ عَلِيِّ بْنِ طَلْقٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَسَا أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَنْصَرِفْ فَلْيَتَوَضَّأْ وَلْيُعِدْ صَلَاتَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari ['Ashim Al Ahwal] dari [Isa bin Hithan] dari [Muslim bin Salam] dari ['Ali bin Thalq] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian kentut dan tidak bersuara dalam shalat, hendaknya ia beranjak untuk berwudlu' dan mengulangi shalatnya.\""},"841":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ وَعَبْدُ الْوَارِثِ عَنْ لَيْثٍ عَنْ الْحَجَّاجِ بْنِ عُبَيْدٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَعْجِزُ أَحَدُكُمْ قَالَ عَنْ عَبْدِ الْوَارِثِ أَنْ يَتَقَدَّمَ أَوْ يَتَأَخَّرَ أَوْ عَنْ يَمِينِهِ أَوْ عَنْ شِمَالِهِ زَادَ فِي حَدِيثِ حَمَّادٍ فِي الصَّلَاةِ يَعْنِي فِي السُّبْحَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dan [Abdul Warits] dari [Laits] dari [Al Hajjaj bin 'Ubaid] dari [Ibrahim bin Isma'il] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah salah seorang dari kalian tidak mampu -Musaddad berkata dari Abdul Warits- hendak maju atau mundur, ke kanan atau ke kiri -dalam haditsnya Hammad di tambahkan- dalam shalat yaitu shalat sunnah.\""},"842":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا أَشْعَثُ بْنُ شُعْبَةَ عَنْ الْمِنْهَالِ بْنِ خَلِيفَةَ عَنْ الْأَزْرَقِ بْنِ قَيْسٍ قَالَصَلَّى بِنَا إِمَامٌ لَنَا يُكْنَى أَبَا رِمْثَةَ فَقَالَ صَلَّيْتُ هَذِهِ الصَّلَاةَ أَوْ مِثْلَ هَذِهِ الصَّلَاةِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَانَ أَبُو بَكْرٍ وَعُمَرُ يَقُومَانِ فِي الصَّفِّ الْمُقَدَّمِ عَنْ يَمِينِهِ وَكَانَ رَجُلٌ قَدْ شَهِدَ التَّكْبِيرَةَ الْأُولَى مِنْ الصَّلَاةِ فَصَلَّى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَلَّمَ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ حَتَّى رَأَيْنَا بَيَاضَ خَدَّيْهِ ثُمَّ انْفَتَلَ كَانْفِتَالِ أَبِي رِمْثَةَ يَعْنِي نَفْسَهُ فَقَامَ الرَّجُلُ الَّذِي أَدْرَكَ مَعَهُ التَّكْبِيرَةَ الْأُولَى مِنْ الصَّلَاةِ يَشْفَعُ فَوَثَبَ إِلَيْهِ عُمَرُ فَأَخَذَ بِمَنْكِبِهِ فَهَزَّهُ ثُمَّ قَالَ اجْلِسْ فَإِنَّهُ لَمْ يُهْلِكْ أَهْلَ الْكِتَابِ إِلَّا أَنَّهُ لَمْ يَكُنْ بَيْنَ صَلَوَاتِهِمْ فَصْلٌ فَرَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَصَرَهُ فَقَالَ أَصَابَ اللَّهُ بِكَ يَا ابْنَ الْخَطَّابِقَالَ أَبُو دَاوُد وَقَدْ قِيلَ أَبُو أُمَيَّةَ مَكَانَ أَبِي رِمْثَةَ","id":"Telah menceritakan kepada kami [Abdul Wahab bin Najdah] telah menceritakan kepada kami [Asy'ats Tsauri bin Syu'bah] dari [Al Minhal bin Khalifah] dari [Al Azraq bin Qais] dia berkata; imam kami yang berkunyah [Abu Rimtsah] shalat bersama kami, katanya; \"Aku shalat seperti ini atau seperti shalat bersama Nabi shallallahu 'alaihi wasallam, -dia melanjutkan perkataannya- sementara Abu Bakar dan Umar shalat di shaf pertama, tepatnya di samping kanan beliau, tiba-tiba seseorang datang dan mendapatkan takbiratul ihram bersama beliau, lalu Nabi Allah shallallahu 'alaihi wasallam mengerjakan shalat, kemudian salam kekanan dan kekiri sehingga kami melihat putihnya pipi beliau. Kemudian beliau merubah posisi sebagaimana Abu Ritsmah merubah posisi. Lantas seorang laki-laki yang tadi hanya mendapatkan takbiratul ihram berdiri untuk menambah raka'at lagi, maka Umar melompat menuju kepadanya dan memegang kedua pundak orang tersebut serta menggetarkannya sambil berkata: \"Duduklah! Karena sesungguhnya ahlul kitab tidak binasa kecuali mereka tidak memisahkan antara shalat-shalat mereka.\" Lalu Nabi shallallahu 'alaihi wasallam memandanginya seraya bersabda: \"Kamu benar wahai Ibnu Khattab.\" Abu Daud berkata: \"Dikatakan bahwa Abu Umayyah diganti dengan Abu Ritsmah.\""},"843":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ الظُّهْرَ أَوْ الْعَصْرَ قَالَ فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ قَامَ إِلَى خَشَبَةٍ فِي مُقَدَّمِ الْمَسْجِدِ فَوَضَعَ يَدَيْهِ عَلَيْهِمَا إِحْدَاهُمَا عَلَى الْأُخْرَى يُعْرَفُ فِي وَجْهِهِ الْغَضَبُ ثُمَّ خَرَجَ سَرْعَانُ النَّاسِ وَهُمْ يَقُولُونَ قُصِرَتْ الصَّلَاةُ قُصِرَتْ الصَّلَاةُ وَفِي النَّاسِ أَبُو بَكْرٍ وَعُمَرُ فَهَابَاهُ أَنْ يُكَلِّمَاهُ فَقَامَ رَجُلٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَمِّيهِ ذَا الْيَدَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَنَسِيتَ أَمْ قُصِرَتْ الصَّلَاةُ قَالَ لَمْ أَنْسَ وَلَمْ تُقْصَرْ الصَّلَاةُ قَالَ بَلْ نَسِيتَ يَا رَسُولَ اللَّهِ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْقَوْمِ فَقَالَ أَصَدَقَ ذُو الْيَدَيْنِ فَأَوْمَئُوا أَيْ نَعَمْ فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَقَامِهِ فَصَلَّى الرَّكْعَتَيْنِ الْبَاقِيَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ وَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ وَكَبَّرَ ثُمَّ كَبَّرَ وَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ وَكَبَّرَقَالَ فَقِيلَ لِمُحَمَّدٍ سَلَّمَ فِي السَّهْوِ فَقَالَ لَمْ أَحْفَظْهُ عَنْ أَبِي هُرَيْرَةَ وَلَكِنْ نُبِّئْتُ أَنَّ عِمْرَانَ بْنَ حُصَيْنٍ قَالَ ثُمَّ سَلَّمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ بِإِسْنَادِهِ وَحَدِيثُ حَمَّادٍ أَتَمُّ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَقُلْ بِنَا وَلَمْ يَقُلْ فَأَوْمَئُوا قَالَ فَقَالَ النَّاسُ نَعَمْ قَالَ ثُمَّ رَفَعَ وَلَمْ يَقُلْ وَكَبَّرَ ثُمَّ كَبَّرَ وَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ وَتَمَّ حَدِيثُهُ لَمْ يَذْكُرْ مَا بَعْدَهُ وَلَمْ يَذْكُرْ فَأَوْمَئُوا إِلَّا حَمَّادُ بْنُ زَيْدٍ قَالَ أَبُو دَاوُد وَكُلُّ مَنْ رَوَى هَذَا الْحَدِيثَ لَمْ يَقُلْ فَكَبَّرَ وَلَا ذَكَرَ رَجَعَ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ عَلْقَمَةَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَمَّادٍ كُلِّهِ إِلَى آخِرِ قَوْلِهِ نُبِّئْتُ أَنَّ عِمْرَانَ بْنَ حُصَيْنٍ قَالَ ثُمَّ سَلَّمَ قَالَ قُلْتُ فَالتَّشَهُّدُ قَالَ لَمْ أَسْمَعْ فِي التَّشَهُّدِ وَأَحَبُّ إِلَيَّ أَنْ يَتَشَهَّدَ وَلَمْ يَذْكُرْ كَانَ يُسَمِّيهِ ذَا الْيَدَيْنِ وَلَا ذَكَرَ فَأَوْمَئُوا وَلَا ذَكَرَ الْغَضَبَ وَحَدِيثُ حَمَّادٍ عَنْ أَيُّوبَ أَتَمُّ حَدَّثَنَا عَلِيُّ بْنُ نَصْرِ بْنِ عَلِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ وَهِشَامٍ وَيَحْيَى بْنِ عَتِيقٍ وَابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قِصَّةِ ذِي الْيَدَيْنِ أَنَّهُ كَبَّرَ وَسَجَدَ وَقَالَ هِشَامٌ يَعْنِي ابْنَ حَسَّانَ كَبَّرَ ثُمَّ كَبَّرَ وَسَجَدَ قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ أَيْضًا حَبِيبُ بْنُ الشَّهِيدِ وَحُمَيْدٌ وَيُونُسُ وَعَاصِمٌ الْأَحْوَلُ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ لَمْ يَذْكُرْ أَحَدٌ مِنْهُمْ مَا ذَكَرَ حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ أَنَّهُ كَبَّرَ ثُمَّ كَبَّرَ وَسَجَدَ وَرَوَى حَمَّادُ بْنُ سَلَمَةَ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ هَذَا الْحَدِيثَ عَنْ هِشَامٍ لَمْ يَذْكُرَا عَنْهُ هَذَا الَّذِي ذَكَرَهُ حَمَّادُ بْنُ زَيْدٍ أَنَّهُ كَبَّرَ ثُمَّ كَبَّرَ حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ وَعُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ بِهَذِهِ الْقِصَّةِ قَالَ وَلَمْ يَسْجُدْ سَجْدَتَيْ السَّهْوِ حَتَّى يَقَّنَهُ اللَّهُ ذَلِكَ حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا بَكْرِ بْنَ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ أَخْبَرَهُ أَنَّهُ بَلَغَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْخَبَرِ قَالَ وَلَمْ يَسْجُدْ السَّجْدَتَيْنِ اللَّتَيْنِ تُسْجَدَانِ إِذَا شَكَّ حَتَّى لَقَاهُ النَّاسُ قَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي بِهَذَا الْخَبَرِ سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ وَأَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو بَكْرِ بْنُ الْحَارِثِ بْنِ هِشَامٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ قَالَ أَبُو دَاوُد رَوَاهُ يَحْيَى بْنُ أَبِي كَثِيرٍ وَعِمْرَانُ بْنُ أَبِي أَنَسٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَالْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ جَمِيعًا عَنْ أَبِي هُرَيْرَةَ بِهَذِهِ الْقِصَّةِ وَلَمْ يَذْكُرْ أَنَّهُ سَجَدَ السَّجْدَتَيْنِ قَالَ أَبُو دَاوُد وَرَوَاهُ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيهِ وَلَمْ يَسْجُدْ سَجْدَتَيْ السَّهْوِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam shalat petang hari bersama kami yaitu shalat dzuhur atau ashar.\" Kata Abu Hurairah; \"Ternyata beliau hanya shalat dua raka'at kemudian salam, lalu pergi ke kayu yang melintang di depan masjid sambil meletakkan tangan yang satunya (kanannya) di atas tangannya yang lain, dan terlihat di wajahnya seolah-olah beliau sedang marah, setelah itu orang-orang bergegas keluar (dari masjid) sambil berkata; \"Shalat di qashar, shalat di qashar.\" Dan di antara orang-orang tersebut terdapat Abu Bakar dan Umar, keduanya merasa segan untuk menanyakan hal itu, maka salah seorang yang di beri nama oleh Rasulullah shallallahu 'alaihi wasallam dengan sebutan Dzul yadain berdiri seraya bertanya; \"Wahai Rasulullah, apakah anda lupa ataukah memang shalat telah di qashar?\" beliau menjawab: \"Aku tidak lupa dan tidak pula mengqashar shalat.\" Dzul Yadain berkata; \"Akan tetapi anda lupa wahai Rasulullah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam menghadap kepada orang-orang seraya bersabda: \"Benarkah apa yang di katakan oleh Dzul Yadain?\" para sahabat menjawab (dengan isyarat); \"Ya, benar\" lalu beliau maju kembali ke tempatnya semula dan menyelesaikan kekurangan (raka'at) yang tertinggal, kemudian salam. Setelah salam beliau bertakbir dan sujud seperti sujud biasa atau agak panjang sedikit lalu mengangkat kepala dan bertakbir, setelah itu beliau bertakbir lagi dan sujud seperti sujud biasa atau agak lama kemudian mengangkat kepala dan bertakbir.\" Di tanyakan kepada Muhammad; \"Apakah beliau salam dalam (sujud) sahwi?\" jawabnya; \"aku tidak menghafalnya dari Abu Hurairah, tapi aku diberitahu bahwa [Imran bin Hushain] berkata; \"Kemudian beliau shallallahu 'alaihi wasallam salam…\". Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ayyub] dari [Muhammad] dengan sanadnya, namun hadits Hammad lebih sempurna, perawi berkata; Rasulullah shallallahu 'alaihi wasallam shalat bersama kami namun dia tidak mengatakan\"…Para sahabat mengangguk…\" katanya melanjutkan; \"…maka orang-orang menjawab; \"Ya, benar\" katanya lagi; \"…kemudian beliau mengangkat (kepalanya) …\" dan tidak mengatakan; \"…beliau bertakbir, kemudian bertakbir dan sujud seperti sujud biasanya atau agak panjang, kemudian beliau mengangkat (kepala).\" Riwayat haditsnya selesai sampai di sini, tanpa menyebutkan redaksi setelahnya dan tidak pula menyebutkan; \"…Para sahabat mengangguk..\" kecuali Hammad bin Zaid, Abu Daud mengatakan; 'Setiap orang yang meriwayatkan hadits ini tidak mengatakan; \"…kemudian bertakbir…'\" tidak pula menyebutkan; \"…dan kembali…\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadlal] telah menceritakan kepada kami [Salamah yaitu Ibnu Alqamah] dari [Muhammad] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat bersama kami…\" seperti maksud hadits Hammad seluruhnya (dari awal) sampai akhir ucapannya, yaitu; \"Aku di beritahu bahwa Imran bin Hushain berkata; …kemudian beliau salam.\" Kata Salamah bin Alqamah; \"kataku; (dengan) membaca tasyahud (sesudah sujud sahwi)?\" kata Muhammad bin Sirin; \"Aku tidak mendengar beliau membaca tasyahud, sedangkan aku lebih suka membaca tasyahud. ' Tidak di sebutkan pula; \"Beliau menyebutnya dengan Dzul Yadain, \" demikian juga tidak menyebutkan; \"…lalu mereka mengangguk…\" begitu juga tentang \"Marah.\" Sedangkan haditsnya Hammad dari Ayyub lebih sempurna. Telah menceritakan kepada kami [Ali bin Nadhr bin Ali] telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dan [Hisyam], [Yahya bin 'Atiq], [Ibnu 'Aun] dari [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam -tentang kisah Dzul Yadain- bahwa beliau bertakbir dan sujud. Hisyam yaitu Ibnu Hasan berkata; 'beliau bertakbir kemudian bertakbir lalu sujud.\" Abu Daud mengatakan; Hadits ini juga di riwayatkan oleh [Habib bin As Syahid], [Humaid], [Yunus] dan ['Ashim Al Ahwal] dari [Muhammad] dari [Abu Hurairah], namun salah satu dari mereka tidak ada yang menyebutkan seperti yang di sebutkan oleh Hammad bin Zaid dari Hisyam bahwa beliau bertakbir kemudian bertakbir lalu sujud.\" Hadits ini juga riwayatkan dari [Hammad bin Salamah] dan [Abu Bakar bin 'Ayyasy] dari [Hisyam], namun keduanya tidak menyebutkan seperti yang di sebutkan oleh Hammad bin Zaid bahwa beliau bertakbir kemudian bertakbir.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dan [Abu Salamah] serta ['Ubaidullah bin Abdullah] dari [Abu Hurairah] seperti kisah ini, dia mengatakan; \"Namun beliau tidak sujud sahwi dua kali sehingga Allah meyakinkan dirinya.\" Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] telah menceritakan kepada kami [Ya'qub yaitu Ibnu Ibrahim] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu Bakar bin Sulaiman bin Abu Hatsmah], telah mengabarkan kepadanya, bahwa telah sampai kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam …\" seperti hadits di atas, katanya; \"beliau tidak sujud dua kali yaitu sujud tatkala ragu sehingga orang-orang menemui beliau.\" [Ibnu Syihab] mengatakan; [Sa'id bin Al Musayyab] telah mengabariku dengan hadits ini, dari [Abu Hurairah] dia berkata; …\" Dan telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dan [Abu Bakar bin Al Harits bin Hisyam] serta ['Ubaidullah bin Abdullah]. Abu Daud berkata; \"di riwayatkan pula dari [Yahya bin Abu Katsir] dan [Imran bin Abu Anas] dari [Abu Salamah bin Abdurrahman] dan ['Ala` bin Abdurrahman] dari [ayahnya] semuanya dari [Abu Hurairah] dengan kisah ini, namun dia tidak menyebutkan dua kali sujud (sahwi).\" Abu Daud mengatakan; \"Dan di riwayatkan dari [Az Zubaidi] dari [Az Zuhri] dari [Abu Bakar bin Sulaiman bin Abu Hatsmah] dari Nabi shallallahu 'alaihi wasallam -katanya dalam hadits tersebut- beliau tidak mengerjakan sujud sahwi dua kali (sujud).\""},"844":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ سَمِعَ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ فَسَلَّمَ فِي الرَّكْعَتَيْنِ فَقِيلَ لَهُ نَقَصْتَ الصَّلَاةَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dia mendengar [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat dluhur kemudian salam di raka'at kedua, maka di beritahukan kepadanya; \"Apakah anda mengurangi jumlah raka'at shalat?\" kemudian beliau melanjutkan dua raka'at lagi lalu sujud dua kali.\""},"845":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ أَخْبَرَنَا شَبَابَةُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ الرَّكْعَتَيْنِ مِنْ صَلَاةِ الْمَكْتُوبَةِ فَقَالَ لَه رَجُلٌ أَقُصِرَتْ الصَّلَاةُ يَا رَسُولَ اللَّهِ أَمْ نَسِيتَ قَالَ كُلَّ ذَلِكَ لَمْ أَفْعَلْ فَقَالَ النَّاسُ قَدْ فَعَلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ فَرَكَعَ رَكْعَتَيْنِ أُخْرَيَيْنِ ثُمَّ انْصَرَفَ وَلَمْ يَسْجُدْ سَجْدَتَيْ السَّهْوِقَالَ أَبُو دَاوُد رَوَاهُ دَاوُدُ بْنُ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ قَالَ ثُمَّ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ التَّسْلِيمِ حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ ضَمْضَمِ بْنِ جَوْسٍ الْهِفَّانِيِّ حَدَّثَنِي أَبُو هُرَيْرَةَ بِهَذَا الْخَبَرِ قَالَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ بَعْدَ مَا سَلَّمَ حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو أُسَامَةَ أَخْبَرَنِي عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ فِي الرَّكْعَتَيْنِ فَذَكَرَ نَحْوَ حَدِيثِ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ","id":"Telah menceritakan kepada kami [Isma'il bin Asad] telah mengabarkan kepada kami [Syababah] telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam beranjak pergi setelah selesai dari dua raka'at shalat wajib, maka seorang laki-laki bertanya kepada beliau; \"Apakah shalat telah di qashar wahai Rasulullah ataukah anda lupa?\" beliau menjawab; \"Semua itu tidak aku lakukan.\" Maka orang-orang berkata; \"Anda telah melakukan hal itu wahai Rasulullah!.\" Kemudian beliau mengerjakan dua raka'at yang tertinggal, lalu beliau beranjak pergi tanpa mengerjakan sujud sahwi dua kali.\" Abu Daud mengatakan; \"Hadits ini di riwayatkan pula oleh [Daud bin Al Hushain] dari [Abu Sufyan bekas budak Ibnnu Abu Ahmad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan kisah seperti ini, katanya; \"kemudian beliau sujud dua kali dan duduk setelah memberi salam.\" Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Ikrimah bin 'Ammar] dari [Dlamdlam bin Jaus Al Hiffani] telah menceritakan kepadaku [Abu Hurairah] dengan hadits seperti ini, katanya; \"Kemudian beliau sujud sahwi setelah memberi salam.\" Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit] telah menceritakan kepada kami [Abu Usamah], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah mengabarkan kepada kami [Abu Usamah] telah mengabarkan kepadaku ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami, kemudian beliau salam di raka'at kedua…\" kemudian ia menyebutkan seperti hadits Ibnu Sirin dari Abu Hurairah dia berkata; \"Kemudian beliau salam lalu sujud sahwi dua kali.\""},"846":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مَسْلَمَةُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا خَالِدٌ الْحَذَّاءُ حَدَّثَنَا أَبُو قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثِ رَكَعَاتٍ مِنْ الْعَصْرِ ثُمَّ دَخَلَ قَالَ عَنْ مَسْلَمَةَ الْحُجَرَ فَقَامَ إِلَيْهِ رَجُلٌ يُقَالُ لَهُ الْخِرْبَاقُ كَانَ طَوِيلَ الْيَدَيْنِ فَقَالَ لَهُ أَقُصِرَتْ الصَّلَاةُ يَا رَسُولَ اللَّهِ فَخَرَجَ مُغْضَبًا يَجُرُّ رِدَاءَهُ فَقَالَ أَصَدَقَ قَالُوا نَعَمْ فَصَلَّى تِلْكَ الرَّكْعَةَ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْهَا ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Maslamah bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Khalid Al Khaddza`] telah menceritakan kepada kami [Abu Qilabah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam salam di raka'at ke tiga shalat Ashar, kemudian beliau masuk (rumah).\" -Katanya dari Maslamah- (beliau masuk) kamar, lalu seorang laki-laki yang bernama Khirbaq -seorang yang memiliki tangan panjang- berdiri, ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam: \"Apakah shalat telah di qashar wahai Rasulullah?\" beliau lalu keluar dengan marah sambil memegang kainnya, beliau bersabda: \"Apakah perkataannya benar?\" mereka menjawab; \"Ya, benar.\" Maka beliau mengerjakan raka'at yang tertinggal kemudian beliau salam, setelah itu beliau sujud dua kali kemudian salam.\""},"847":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَ حَفْصٌ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ قَالَ صَلَّيْتَ خَمْسًا فَسَجَدَ سَجْدَتَيْنِ بَعْدَ مَا سَلَّمَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] dan [Muslim bin Ibrahim] sedangkan maksud haditsnya sama, Hafsh mengatakan; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat dzuhur lima raka'at, lantas di beritahukan kepada beliau; \"Apakah shalat telah di tambah (bilangan raka'atnya)?\" beliau bersabda: \"Apa maksudnya?\" mereka berkata; \"Anda telah shalat lima raka'at.\" Maka beliau sujud dua kali setelah salam.\""},"848":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِبْرَاهِيمُ فَلَا أَدْرِي زَادَ أَمْ نَقَصَ فَلَمَّا سَلَّمَ قِيلَ لَهُ يَا رَسُولَ اللَّهِ أَحَدَثَ فِي الصَّلَاةِ شَيْءٌ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ كَذَا وَكَذَا فَثَنَى رِجْلَهُ وَاسْتَقْبَلَ الْقِبْلَةَ فَسَجَدَ بِهِمْ سَجْدَتَيْنِ ثُمَّ سَلَّمَ فَلَمَّا انْفَتَلَ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَوْ حَدَثَ فِي الصَّلَاةِ شَيْءٌ أَنْبَأْتُكُمْ بِهِ وَلَكِنْ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ فَإِذَا نَسِيتُ فَذَكِّرُونِي وَقَالَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَتَحَرَّ الصَّوَابَ فَلْيُتِمَّ عَلَيْهِ ثُمَّ لِيُسَلِّمْ ثُمَّ لِيَسْجُدْ سَجْدَتَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بِهَذَا قَالَ فَإِذَا نَسِيَ أَحَدُكُمْ فَلْيَسْجُدْ سَجْدَتَيْنِ ثُمَّ تَحَوَّلَ فَسَجَدَ سَجْدَتَيْنِ قَالَ أَبُو دَاوُد رَوَاهُ حُصَيْنٌ نَحْوَ حَدِيثِ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; [Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat -Ibrahim mengatakan; \"Aku tidak tahu, apakah (raka'atnya) lebih ataukah kurang- setelah salam, di beritahukan kepada beliau; \"Wahai Rasulullah, (apakah) terjadi sesuatu yang nggek beres dalam shalat?\" beliau bersabda: \"Memangnya kenapa?\" mereka berkata; \"Anda shalat begini dan begini.\" Lalu beliau merubah posisi kakinya dan menghadap kiblat, bersujud bersama mereka dua kali, lalu salam. Setelah itu beliau menghadap kepada kami seraya bersabda: \"Kalau terjadi sesuatu yang nggak beres dalam shalat, aku beritahukan kepada kalian. Akan tetapi aku hanyalah manusia biasa yang terkadang lupa sebagaimana kalian lupa, oleh karena itu, apabila aku lupa, maka ingatkanlah aku.\" selanjutnya beliau bersabda: \"Apabila salah seorang dari kalian ragu dalam shalatnya, hendaknya ia mengambil sesuatu (raka'at) yang di yakininya, lalu menyempurnakannya, kemudian hendaknya ia sujud dua kali.\" telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] … seperti hadits sebelumnya… sabdanya: \"Apabila salah seorang dari kalian lupa, hendaknya ia sujud dua kali.\" kemudian beliau agak bergeser, lalu sujud dua kali.\" Abu Daud berkata; hadits ini juga diriwayatkan oleh [Hushain] seperti hadits Al A'masy. "},"849":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ وَهَذَا حَدِيثُ يُوسُفَ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسًا فَلَمَّا انْفَتَلَ تَوَشْوَشَ الْقَوْمُ بَيْنَهُمْ فَقَالَ مَا شَأْنُكُمْ قَالُوا يَا رَسُولَ اللَّهِ هَلْ زِيدَ فِي الصَّلَاةِ قَالَ لَا قَالُوا فَإِنَّكَ قَدْ صَلَّيْتَ خَمْسًا فَانْفَتَلَ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ قَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Jarir]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Jarir] dan ini adalah hadits Yusuf dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim bin Suwaid] dari ['Alqamah] dia berkata; [Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat lima raka'at bersama kami, setelah beliau selesai shalat, orang-orang orang-orang pada berbisik di antara mereka, maka beliau bersabda: \"Ada apa dengan kalian?\" mereka berkata; \"Wahai Rasulullah, apakah (raka'at) shalat di tambah?\" beliau menjawab: \"Tidak.\" Mereka berkata; \"Sesungguhnya anda shalat lima raka'at1.\" Setelah selesai, beliau melakukan dua kali sujud, lalu salam. Setelah itu beliau bersabda: \"Sesungguhnya aku adalah manusia biasa yang terkadang lupa sebagaimana kalian lupa.\""},"850":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ يَعْنِي ابْنَ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ سُوَيْدَ بْنَ قَيْسٍ أَخْبَرَهُ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمًا فَسَلَّمَ وَقَدْ بَقِيَتْ مِنْ الصَّلَاةِ رَكْعَةٌ فَأَدْرَكَهُ رَجُلٌ فَقَالَ نَسِيتَ مِنْ الصَّلَاةِ رَكْعَةً فَرَجَعَ فَدَخَلَ الْمَسْجِدَ وَأَمَرَ بِلَالًا فَأَقَامَ الصَّلَاةَ فَصَلَّى لِلنَّاسِ رَكْعَةًفَأَخْبَرْتُ بِذَلِكَ النَّاسَ فَقَالُوا لِي أَتَعْرِفُ الرَّجُلَ قُلْتُ لَا إِلَّا أَنْ أَرَاهُ فَمَرَّ بِي فَقُلْتُ هَذَا هُوَ فَقَالُوا هَذَا طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits yaitu Ibnu Sa'd] dari [Yazid bin Abu Habib] bahwa [Suwaid bin Qais] telah mengabarkan kepadanya, dari [Mu'awiyah bin Hudaij] bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, kemudian salam. Padahal masih tersisa satu raka'at lagi, lalu seorang laki-laki menemui beliau sambil berkata; \"Anda lupa satu raka'at shalat.\" Maka beliau kembali masuk masjid dan menyuruh Bilal untuk menyerukan iqamah, kemudian beliau shalat satu raka'at bersama orang-orang.\" Lalu aku beritahukan peristiwa tersebut kepada orang-orang, mereka berkata kepadaku; \"Tahukah kamu laki-laki tersebut?\" jawabku; \"Tidak, kecuali jika aku di beritahu.\" Tiba-tiba seseorang lewati di hadapanku, maka aku berkata; \"Inikah orangnya?\" mereka menjawab; \"Ini adalah Thalhah bin 'Ubaidullah.\""},"851":{"ar":"حَدَّثَنَا مُحَمَّدُّ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو خَالِدٍ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيُلْقِ الشَّكَّ وَلْيَبْنِ عَلَى الْيَقِينِ فَإِذَا اسْتَيْقَنَ التَّمَامَ سَجَدَ سَجْدَتَيْنِ فَإِنْ كَانَتْ صَلَاتُهُ تَامَّةً كَانَتْ الرَّكْعَةُ نَافِلَةً وَالسَّجْدَتَانِ وَإِنْ كَانَتْ نَاقِصَةً كَانَتْ الرَّكْعَةُ تَمَامًا لِصَلَاتِهِ وَكَانَتْ السَّجْدَتَانِ مُرْغِمَتَيْ الشَّيْطَانِقَالَ أَبُو دَاوُد رَوَاهُ هِشَامُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ أَبِي خَالِدٍ أَشْبَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Khalid] dari [Ibnu Al 'Ajlan] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian ragu dalam shalatnya, hendaknya ia meninggalkan keraguannya dan menetapkan yang di yakininya, apabila dia yakin (raka'atnya) telah sempurna, lalu sujud dua kali. Apabila ternyata raka'atnya telah sempurna, maka satu raka'at dan kedua sujudnya itu menjadi tambahan baginya (amalan sunnah), kalau memang ternyata raka'atnya kurang, maka raka'at itu menjadi penyempurna shalatnya dan kedua sujudnya itu sebagai pembuat syetan jengkel.\" Abu Daud berkata; \"Di riwayatkan pula oleh [Hisyam bin Sa'd] dan [Muhammad bin Mutharif] dari [Zaid] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, sedangkan haditsnya Abu Khalid lebih sempurna (daripada haditsnya Hisyam).\""},"852":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ كَيْسَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمَّى سَجْدَتَيْ السَّهْوِ الْمُرْغِمَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah] telah mengabarkan kepada kami [Al Fadl bin Musa] dari [Abdullah bin Kaisan] dari ['Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam menamakan dua sujud sahwi (sujud karena lupa) sebagai Al Murghimataini (Pembuat syetan jengkel).\""},"853":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلَا يَدْرِي كَمْ صَلَّى ثَلَاثًا أَوْ أَرْبَعًا فَلْيُصَلِّ رَكْعَةً وَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ فَإِنْ كَانَتْ الرَّكْعَةُ الَّتِي صَلَّى خَامِسَةً شَفَعَهَا بِهَاتَيْنِ وَإِنْ كَانَتْ رَابِعَةً فَالسَّجْدَتَانِ تَرْغِيمٌ لِلشَّيْطَانِحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ زَيْدِ بْنِ أَسْلَمَ بِإِسْنَادِ مَالِكٍ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَإِنْ اسْتَيْقَنَ أَنْ قَدْ صَلَّى ثَلَاثًا فَلْيَقُمْ فَلْيُتِمَّ رَكْعَةً بِسُجُودِهَا ثُمَّ يَجْلِسْ فَيَتَشَهَّدْ فَإِذَا فَرَغَ فَلَمْ يَبْقَ إِلَّا أَنْ يُسَلِّمَ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ ثُمَّ لِيُسَلِّمْ ثُمَّ ذَكَرَ مَعْنَى مَالِكٍ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ ابْنُ وَهْبٍ عَنْ مَالِكٍ وَحَفْصِ بْنِ مَيْسَرَةَ وَدَاوُدَ بْنِ قَيْسٍ وَهِشَامِ بْنِ سَعْدٍ إِلَّا أَنَّ هِشَامًا بَلَغَ بِهِ أَبَا سَعِيدٍ الْخُدْرِيَّ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian ragu dalam shalatnya, sehingga tidak tahu tiga atukah empat raka'atkah yang telah di kerjakan, hendaknya ia sujud dua kali ketika sedang duduk sebelum salam, jika ternyata raka'at yang di kerjakannya itu raka'at yang kelima, maka shalatnya di sempurnakan oleh dua sujud tersebut, sekiranya sudah cukup empar raka'at, maka sujudnya itu untuk menjengkelkan syetan.\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qarri] dari [Zaid bin Aslam] dengan isnadnya Malik dia berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian ragu dalam shalatnya, dan apabila ia meyakini telah mengerjakan tiga raka'at, hendaknya ia berdiri untuk menyempurnakan satu raka'at dengan sujudnya kemudian dia duduk sambil membaca tasyahud. Apabila telah selesai dan tinggal salam, hendaknya ia sujud dua kali kemudian salam…\" kemudian dia menyebutkan makna hadits Malik. Abu Daud mengatakan; \"Demikian juga yang di riwayatkan oleh [Ibnu Wahb] dari [Malik] dan [Hafsh bin Maisarah], [Daud bin Qais] serta [Hisyam bin Sa'd] kecuali Hisyam yang menyampaikan dari [Abu Sa'id Al Khudri].\""},"854":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ خُصَيْفٍ عَنْ أَبِي عُبَيْدَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كُنْتَ فِي صَلَاةٍ فَشَكَكْتَ فِي ثَلَاثٍ أَوْ أَرْبَعٍ وَأَكْبَرُ ظَنِّكَ عَلَى أَرْبَعٍ تَشَهَّدْتَ ثُمَّ سَجَدْتَ سَجْدَتَيْنِ وَأَنْتَ جَالِسٌ قَبْلَ أَنْ تُسَلِّمَ ثُمَّ تَشَهَّدْتَ أَيْضًا ثُمَّ تُسَلِّمُقَالَ أَبُو دَاوُد رَوَاهُ عَبْدُ الْوَاحِدِ عَنْ خُصَيْفٍ وَلَمْ يَرْفَعْهُ وَوَافَقَ عَبْدَ الْوَاحِدِ أَيْضًا سُفْيَانُ وَشَرِيكٌ وَإِسْرَائِيلُ وَاخْتَلَفُوا فِي الْكَلَامِ فِي مَتْنِ الْحَدِيثِ وَلَمْ يُسْنِدُوهُ","id":"Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Khushaif] dari [Abu 'Ubaidah bin Abdullah] dari [ayahnya] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Apabila kamu sedang shalat, kemudian ragu apakah tiga ataukah empat raka'at (yang telah di kerjakan), sedangkan berat prasangka kamu telah mengerjakan empat raka'at, maka tasyahudlah kamu kemudian sujud dua kali ketika masih duduk (tasyahud) sebelum salam, kemudian tasyahud lagi lalu salam.\" Abu Daud berkata; \"Telah di riwayatkan pula oleh [Abdul Wahid] dari [Khushaif] namun dia tidak merafa'kan, hadits Abdul Wahid juga di sepakati oleh [Sufyan], [Syarik] dan [Isra'il] dan mereka berbeda mengenai redaksi hadits yaitu dalam matannya, dan mereka tidak menyandarkan kepada seorang Perawi pun.\""},"855":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا عِيَاضٌ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ هِلَالِ بْنِ عِيَاضٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلَمْ يَدْرِ زَادَ أَمْ نَقَصَ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ قَاعِدٌ فَإِذَا أَتَاهُ الشَّيْطَانُ فَقَالَ إِنَّكَ قَدْ أَحْدَثْتَ فَلْيَقُلْ كَذَبْتَ إِلَّا مَا وَجَدَ رِيحًا بِأَنْفِهِ أَوْ صَوْتًا بِأُذُنِهِوَهَذَا لَفْظُ حَدِيثِ أَبَانَ قَالَ أَبُو دَاوُد و قَالَ مَعْمَرٌ وَعَلِيُّ بْنُ الْمُبَارَكِ عِيَاضُ بْنُ هِلَالٍ و قَالَ الْأَوْزَاعِيُّ عِيَاضُ بْنُ أَبِي زُهَيْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepada kami ['Iyadl]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya] dari [Hilal bin 'Iyadl] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian shalat, dan tidak tahu apakah lebih ataukah kurang (raka'atnya) hendaknya ia sujud dua kali ketika masih duduk (tasyahud), apabila datang (was-was) syetan dan mengatakan; \"Kamu telah hadats (batal) \" hendaknya ia mengatakan; \"Kamu dusta\", melainkan jika ia hidungnya mencium angin (bau), atau telinganya mendengar suara.\" Ini adalah lafadz haditsnya Aban. Abu Daud mengatakan; (dari) Ma'mar, Ali bin Mubarrak. 'Iyadl bin Hilal. Al Auza'i mengatakan; \"'Iyadl bin abu Zuhair.\""},"856":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَدَكُمْ إِذَا قَامَ يُصَلِّي جَاءَهُ الشَّيْطَانُ فَلَبَّسَ عَلَيْهِ حَتَّى لَا يَدْرِيَ كَمْ صَلَّى فَإِذَا وَجَدَ أَحَدُكُمْ ذَلِكَ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌقَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ ابْنُ عُيَيْنَةَ وَمَعْمَرٌ وَاللَّيْثُ حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ زَادَ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا يَعْقُوبُ أَخْبَرَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمٍ الزُّهْرِيُّ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فَلْيَسْجُدْ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ لِيُسَلِّمْ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian tengah mengerjakan shalat, maka syetan akan datang kepadanya kemudian ia mengacaukan (pikiran) hingga tidak tahu berapa kali dia shalat, apabila salah seorang dari kalian mendapati yang demikian itu, hendaknya ia sujud dua kali ketika masih duduk (tasyahud).\" Abu Daud mengatakan; \"Demikianlah yang di riwayatkan oleh [Ibnu 'Uyainah], [Ma'mar], [Al Laits]. Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [sepupunya Az Zuhri] dari [Muhammad bin Muslim] seperti isnad hadits ini, dia menambahkan; \"…ketika masih duduk sebelum salam.\" Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Ya'qub] telah mengabarkan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Muhammad bin Muslim Az Zuhri] dengan isnad dan maknanya, dia berkata; \"…Kemudian dia sujud dua kali sebelum salam, lalu salam.\""},"857":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ أَنَّ مُصْعَبَ بْنَ شَيْبَةَ أَخْبَرَهُ عَنْ عُتْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَكَّ فِي صَلَاتِهِ فَلْيَسْجُدْ سَجْدَتَيْنِ بَعْدَمَا يُسَلِّمُ","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] telah mengabarkan kepadaku [Abdullah bin Musafi'] bahwa [Mush'ab bin Syaibah] telah mengabarkan kepadanya, dari ['Utbah bin Muhammad bin Al Harits] dari [Abdullah bin Ja'far] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ragu-ragu dalam shalatnya, hendaknya ia sujud dua kali setelah salam.\""},"858":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ قَامَ فَلَمْ يَجْلِسْ فَقَامَ النَّاسُ مَعَهُ فَلَمَّا قَضَى صَلَاتَهُ وَانْتَظَرْنَا التَّسْلِيمَ كَبَّرَ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ ثُمَّ سَلَّمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا أَبِي وَبَقِيَّةُ قَالَا حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ بِمَعْنَى إِسْنَادِهِ وَحَدِيثِهِ زَادَ وَكَانَ مِنَّا الْمُتَشَهِّدُ فِي قِيَامِهِ قَالَ أَبُو دَاوُد وَكَذَلِكَ سَجَدَهُمَا ابْنُ الزُّبَيْرِ قَامَ مِنْ ثِنْتَيْنِ قَبْلَ التَّسْلِيمِ وَهُوَ قَوْلُ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abdurrahman bin Al A'raj] dari [Abdullah bin Buhainah] bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua raka'at bersama kami, lalu beliau langsung berdiri, sementara beliau belum duduk (tasyahud), maka orang-orang pun berdiri mengikuti beliau, setelah selesai shalat, sedangkan kami tengah menunggu salam, beliau lalu bertakbir dan sujud dua kali sewaktu beliau duduk sebelum salam, kemudian beliau (shallallahu 'alaihi wasallam) salam.\" Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [ayahku] dan [Baqiyah] keduanya berkata; telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] dengan maksud hadits dan isnad yang sama, dia menambahkan; \"…di antara kami ada juga yang membaca tasyahud ketika beliau berdiri (karena lupa).\" Abu Daud berkata; \"Demikianlah Ibnu Zubair mengerjakan kedua sujud, beliau berdiri dari raka'at kedua sebelum memberi salam\" ini adalah pendapat Az Zuhri. "},"859":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ الْوَلِيدِ عَنْ سُفْيَانَ عَنْ جَابِرٍ يَعْنِي الْجُعْفِيَّ قَالَ حَدَّثَنَا الْمُغِيرَةُ بْنُ شُبَيْلٍ الْأَحْمَسِيُّ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ الْإِمَامُ فِي الرَّكْعَتَيْنِ فَإِنْ ذَكَرَ قَبْلَ أَنْ يَسْتَوِيَ قَائِمًا فَلْيَجْلِسْ فَإِنْ اسْتَوَى قَائِمًا فَلَا يَجْلِسْ وَيَسْجُدْ سَجْدَتَيْ السَّهْوِقَالَ أَبُو دَاوُد وَلَيْسَ فِي كِتَابِي عَنْ جَابِرٍ الْجُعْفِيِّ إِلَّا هَذَا الْحَدِيثُ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Amru] dari [Abdullah bin Walid] dari [Sufyan] dari [Jabir yaitu Al Ju'fi] dia berkata; telah menceritakan kepada kami [Al Mughirah bin Syubail Al Ahmasi] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Apabila seorang imam terlanjur berdiri pada raka'at kedua, dan ingat sebelum berdiri tegak, hendaknya ia kembali duduk, dan apabila telah berdiri tegak hendaknya ia tidak duduk dan sujudlah dua kali yaitu sujud sahwi.\" Abu Daud berkata; \"Dan dalam kitabku tidak di sebutkan dari Jabir Al Ju'fi kecuali dari hadits ini.\""},"860":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْجُشَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْمَسْعُودِيُّ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَصَلَّى بِنَا الْمُغِيرَةُ بْنُ شُعْبَةَ فَنَهَضَ فِي الرَّكْعَتَيْنِ قُلْنَا سُبْحَانَ اللَّهِ قَالَ سُبْحَانَ اللَّهِ وَمَضَى فَلَمَّا أَتَمَّ صَلَاتَهُ وَسَلَّمَ سَجَدَ سَجْدَتَيْ السَّهْوِ فَلَمَّا انْصَرَفَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ كَمَا صَنَعْتُقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ ابْنُ أَبِي لَيْلَى عَنْ الشَّعْبِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ وَرَفَعَهُ وَرَوَاهُ أَبُو عُمَيْسٍ عَنْ ثَابِتِ بْنِ عُبَيْدٍ قَالَ صَلَّى بِنَا الْمُغِيرَةُ بْنُ شُعْبَةَ مِثْلَ حَدِيثِ زِيَادِ بْنِ عِلَاقَةَ قَالَ أَبُو دَاوُد أَبُو عُمَيْسٍ أَخُو الْمَسْعُودِيِّ وَفَعَلَ سَعْدُ بْنُ أَبِي وَقَّاصٍ مِثْلَ مَا فَعَلَ الْمُغِيرَةُ وَعِمْرَانُ بْنُ حُصَيْنٍ وَالضَّحَّاكُ بْنُ قَيْسٍ وَمُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ وَابْنُ عَبَّاسٍ أَفْتَى بِذَلِكَ وَعُمَرُ بْنُ عَبْدِ الْعَزِيزِ قَالَ أَبُو دَاوُد وَهَذَا فِيمَنْ قَامَ مِنْ ثِنْتَيْنِ ثُمَّ سَجَدُوا بَعْدَ مَا سَلَّمُوا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar Al Jusyami] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Mas'udi] dari [Ziyad bin 'Ilaqah] dia berkata; \" [Al Mughirah bin Syu'bah] shalat bersama kami, lalu langsung berdiri di raka'at kedua, lantas kami mengucapkan \"Subhanallah\" dia juga mengucapkan; \"Subhanallah\" dan dia terus berdiri. Setelah menyempurnakan shalat dan memberi salam, dia sujud sahwi dua kali, seusai shalat dia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan seperti yang aku kerjakan.\" Abu Daud berkata; \"Demikian pula yang di riwayatkan oleh [Ibnu Abu Laila] dari [Asy Sya'bi] dari [Al Mughirah bin Syu'bah] dan dia merafa'kan hadits tersebut.\" Dan di riwayatkan pula oleh [Abu 'Umais] dari [Tsabit bin 'Ubaid] dia berkata; \" [Al Mughirah bin Syu'bah] shalat bersama kami…\" seperti haditsnya Ziyad bin 'Ilaqah. Abu Daud mengatakan; \"Abu 'Umais adalah saudara Al Mas'udi, sedangkan Sa'd bin Abu Waqash juga pernah mengerjakan apa yang di kerjakan oleh Al Mughirah, begitu juga dengan 'Imran bin Hushain, Dlahak bin Qais, Mu'awiyah bin Abu Sufyan dan Ibnu Abbas. Umar bin Abdul Aziz juga pernah memberi fatwa seperti itu. Abu Daud berkata; \"Dan yang demikian bagi orang yang langsung berdiri dari dua raka'at (lupa dari tasyahud), kemudian dia sujud (sahwi) setelah salam.\""},"861":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ وَالرَّبِيعُ بْنُ نَافِعٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَشُجَاعُ بْنُ مَخْلَدٍ بِمَعْنَى الْإِسْنَادِ أَنَّ ابْنَ عَيَّاشٍ حَدَّثَهُمْ عَنْ عُبَيْدِ اللَّهِ بْنِ عُبَيْدٍ الْكَلَاعِيِّ عَنْ زُهَيْرٍ يَعْنِي ابْنَ سَالِمٍ الْعَنْسِيَّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ عَمْرٌو وَحْدَهُ عَنْ أَبِيهِ عَنْ ثَوْبَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ سَهْوٍ سَجْدَتَانِ بَعْدَ مَا يُسَلِّمُوَلَمْ يَذْكُرْ عَنْ أَبِيهِ غَيْرُ عَمْرٍو","id":"Telah menceritakan kepada kami ['Amru bin Utsman], [Ar Rabi' bin Nafi'], [Utsman bin Abu Syaibah] dan [Syuja' bin Makhlad], semakna dengan isnad, bahwa [Ibnu 'Ayyasy] telah menceritakan kepada mereka, dari ['Ubaidullah bin 'Ubaid al Kala'i] dari [Zuhair yaitu Ibnu Salim Al 'Ansi] dari [Abdurrahman bin Jubair bin Nufair], 'Amru mengatakan secara munfarid (sendirian) dari [ayahnya] dari [Tsauban] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; 'Setiap kali lupa, ada dua kali sujud setelah salam.\" Namun dia tidak menyebutkan dari ayahnya tanpa sebutan 'Amru. "},"862":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُثَنَّى حَدَّثَنِي أَشْعَثُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ خَالِدٍ يَعْنِي الْحَذَّاءَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فَسَهَا فَسَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Muhammad bin Abdullah bin Al Mutsanna] telah menceritakan kepadaku [Asy'ats] dari [Muhammad bin Sirin] dari [Khalid yaitu Al Khaddza`] dari [Abu Qilabah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam shalat bersama mereka lalu lupa, maka beliau sujud dua kali, lalu tasyahud dan salam.\""},"863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ هِنْدِ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ مَكَثَ قَلِيلًا وَكَانُوا يَرَوْنَ أَنَّ ذَلِكَ كَيْمَا يَنْفُذُ النِّسَاءُ قَبْلَ الرِّجَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Muhammad bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Hind binti Al Harits] dari [Ummu Salamah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam salam (dari shalat), beliau berhenti sejenak.\" -mereka berpendapat, yang demikian supaya para wanita keluar lebih dahulu sebelum kaum laki-laki.\""},"864":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ رَجُلٍ مِنْ طَيِّئٍ عَنْ أَبِيهِأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يَنْصَرِفُ عَنْ شِقَّيْهِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Syimak bin Harb] dari [Qabishah bin Hulb] -seorang laki-laki dari kabilah Thayi`- dari [ayahnya] bahwa dia pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dan beliau biasa berbalik dari dua sisi (kanan dan kiri).\""},"865":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَلَا يَجْعَلُ أَحَدُكُمْ نَصِيبًا لِلشَّيْطَانِ مِنْ صَلَاتِهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرُ مَا يَنْصَرِفُ عَنْ شِمَالِهِقَالَ عُمَارَةُ أَتَيْتُ الْمَدِينَةَ بَعْدُ فَرَأَيْتُ مَنَازِلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari ['Umarah bin 'Umair] dari [Al Aswad bin Yazid] dari [Abdullah] dia berkata; \"Jangan sekali-kali salah seorang dari kalian memberi kesempatan bagi syetan dalam shalatnya, hendaknya ia tidak berbalik kecuali ke sisi kanan. Namun aku melihat Rasulullah shallallahu 'alaihi wasallam paling banyak berbalik ke sisi kiri.\" Ammarah berkata; \"Setelah itu, aku mengunjungi Madinah, maka aku dapati rumah-rumah Nabi shallallahu 'alaihi wasallam di sebelah kiri beliau.\""},"866":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوا فِي بُيُوتِكُمْ مِنْ صَلَاتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah rumah-rumah kalian sebagai tempat mengerjakan shalat (sunnah), dan janganlah kalian jadikan sebagai kuburan.\""},"867":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ إِبْرَاهِيمَ بْنِ أَبِي النَّضْرِ عَنْ أَبِيهِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْمَرْءِ فِي بَيْتِهِ أَفْضَلُ مِنْ صَلَاتِهِ فِي مَسْجِدِي هَذَا إِلَّا الْمَكْتُوبَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Ibrahim bin Abu An Nadlr] dari [ayahnya] dari [Busr bin Sa'id] dari [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seseorang di rumahnya itu lebih utama daripada shalatnya dia di masjidku ini, kecuali shalat fardlu.\""},"868":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَحُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ كَانُوا يُصَلُّونَ نَحْوَ بَيْتِ الْمَقْدِسِ فَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ وَحَيْثُ مَا كُنْتُمْ فَوَلُّوا وُجُوهَكُمْ شَطْرَهُ }فَمَرَّ رَجُلٌ مِنْ بَنِي سَلَمَةَ فَنَادَاهُمْ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْفَجْرِ نَحْوَ بَيْتِ الْمَقْدِسِ أَلَا إِنَّ الْقِبْلَةَ قَدْ حُوِّلَتْ إِلَى الْكَعْبَةِ مَرَّتَيْنِ فَمَالُوا كَمَا هُمْ رُكُوعٌ إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit] dan [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam dan para sahabatnya shalat menghadap ke arah Baitul Maqdis, ketika turun ayat; \"Palingkanlah mukamu ke arah Masjidil Haram. dan dimana saja kamu berada, palingkanlah mukamu ke arahnya.\" (QS Al Baqarah; 144), lalu seorang laki-laki dari Bani Salamah lewat dan berseru kepada kaumnya ketika mereka sedang ruku' dalam shalat dengan menghadap Baitul Maqdis; \"Ketahuilah, bahwa kiblat telah di alihkan ke Ka'bah -ia berseru dua kali- akhirnya mereka beralih ke Ka'bah dalam posisi ruku'.\""},"869":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُهْبِطَ وَفِيهِ تِيبَ عَلَيْهِ وَفِيهِ مَاتَ وَفِيهِ تَقُومُ السَّاعَةُ وَمَا مِنْ دَابَّةٍ إِلَّا وَهِيَ مُسِيخَةٌ يَوْمَ الْجُمُعَةِ مِنْ حِينَ تُصْبِحُ حَتَّى تَطْلُعَ الشَّمْسُ شَفَقًا مِنْ السَّاعَةِ إِلَّا الْجِنَّ وَالْإِنْسَ وَفِيهِ سَاعَةٌ لَا يُصَادِفُهَا عَبْدٌ مُسْلِمٌ وَهُوَ يُصَلِّي يَسْأَلُ اللَّهَ حَاجَةً إِلَّا أَعْطَاهُ إِيَّاهَا قَالَ كَعْبٌ ذَلِكَ فِي كُلِّ سَنَةٍ يَوْمٌ فَقُلْتُ بَلْ فِي كُلِّ جُمُعَةٍ قَالَ فَقَرَأَ كَعْبٌ التَّوْرَاةَ فَقَالَ صَدَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو هُرَيْرَةَ ثُمَّ لَقِيتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ فَحَدَّثْتُهُ بِمَجْلِسِي مَعَ كَعْبٍ فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ قَدْ عَلِمْتُ أَيَّةَ سَاعَةٍ هِيَ قَالَ أَبُو هُرَيْرَةَ فَقُلْتُ لَهُ فَأَخْبِرْنِي بِهَا فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ هِيَ آخِرُ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ فَقُلْتُ كَيْفَ هِيَ آخِرُ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَادِفُهَا عَبْدٌ مُسْلِمٌ وَهُوَ يُصَلِّي وَتِلْكَ السَّاعَةُ لَا يُصَلِّي فِيهَا فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَلَسَ مَجْلِسًا يَنْتَظِرُ الصَّلَاةَ فَهُوَ فِي صَلَاةٍ حَتَّى يُصَلِّيَ قَالَ فَقُلْتُ بَلَى قَالَ هُوَ ذَاكَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik hari ketika matahari terbit adalah hari Jum'at, pada hari itu Adam di cipta, pada hari itu Adam di turunkan dari surga, pada hari itu pula taubatnya di terima, pada hari itu juga ia wafat, pada hari itu Kiamat akan terjadi dan tidak ada binatang melata satu pun kecuali mereka menunggu pada hari Jum'at sejak shubuh sampai terbit matahari karena takut akan datangnya hari Kiamat kecuali Jin dan manusia, pada hari Jum 'at ada suatu waktu yang tidaklah seorang mukmin pun ketika shalat, dan berdoa meminta sesuatu kepada Allah yang bertepatan dengan waktu itu, melainkan Allah akan mengabulkannya\". Ka'ab lalu berkata; 'Apakah waktu itu hanya ada dalam satu hari di setiap tahun? '. Jawabku; 'Bahkan waktu itu ada pada setiap hari Jum'at'. Lantas Ka'ab membaca Taurat. Kemudian berkata; 'Rasulullah Shalallahu 'Alaihi Wa Sallam benar, hari itu ada pada setiap hari Jum'at'. Abu Hurairah berkata; \"Kemudian aku menemui Abdullah bin Salam, lalu aku ceritakan peristiwaku bersama Ka'ab ketika di majlisku.\" Maka [Abdullah bin Salam] berkata; \"Sungguh aku tahu saat itu.\" Abu Hurairah berkata; \"Beritahukanlah kepadaku saat itu.\" Abdullah bin Salam menjawab; \"Saat itu adalah waktu terakhir pada hari Jum'at.\" Kataku; \"Bagaimana saat itu bisa terjadi di akhir hari Jum'at? Padahal Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan tidaklah seorang hamba muslim yang shalat pada waktu itu, dan tidaklah ia shalat …\" Maka Abdullah bin Salam berkata; \"Tidakkah Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bermajlis untuk menunggu shalat, maka ia terus dihitung dalam shalat hingga ia benar-benar shalat.\" Abu Hurairah berkata; jawabku; \"Benar.\" Abdullah bin Salam berkata; \"Itulah waktunya.\""},"870":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَفْضَلِ أَيَّامِكُمْ يَوْمَ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ قُبِضَ وَفِيهِ النَّفْخَةُ وَفِيهِ الصَّعْقَةُ فَأَكْثِرُوا عَلَيَّ مِنْ الصَّلَاةِ فِيهِ فَإِنَّ صَلَاتَكُمْ مَعْرُوضَةٌ عَلَيَّ قَالَ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ تُعْرَضُ صَلَاتُنَا عَلَيْكَ وَقَدْ أَرِمْتَ يَقُولُونَ بَلِيتَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَ عَلَى الْأَرْضِ أَجْسَادَ الْأَنْبِيَاءِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Husain bin Ali] dari [Abdurrahman bin Yazid bin Jabir] dari [Abu Al Asy'Ats Tsauri Ash Shan'ani] dari [Aus bin Aus] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara hari-harimu yang paling utama adalah hari Jum'at, pada hari itu Adam di ciptakan, pada hari itu beliau wafat, pada hari itu juga ditiup (sangkakala) dan pada hari itu juga mereka pingsan. Maka perbanyaklah shalawat kepadaku -karena- shalawat kalian akan disampaikan kepadaku.\" Aus bin Aus berkata; para sahabat bertanya; \"Wahai Rasulullah Shalallahu, bagaimana mungkin shalawat kami bisa disampaikan kepadamu, sementara anda telah tiada (meninggal)? -atau mereka berkata; \"Telah hancur (menjadi tulang) \"- Beliau bersabda: \"Sesungguhnya Allah Azza wa Jalla mengharamkan bumi untuk memakan jasad para Nabi.\""},"871":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ أَنَّ الْجُلَاحَ مَوْلَى عَبْدِ الْعَزِيزِ حَدَّثَهُ أَنَّ أَبَا سَلَمَةَ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَوْمُ الْجُمُعَةِ ثِنْتَا عَشْرَةَ يُرِيدُ سَاعَةً لَا يُوجَدُ مُسْلِمٌ يَسْأَلُ اللَّهَ عَزَّ وَجَلَّ شَيْئًا إِلَّا أَتَاهُ اللَّهُ عَزَّ وَجَلَّ فَالْتَمِسُوهَا آخِرَ سَاعَةٍ بَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Ibnu 'Amru yaitu Ibnu Al Harits] bahwa [Al Julah bekas budak Abdul Aziz] telah menceritakan kepadanya, bahwa [Abu Salamah yaitu Ibnu Abdurrahman] telah menceritakan kepadanya, dari [Jabir bin Abdullah] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda; \"Hari jum'at itu dua belas -maksudnya jam- dan tidak di dapati seorang muslim pun yang meminta kepada Allah kecuali Allah 'azza wajalla akan mengabulkannya, maka bersegeralah untuk mendapatkannya pada waktu-waktu akhir setelah Ashar.\""},"872":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَخْرَمَةُ يَعْنِي ابْنَ بُكَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَ قَالَ لِي عَبْدُ اللَّهِ بْنُ عُمَرَ أَسَمِعْتَ أَبَاكَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَأْنِ الْجُمُعَةِ يَعْنِي السَّاعَةَ قَالَ قُلْتُ نَعَمْ سَمِعْتُهُ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هِيَ مَا بَيْنَ أَنْ يَجْلِسَ الْإِمَامُ إِلَى أَنْ تُقْضَى الصَّلَاةُقَالَ أَبُو دَاوُد يَعْنِي عَلَى الْمِنْبَرِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Makhramah yaitu Ibnu Bukair] dari [ayahnya] dari [Abu Burdah bin Abu Musa Al Asy'ari] dia berkata; [Abdullah bin Umar] berkata kepadaku; \"Apakah kamu pernah mendengar ayahmu mengatakan suatu hadits dari Rasulullah shallallahu 'alaihi wasallam mengenai waktu yang mustajab di hari Jum'at?\" Aku menjawab; \"Ya! Aku pernah mendengar dia berkata, (katanya); aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \"(waktu mustajab hari Jum'at) terjadi antara tempat duduknya imam hingga selesai shalat (Jum'at).\" Abu Daud berkata; \"Maksudnya ketika masih diatas mimbar.\""},"873":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْجُمُعَةَ فَاسْتَمَعَ وَأَنْصَتَ غُفِرَ لَهُ مَا بَيْنَ الْجُمُعَةِ إِلَى الْجُمُعَةِ وَزِيَادَةَ ثَلَاثَةِ أَيَّامٍ وَمَنْ مَسَّ الْحَصَى فَقَدْ لَغَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu' dengan menyempurnakan wudlu'nya, kemudian mendatangi shalat jum'at, mendengarkan dan memperhatikan (Khutbah Jum'at), maka dosa-dosanya akan di ampuni hingga jum'at berikutnya, di tambah tiga hari. Dan barangsiapa bermain kerikil, sungguh (jum'atnya) telah sia-sia.\""},"874":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ قَالَ حَدَّثَنِي عَطَاءٌ الْخُرَاسَانِيُّ عَنْ مَوْلَى امْرَأَتِهِ أُمِّ عُثْمَانَ قَالَسَمِعْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ عَلَى مِنْبَرِ الْكُوفَةِ يَقُولُ إِذَا كَانَ يَوْمُ الْجُمُعَةِ غَدَتْ الشَّيَاطِينُ بِرَايَاتِهَا إِلَى الْأَسْوَاقِ فَيَرْمُونَ النَّاسَ بِالتَّرَابِيثِ أَوْ الرَّبَائِثِ وَيُثَبِّطُونَهُمْ عَنْ الْجُمُعَةِ وَتَغْدُو الْمَلَائِكَةُ فَيَجْلِسُونَ عَلَى أَبْوَابِ الْمَسْجِدِ فَيَكْتُبُونَ الرَّجُلَ مِنْ سَاعَةٍ وَالرَّجُلَ مِنْ سَاعَتَيْنِ حَتَّى يَخْرُجَ الْإِمَامُ فَإِذَا جَلَسَ الرَّجُلُ مَجْلِسًا يَسْتَمْكِنُ فِيهِ مِنْ الِاسْتِمَاعِ وَالنَّظَرِ فَأَنْصَتَ وَلَمْ يَلْغُ كَانَ لَهُ كِفْلَانِ مِنْ أَجْرٍ فَإِنْ نَأَى وَجَلَسَ حَيْثُ لَا يَسْمَعُ فَأَنْصَتَ وَلَمْ يَلْغُ لَهُ كِفْلٌ مِنْ أَجْرٍ وَإِنْ جَلَسَ مَجْلِسًا يَسْتَمْكِنُ فِيهِ مِنْ الِاسْتِمَاعِ وَالنَّظَرِ فَلَغَا وَلَمْ يُنْصِتْ كَانَ لَهُ كِفْلٌ مِنْ وِزْرٍ وَمَنْ قَالَ يَوْمَ الْجُمُعَةِ لِصَاحِبِهِ صَهٍ فَقَدْ لَغَا وَمَنْ لَغَا فَلَيْسَ لَهُ فِي جُمُعَتِهِ تِلْكَ شَيْءٌ ثُمَّ يَقُولُ فِي آخِرِ ذَلِكَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَقَالَ أَبُو دَاوُد رَوَاهُ الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ جَابِرٍ قَالَ بِالرَّبَائِثِ وَقَالَ مَوْلَى امْرَأَتِهِ أُمِّ عُثْمَانَ بْنِ عَطَاءٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Isa] telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] dia berkata; telah menceritakan kepadaku ['Atha` Al Khurasani] dari [bekas budak isterinya Ummu Ustman] dia berkata; aku mendengar [Ali radliallahu 'anhu] berkata ketika di atas mimbar di Kufah: \"Apabila datang hari jum'at, maka setan akan berpagi-pagi dengan membawa benderanya menuju pasar-pasar sambil menaburkan rintangan atau penghalang-penghalang sehingga mereka mengakhirkan shalat jum'at, sementara para Malaikat berpagi-pagi dan duduk di pintu-pintu masjid mencacat manusia berdasarkan tingkatan mereka yang lebih awal dan orang yang berikutnya sampai Imam keluar, maka apabila seseorang duduk diam untuk mendengar dan memperhatikan serta tidak lalai, maka baginya dua bagian pahala, dan barangsiapa yang menjauh (dari imam), tidak mendengar dan diam serta tidak lalai maka baginya satu bagian dari pahala, dan barangsiapa duduk mendekat (kepada imam) kemudian duduk untuk mendengarkan dan memperhatikan, namun dirinya lalai dan tidak biasa diam, maka baginya satu bagian dari dosa, dan barangsiapa berkata kepada temannya \"diamlah\" pada waktu (khutbah) jum'at, maka ia telah lalai (bebuat sia-sia), dan barangsiapa lalai, maka ia tidak mendapatkan bagian dari Jum'atnya.\" Di akhir dari hadits tersebut, Ali berkata; \"saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda seperti itu.\" Abu Daud mengatakan; \"di riwayatkan pula oleh [Al Walid bin Muslim] dari [Ibnu Jabir] dia berkata dengan redaksi lafadz \"bir rabaa`is (rintangan).\" Dan berkata pula bekas budak istrinya yaitu Ummu Utsman bin 'Atha` seperti itu.\""},"875":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنِي عَبِيدَةُ بْنُ سُفْيَانَ الْحَضْرَمِيُّ عَنْ أَبِي الْجَعْدِ الضَّمْرِيِّ وَكَانَتْ لَهُ صُحْبَةٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ ثَلَاثَ جُمَعٍ تَهَاوُنًا بِهَا طَبَعَ اللَّهُ عَلَى قَلْبِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Muhammad bin 'Amru] dia berkata; telah menceritakan kepadaku ['Abidah bin Sufyan Al Hadlrami] dari [Abu Al Ja'd Adl Dlamri] -beliau termasuk dari sahabat Nabi- bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan Jum'at tiga kali karena meremehkannya, Allah menutup pintu hatinya.\""},"876":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ قُدَامَةَ بْنِ وَبَرَةَ الْعُجَيْفِيِّ عَنْ سَمُرَةَ بْنِ جُنْدُبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ الْجُمُعَةَ مِنْ غَيْرِ عُذْرٍ فَلْيَتَصَدَّقْ بِدِينَارٍ فَإِنْ لَمْ يَجِدْ فَبِنِصْفِ دِينَارٍقَالَ أَبُو دَاوُد وَهَكَذَا رَوَاهُ خَالِدُ بْنُ قَيْسٍ وَخَالَفَهُ فِي الْإِسْنَادِ وَوَافَقَهُ فِي الْمَتْنِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Qudamah bin Wabarah Al 'Ujaifi] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan Jum'at tanpa ada udzur (syar'i) hendaknya ia bersedekah satu Dinar, apabila ia tidak mendapati (satu Dinar), maka dengan setengah Dinar.\" Abu Daud mengatakan; \"Demikianlah yang di riwayatkan Khalid bin Qais, ia menyelisihinya dalam isnad, namun sepakat pada matan-nya.\""},"877":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ وَإِسْحَقُ بْنُ يُوسُفَ عَنْ أَيُّوبَ أَبِي الْعَلَاءِ عَنْ قَتَادَةَ عَنْ قُدَامَةَ بْنِ وَبَرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَاتَهُ الْجُمُعَةُ مِنْ غَيْرِ عُذْرٍ فَلْيَتَصَدَّقْ بِدِرْهَمٍ أَوْ نِصْفِ دِرْهَمٍ أَوْ صَاعِ حِنْطَةٍ أَوْ نِصْفِ صَاعٍقَالَ أَبُو دَاوُد رَوَاهُ سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ هَكَذَا إِلَّا أَنَّهُ قَالَ مُدًّا أَوْ نِصْفَ مُدٍّ وَقَالَ عَنْ سَمُرَةَ قَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يُسْأَلُ عَنْ اخْتِلَافِ هَذَا الْحَدِيثِ فَقَالَ هَمَّامٌ عِنْدِي أَحْفَظُ مِنْ أَيُّوبَ يَعْنِي أَبَا الْعَلَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Muhammad bin Yazid] dan [Ishaq bin Yusuf] dari [Ayyub Abu Al 'Ala`] dari [Qatadah] dari [Qudamah bin Wabarah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan jum'at tanpa ada udzur (syar'i), hendaknya ia bersedekah satu dirham atau setengah dirham atau satu sha' gandum atau setengahnya.\" Abu Daud berkata; \"di riwayatkan pula oleh [Sa'id bin Basyir] dari [Qatadah] seperti ini, namun dia mengatakan; \"satu mud atau setengahnya.\" perawi berkata; dari [Samurah]. Abu Daud berkata; saya mendengar Ahmad bin Hanbal bertanya mengenai perbedaan hadits ini, maka Hammam berkata; \"Menurutku dia lebih hafal dari Ayyub yaitu Ibnu Al 'Ala`.\""},"878":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكَانَ النَّاسُ يَنْتَابُونَ الْجُمُعَةَ مِنْ مَنَازِلِهِمْ وَمِنْ الْعَوَالِي","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru] dari ['Ubaidullah bin Abu Ja'far] bahwa [Muhammad bin Ja'far] telah menceritakan kepadanya dari ['Urwah bin Az Zubair] dari [Aisyah istri Rasulullah shallallahu 'alaihi wasallam] bahwa dia berkata; \"Orang-orang berbondong-bondong untuk melaksanakan shalat jum'at dari rumah-rumah mereka dan dari 'Awali (dataran tinggi yang jaraknya sekitar empat mil dari Madinah). "},"879":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ سَعِيدٍ يَعْنِي الطَّائِفِيَّ عَنْ أَبِي سَلَمَةَ بْنِ نُبَيْهٍ عَنْ عَبْدِ اللَّهِ بْنِ هَارُونَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجُمُعَةُ عَلَى كُلِّ مَنْ سَمِعَ النِّدَاءَقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ جَمَاعَةٌ عَنْ سُفْيَانَ مَقْصُورًا عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو وَلَمْ يَرْفَعُوهُ وَإِنَّمَا أَسْنَدَهُ قَبِيصَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Sa'id yaitu Ath Tha`ifi] dari [Abu Salamah bin Nubaih] dari [Abdullah bin Harun] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat jum'at wajib bagi orang yang mendengarkan adzan.\" Abu Daud berkata; \"Hadits ini diriwayatkan oleh Jama'ah dari Sufyan sebatas Abdullah bin Amru saja dan tidak merafa'-kannya, yang men-sanadkan (menyambungkan riwayatnya sampai kepada Nabi) hanya Qabishah. "},"880":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّ يَوْمَ حُنَيْنٍ كَانَ يَوْمَ مَطَرٍ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيَهُ أَنَّ الصَّلَاةَ فِي الرِّحَالِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ صَاحِبٍ لَهُ عَنْ أَبِي مَلِيحٍ أَنَّ ذَلِكَ كَانَ يَوْمَ جُمُعَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Hammam] dari [Qatadah] dari [Abu Al Malih] dari [ayahnya] bahwa pada waktu Perang Hunain, hari sedang hujan, maka Nabi shallallahu 'alaihi wasallam memerintahkan Mu'adzinnya untuk menyerukan shalat di persinggahan masing-masing.\" Telah menceritakan kepada kami Muhammad bin Al Mutsanna telah menceritakan kepada kami Abdul A'la telah menceritakan kepada kami Sa'id dari sahabatnya Sa'id dari Abu Malih, bahwa waktu itu adalah hari Jum'at.\""},"881":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ سُفْيَانُ بْنُ حَبِيبٍ خَبَّرَنَا عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ فِي يَوْمِ جُمُعَةٍ وَأَصَابَهُمْ مَطَرٌ لَمْ تَبْتَلَّ أَسْفَلُ نِعَالِهِمْ فَأَمَرَهُمْ أَنْ يُصَلُّوا فِي رِحَالِهِمْ","id":"Telah menceritakan kepada kami [Nashr bin Ali], [Sufyan bin Habib] berkata; telah mengabarkan kepada kami, dari [Khalid Al Khaddza`] dari [Abu Qilabah] dari [Abu Al Malih] dari [ayahnya] bahwa dia melihat Nabi shallallahu 'alaihi wasallam pada peristiwa Hudaibiyah ketika hari Jum'at, mereka kehujanan yang tidak hanya mengenai bagian bawah sandal mereka, maka beliau memerintahkan mereka untuk mengerjakan shalat di persinggahan mereka.\""},"882":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ نَزَلَ بِضَجْنَانَ فِي لَيْلَةٍ بَارِدَةٍ فَأَمَرَ الْمُنَادِيَ فَنَادَى أَنْ الصَّلَاةُ فِي الرِّحَالِ قَالَ أَيُّوبُ وَحَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ أَوْ مَطِيرَةٌ أَمَرَ الْمُنَادِيَ فَنَادَى الصَّلَاةُ فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] pernah singgah di Dlajnan ketika malam dingin mencekam, maka dia memerintahkan Mu'adzinnya untuk menyerukan bahwa Shalat di kerjakan di persinggahan.\" [Ayyub] berkata; telah menceritakan kepada kami [Nafi'] dari [Ibnu Umar] bahwa apabila malam sangat dingin atau terjadi hujan lebat, maka Rasulullah shallallahu 'alaihi wasallam memerintahkan Mu'adzinnya untuk menyerukan supaya shalat di kerjakan di persinggahan.\""},"883":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَ نَادَى ابْنُ عُمَرَ بِالصَّلَاةِ بِضَجْنَانَ ثُمَّ نَادَى أَنْ صَلُّوا فِي رِحَالِكُمْقَالَ فِيهِ ثُمَّ حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَأْمُرُ الْمُنَادِيَ فَيُنَادِي بِالصَّلَاةِ ثُمَّ يُنَادِي أَنْ صَلُّوا فِي رِحَالِكُمْ فِي اللَّيْلَةِ الْبَارِدَةِ وَفِي اللَّيْلَةِ الْمَطِيرَةِ فِي السَّفَرِقَالَ أَبُو دَاوُد وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ وَعُبَيْدِ اللَّهِ قَالَ فِيهِ فِي السَّفَرِ فِي اللَّيْلَةِ الْقَرَّةِ أَوْ الْمَطِيرَةِ","id":"Telah menceritakan kepada kami [Mu'ammal bin Hisyam] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dri [Nafi'] dia berkata; [Ibnu Umar] pernah menyerukan untuk shalat ketika di Dlajnan, kemudian dia berseru; \"Shalatlah kalian di persinggahan kalian.\" Dalam hadits ini, dia juga berkata; \"Kemudian Ibnu Umar menuturkan dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau menyuruh mu'adzinnya untuk menyerukan shalat, kemudian seseorang menyeru; 'Hendaknya kalian shalat di persinggahan kalian ketika malam yang dingin mencekam, dan ketika malam hujan, serta dalam perjalanan.\" Abu Daud mengatakan; \"Di riwayatkan pula oleh [Hammad bin Salamah] dari [Ayyub] dan ['Ubaidullah], dalam hadits tersebut dia mengatakan; \" yaitu ketika dalam perjalanan dan di saat dinginnnya malam atau hujan.\""},"884":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ نَادَى بِالصَّلَاةِ بِضَجْنَانَ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ فَقَالَ فِي آخِرِ نِدَائِهِ أَلَا صَلُّوا فِي رِحَالِكُمْ أَلَا صَلُّوا فِي الرِّحَالِثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ أَوْ ذَاتُ مَطَرٍ فِي سَفَرٍ يَقُولُ أَلَا صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa dirinya menyerukan untuk shalat ketika di daerah Dlajnan pada malam yang sangat dingin dan berangin, di akhir seruannya dia mengatakan; \"Ingatlah, shalatlah kalian di persinggahan kalian, shalatlah kalian di persinggahan.\" Selanjutnya dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memerintahkan Mu'adzinnya apabila malam sangat dingin atau hujan ketika dalam perjalanan, dengan sabdanya: \"Ingatlah, shalatlah kalian di persinggahan kalian masing-masing.\""},"885":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ يَعْنِي أَذَّنَ بِالصَّلَاةِ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ فَقَالَ أَلَا صَلُّوا فِي الرِّحَالِ ثُمَّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ أَوْ ذَاتُ مَطَرٍ يَقُولُ أَلَا صَلُّوا فِي الرِّحَالِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ نَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فِي الْمَدِينَةِ فِي اللَّيْلَةِ الْمَطِيرَةِ وَالْغَدَاةِ الْقَرَّةِ قَالَ أَبُو دَاوُد وَرَوَى هَذَا الْخَبَرَ يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ عَنْ الْقَاسِمِ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيهِ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] bahwa [Ibnu Umar] yaitu (dia) adzan untuk mengerjakan shalat di saat malam yang sangat dingin dan berangin, katanya; \"Shalatlah kalian di persinggahan.\" Kemudian dia berkata; \" Rasulullah shallallahu 'alaihi wasallam pernah memerintahkan Mu'adzinnya, apabila malam sangat dingin atau hujan, beliau bersabda: \"Shalatlah kalian di persinggahan.\" Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Maslamah] dari [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Sorang penyeru Rasulullah shallallahu 'alaihi wasallam pernah menyerukan seperti itu ketika di Madinah yaitu di malam yang hujan dan di pagi yang sangat dingin.\" Abu Daud mengatakan; \"Haidts ini juga di riwayatkan oleh [Yahya bin Sa'id Al Anshari] dari [Al Qasim] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, dalam hadits itu dia berkata; \"…dan dalam perjalanan.\""},"886":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَمُطِرْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّ مَنْ شَاءَ مِنْكُمْ فِي رَحْلِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Al Fadl bin Dukain] telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, lalu kami kehujanan, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya seseorang shalat di persinggahannya bagi yang berkehendak.\""},"887":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنِي عَبْدُ الْحَمِيدِ صَاحِبُ الزِّيَادِيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ ابْنِ عَمِّ مُحَمَّدِ بْنِ سِيرِينَ أَنَّ ابْنَ عَبَّاسٍقَالَ لِمُؤَذِّنِهِ فِي يَوْمٍ مَطِيرٍ إِذَا قُلْتُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَلَا تَقُلْ حَيَّ عَلَى الصَّلَاةِ قُلْ صَلُّوا فِي بُيُوتِكُمْ فَكَأَنَّ النَّاسَ اسْتَنْكَرُوا ذَلِكَ فَقَالَ قَدْ فَعَلَ ذَا مَنْ هُوَ خَيْرٌ مِنِّي إِنَّ الْجُمُعَةَ عَزْمَةٌ وَإِنِّي كَرِهْتُ أَنْ أُخْرِجَكُمْ فَتَمْشُونَ فِي الطِّينِ وَالْمَطَرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah mengabarkan kepadaku [Abdul Hamid] salah seorang sahabatnya Az Ziyadi, telah menceritakan kepada kami [Abdullah bin Al Harits] sepupunya Muhammad bin Sirin, bahwa [Ibnu Abbas] berkata kepada Mu'adzinnya ketika hujan lebat; \"Jika aku mengucapkan; \"asyhadu anna Muhammadan Rasulullah\" maka jangan kamu teruskan dengan; \"Hayya 'alas shalah\" tapi serukanlah; \"Shalluu fii buyuutikum (Shalatlah kalian di rumah kalian masing-masing.\" Mendengar hal itu, orang-orang banyak mengingkarinya, maka Ibnu Abbas berkata; \"Yang demikian itu telah di kerjakan oleh orang-orang yang lebih baik daripadaku, sesungguhnya jum'at merupakan suatu kewajiban, namun aku tidak bermaksud menyuruh kalian keluar rumah melalui jalan yang berlumpur lagi becek.\""},"888":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا هُرَيْمٌ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجُمُعَةُ حَقٌّ وَاجِبٌ عَلَى كُلِّ مُسْلِمٍ فِي جَمَاعَةٍ إِلَّا أَرْبَعَةً عَبْدٌ مَمْلُوكٌ أَوْ امْرَأَةٌ أَوْ صَبِيٌّ أَوْ مَرِيضٌقَالَ أَبُو دَاوُد طَارِقُ بْنُ شِهَابٍ قَدْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَسْمَعْ مِنْهُ شَيْئًا","id":"Telah menceritakan kepada kami ['Abbas bin 'Abdul 'Adzim] telah menceritakan kepadaku [Ishaq bin Manshur] telah menceritakan kepada kami [Huraim] dari [Ibrahim bin Muhammad Al Muntasyir] dari [Qais bin Muslim] dari [Thariq bin Syihab] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Jum'at itu wajib bagi setiap Muslim dengan berjama'ah, kecuali empat golongan, yaitu; hamba sahaya, wanita, anak-anak dan orang yang sakit.\" Abu Daud berkata; \"Thariq bin Ziyad pernah melihat (hidup semasa) Nabi shallallahu 'alaihi wasallam, namun dirinya tidak mendengar sesuatu pun dari beliau.\""},"889":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْمُخَرِّمِيُّ لَفْظُهُ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ أَوَّلَ جُمُعَةٍ جُمِّعَتْ فِي الْإِسْلَامِ بَعْدَ جُمُعَةٍ جُمِّعَتْ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ لَجُمُعَةٌ جُمِّعَتْ بِجَوْثَاءَ قَرْيَةٌ مِنْ قُرَى الْبَحْرَيْنِقَالَ عُثْمَانُ قَرْيَةٌ مِنْ قُرَى عَبْدِ الْقَيْسِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syiabah] dan [Muhammad bin Abdullah Al Muharami] secara lafaadz, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Thahman] dari [Abu Jamrah] dari [Ibnu Abbas] dia berkata; \"Shalat jum'at yang pertama kali dalam Islam setelah shalat Jum'at yang di laksanakan di masjid Rasulullah shallallahu 'alaihi wasallam di Madinah, adalah shalat Jum'at di desa Juwatsa, yaitu suatu desa yang terletak di daerah Bahrain.\" Utsman mengatakan; 'Yaitu suatu desa yang terletak di wilayah (Bani) Abdul Qais.\""},"890":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ أَبِيهِ بَعْدَ مَا ذَهَبَ بَصَرُهُ عَنْ أَبِيهِ كَعْبِ بْنِ مَالِكٍأَنَّهُ كَانَ إِذَا سَمِعَ النِّدَاءَ يَوْمَ الْجُمُعَةِ تَرَحَّمَ لِأَسْعَدَ بْنِ زُرَارَةَ فَقُلْتُ لَهُ إِذَا سَمِعْتَ النِّدَاءَ تَرَحَّمْتَ لِأَسْعَدَ بْنِ زُرَارَةَ قَالَ لِأَنَّهُ أَوَّلُ مَنْ جَمَّعَ بِنَا فِي هَزْمِ النَّبِيتِ مِنْ حَرَّةِ بَنِي بَيَاضَةَ فِي نَقِيعٍ يُقَالُ لَهُ نَقِيعُ الْخَضَمَاتِ قُلْتُ كَمْ أَنْتُمْ يَوْمَئِذٍ قَالَ أَرْبَعُونَ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ibnu Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin Abu Umamah bin Sahl] dari [ayahnya] dari [Abdurrahman bin Ka'b bin Malik] -dia adalah seorang yang selalu menuntun ayahnya setelah ayahnya buta- dari [ayahnya yaitu Ka'ab bin Malik] bahwa apabila dia mendengar adzan pada hari jum'at, dia memohonkan rahmat untuk As'ad bin Zurarah. Lantas aku bertanya kepadanya; \"Mengapa anda memohonkan rahmat untk as'ad bin Zurarah setiap kali mendengar adzan Jum'at?\" jawabnya; Karena dia adalah orang yang pertama kali sebagai pelopor pelaksanaan shalat Jum'at di tengah-tengah kami di Hazmin-nabit, yang terletak di Bani Bayadhah di Baqi', yaitu Naqi'ul Khadhamat.\" Aku bertanya; \"Berapakah jumlah kalian ketika itu?\" dia menjawab; \"Empat puluh orang.\""},"891":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا عُثْمَانُ بْنُ الْمُغِيرَةِ عَنْ إِيَاسِ بْنِ أَبِي رَمْلَةَ الشَّامِيِّ قَالَشَهِدْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ وَهُوَ يَسْأَلُ زَيْدَ بْنَ أَرْقَمَ قَالَ أَشَهِدْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِيدَيْنِ اجْتَمَعَا فِي يَوْمٍ قَالَ نَعَمْ قَالَ فَكَيْفَ صَنَعَ قَالَ صَلَّى الْعِيدَ ثُمَّ رَخَّصَ فِي الْجُمُعَةِ فَقَالَ مَنْ شَاءَ أَنْ يُصَلِّيَ فَلْيُصَلِّ","id":"Telah menceritakan kepada kami [Muhammad bin katsir] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Utsman bin Al Mughirah] dari [Iyas Ibnu Abu Ramlah As Syami] dia berkata; aku pernah melihat Mu'awiyah bin Abu Sufyan bertanya kepada Zaid bin Arqam, tanyanya; \"Apakah kamu pernah melakukan dua hari raya bertepatan dalam satu hari ketika bersama Rasulullah shallallahu 'alaihi wasallam?\" Jawabnya; \"Ya. ' Mu'awiyah bertanya; \"Bagaimana beliau mengerjakan shalat tersebut?\" [Zaid bin Arqam] menjawab; \"Beliau mengerjakan shalat ied dan memberi keringanan pada waktu shalat Jum'at, lalu beliau bersabda: \"Barangsiapa ingin mengerjakan (shalat Jum'at), hendaknya mengerjakan shalat (Jum'at).\""},"892":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ الْبَجَلِيُّ حَدَّثَنَا أَسْبَاطٌ عَنْ الْأَعْمَشِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَصَلَّى بِنَا ابْنُ الزُّبَيْرِ فِي يَوْمِ عِيدٍ فِي يَوْمِ جُمُعَةٍ أَوَّلَ النَّهَارِ ثُمَّ رُحْنَا إِلَى الْجُمُعَةِ فَلَمْ يَخْرُجْ إِلَيْنَا فَصَلَّيْنَا وُحْدَانًا وَكَانَ ابْنُ عَبَّاسٍ بِالطَّائِفِ فَلَمَّا قَدِمَ ذَكَرْنَا ذَلِكَ لَهُ فَقَالَ أَصَابَ السُّنَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif Al Bajali] telah menceritakan kepada kami [Asbath] dari [Al A'masy] dari [Atha' bin Abu Rabah] dia berkata; [Ibnu Zubair] shalat bersama kami pada hari raya di hari jum'at, di awal hari, kemudian kami berangkat untuk melaksanakan shalat jum'at, namun dia tidak keluar untuk mengimami kami, akhirnya kami shalat sendiri-sendiri, ketika itu [Ibnu Abbas] sedang berada di thaif, setelah datang, kami sampaikan hal itu kepadanya, dia menjawab; \"Dia (Ibnu Zubair) benar telah melaksanakan sunnah.\""},"893":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ قَالَ عَطَاءٌاجْتَمَعَ يَوْمُ جُمُعَةٍ وَيَوْمُ فِطْرٍ عَلَى عَهْدِ ابْنِ الزُّبَيْرِ فَقَالَ عِيدَانِ اجْتَمَعَا فِي يَوْمٍ وَاحِدٍ فَجَمَعَهُمَا جَمِيعًا فَصَلَّاهُمَا رَكْعَتَيْنِ بُكْرَةً لَمْ يَزِدْ عَلَيْهِمَا حَتَّى صَلَّى الْعَصْرَ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dia berkata; ['Atha'] berkata; Hari raya ied dan hari Jum'at pernah bertepatan pada masa [Ibnu Zubair], lalu dia berkata; \"Dua hari raya telah bertepatan dalam satu hari, maka keduanya di kumpulkan (oleh Nabi), dan shalat dua rak'at di pagi hari, tidak menambah dua raka'at, hingga beliau shalat Ashar.\""},"894":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى وَعُمَرُ بْنُ حَفْصٍ الْوَصَّابِيُّ الْمَعْنَى قَالَا حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ الضَّبِّيِّ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ قَدْ اجْتَمَعَ فِي يَوْمِكُمْ هَذَا عِيدَانِ فَمَنْ شَاءَ أَجْزَأَهُ مِنْ الْجُمُعَةِ وَإِنَّا مُجَمِّعُونَقَالَ عُمَرُ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] dan [Umar bin Hafsh Al Washabi] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Baqiyah] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah Adl dlabi] dari [Abdul Aziz bin Rufai'] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda; \"Pada hari ini telah berkumpul bagi kalian dua hari raya, barangsiapa ingin melaksanakan, maka hari rayanya ini sudah mencukupi shalat jum'atnya, namun kami akan tetap melaksanakan Jum'at.\" Umar berkata dari Syu'bah. "},"895":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُخَوَّلِ بْنِ رَاشِدٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْفَجْرِ يَوْمَ الْجُمُعَةِ تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِ حِينٌ مِنْ الدَّهْرِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ مُخَوَّلٍ بِإِسْنَادِهِ وَمَعْنَاهُ وَزَادَ فِي صَلَاةِ الْجُمُعَةِ بِسُورَةِ الْجُمُعَةِ وَإِذَا جَاءَكَ الْمُنَافِقُونَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Mukhawwal bin Rasyid] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa dalam shalat shubuh di hari Jum'at, Rasulullah shallallahu 'alaihi wasallam membaca suraj As Sajdah dan HAL ATAA 'ALAL INSAAN HIINUM MINAD DAHRI (surat Al insan).\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Mukhawwal] dengan sanad dan maksud yang sama. Dia menambahkan; \"dalam shalat Jum'at, beliau membaca surat Al Jum'at dan \"IDZAA JAA`AKAL MUNAAFIQUUN (surat Al Munafiqun).\""},"896":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عُمَرَ بْنَ الْخَطَّابِرَأَى حُلَّةً سِيَرَاءَ يَعْنِي تُبَاعُ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَ هَذِهِ فَلَبِسْتَهَا يَوْمَ الْجُمُعَةِ وَلِلْوَفْدِ إِذَا قَدِمُوا عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ ثُمَّ جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا حُلَلٌ فَأَعْطَى عُمَرَ حُلَّةً فَقَالَ عُمَرُ كَسَوْتَنِيهَا يَا رَسُولَ اللَّهِ وَقَدْ قُلْتَ فِي حُلَّةِ عُطَارِدَ مَا قُلْتَ فَقَالَ رَسُولُ اللَّهِ إِنِّي لَمْ أَكْسُكَهَا لِتَلْبَسَهَا فَكَسَاهَا عُمَرُ أَخًا لَهُ مُشْرِكًا بِمَكَّةَحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ وَعَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ وَجَدَ عُمَرُ بْنُ الْخَطَّابِ حُلَّةَ إِسْتَبْرَقٍ تُبَاعُ بِالسُّوقِ فَأَخَذَهَا فَأَتَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْتَعْ هَذِهِ تَجَمَّلْ بِهَا لِلْعِيدِ وَلِلْوُفُودِ ثُمَّ سَاقَ الْحَدِيثَ وَالْأَوَّلُ أَتَمُّ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Umar bin Khattab pernah melihat kain campuran sutera di jual dekat pintu masjid, maka dia berkata; \"Wahai Rasulullah, alangkah baiknya jika anda membelinya kemudian anda kenakan pada hari Jum'at, dan untuk menyambut delegasi yang datang kepada anda.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang mengenakan pakaian ini hanyalah orang yang tidak mendapatkan bagiannya di akhirat.\" Kemudian Rasulullah shallallahu 'alaihi wasallam di beri beberapa pakaian yang di antaranya terbuat dari sutera, kemudian beliau berikan kain sutera itu kepada Umar, maka Umar berkata; \"Wahai Rasulullah, anda memakaikannya kepadaku, padahal anda telah mengatakannya kepadaku tentang status pakaian 'Utharid tersebut.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku memberikan itu bukan bermaksud untuk kamu pakai.\" Maka Umar memberikannya kepada saudaranya yang masih Musyrik di Makkah. ' Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dan ['Amru bin Al Harits] dari [Ibnu Syihab] dari [Salim] dari [ayahnya] dia berkata; \"Umar bin Khattab mendapati kain sutera yang di jual di pasar, kemudian dia mengambilnya lalu membawanya kepada Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Belilah ini, untuk berhias diri pada hari raya atau untuk menerima tami delegasi…\" kemudian dia menyebutkan hadits tersebut, namun hadits yang pertama lebih sempurna.\""},"897":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ وَعَمْرٌو أَنَّ يَحْيَى بْنَ سَعِيدٍ الْأَنْصَارِيَّ حَدَّثَهُ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَلَى أَحَدِكُمْ إِنْ وَجَدَ أَوْ مَا عَلَى أَحَدِكُمْ إِنْ وَجَدْتُمْ أَنْ يَتَّخِذَ ثَوْبَيْنِ لِيَوْمِ الْجُمُعَةِ سِوَى ثَوْبَيْ مِهْنَتِهِقَالَ عَمْرٌو وَأَخْبَرَنِي ابْنُ أَبِي حَبِيبٍ عَنْ مُوسَى بْنِ سَعْدٍ عَنْ ابْنِ حَبَّانَ عَنْ ابْنِ سَلَامٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَ عَلَى الْمِنْبَرِ قَالَ أَبُو دَاوُد وَرَوَاهُ وَهْبُ بْنُ جَرِيرٍ عَنْ أَبِيهِ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُوسَى بْنِ سَعْدٍ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dan ['Amru] bahwa [Yahya bin Sa'id Al Anshari] telah menceritakan kepadanya, bahwa [Muhammad bin Yahya bin Habban] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah tidak semestinya salah seorang dari kalian memiliki dua pakaian atau jika salah seorang punya kemampuan mempunyai dua pakaian untuk melaksanakan shalat jum'at selain pakaian untuk bekerja sehari-hari?.\" 'Amru berkata; telah mengabarkan kepadaku [Ibnu Abu Habib] dari [Musa bin Sa'd] dari [Ibnu Habban] dari [Ibnu Salam] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda demikian diatas mimbar.\" Abu Daud berkata; \"Dan hadits ini di riwayatkan oleh [Wahb bin Jarir] dari [ayahnya] dari [Yahya bin Ayyub] dari [Yazid bin Abu Habib] dari [Musa bin Sa'd] dari [Yusuf bin Abdullah bin Salam] dari Nabi shallallahu 'alaihi wasallam.\""},"898":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّرَاءِ وَالْبَيْعِ فِي الْمَسْجِدِ وَأَنْ تُنْشَدَ فِيهِ ضَالَّةٌ وَأَنْ يُنْشَدَ فِيهِ شِعْرٌ وَنَهَى عَنْ التَّحَلُّقِ قَبْلَ الصَّلَاةِ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang berjual beli di masjid, mencari sesuatu yang hilang, mendendangkan syair dan mengadakan mengadakan pertemuan (di masjid) sebelum shalat Jum'at.\""},"899":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدٍ الْقَارِيُّ الْقُرَشِيُّ حَدَّثَنِي أَبُو حَازِمِ بْنُ دِينَارٍأَنَّ رِجَالًا أَتَوْا سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ وَقَدْ امْتَرَوْا فِي الْمِنْبَرِ مِمَّ عُودُهُ فَسَأَلُوهُ عَنْ ذَلِكَ فَقَالَ وَاللَّهِ إِنِّي لَأَعْرِفُ مِمَّا هُوَ وَلَقَدْ رَأَيْتُهُ أَوَّلَ يَوْمٍ وُضِعَ وَأَوَّلَ يَوْمٍ جَلَسَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فُلَانَةَ امْرَأَةٌ قَدْ سَمَّاهَا سَهْلٌ أَنْ مُرِي غُلَامَكِ النَّجَّارَ أَنْ يَعْمَلَ لِي أَعْوَادًا أَجْلِسُ عَلَيْهِنَّ إِذَا كَلَّمْتُ النَّاسَ فَأَمَرَتْهُ فَعَمِلَهَا مِنْ طَرْفَاءِ الْغَابَةِ ثُمَّ جَاءَ بِهَا فَأَرْسَلَتْهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا فَوُضِعَتْ هَاهُنَا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَيْهَا وَكَبَّرَ عَلَيْهَا ثُمَّ رَكَعَ وَهُوَ عَلَيْهَا ثُمَّ نَزَلَ الْقَهْقَرَى فَسَجَدَ فِي أَصْلِ الْمِنْبَرِ ثُمَّ عَادَ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ أَيُّهَا النَّاسُ إِنَّمَا صَنَعْتُ هَذَا لِتَأْتَمُّوا بِي وَلِتَعْلَمُوا صَلَاتِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman bin Muhammad bin Abdullah bin Abdul Qarri` Al Qurasyi] telah menceritakan kepadaku [Abu Hazim bin Dinar] bahwa beberapa orang pergi menemui [Sahl bin Sa'd As Saidi], sedangkan mereka memperdebatkan mengenai bahan kayu untuk membuat mimbar, mereka menanyakan hal itu kepada Sahl, jawab Sahl; \"Demi Allah, sungguh aku telah mengetahuinya dari apakah ia di buat, sesungguhnya aku telah melihatnya ketika pertama kali di letakkan, dan pada hari pertama Rasulullah shallallahu 'alaihi wasallam duduk di atasnya. Rasulullah shallallahu 'alaihi wasallam pernah mengutus seseorang untuk menemui fulanah -seorang wanita yang namanya di sebutkan oleh Sahl-, sabdanya: \"Suruhlah budakmu yang tukang kayu untuk membuatkanku mimbar supaya aku bisa duduk di atasnya apabila aku berkhutbah (pidato) di hadapan manusia.\" Lantas fulanah tadi menyuruh budaknya, dan budak tersebut mulai membuatnya yang di ambil (kayunya) dari hutan Tharfa' (derah pedesaan), setelah jadi, budak tersebut membawanya kepada wanita itu, lalu (mimbar itu) di kirim kepada Nabi shallallahu 'alaihi wasallam, maka beliau menyuruh untuk meletakkan di sini, aku melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat di atas mimbar tersebut, lalu beliau bertakbir dan ruku', sementara beliau masih di atas mimbar, kemudian beliau turun pelan-pelan dan mundur ke belakang lalu sujud di pangkal mimbarnya, kemudian beliau kembali. Selesai shalat, beliau menghadap kepada orang-orang lalu bersabda: \"Wahai sekalian manusia, aku melakukan hal ini tidak lain supaya kalian mengikutiku dan melihat tata cara shalatku.\""},"900":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَدَّنَ قَالَ لَهُ تَمِيمٌ الدَّارِيُّ أَلَا أَتَّخِذُ لَكَ مِنْبَرًا يَا رَسُولَ اللَّهِ يَجْمَعُ أَوْ يَحْمِلُ عِظَامَكَ قَالَ بَلَى فَاتَّخَذَ لَهُ مِنْبَرًا مِرْقَاتَيْنِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] bahwa ketika Nabi shallallahu 'alaihi wasallam memasuki usia lanjut, sahabat Tamim Addari berkata kepadanya; \"Sudikah anda aku buatkan mimbar untuk anda pergunakan duduk wahai Rasulullah?\" Beliau menjawab: \"Ya!.\" Maka dia membuatkan mimbar dengan dua anak tangga untuk beliau.\""},"901":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَكَانَ بَيْنَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْحَائِطِ كَقَدْرِ مَمَرِّ الشَّاةِ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Abu 'Ashim] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] dia berkata; Di antara mimbar Rasulullah shallallahu 'alaihi wasallam dengan tembok berjarak kira-kira seekor kambing bisa melewatinya.\""},"902":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَسَّانُ بْنُ إِبْرَاهِيمَ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ أَبِي الْخَلِيلِ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ الصَّلَاةَ نِصْفَ النَّهَارِ إِلَّا يَوْمَ الْجُمُعَةِ وَقَالَ إِنَّ جَهَنَّمَ تُسَجَّرُ إِلَّا يَوْمَ الْجُمُعَةِقَالَ أَبُو دَاوُد هُوَ مُرْسَلٌ مُجَاهِدٌ أَكْبَرُ مِنْ أَبِي الْخَلِيلِ وَأَبُو الْخَلِيلِ لَمْ يَسْمَعْ مِنْ أَبِي قَتَادَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Hassan bin Ibrahim] dari [Laits] dari [Mujahid] dari [Abu Al Khalil] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau tidak suka melaksanakan shalat pertengahan siang kecuali hari jum'at. Beliau bersabda: \"Sesungguhnya neraka Jahannam di nyalakan pada waktu itu kecuali hari Jum'at.\" Abu Daud berkata; \"Hadits ini mursal karena Mujahid lebih tua dari Abu Khalil, sedangkan Abu Khalil tidak pernah mendengar dari Abu Qatadah.\""},"903":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنِي عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ التَّيْمِيُّ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْجُمُعَةَ إِذَا مَالَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Zaid bin Al Khubbab] telah menceritakan kepadaku [Fulaih bin Sulaiman] telah menceritakan kepadaku [Utsman bin Abdurrahman At Taimi] saya mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat Jum'at ketika matahari mulai condong.\""},"904":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا يَعْلَى بْنُ الْحَارِثِ سَمِعْتُ إِيَاسَ بْنَ سَلَمَةَ بْنِ الْأَكْوَعِ يُحَدِّثُ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَنْصَرِفُ وَلَيْسَ لِلْحِيطَانِ فَيْءٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ya'la bin Al Harits] saya mendengar [Iyas bin Salamah bin Al Akwa'] bercerita dari [ayahnya] dia berkata; \"Kami shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami beranjak pergi sedangkan tembok sudah tidak memiliki bayang-bayang lagi (ditengah hari).\""},"905":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكُنَّا نَقِيلُ وَنَتَغَدَّى بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Kami melaksanakan qailulah (tidur siang) dan makan siang setelah melaksanakan shalat Jum'at.\""},"906":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَأَنَّ الْأَذَانَ كَانَ أَوَّلُهُ حِينَ يَجْلِسُ الْإِمَامُ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا كَانَ خِلَافَةُ عُثْمَانَ وَكَثُرَ النَّاسُ أَمَرَ عُثْمَانُ يَوْمَ الْجُمُعَةِ بِالْأَذَانِ الثَّالِثِ فَأُذِّنَ بِهِ عَلَى الزَّوْرَاءِ فَثَبَتَ الْأَمْرُ عَلَى ذَلِكَحَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَ كَانَ يُؤَذَّنُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ عَلَى بَابِ الْمَسْجِدِ وَأَبِي بَكْرٍ وَعُمَرَ ثُمَّ سَاقَ نَحْوَ حَدِيثِ يُونُسَ حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ قَالَ لَمْ يَكُنْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مُؤَذِّنٌ وَاحِدٌ بِلَالٌ ثُمَّ ذَكَرَ مَعْنَاهُ حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ ابْنَ أُخْتِ نَمِرٍ أَخْبَرَهُ قَالَ وَلَمْ يَكُنْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ مُؤَذِّنٍ وَاحِدٍ وَسَاقَ هَذَا الْحَدِيثَ وَلَيْسَ بِتَمَامِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [As Sa`ib bin Yazid] bahwa pada mulanya, adzan pertama pada hari Jum'at ketika imam duduk di atas mimbar yaitu di masa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar radliallahu 'anhuma, ketika Utsman menjabat Khilafah, sementara orang-orang semakin banyak jumlahnya, maka Utsman memerintahkan untuk mengumandangkan adzan ketiga di hari Jum'at, maka di kumandangkanlah adzan di atas Zaura`(tempat ketinggian di pasar Madinah), lalu perkara tersebut menjadi tetap.\" Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari [As Sa`ib bin Yazid] dia berkata; \"Mu'adzin mengumandangkan adzan di hadapan Rasulullah Shallallahu shallallahu 'alaihi wasallam pada hari Jum'at, yaitu ketika beliau telah duduk di atas mimbar, sedangkan Abu Bakar dan Umar berada di depan pintu masjid…\" kemudian dia melanjutkan hadits tersebut sebagaimana hadits Yunus. Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami ['Abdah] dari [Muhammad yaitu Ibnu Ishaq] dari [Az Zuhri] dari [As Sa`ib] dia berkata; \"Rasulullah tidak memiliki Mu'adzin (tetap) kecuali satu orang, yaitu Bilal…\" kemudian dia menyebutkan makna haditsnya.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Ya'kub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [As Sa`ib bin Yazid sepupunya Namir] telah mengabarkan kepadanya, katanya; \"Rasulullah shallallahu 'alaihi wasallam tidak memiliki selain satu Mu'adzin…\" kemudian dia melanjutkan hadits tersebut, namun tidak sempurna.\""},"907":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ كَعْبٍ الْأَنْطَاكِيُّ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَلَمَّا اسْتَوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ قَالَ اجْلِسُوا فَسَمِعَ ذَلِكَ ابْنُ مَسْعُودٍ فَجَلَسَ عَلَى بَابِ الْمَسْجِدِ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَعَالَ يَا عَبْدَ اللَّهِ بْنَ مَسْعُودٍقَالَ أَبُو دَاوُد هَذَا يُعْرَفُ مُرْسَلًا إِنَّمَا رَوَاهُ النَّاسُ عَنْ عَطَاءٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَخْلَدٌ هُوَ شَيْخٌ","id":"Telah menceritakan kepada kami [Ya'kub bin Ka'b Al Anthaki] telah menceritakan kepada kami [Makhlad bin Yazid] telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha`] dari [Jabir] dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam duduk diatas mimbar pada hari Jum'at, beliau bersabda: \"Duduklah kalian!.\" ucapan itu di dengar oleh Abdullah bin Mas'ud, maka dia segera duduk di dekat pintu pintu Masjid, ketika Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau berseru kepadanya: \"Kemarilah wahai Abdullah bin Mas'ud!.\" Abu Daud berkata; \"Hadits ini terkenal mursal, karena orang-orang meriwayatkan dari 'Atha` dari Nabi shallallahu 'alaihi wasallam, sementara Makhlad adalah seorang syaikh (maksudnya adalah haditsnya boleh ditulis).\""},"908":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي ابْنَ عَطَاءٍ عَنْ الْعُمَرِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ خُطْبَتَيْنِ كَانَ يَجْلِسُ إِذَا صَعِدَ الْمِنْبَرَ حَتَّى يَفْرَغَ أُرَاهُ قَالَ الْمُؤَذِّنُ ثُمَّ يَقُومُ فَيَخْطُبُ ثُمَّ يَجْلِسُ فَلَا يَتَكَلَّمُ ثُمَّ يَقُومُ فَيَخْطُبُ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Abdul Wahab yaitu Ibnu 'Atha`] dari [Al 'Umari] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Nabi shallallahu 'alaihi wasallam menyampaikan khutbah dua kali, beliau duduk setelah naik mimbar sehingga Mu'adzin selesai mengumandangkan adzan, setelah itu beliau berdiri dan berkhutbah, lalu duduk lagi dan tidak berbicara kemudian bangkit dan berkhutbah.\""},"909":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا زُهَيْرٌ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ فَيَخْطُبُ قَائِمًا فَمَنْ حَدَّثَكَ أَنَّهُ كَانَ يَخْطُبُ جَالِسًا فَقَدْ كَذَبَ فَقَالَ فَقَدْ وَاللَّهِ صَلَّيْتُ مَعَهُ أَكْثَرَ مِنْ أَلْفَيْ صَلَاةٍ","id":"Telah menceritakan kepada kami [An Nufaili Abdullah bin Muhammad] telah menceritakan kepada kami [Zuhair] dari [Simak] dari [Jabir bin Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam khutbah dengan berdiri, lalu duduk, setelah itu beliau berdiri lagi dan menyampaikan khutbahnya. Barangsiapa menyampaikan kepadamu bahwa beliau berkhutbah dengan duduk, sungguh dia telah berdusta.\" Jabir berkata; \"Sungguh, aku shalat bersama beliau lebih dari dua ribu shalat.\""},"910":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى عَنْ أَبِي الْأَحْوَصِ حَدَّثَنَا سِمَاكٌ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَتَانِ كَانَ يَجْلِسُ بَيْنَهُمَا يَقْرَأُ الْقُرْآنَ وَيُذَكِّرُ النَّاسَحَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَقْعُدُ قَعْدَةً لَا يَتَكَلَّمُ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] dan [Utsman bin Abi Syaibah] sedangkan ma'na haditsnya dari [Abu Al Ahwash] telah menceritakan kepada kami [Simak] dari [Jabir bin Samurah] dia berkata; \"Nabi shallallahu 'alaihi wasallam biasa menyampaikan dua kali khutbah, beliau duduk di antara dua khutbah tersebut, beliau membaca Al Qur'an dan memberi peringatan kepada orang-orang.\" Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Abu 'Awanah] dari [Simak bin Harb] dari [Jabir bin Samurah] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam khutbah dengan berdiri kemudian duduk, beliau tidak mengatakan sepatah katapun,,,, \" kemudian dia melanjutkan hadits tersebut.\""},"911":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا شِهَابُ بْنُ خِرَاشٍ حَدَّثَنِي شُعَيْبُ بْنُ زُرَيْقٍ الطَّائِفِيُّ قَالَجَلَسْتُ إِلَى رَجُلٍ لَهُ صُحْبَةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ الْحَكَمُ بْنُ حَزْنٍ الْكُلَفِيُّ فَأَنْشَأَ يُحَدِّثُنَا قَالَ وَفَدْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابِعَ سَبْعَةٍ أَوْ تَاسِعَ تِسْعَةٍ فَدَخَلْنَا عَلَيْهِ فَقُلْنَا يَا رَسُولَ اللَّهِ زُرْنَاكَ فَادْعُ اللَّهَ لَنَا بِخَيْرٍ فَأَمَرَ بِنَا أَوْ أَمَرَ لَنَا بِشَيْءٍ مِنْ التَّمْرِ وَالشَّأْنُ إِذْ ذَاكَ دُونٌ فَأَقَمْنَا بِهَا أَيَّامًا شَهِدْنَا فِيهَا الْجُمُعَةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ مُتَوَكِّئًا عَلَى عَصًا أَوْ قَوْسٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ كَلِمَاتٍ خَفِيفَاتٍ طَيِّبَاتٍ مُبَارَكَاتٍ ثُمَّ قَالَ أَيُّهَا النَّاسُ إِنَّكُمْ لَنْ تُطِيقُوا أَوْ لَنْ تَفْعَلُوا كُلَّ مَا أُمِرْتُمْ بِهِ وَلَكِنْ سَدِّدُوا وَأَبْشِرُواقَالَ أَبُو عَلِيٍّ سَمِعْت أَبُو دَاوُد قَالَ ثَبَّتَنِي فِي شَيْءٍ مِنْهُ بَعْضُ أَصْحَابِنَا وَقَدْ كَانَ انْقَطَعَ مِنْ الْقِرْطَاسِ","id":"Telah menceritakan kepada kami [Sa'd bin Manshur] telah menceritakan kepada kami [Syihab bin Khirasy] telah menceritakan kepadaku [Syu'aib bin Zuraiq Ath Tha`ifi] dia berkata; \"Aku duduk di samping seorang sahabat Rasulullah shallallahu 'alaihi wasallam yang bernama [Al Hakam bin Hazn Al Kulafi], lalu dia menceritakan kepada kami, katanya; \"Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam bersama dengan tujuh atau sembilan orang, setelah kami masuk menemui beliau, kami bertanya; \"Wahai Rasulullah, kami mengunjungi anda, oleh karena itu, do'akanlah kebaikan untuk kami.\" Maka beliau memerintahkan supaya kami di suguhi kurma, pada waktu itu, kondisi dalam situasi lemah. Kami pun tinggal di Madinah beberapa hari, kami juga mengikuti pelaksanaan shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam, saat itu beliau berdiri bertopang pada tongkat atau busur, lalu beliau memuji Allah dan menyanjung-Nya dengan beberapa patah kata ringan, baik lagi penuh berkah, beliau bersabda: \"Wahai sekalian manusia, sesungguhnya kalian tidak akan mampu mengerjakan semua yang di perintahkan kalian, akan tetapi bertindaklah yang benar dan berilah kabar gembira.\" Abu Ali berkata; \"Aku mendengar Abu Daud berkata; \"Para sahabat kami telah meneguhkan sesuatu dari hadits tersebut, sebab kertas-kertas telah terputus.\""},"912":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عِمْرَانُ عَنْ قَتَادَةَ عَنْ عَبْدِ رَبِّهِ عَنْ أَبِي عِيَاضٍ عَنْ ابْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا تَشَهَّدَ قَالَ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا مِنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَرْسَلَهُ بِالْحَقِّ بَشِيرًا وَنَذِيرًا بَيْنَ يَدَيْ السَّاعَةِ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَإِنَّهُ لَا يَضُرُّ إِلَّا نَفْسَهُ وَلَا يَضُرُّ اللَّهَ شَيْئًاحَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ أَنَّهُ سَأَلَ ابْنَ شِهَابٍ عَنْ تَشَهُّدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ فَذَكَرَ نَحْوَهُ قَالَ وَمَنْ يَعْصِهِمَا فَقَدْ غَوَى وَنَسْأَلُ اللَّهَ رَبَّنَا أَنْ يَجْعَلَنَا مِمَّنْ يُطِيعُهُ وَيُطِيعُ رَسُولَهُ وَيَتَّبِعُ رِضْوَانَهُ وَيَجْتَنِبُ سَخَطَهُ فَإِنَّمَا نَحْنُ بِهِ وَلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami ['Imran] dari [Qatadah] dari ['Abd Rabbihi] dari [Abu 'Iyadl] dari [Ibnu Mas'ud] bahwa apabila Rasulullah shallallahu 'alaihi wasallam bertasyahhud (memulai khutbahnya), beliau mengucapkan: \"ALHAMDULILLAH NASTA'IINUHU WANASTAGHFIRUHU WANA'UDZU BILLAHI MIN SYURURI ANFUSINA MAN YAHDIHILLAHU FALA MUDHILLA LAHU WAMAN YUDHLIL FALA HADIYA LAHU. WAASYHADU ALLA ILAAHA ILLALLAH WAASYHADU ANNA MUHAMMADAN ABDUHU WA RASULUHU ARSALAHU BIL HUDA, BASYIRAW WANADZIRAN BAINA YADAYISSA'AH MAN YUTHI'ILLAHA WARASULAHU FAQAD RASYAD WAMAN YA'SHIHIMA FAINNAHU LA YADHURRU ILLA NAFSAHUWALA YADHURRU-LLAHA SYAIAN (segala puji bagi Allah, kita memohon ampun kepada-Nya dan memohon pertolongan kepada-Nya dan berlindung kepada Allah dari kejahatan-kejahatan diri kita, barang siapa yang di beri petunjuk oleh Allah, maka tidak ada seorangpun yang dapat menyesatkannya dan barangsiapa di sesatkan-Nya, maka tidak ada seorangpun yang dapat memberikannya petunjuk. Aku bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Allah dan aku bersaksi bahwa Muhammad adalah hamba dan rasul-Nya yang diutus dengan kebenaran sebagai pamberi kabar gembira dan sekaligus pemberi peringatan sebelum datangnya hari Kiamat. Barangsiapa menaati Allah dan rasul-Nya, maka dia telah mendapatkan petunjuk dan barangsiapa bermaksiat kepada keduanya, maka sesungguhnya dia tidaklah mencelakakan kecuali dirinya sendiri dan Allah tidak rugi sedikitpun).\" Telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah mengabarkan kepadaku [Ibnu Wahb] dari [Yunus] bahwa dia bertanya kepada [Ibnu Syihab] tentang tasyahhudnya Rasulullah shallallahu 'alaihi wasallam pada khutbah Jum'at, maka dia menyebutkan seperti diatas dengan tambahan; \"WAMAN YA'SHIHIMA FAQAD GHAWA WANAS'ALULLAHA RABBANA AN YAJ'ALANA MIMMAN YUTHI'UHU WA YUTHI'I RASULAHU WA YATTABI' RIDHWANAHU WA YAJTANIB SAKHATHAHU FAINNAMA NAHNU BIHI WA LAHU\" (Dan barangsiapa bermaksiat kepada keduanya, maka dia telah tersesat, kami memohon kepada Allah Rabb kami agar menjadikan kami termasuk orang-orang yang taat kepada-Nya dan taat kepada rasul-Nya dan termasuk orang yang mengikuti keridhaan-Nya serta menjauhi kamurkaan-Nya, sesungguhnya kami adalah orang-orang yang selalu merindukan keridhaan-Nya dan menjauhi kamurkaan-Nya).\""},"913":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ بْنِ سَعِيدٍ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ عَنْ تَمِيمٍ الطَّائِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ خَطِيبًا خَطَبَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَقَالَ قُمْ أَوْ اذْهَبْ بِئْسَ الْخَطِيبُ أَنْتَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan bin Sa'id] telah menceritakan kepadaku [Abdul Aziz bin Rufai'] dari [Tamim Ath Tha`i] dari ['Adi bin Hatim] bahwa seprang Khatib menyampaikan khutbahnya di samping Nabi shallallahu 'alaihi wasallam, katanya; \"Barangsiapa mena'ati Allah dan Rasul-Nya, sungguh ia akan memperoleh petunjuk. Dan barangsiapa bermaksiat kepada keduanya, (maka telah tersesat).\" Maka beliau bersabda: \"Berdirilah dan pergi, kamu adalah seburuk-buruk Khatib.\""},"914":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ مَعْنٍ عَنْ بِنْتِ الْحَارِثِ بْنِ النُّعْمَانِ قَالَتْمَا حَفِظْتُ قَافْ إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ بِهَا كُلَّ جُمُعَةٍ قَالَتْ وَكَانَ تَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَنُّورُنَا وَاحِدًاقَالَ أَبُو دَاوُد قَالَ رَوْحُ بْنُ عُبَادَةَ عَنْ شُعْبَةَ قَالَ بِنْتُ حَارِثَةَ بْنِ النُّعْمَانِ و قَالَ ابْنُ إِسْحَقَ أُمُّ هِشَامٍ بِنْتُ حَارِثَةَ بْنِ النُّعْمَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syubah] dari [Khubaib] dari [Abdullah bin Muhammad bin Ma'n] dari [Bintu Al Harits bin Nu'man] dia berkata; \"Aku tidak pernah hafal surat Qaaf kecuali langsung dari mulut Rasulullah shallallahu 'alaihi wasallam, sebab beliau selalu berkhutbah dengan surat tersebut setiap hari Jum'at.\" Katanya lagi; \"Dan juga tungku Rasulullah shallallahu 'alaihi wasallam dengan tungku kami menjadi satu.\" Abu Daud berkata; [Rauh bin 'Ubadah] berkata dari [Syu'bah] dia mengatakan; [Bintu Haritsah bin Nu'man] ….\" sedangkan [Ibnu Ishaq] mengatakan; [Ummu Hisyam bintu Haritsah bin Nu'man] …\""},"915":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي سِمَاكٌ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَصْدًا وَخُطْبَتُهُ قَصْدًا يَقْرَأُ آيَاتٍ مِنْ الْقُرْآنِ وَيُذَكِّرُ النَّاسَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Simak] dari [Jabir bin Samurah] dia berkata; \"Shalat yang di kerjakan Rasulullah sangatlah sederhana, begitu juga dengan khutbah beliau, (dalam khutbahnya) beliau hanya membaca beberapa ayat Al Qur'an dan memberi peringatan kepada orang-orang.\""},"916":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مَرْوَانُ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتِهَا قَالَتْمَا أَخَذْتُ قَافْ إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَؤُهَا فِي كُلِّ جُمُعَةٍقَالَ أَبُو دَاوُد كَذَا رَوَاهُ يَحْيَى بْنُ أَيُّوبَ وَابْنُ أَبِي الرِّجَالِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتٍ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ كَانَتْ أَكْبَرَ مِنْهَا بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Marwan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari ['Amrah] dari [saudara perempuannya] dia berkata; \"Aku tidak pernah hafal surat Qaaf, kecuali dari mulut Rasulullah shallallahu 'alaihi wasallam, karena beliau membacanya setiap Jum'at.\" Abu Daud berkata; Demikianlah yang di riwayatkan oleh [Yahya bin Ayyub] dan [Ibnu Abu Rijal] dari [Yahya bin Sa'id] dari ['Amrah] dari [Ummu Hisyam binti Haritsah bin Nu'man]. Telah menceritakan kepada kami [Ibnu As Sarh] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yahya bin Ayyub] dari [Yahya bin Sa'id] dari ['Amrah] dari [Saudara perempuannya 'Amrah binti Abdurrahman] bahwa dirinya lebih tua daripada saudara perempuannya dan haditsnya semakna.\""},"917":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ قَالَرَأَى عُمَارَةُ بْنُ رُوَيْبَةَ بِشْرَ بْنَ مَرْوَانَ وَهُوَ يَدْعُو فِي يَوْمِ جُمُعَةٍ فَقَالَ عُمَارَةُ قَبَّحَ اللَّهُ هَاتَيْنِ الْيَدَيْنِ قَالَ زَائِدَةُ قَالَ حُصَيْنٌ حَدَّثَنِي عُمَارَةُ قَالَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ مَا يَزِيدُ عَلَى هَذِهِ يَعْنِي السَّبَّابَةَ الَّتِي تَلِي الْإِبْهَامَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Za`idah] dari [Hushain bin Abdurrahman] dia berkata; ['Umarah bin Ruwaibah] melihat Bisyr bin Marwan sedang berdo'a pada hari Jum'at (dengan mengangkat tangan), maka Umarah berkata; \"Semoga Allah menjadikan kedua tangan ini jelek.\" [Za`idah] berkata; [Hushain] berkata; telah menceritakan kepadaku ['Umarah] dia berkata; \"Sungguh aku pernah melihat Rasulullah shallallahu 'alaihi wasallam ketika beliau di atas mimbar, (berdo'a) tidak lebih dari memberi isyarat dengan ini.\" yaitu jari telunjuk dekat ibu jari.\""},"918":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ ابْنِ أَبِي ذُبَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاهِرًا يَدَيْهِ قَطُّ يَدْعُو عَلَى مِنْبَرِهِ وَلَا عَلَى غَيْرِهِ وَلَكِنْ رَأَيْتُهُ يَقُولُ هَكَذَا وَأَشَارَ بِالسَّبَّابَةِ وَعَقَدَ الْوُسْطَى بِالْإِبْهَامِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadlal] telah menceritakan kepada kami [Abdurrahman yaitu Ibnu Ishaq] dari [Abdurrahman bin Mu'awiyah] dari [Ibnu Abu Dzubab] dari [Sahl bin Sa'd] dia berkata; \"Aku tidak pernah melihat sama sekali Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya ketika berdo'a, baik di atas mimbar maupun di tempat lain, akan tetapi aku melihat beliau hanya memberi isyarat seperti ini.\" lalu Sahl memberi isyarat dengan jari telunjuk sambil mengenggam jari tengah dengan jempol.\""},"919":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْعَلَاءُ بْنُ صَالِحٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي رَاشِدٍ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِقْصَارِ الْخُطَبِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al 'Ala` bin Shalih] dari ['Adi bin Tsabit] dari [Abu Rasyid] dari ['Ammar bin Yasir] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk mempersingkat khutbah.\""},"920":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْوَلِيدُ أَخْبَرَنِي شَيْبَانُ أَبُو مُعَاوِيَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ السُّوَائِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُطِيلُ الْمَوْعِظَةَ يَوْمَ الْجُمُعَةِ إِنَّمَا هُنَّ كَلِمَاتٌ يَسِيرَاتٌ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Al Walid] telah mengabarkan kepadaku [Syaiban Abu Mu'awiyah] dari [Simak bin Harb] daru [Jabir bin Samurah As Suwa`i] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah berpanjang lebar dalam menyampaikan nasehat pada hari Jum'at, hanyasanya ia merupakan beberapa patah kata yang singkat.\""},"921":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ وَلَمْ أَسْمَعْهُ مِنْهُ قَالَ قَتَادَةُ عَنْ يَحْيَى بْنِ مَالِكٍ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْضُرُوا الذِّكْرَ وَادْنُوا مِنْ الْإِمَامِ فَإِنَّ الرَّجُلَ لَا يَزَالُ يَتَبَاعَدُ حَتَّى يُؤَخَّرَ فِي الْجَنَّةِ وَإِنْ دَخَلَهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; aku mendapati dalam kitabnya [ayahku] dengan tulisannya sendiri, namun aku belum pernah mendengar darinya, [Qatadah] mengatakan, dari [Yahya bin Malik] dari [Samurah bin Jundub] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Hadirilah peringatan (khutbah) dan mendekatlah kepada imam, karena seseorang yang selalu menjauh darinya hingga ia akan di akhirkan masuk surga, meskipun ia memasukinya.\""},"922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَنَّ زَيْدَ بْنَ حُبَابٍ حَدَّثَهُمْ حَدَّثَنَا حُسَيْنُ بْنُ وَاقِدٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ الْحَسَنُ وَالْحُسَيْنُ رَضِيَ اللَّهُ عَنْهُمَا عَلَيْهِمَا قَمِيصَانِ أَحْمَرَانِ يَعْثُرَانِ وَيَقُومَانِ فَنَزَلَ فَأَخَذَهُمَا فَصَعِدَ بِهِمَا الْمِنْبَرَ ثُمَّ قَالَ صَدَقَ اللَّهُ{ إِنَّمَا أَمْوَالُكُمْ وَأَوْلَادُكُمْ فِتْنَةٌ }رَأَيْتُ هَذَيْنِ فَلَمْ أَصْبِرْ ثُمَّ أَخَذَ فِي الْخُطْبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] bahwa [Zaid bin Al Hubab] telah menceritakan kepada mereka, katanya; telah menceritakan kepada kami [Husain bin Waqid] telah menceritakan kepadaku [Abdullah bin Buraidah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam tengah berkhutbah di tengah-tengah kami, tiba-tiba Hasan dan Husain radliallahu 'anhuma membawakan dua baju yang berwarna merah. Keduanya lalu terjatuh, Rasulullah shallallahu 'alaihi wasallam turun dari mimbar dan menggendong keduanya lalu kembali ke mimbar dengan bersabda: \"Maha benar Allah atas firman-Nya: 'Sesungguhnya hartamu dan anak-anakmu hanyalah sebagai cobaan'. (Qs. Al-Anfaal (8): 28). Aku melihat kedua anak ini terjatuh dalam kedua bajunya, maka aku tidak sabar hingga aku mempersingkat khutbahku.\""},"923":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ حَدَّثَنَا الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحُبْوَةِ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf] telah menceritakan kepada kami [Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari [Abu Marhum] dari [Sahl bin Mu'adz bin Anas] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang duduk bertekuk lutut ketika imam berkhutbah pada hari Jum'at.\""},"924":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا خَالِدُ بْنُ حَيَّانَ الرَّقِّيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ اللَّهِ بْنِ الزِّبْرِقَانِ عَنْ يَعْلَى بْنِ شَدَّادِ بْنِ أَوْسٍ قَالَشَهِدْتُ مَعَ مُعَاوِيَةَ بَيْتَ الْمَقْدِسِ فَجَمَّعَ بِنَا فَنَظَرْتُ فَإِذَا جُلُّ مَنْ فِي الْمَسْجِدِ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُهُمْ مُحْتَبِينَ وَالْإِمَامُ يَخْطُبُقَالَ أَبُو دَاوُد كَانَ ابْنُ عُمَرَ يَحْتَبِي وَالْإِمَامُ يَخْطُبُ وَأَنَسُ بْنُ مَالِكٍ وَشُرَيْحٌ وَصَعْصَعَةُ بْنُ صُوحَانَ وَسَعِيدُ بْنُ الْمُسَيَّبِ وَإِبْرَاهِيمُ النَّخَعِيُّ وَمَكْحُولٌ وَإِسْمَعِيلُ بْنُ مُحَمَّدِ بْنِ سَعْدٍ وَنُعَيْمُ بْنُ سَلَامَةَ قَالَ لَا بَأْسَ بِهَا قَالَ أَبُو دَاوُد وَلَمْ يَبْلُغْنِي أَنَّ أَحَدًا كَرِهَهَا إِلَّا عُبَادَةَ بْنَ نُسَيٍّ","id":"Telah menceritakan kepada kami [Daud bin Rusyaid] telah menceritakan kepada kami [Khalid bin Hayyan Ar Raqqi] telah menceritakan kepada kami [Sulaiman bin Abdullah bin Az Zibriqan] dari [Ya'la bin Syaddad bin Aus] dia berkata; \"Aku bersama Muawiyah menyaksikan penaklukan Baitul Maqdis, lalu dia melaksanakan shalat jum'at bersamanya, maka aku melihat kebanyakan jama'ah yang ada di masjid adalah para sahabat Nabi shallallahu 'alaihi wasallam, aku melihat mereka duduk bertekuk lutut ketika imam sedang berkhutbah.\" Abu Daud berkata; \" [Ibnu Umar] juga duduk bertekuk lutut sementara imam sedang berkhutbah, begitu juga [Anas bin Malik], Syuraih, Sha'sha'ah bin Shuhan, Sa'id bin Musayyab, Ibrahim An Nakha'i, Makhul, Isma'il bin Muhammad bin Sa'd dan Nu'aim bin Salamah, katanya; \"Tidak mengapa duduk seperti itu.\" Abu Daud berkata; \"Belum sampai kepadaku, bahwa ada seseorang yang membencinya kecuali 'Ubadah bin Nusai.\""},"925":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ أَنْصِتْ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu berkata; \"Diamlah\" padahal imam tengah berkhutbah, maka (jum'atmu) telah sia-sia.\""},"926":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا يَزِيدُ عَنْ حَبِيبٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَحْضُرُ الْجُمُعَةَ ثَلَاثَةُ نَفَرٍ رَجُلٌ حَضَرَهَا يَلْغُو وَهُوَ حَظُّهُ مِنْهَا وَرَجُلٌ حَضَرَهَا يَدْعُو فَهُوَ رَجُلٌ دَعَا اللَّهَ عَزَّ وَجَلَّ إِنْ شَاءَ أَعْطَاهُ وَإِنْ شَاءَ مَنَعَهُ وَرَجُلٌ حَضَرَهَا بِإِنْصَاتٍ وَسُكُوتٍ وَلَمْ يَتَخَطَّ رَقَبَةَ مُسْلِمٍ وَلَمْ يُؤْذِ أَحَدًا فَهِيَ كَفَّارَةٌ إِلَى الْجُمُعَةِ الَّتِي تَلِيهَا وَزِيَادَةِ ثَلَاثَةِ أَيَّامٍ وَذَلِكَ بِأَنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ{ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا }","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Yazid] dari [Habib Al Mu'allim] dari ['Amru bin Syu'aib] dari [ayahnya] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ada tiga golongan seseorang dalam menghadiri shalat Jum'at, yaitu; seseorang menghadiri shalat Jum'at sambil bicara, maka bicaranya itulah yang menjadi bagiannya, seseorang yang menghadiri shalat jum'at sambil memanjatkan do'a maka itulah orang yang benar-benar memanjatkan do'a kepada Allah 'azza wajalla, Kalau Dia menghendaki, maka akan di kabulkan atau jika Dia menghendaki maka Dia akan menahannya. Dan orang yang menghadiri shalat Jum'at dengan sikap diam dan tenang, tidak melangkahi pundak orang lain dan tidak pula menyakiti seorang pun, maka jum'atnya menjadi penebus dosanya hingga jum'at berikutnya, di tambah tiga hari, yang demikian itu karena Allah 'azza wajalla berfirman: \"Barangsiapa melakukan amal kebaikan, maka baginya sepuluh kali lipat.\" QS Al An'am; 160. "},"927":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحْدَثَ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَأْخُذْ بِأَنْفِهِ ثُمَّ لِيَنْصَرِفْقَالَ أَبُو دَاوُد رَوَاهُ حَمَّادُ بْنُ سَلَمَةَ وَأَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَذْكُرَا عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Hasan Al Mishishi] telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Hisyam bin 'Urwah] dari ['Urwah] dari ['Aisyah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian berhadats dalam shalatnya, hendaknya ia memegang hidungnya lalu keluar.\" Abu Daud berkata; \"(hadits ini) juga di riwayatkan oleh [Hammad bin Salamah] dan [Abu Usamah] dari [Hisyam] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, namun keduanya (Hammad dan Abu Usamah) tidak menyebutkan \"Aisyah radliallahu 'anha.\""},"928":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو وَهُوَ ابْنُ دِينَارٍ عَنْ جَابِرٍأَنَّ رَجُلًا جَاءَ يَوْمَ الْجُمُعَةِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَصَلَّيْتَ يَا فُلَانُ قَالَ لَا قَالَ قُمْ فَارْكَعْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari ['Amru yaitu Ibnu Dinar] dari [Jabir] bahwa seorang laki-laki datang pada hari jum'at, sementara Nabi shallallahu 'alaihi wasallam sedang berkhutbah, lalu beliau bersabda: \"Apakah kamu sudah shalat (sunnah) wahai fulan?\" jawabnya; \"Belum.\" Beliau bersabda: \"Berdiri dan kerjakanlah shalat (sunnah).\""},"929":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ وَإِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَا حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ وَعَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَاجَاءَ سُلَيْكٌ الْغَطَفَانِيُّ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ لَهُ أَصَلَّيْتَ شَيْئًا قَالَ لَا قَالَ صَلِّ رَكْعَتَيْنِ تَجَوَّزْ فِيهِمَاحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ سَعِيدٍ عَنْ الْوَلِيدِ أَبِي بِشْرٍ عَنْ طَلْحَةَ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ أَنَّ سُلَيْكًا جَاءَ فَذَكَرَ نَحْوَهُ زَادَ ثُمَّ أَقْبَلَ عَلَى النَّاسِ قَالَ إِذَا جَاءَ أَحَدُكُمْ وَالْإِمَامُ يَخْطُبُ فَلْيُصَلِّ رَكْعَتَيْنِ يَتَجَوَّزْ فِيهِمَا","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] dan [Isma'il bin Ibrahim] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dan [Abu Shalih] dari [Abu Hurairah] katanya; \"Sulaik Al Ghathafani datang, sedangkan Rasulullah shallallahu 'alaihi wasallam tengah berkhutbah, maka beliau bersabda kepadanya; \"Apakah kamu sudah shalat (sunnah)?\" jawabnya; \"Belum.\" Beliau bersabda: \"Shalatlah dua raka'at yang ringan.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Sa'id] dari [Al Walid Abu Bisyr] dari [Thalhah] bahwa dia mendengar [Jabir bin Abdullah] bercerita bahwa Sulaik datang…\" kemudian dia menyebutkan hadits semisalnya, ia menambahkan; \"Kemudian beliau menghadap kepada orang-orang sambil bersabda: \"Apabila salah seorang dari kalian datang, sedangkan imam tengah berkhutbah, hendaknya ia shalat dua raka'at yang ringan.\""},"930":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ قَالَكُنَّا مَعَ عَبْدِ اللَّهِ بْنِ بُسْرٍ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ فَجَاءَ رَجُلٌ يَتَخَطَّى رِقَابَ النَّاسِ فَقَالَ عَبْدُ اللَّهِ بْنُ بُسْرٍ جَاءَ رَجُلٌ يَتَخَطَّى رِقَابَ النَّاسِ يَوْمَ الْجُمُعَةِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ فَقَدْ آذَيْتَ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakan kepada kami [Bisyr bin As Sarri] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyah] dia berkata; \"Kami bersama Abdullah bin Busr -salah seorang sahabat Nabi shallallahu 'alaihi wasallam- pada hari Jum'ah, tiba-tiba seorang laki-laki datang melangkahi pundak orang-orang, maka [Abdullah bin Busr] berkata; \"Pernah datang seseorang dengan melangkahi pundak orang-orang pada hari jum'at, sedangkan Nabi shallallahu 'alaihi wasallam tengah berkhutbah, maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Duduklah, kamu benar-benar telah mengganggu (orang lain).\""},"931":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدَةَ عَنْ ابْنِ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا نَعَسَ أَحَدُكُمْ وَهُوَ فِي الْمَسْجِدِ فَلْيَتَحَوَّلْ مِنْ مَجْلِسِهِ ذَلِكَ إِلَى غَيْرِهِ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] dari ['Abdah] dari [Ibnu Ishaq] dari [Nafi'] dari [Ibnu Umar] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang mengantuk di dalam masjid(ketika khutbah Jum'at), hendaknya ia pindah tempat duduk ke tempat duduk yang lain.\""},"932":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ عَنْ جَرِيرٍ هُوَ ابْنُ حَازِمٍ لَا أَدْرِي كَيْفَ قَالَهُ مُسْلِمٌ أَوْ لَا عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْزِلُ مِنْ الْمِنْبَرِ فَيَعْرِضُ لَهُ الرَّجُلُ فِي الْحَاجَةِ فَيَقُومُ مَعَهُ حَتَّى يَقْضِيَ حَاجَتَهُ ثُمَّ يَقُومُ فَيُصَلِّيقَالَ أَبُو دَاوُد الْحَدِيثُ لَيْسَ بِمَعْرُوفٍ عَنْ ثَابِتٍ هُوَ مِمَّا تَفَرَّدَ بِهِ جَرِيرُ بْنُ حَازِمٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] dari [Jarir yaitu Ibnu Hazim] aku tidak tahu bagaimana yang di katakan Muslim, kalau bukan dari [Tsabit] dari [Anas] dia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam turun dari mimbar, tiba-tiba seseorang muncul dan hendak menyampaikan kebutuhannya kepada beliau, lantas orang tersebut berdiri bersama beliau hingga hajatnya selesai, setelah itu beliau berdiri dan mengerjakan shalat.\" Abu Daud berkata; \"Hadits ini tidak di kenal dari Tsabit, akan tetapi ia merupakan riwayatnya Jarir bin Hazim secara terpisah (sendiri).\""},"933":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ رَكْعَةً مِنْ الصَّلَاةِ فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapat satu raka'at dalam shalat, berarti ia telah mendapatkan shalat itu.\""},"934":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْعِيدَيْنِ وَيَوْمِ الْجُمُعَةِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ قَالَ وَرُبَّمَا اجْتَمَعَا فِي يَوْمٍ وَاحِدٍ فَقَرَأَ بِهِمَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [ayahnya] dari [Habib bin Salim] dari [Nu'man bin Basyir] bahwa dalam shalat hari raya dan shalat Jum'at, Rasulullah shallallahu 'alaihi wasallam biasa membaca dengan: \"Sabbihisma rabbikal a'la dan Hal ataaka hadiitsul ghaatsiyah.\" Kata Nu'man; \"Apabila (hari raya dengan shalat jum'at) bertepatan dalam satu hari, maka beliau juga membaca kedua surat tersebut.\""},"935":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍ مَاذَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ فَقَالَ كَانَ يَقْرَأُ بِهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa Dlahhak bin Qais bertanya kepada [Nu'man bin Basyir]; \"Surat apakah yang biasa di baca Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at setelah surat Al Jum'ah?\" dia menjawab; \"Beliau biasa membaca dengan; \"Hal ataaka hadiitsul Ghaasyiyah.\""},"936":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي رَافِعٍ قَالَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ وَفِي الرَّكْعَةِ الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ يَقْرَأُ بِهِمَا بِالْكُوفَةِ قَالَ أَبُو هُرَيْرَةَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Bilal] dari [Ja'far] dari [ayahnya] dari [Ibnu Abu Rafi'] dia berkata; Abu Hurairah shalat mangimami kami pada hari (shalat) Jum'at, lalu dia membaca surat Al Jumuah pada raka'at pertama dan \"idza jaa-akal munafiqun\" pada raka'at terakhir. Selesai shalat, aku menjumpai Abu Hurairah dan berkata kepadanya; \"Sesungguhnya anda membaca surat sebagaimana yang dibaca oleh Ali bin Abu Thalib di Kufah.\" [Abu Hurairah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca kedua surat tersebut pada shalat Jum'at.\""},"937":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ شُعْبَةَ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ زَيْدِ بْنِ عُقْبَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya bin Sa'id] dari [Syu'bah] dari [Ma'bad bin Khalid] dari [Zaid bin 'Uqbah] dari [Samurah bin Jundub] bahwa pada waktu shalat Jum'at, Rasulullah shallallahu 'alaihi wasallam membaca \"Sabbihisma Rabbikal-a'la\" dan\"Hal ataaka haditsul ghasyiyah.\""},"938":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حُجْرَتِهِ وَالنَّاسُ يَأْتَمُّونَ بِهِ مِنْ وَرَاءِ الْحُجْرَةِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepadaku [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah radliallahu 'anha] dia berkata; Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat di kamarnya, ternyata orang-orang mengikuti beliau dari belakang kamarnya.\""},"939":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ وَسُلَيْمَانُ بْنُ دَاوُدَ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَرَأَى رَجُلًا يُصَلِّي رَكْعَتَيْنِ يَوْمَ الْجُمُعَةِ فِي مَقَامِهِ فَدَفَعَهُ وَقَالَ أَتُصَلِّي الْجُمُعَةَ أَرْبَعًا وَكَانَ عَبْدُ اللَّهِ يُصَلِّي يَوْمَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ وَيَقُولُ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] dan [Sulaiman bin Daud] sedangkan maksud haditsnya sama, keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] melihat seseorang laki-laki shalat dua raka'at di tempat (shalat) nya, maka Ibnu Umar mendorongnya sambil berkata; \"Apakah kamu hendak shalat Jum'at empat raka'at? Abdullah biasa mengerjakan shalat Jum'at (sunnah ba'da Jum'at) dua raka'at di rumahnya, lalu dia berkata; \"Demikianlah yang pernah di lakukan Rasulullah shallallahu 'alaihi wasallam.\""},"940":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ قَالَكَانَ ابْنُ عُمَرَ يُطِيلُ الصَّلَاةَ قَبْلَ الْجُمُعَةِ وَيُصَلِّي بَعْدَهَا رَكْعَتَيْنِ فِي بَيْتِهِ وَيُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] dia berkata; \" [Ibnu Umar] biasa memanjangkan shalatnya sebelum (shalat) Jum'at, dan shalat (sunnah) setelahnya dua raka'at di rumahnya, dia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam juga melakukan yang demikian itu.\""},"941":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءِ بْنِ أَبِي الْخُوَارِأَنَّ نَافِعَ بْنَ جُبَيْرٍ أَرْسَلَهُ إِلَى السَّائِبِ بْنِ يَزِيدَ ابْنَ أُخْتِ نَمِرٍ يَسْأَلُهُ عَنْ شَيْءٍ رَأَى مِنْهُ مُعَاوِيَةُ فِي الصَّلَاةِ فَقَالَ صَلَّيْتُ مَعَهُ الْجُمُعَةَ فِي الْمَقْصُورَةِ فَلَمَّا سَلَّمْتُ قُمْتُ فِي مَقَامِي فَصَلَّيْتُ فَلَمَّا دَخَلَ أَرْسَلَ إِلَيَّ فَقَالَ لَا تَعُدْ لِمَا صَنَعْتَ إِذَا صَلَّيْتَ الْجُمُعَةَ فَلَا تَصِلْهَا بِصَلَاةٍ حَتَّى تَكَلَّمَ أَوْ تَخْرُجَ فَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِذَلِكَ أَنْ لَا تُوصَلَ صَلَاةٌ بِصَلَاةٍ حَتَّى يَتَكَلَّمَ أَوْ يَخْرُجَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Umar bin 'Atha` bin Abu Al Khuwwar] bahwa Nafi' bin Jubair mengutusnya untuk menemui [As Sa`ib bin Yazid Ibnu Ukhti Namir], dan menanyakan sesuatu yang pernah di lihat Mu'awiyah dalam shalat, dia menjawab; \"Aku pernah mengerjakan shalat Jum'at bersama dia di dalam kamar (dalam masjid), seusai salam, aku langsung berdiri di tempat (shalat Jum'at), lalu aku shalat, sewaktu Mu'awiyah masuk menemuiku, dia berkata; \"jangan kamu ulangi lagi apa yang kamu lakukan itu, apabila kamu selesai shalat jum'at, maka janganlah kamu menyambung shalatmu dengan shalat lain hingga kamu berbicara atau keluar, sesungguhnya Nabi Allah shallallahu 'alaihi wasallam memerintahkan yang demikian itu, yaitu; janganlah kamu menyambung (shalat Jum'at) dengan shalat yang lain sehingga ia (selingi) dengan bicara atau keluar.\""},"942":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ الْمَرْوَزِيُّ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ إِذَا كَانَ بِمَكَّةَ فَصَلَّى الْجُمُعَةَ تَقَدَّمَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ تَقَدَّمَ فَصَلَّى أَرْبَعًا وَإِذَا كَانَ بِالْمَدِينَةِ صَلَّى الْجُمُعَةَ ثُمَّ رَجَعَ إِلَى بَيْتِهِ فَصَلَّى رَكْعَتَيْنِ وَلَمْ يُصَلِّ فِي الْمَسْجِدِ فَقِيلَ لَهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah Al Marwazi] telah mengabarkan kepada kami [Al Fadl bin Musa] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] dari ['Atha`] dari [Ibnu Umar] dia berkata; Apabila di Makkah, dia mengerjakan shalat Jum'at, lalu maju kemudian dia mengerjakan shalat (sunnah) dua raka'at, sesudah itu beliau maju kembali dan mengerjakan shalat empat raka'at, apabila di Madinah, dia shalat Jum'at kemudian pulang ke rumahnya lalu shalat dua raka'at, dan tidak shalat di Masjid, lalu di beritahukan kepadanya, maka dia menjawab; \"Rasulullah shallallahu 'alaihi wasallam juga melakukan hal itu.\""},"943":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ الصَّبَّاحِ قَالَ مَنْ كَانَ مُصَلِّيًا بَعْدَ الْجُمُعَةِ فَلْيُصَلِّ أَرْبَعًا وَتَمَّ حَدِيثُهُ وَقَالَ ابْنُ يُونُسَ إِذَا صَلَّيْتُمْ الْجُمُعَةَ فَصَلُّوا بَعْدَهَا أَرْبَعًاقَالَ فَقَالَ لِي أَبِي يَا بُنَيَّ فَإِنْ صَلَّيْتَ فِي الْمَسْجِدِ رَكْعَتَيْنِ ثُمَّ أَتَيْتَ الْمَنْزِلَ أَوْ الْبَيْتَ فَصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair], dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin As Shabah Al Bazzaz] telah menceritakan kepada kami [Isma'il bin Zakariya] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: …-Ibnu Shabah mengatakan, beliau bersabda; \"Barangsiapa hendak shalat selepas (shalat) Jum'at, hendaknya ia shalat empat raka'at.\" haditsnya (selesai) sampai di sini, Ibnu Yunus mengatakan; \"Apabila kalian shalat Jum'at, maka shalatlah setelahnya empat raka'at.\" Suhal berkata; \"ayahku pernah berkata kepadaku; \"Wahai anakku, apabila kamu telah shalat dua raka'at di masjid, maka setibanya di rumah, shalatlah dua raka'at.\""},"944":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa mengerjakan shalat dua raka'at setelah jum'at di rumahnya.\" Abu Daud berkata; \"Demikianlah yang di riwayatkan [Abdullah bin Dinar] dari [Ibnu Umar]. "},"945":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌأَنَّهُ رَأَى ابْنَ عُمَرَ يُصَلِّي بَعْدَ الْجُمُعَةِ فَيَنْمَازُ عَنْ مُصَلَّاهُ الَّذِي صَلَّى فِيهِ الْجُمُعَةَ قَلِيلًا غَيْرَ كَثِيرٍ قَالَ فَيَرْكَعُ رَكْعَتَيْنِ قَالَ ثُمَّ يَمْشِي أَنْفَسَ مِنْ ذَلِكَ فَيَرْكَعُ أَرْبَعَ رَكَعَاتٍ قُلْتُ لِعَطَاءٍ كَمْ رَأَيْتَ ابْنَ عُمَرَ يَصْنَعُ ذَلِكَ قَالَ مِرَارًاقَالَ أَبُو دَاوُد وَرَوَاهُ عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ وَلَمْ يُتِمَّهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Hasan] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Atha`] bahwa dia melihat [Ibnu Umar] mengerjakan shalat setelah (shalat) Jum'at, lalu dia bergeser sedikit dari tempat ia mengerjakan shalat Jum'at.\" 'Atha` berkata; \"Kemudian ia shalat dua raka'at.\" 'Atha` melanjutkan; \"Setelah itu Ibnu Umar berjalan sedikit dari tempat tersebut dan mengerjakan shalat empat raka'at.\" Tanyaku kepada 'Atha`; \"Berapa kalikah anda melihat Ibnu Umar melakukan hal itu?\" 'Atha` menjawab; \"Sering.\" Abu Daud mengatakan; \"Di riwayatkan pula oleh [Abdul Malik bin Abu Sulaiman], namun tidak selangka hadits di atas.\""},"946":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَلَهُمْ يَوْمَانِ يَلْعَبُونَ فِيهِمَا فَقَالَ مَا هَذَانِ الْيَوْمَانِ قَالُوا كُنَّا نَلْعَبُ فِيهِمَا فِي الْجَاهِلِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ قَدْ أَبْدَلَكُمْ بِهِمَا خَيْرًا مِنْهُمَا يَوْمَ الْأَضْحَى وَيَوْمَ الْفِطْرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Anas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, sedangkan penduduknya memiliki dua hari khusus untuk permainan, maka beliau bersabda: \"Apakah maksud dari dua hari ini?\" mereka menjawab; \"Kami biasa mengadakan permainan pada dua hari tersebut semasa masih Jahiliyah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya Allah telah menggantikan untuk kalian yang lebih baik dari kedua hari tersebut, yaitu hari (raya) kurban (iedul Aldha) dan hari raya Iedul fithri.\""},"947":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنَا يَزِيدُ بْنُ خُمَيْرٍ الرَّحَبِيُّ قَالَخَرَجَ عَبْدُ اللَّهِ بْنُ بُسْرٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ النَّاسِ فِي يَوْمِ عِيدِ فِطْرٍ أَوْ أَضْحَى فَأَنْكَرَ إِبْطَاءَ الْإِمَامِ فَقَالَ إِنَّا كُنَّا قَدْ فَرَغْنَا سَاعَتَنَا هَذِهِ وَذَلِكَ حِينَ التَّسْبِيحِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shufwan] telah menceritakan kepada kami [Yazid bin Khumair Ar Rahabi] dia berkata; [Abdullah bin Busr] -salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam- keluar untuk melaksanakan shalat Iedul Fithri atau Iedul Adha bersama orang-orang, dia tidak membenarkan keterlambatan imam, lalu berkata; \"Sesungguhnya kami dahulu pada saat seperti ini telah selesai melaksanakan shalat.\" waktu itu adalah waktu Dhuha.\""},"948":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَيُونُسَ وَحَبِيبٍ وَيَحْيَى بْنِ عَتِيقٍ وَهِشَامٍ فِي آخَرِينَ عَنْ مُحَمَّدٍ أَنَّ أُمَّ عَطِيَّةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُخْرِجَ ذَوَاتِ الْخُدُورِ يَوْمَ الْعِيدِ قِيلَ فَالْحُيَّضُ قَالَ لِيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ قَالَ فَقَالَتْ امْرَأَةٌ يَا رَسُولَ اللَّهِ إِنْ لَمْ يَكُنْ لِإِحْدَاهُنَّ ثَوْبٌ كَيْفَ تَصْنَعُ قَالَ تُلْبِسُهَا صَاحِبَتُهَا طَائِفَةً مِنْ ثَوْبِهَاحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيَّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ بِهَذَا الْخَبَرِ قَالَ وَيَعْتَزِلُ الْحُيَّضُ مُصَلَّى الْمُسْلِمِينَ وَلَمْ يَذْكُرْ الثَّوْبَ قَالَ وَحَدَّثَ عَنْ حَفْصَةَ عَنْ امْرَأَةٍ تُحَدِّثُهُ عَنْ امْرَأَةٍ أُخْرَى قَالَتْ قِيلَ يَا رَسُولَ اللَّهِ فَذَكَرَ مَعْنَى حَدِيثِ مُوسَى فِي الثَّوْبِ حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ كُنَّا نُؤْمَرُ بِهَذَا الْخَبَرِ قَالَتْ وَالْحُيَّضُ يَكُنَّ خَلْفَ النَّاسِ فَيُكَبِّرْنَ مَعَ النَّاسِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Ayyub], [Yunus], [Habib], [Yahya bin 'Atiq] dan [Hisyam] di riwayat yang lain, dari [Muhammad] bahwa [Ummu 'Athiyah] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya menyuruh keluar para wanita yang terpingit dalam rumah untuk keluar pada hari raya Ied, lalu di tanyakan; \"Bagaimana dengan wanita haid?\" beliau bersabda; \"Hendaknya ia menyaksikan kebaikan pada hari itu dan juga do'a dari kaum Muslimin.\" Perawi berkata; Seorang wanita bertanya; \"Wahai Rasulullah, bagaimana kalau sekiranya salah seorang dari wanita tidak memiliki pakaian, apa yang harus ia lakukan?\" beliau menjawab: \"Hendaknya saudaranya meminjami sebagian dari pakaiannya.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyah] seperti hadits ini, katanya; \"Hendaklah wanita haidh agak menjauh dari tempat shalat kaum Muslimin…\" tanpa menyebutkan; \"…pakaian…\" Perawi berkata; dan telah bercerita dari [Hafshah] dari [seorang wanita] menceritakan dari [seorang wanita lain] dia berkata; \"…di beritahukan; \"Wahai Rasulullah…\" lalu dia menyebutkan semakna dengan hadits Musa tentang \"pakaian.\" Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah] dia berkata; \"Kami di perintah …\" seperti hadits ini, katanya; \"Hendaknya wanita-wanita hendaknya berada di belakang orang-orang dan bertakbir bersama mereka.\""},"949":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ يَعْنِي الطَّيَالِسِيَّ وَمُسْلِمٌ قَالَا حَدَّثَنَا إِسْحَقُ بْنُ عُثْمَانَ حَدَّثَنِي إِسْمَعِيلُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَطِيَّةَ عَنْ جَدَّتِهِ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ الْمَدِينَةَ جَمَعَ نِسَاءَ الْأَنْصَارِ فِي بَيْتٍ فَأَرْسَلَ إِلَيْنَا عُمَرَ بْنَ الْخَطَّابِ فَقَامَ عَلَى الْبَابِ فَسَلَّمَ عَلَيْنَا فَرَدَدْنَا عَلَيْهِ السَّلَامَ ثُمَّ قَالَ أَنَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكُنَّ وَأَمَرَنَا بِالْعِيدَيْنِ أَنْ نُخْرِجَ فِيهِمَا الْحُيَّضَ وَالْعُتَّقَ وَلَا جُمُعَةَ عَلَيْنَا وَنَهَانَا عَنْ اتِّبَاعِ الْجَنَائِزِ","id":"Telah menceritakan kepada kami [Abu Al Walid yaitu Ath Thayalisi] dan [Muslim] keduanya berkata; telah menceritakan kepada kami [Ishaq bin 'Utsman] telah menceritakan kepadaku [Isma'il bin Abdurrahman bin 'Athiyah] dari [neneknya yaitu Ummu 'Athiyah] bahwa ketika Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, beliau mengumpulkan para wanita Anshar di suatu rumah, beliau mengutus Umar bin Khattab untuk menemui kami, lalu Umar berdiri di depan pintu, dia memberi salam kepada kami dan kami pun menjawab salamnya, lalu dia berkata; \"Aku adalah utusan Rasulullah shallallahu 'alaihi wasallam kepada kalian, beliau memerintahkan kami untuk menyuruh keluar wanita haidh dan para hamba sahaya pada dua hari raya, tidak mewajibkan shalat jum'at atas kami dan beliau melarang kami ikut mengantar jenazah.\""},"950":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ ح وَعَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَخْرَجَ مَرْوَانُ الْمِنْبَرَ فِي يَوْمِ عِيدٍ فَبَدَأَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ فَقَامَ رَجُلٌ فَقَالَ يَا مَرْوَانُ خَالَفْتَ السُّنَّةَ أَخْرَجْتَ الْمِنْبَرَ فِي يَوْمِ عِيدٍ وَلَمْ يَكُنْ يُخْرَجُ فِيهِ وَبَدَأْتَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ فَقَالَ أَبُو سَعِيدٍ الْخُدْرِيِّ مَنْ هَذَا قَالُوا فُلَانُ بْنُ فُلَانٍ فَقَالَ أَمَّا هَذَا فَقَدْ قَضَى مَا عَلَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مُنْكَرًا فَاسْتَطَاعَ أَنْ يُغَيِّرَهُ بِيَدِهِ فَلْيُغَيِّرْهُ بِيَدِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Isma'il bin Raja`] dari [ayahnya] dari [Abu Sa'id Al Khudri]. Dan telah di riwayatkan dari jalur lain, dan dari [Qais bin Muslim] dari [Thariq bin Syihab] dari [Abu Sa'id Al Khudri] dia berkata; \"Marwan pernah mengeluarkan mimbar pada waktu hari raya, lalu dia mulai khutbah sebelum shalat, maka seorang laki-laki berdiri dan berkata; \"Wahai Marwan, kamu telah menyelisihi sunnah, kamu telah mengeluarkan mimbar pada hari raya, padahal mimbar belum pernah sama sekali di keluarkan, dan kamu juga memulai khutbah sebelum shalat.\" Abu Sa'id Al Khudri berkata; \"Siapakah laki-laki ini?\" mereka menjawab; \"Fulan bin fulan.\" Abu Sa'id berkata; \"Orang ini telah melaksanakan kewajibannya ('Amar ma'ruf dan nahi munkar), aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihat kemungkaran, hendaklah semampunya ia merubah dengan tangannya, jika tidak mampu, maka dengan lisannya, dan jika tidak mampu, maka dengan hatinya, dan yang demikian itu adalah selemah-lemah iman.\""},"951":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُهُ يَقُولُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَ الْفِطْرِ فَصَلَّى فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ النَّاسَ فَلَمَّا فَرَغَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ فَأَتَى النِّسَاءَ فَذَكَّرَهُنَّ وَهُوَ يَتَوَكَّأُ عَلَى يَدِ بِلَالٍ وَبِلَالٌ بَاسِطٌ ثَوْبَهُ تُلْقِي فِيهِ النِّسَاءُ الصَّدَقَةَ قَالَ تُلْقِي الْمَرْأَةُ فَتَخَهَا وَيُلْقِينَ وَيُلْقِينَ وَقَالَ ابْنُ بَكْرٍ فَتَخَتَهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazaq] dan [Muhammad bin Bakr] keduanya berkata; telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku ['Atha`] dari [Jabir bin Abdullah] dia berkata; -saya mendengar dia (Jabir) berkata- sesungguhnya Nabi shallallahu 'alaihi wasallam berdiri pada hari raya fithri, lalu beliau mengerjakan shalat, beliau memulai shalat sebelum berkhutbah, setelah itu barulah beliau berkhutbah di hadapan manusia. Tatkala Nabi Allah shallallahu 'alaihi wasallam selesai khutbah, beliau turun lalu mendatangi kaum wanita, beliau memberi peringatan kepada mereka sambil bersandar kepada tangan Bilal, sedangkan Bilal sendiri membentangkan secarik kain sebagai tempat sedekah yang di sumbangkan oleh kaum perempuan.\" Kata Jabir; \"Ada seorang wanita yang melepas cincinnya dan melemparnya ke (kain tersebut), kemudian mereka bergantian melepaskan perhiasannya.\""},"952":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا ابْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ عَطَاءٍ قَالَأَشْهَدُ عَلَى ابْنِ عَبَّاسٍ وَشَهِدَ ابْنُ عَبَّاسٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَرَجَ يَوْمَ فِطْرٍ فَصَلَّى ثُمَّ خَطَبَ ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ قَالَ ابْنُ كَثِيرٍ أَكْبَرُ عِلْمِ شُعْبَةَ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلْنَ يُلْقِينَحَدَّثَنَا مُسَدَّدٌ وَأَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ بِمَعْنَاهُ قَالَ فَظَنَّ أَنَّهُ لَمْ يُسْمِعْ النِّسَاءَ فَمَشَى إِلَيْهِنَّ وَبِلَالٌ مَعَهُ فَوَعَظَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ فَكَانَتْ الْمَرْأَةُ تُلْقِي الْقُرْطَ وَالْخَاتَمَ فِي ثَوْبِ بِلَالٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذَا الْحَدِيثِ قَالَ فَجَعَلَتْ الْمَرْأَةُ تُعْطِي الْقُرْطَ وَالْخَاتَمَ وَجَعَلَ بِلَالٌ يَجْعَلُهُ فِي كِسَائِهِ قَالَ فَقَسَمَهُ عَلَى فُقَرَاءِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ibnu Katsir] telah mengabarkan kepada kami [Syu'bah] dari [Ayyub] dari ['Atha`] dia berkata; aku menyaksikan [Ibnu Abbas], dan Ibnu Abbas menyaksikan Rasulullah shallallahu 'alaihi wasallam, bahwa beliau keluar pada hari raya Iedul Fithri, kemudian beliau shalat dan berkhutbah, setelah itu beliau bersama Bilal mendatangi kaum wanita -Ibnu Katsir mengatakan; Syu'bah adalah orang yang banyak ilmunya, (berkatanya) - lantas beliau menyuruh mereka bersedekah, maka mereka melepaskan perhiasannya.\" Telah menceritakan kepada kami [Musaddad] dan [Abu Ma'mar Abdullah bin 'Amru] keduanya berkata; telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari ['Atha`] dari [Ibnu Abbas] dengan maksud yang sama, katanya; \"Beliau mengira kalau para wanita tidak mendengar khutbahnya, maka beliau bersama Bilal menemui mereka dan menasehati mereka serta menyuruh mereka supaya memperbanyak sedekah. Maka ada seorang wanita yang melepas anting dan cincinnya ke kain Bilal.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Atha`] dari [Ibnu Abbas] mengenai hadits ini, katanya; \"Lantas ada seorang wanita yang melepas anting dan cincinnya, lalu Bilal menaruh di kainnya.\" Jabir melanjutkan; \"Setelah itu, beliau membagi-bagi hasil sedekahnya kepada orang-orang miskin dari kalangan kaum Muslimin.\""},"953":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ أَبِي جَنَابٍ عَنْ يَزِيدَ بْنِ الْبَرَاءِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُووِلَ يَوْمَ الْعِيدِ قَوْسًا فَخَطَبَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ibnu Uyainah] dari [Abu Jaban] dari [Yazid bin Bara'] dari [ayahnya] bahwasanya Nabi Shallallahu'alaihiwasallam diberikan sebuah busur pada waktu shalat Ied dan beliau berkhutbah diatasnya. "},"954":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ قَالَسَأَلَ رَجُلٌ ابْنَ عَبَّاسٍ أَشَهِدْتَ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا مَنْزِلَتِي مِنْهُ مَا شَهِدْتُهُ مِنْ الصِّغَرِ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَلَمَ الَّذِي عِنْدَ دَارِ كَثِيرِ ب��نِ الصَّلْتِ فَصَلَّى ثُمَّ خَطَبَ وَلَمْ يَذْكُرْ أَذَانًا وَلَا إِقَامَةً قَالَ ثُمَّ أَمَرَنَا بِالصَّدَقَةِ قَالَ فَجَعَلَ النِّسَاءُ يُشِرْنَ إِلَى آذَانِهِنَّ وَحُلُوقِهِنَّ قَالَ فَأَمَرَ بِلَالًا فَأَتَاهُنَّ ثُمَّ رَجَعَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abdurrahman bin 'Abis] dia berkata; seorang laki-laki bertanya kepada [Ibnu Abbas]; \"Apakah kamu pernah menyaksikan hari raya bersama Rasulullah shallallahu 'alaihi wasallam?\" jawabnya; \"Ya, sekiranya tidak karena kedudukanku di sisi beliau, niscaya aku tidak akan menyaksikan sejak kecil. Rasulullah shallallahu 'alaihi wasallam mendekati bendera yang mendatangi bendera yang berada di rumah Katsir bin Ash-Shalt, lalu beliau mengerjakan shalat kemudian menyampaikan khutbah. -tanpa menyebutkan adzan dan iqamah- Ibnu Abbas berkata; setelah itu beliau memerintahkan kami untuk bersedekah.\" Kata ibnu Abbas melanjutkan; \"Maka para wanita menunjuk ke telinga dan leher mereka (melepas anting dan kalung mereka -pent), \" Kata Ibnu Abbas; \"Beliau menyuruh Bilal mendatangi mereka (untuk mengambil hasil sedekah), lantas Bilal menyerahkan kepada Nabi shallallahu 'alaihi wasallam.\""},"955":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْعِيدَ بِلَا أَذَانٍ وَلَا إِقَامَةٍ وَأَبَا بَكْرٍ وَعُمَرَ أَوْ عُثْمَانَ شَكَّ يَحْيَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dari [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat Ied tanpa di iringi dengan adzan dan iqamah, begitu juga Abu Bakar dan Umar atau Utsman -Yahya ragu dalam redaksi haditsnya-.\""},"956":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَنَّادٌ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ يَعْنِي ابْنَ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ الْعِيدَيْنِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] dan [Hannan], keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak yaitu Ibnu Harb] dari [Jabir bin Samurah] berkata; aku shalat ied bersama Nabi shallallahu 'alaihi wasallam tidak hanya satu kali dan tidak pula dua kali, tanpa ada adzan dan iqomat. "},"957":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَبِّرُ فِي الْفِطْرِ وَالْأَضْحَى فِي الْأُولَى سَبْعَ تَكْبِيرَاتٍ وَفِي الثَّانِيَةِ خَمْسًاحَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ سِوَى تَكْبِيرَتَيْ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam shalat Iedul Fithri dan Adha dan biasa takbir tujuh kali pada raka'at pertama dan lima kali pada raka'at kedua.\" telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Khalid bin Yazid] dari [Ibnu Syihab] dengan sanad dan maksud yang sama, katanya; \"Selain takbir untuk ruku'.\""},"958":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ الطَّائِفِيَّ يُحَدِّثُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّكْبِيرُ فِي الْفِطْرِ سَبْعٌ فِي الْأُولَى وَخَمْسٌ فِي الْآخِرَةِ وَالْقِرَاءَةُ بَعْدَهُمَا كِلْتَيْهِمَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Al Mu'tamir] dia berkata; aku mendengar [Abdullah bin Abdurrahman Ath Thaifi] menceritakan dari [Amru bin Syu'aib] dari [ayahnya] dari [Abdullah bin Amr bin Ash] berkata Nabi Shallallahu'alaihiwasallam bersabda: takbir pada waktu shalat Iedul fithri tujuh kali pada rakaat pertama dan lima pada rakaat terakhir dan bacaan AlQur'an setelah itu semua. "},"959":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ حَيَّانَ عَنْ أَبِي يَعْلَى الطَّائِفِيِّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَبِّرُ فِي الْفِطْرِ الْأُولَى سَبْعًا ثُمَّ يَقْرَأُ ثُمَّ يُكَبِّرُ ثُمَّ يَقُومُ فَيُكَبِّرُ أَرْبَعًا ثُمَّ يَقْرَأُ ثُمَّ يَرْكَعُقَالَ أَبُو دَاوُد رَوَاهُ وَكِيعٌ وَابْنُ الْمُبَارَكِ قَالَا سَبْعًا وَخَمْسًا","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Hayyan] dari [Abu Ya'la Ath Tha`ifi] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam dalam shalat Iedul Fithri bertakbir tujuh kali pada raka'at pertama kemudian membaca (Fatihah dan surat Al Qur'an), kemudian beliau berdiri dan bertakbir empat kali lalu membaca (Fatihah dan surat Al Qur'an) setelah itu beliau ruku'.\" Abu Daud mengatakan; \"di riwayatkan pula oleh [Waki'] dan [Ibnu Mubarrak], keduanya berkata; \"(bertakbir) tujuh kali dan lima kali.\""},"960":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَابْنُ أَبِي زِيَادٍ الْمَعْنَى قَرِيبٌ قَالَا حَدَّثَنَا زَيْدٌ يَعْنِي ابْنَ حُبَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ قَالَ أَخْبَرَنِي أَبُو عَائِشَةَ جَلِيسٌ لِأَبِي هُرَيْرَةَأَنَّ سَعِيدَ بْنَ الْعَاصِ سَأَلَ أَبَا مُوسَى الْأَشْعَرِيَّ وَحُذَيْفَةَ بْنَ الْيَمَانِ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي الْأَضْحَى وَالْفِطْرِ فَقَالَ أَبُو مُوسَى كَانَ يُكَبِّرُ أَرْبَعًا تَكْبِيرَهُ عَلَى الْجَنَائِزِفَقَالَ حُذَيْفَةُ صَدَقَ فَقَالَ أَبُو مُوسَى كَذَلِكَ كُنْتُ أُكَبِّرُ فِي الْبَصْرَةِ حَيْثُ كُنْتُ عَلَيْهِمْ و قَالَ أَبُو عَائِشَةَ وَأَنَا حَاضِرٌ سَعِيدَ بْنَ الْعَاصِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] dan [Ibnu Abu Ziyad] sedangkan maknanya saling berdekatan, keduanya berkata; telah menceritakan kepada kami [Zaid yaitu Ibnu Hubab] dari [Abdurrahman bin Tsauban] dari [ayahnya] dari [Makhul] dia berkata; telah mengabarkan kepadaku [Abu 'Aisyah] -sahabat Abu Hurairah- bahwa Sa'id bin Al 'Ash bertanya kepada [Abu Musa Al Asy'ari] dan [Hudzaifah bin Yaman]; \"Bagaimanakah cara Rasulullah shallallahu 'alaihi wasallam bertakbir pada hari raya Adha dan Fithri?\" Abu Musa menjawab; \"Biasanya beliau bertakbir empat kali, sebagaimana shalat jenazah.\" Hudzaifah menimpali; \"Dia benar.\" Abu Musa berkata; \"aku juga bertakbir seperti itu ketika di Bashrah, ketika aku menjadi pemimpin mereka (penduduk Bashrah).\" Abu Aisyah berkata; \"Aku juga ikut hadir ketika Sa'id bin Al Ash mengajukan pertanyaan tersebut.\""},"961":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ مَاذَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَضْحَى وَالْفِطْرِ قَالَ كَانَ يَقْرَأُ فِيهِمَا ق وَالْقُرْآنِ الْمَجِيدِ وَاقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] bahwa Umar bin Khattab bertanya kepada [Abu Waqid Al Laitsi]; \"Apa yang biasa di baca oleh Rasulullah shallallahu 'alaihi wasallam pada waktu shalat iedul Adha dan Fithri?\" dia menjawab; \"Pada shalat dua hari raya tersebut, beliau biasa membaca; \"Qaaf wal quraanil majiid\" dan \"Waqtarabatis saa'ah wan syaqqal Qamar.\""},"962":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى السِّينَانِيُّ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِيدَ فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّا نَخْطُبُ فَمَنْ أَحَبَّ أَنْ يَجْلِسَ لِلْخُطْبَةِ فَلْيَجْلِسْ وَمَنْ أَحَبَّ أَنْ يَذْهَبَ فَلْيَذْهَبْقَالَ أَبُو دَاوُد هَذَا مُرْسَلٌ عَنْ عَطَاءٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah Al Bazzaz] telah menceritakan kepada kami [Al Fadl bin Musa As Sinani] telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha`] dari [Abdullah bin As Sa`ib] dia berkata; \"Aku menyaksikan shalat Ied bersama Rasulullah shallallahu 'alaihi wasallam, setelah melaksanakan shalat, beliau bersabda: \"Kami akan melaksanakan khutbah, barangsiapa ingin mendengarkan khutbah, hendaklah dia duduk. Dan barangsiapa ingin pergi, silahkan pergi.\" Abu Daud berkata; \"Hadits ini Mursal, dari 'Atha` dari Nabi shallallahu 'alaihi wasallam.\""},"963":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ يَوْمَ الْعِيدِ فِي طَرِيقٍ ثُمَّ رَجَعَ فِي طَرِيقٍ آخَرَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdullah yaitu Ibnu Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam, ketika hendak berangkat shalat Ied, beliau melewati suatu jalan dan kembali dari shalat Ied melewati jalan yang lain.\""},"964":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ جَعْفَرِ بْنِ أَبِي وَحْشِيَّةَ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسٍ عَنْ عُمُومَةٍ لَهُ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَكْبًا جَاءُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْهَدُونَ أَنَّهُمْ رَأَوْا الْهِلَالَ بِالْأَمْسِ فَأَمَرَهُمْ أَنْ يُفْطِرُوا وَإِذَا أَصْبَحُوا أَنْ يَغْدُوا إِلَى مُصَلَّاهُمْ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Ja'far bin Abu wahsyiyah] dari [Abu 'Umair bin Anas] dari [paman-pamannya yang juga sahabat Rasulullah shallallahu 'alaihi wasallam] bahwa suatu rombongan datang kepada Nabi shallallahu 'alaihi wasallam, mereka bersaksi bahwa mereka telah melihat hilal kemarin. Maka beliau memerintahkan mereka (masyarakat) untuk berbuka puasa, dan keesokan harinya, mereka berpagi-pagi menuju ke tempat shalat (untuk melaksanakan shalat hari raya).\""},"965":{"ar":"حَدَّثَنَا حَمْزَةُ بْنُ نُصَيْرٍ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُوَيْدٍ أَخْبَرَنِي أُنَيْسُ بْنُ أَبِي يَحْيَى أَخْبَرَنِي إِسْحَقُ بْنُ سَالِمٍ مَوْلَى نَوْفَلِ بْنِ عَدِيٍّ أَخْبَرَنِي بَكْرُ بْنُ مُبَشِّرٍ الْأَنْصَارِيُّ قَالَكُنْتُ أَغْدُو مَعَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى فَنَسْلُكُ بَطْنَ بَطْحَانَ حَتَّى نَأْتِيَ الْمُصَلَّى فَنُصَلِّيَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَرْجِعَ مِنْ بَطْنِ بَطْحَانَ إِلَى بُيُوتِنَا","id":"Telah menceritakan kepada kami [Hamzah bin Nushair] telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Ibrahim bin Suwaid] telah mengabarkan kepadaku [Unais bin Abu Yahya] telah mengabarkan kepadaku [Ishaq bin Salim bekas budak Naufal bin 'Adi] telah mengabarkan kepadaku [Bakr bin Mubasyir Al Anshari] dia berkata; \"Aku berangkat untuk melaksanakan shalat Iedul Fithri dan Iedul Adha bersama sahabat-sahabat Rasulullah shallallahu 'alaihi wasallam. Ketika pergi, kami melewati lembah Bathhan hingga sampai di tempat shalat, lalu kami shalat bersama Rasulullah shallallahu 'alaihi wasallam, ketika kami pulang ke rumah masing-masing, kami juga lewat lembah Bathhan.\""},"966":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فِطْرٍ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهُمَا وَلَا بَعْدَهُمَا ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي خُرْصَهَا وَسِخَابَهَا","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam keluar pada hari raya Fithri, kemudian shalat dia raka'at, beliau tidak shalat (sunnah) baik sebelum maupun sesudahnya. Setelah itu, beliau bersama Bilal pergi menemui kaum wanita, dan menyuruh mereka memperbanyak sedekah, maka kaum wanita melepas anting dan kalung mereka.\""},"967":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ ح و حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا رَجُلٌ مِنْ الْقَرَوِيِّينَ وَسَمَّاهُ الرَّبِيعُ فِي حَدِيثِهِ عِيسَى بْنَ عَبْدِ الْأَعْلَى بْنِ أَبِي فَرْوَةَ سَمِعَ أَبَا يَحْيَى عُبَيْدَ اللَّهِ التَّيْمِيَّ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّهُ أَصَابَهُمْ مَطَرٌ فِي يَوْمِ عِيدٍ فَصَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعِيدِ فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid] dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ar Rabi' bin Sulaiman] telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami seorang dari pedesaan yang Ar Rabi' beri nama dalam haditsnya [Isa bin Abdul A'la bin Abi Farawwah] dia mendengar [Abu Yahya 'Ubaidullah Attaimi] mengatakan dari [Abu Hurairah] berkata; bahwa kami pernah kehujanan pada waktu pelaksanaan shalat Ied, maka Nabi shallallahu 'alaihi wasallam melaksanakannya di masjid.\""},"968":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ بِالنَّاسِ لِيَسْتَسْقِيَ فَصَلَّى بِهِمْ رَكْعَتَيْنِ جَهَرَ بِالْقِرَاءَةِ فِيهِمَا وَحَوَّلَ رِدَاءَهُ وَرَفَعَ يَدَيْهِ فَدَعَا وَاسْتَسْقَى وَاسْتَقْبَلَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Mawarzi] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [pamannya] bahwa Rasulullah shallallahu 'alaihi wasallam keluar bersama orang-orang untuk memohon hujan, lalu beliau shalat dua raka'at dengan mengeraskan bacaan pada raka'at tersebut, beliau membalik kain selendangnya sambil berdo'a dan memohon supaya di turunkan hujan dengan menghadap ke arah Kiblat.\""},"969":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ وَسُلَيْمَانُ بْنُ دَاوُدَ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ وَيُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبَّادُ بْنُ تَمِيمٍ الْمَازِنِيُّ أَنَّهُ سَمِعَ عَمَّهُ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يَسْتَسْقِي فَحَوَّلَ إِلَى النَّاسِ ظَهْرَهُ يَدْعُو اللَّهَ عَزَّ وَجَلَّ قَالَ سُلَيْمَانُ بْنُ دَاوُدَ وَاسْتَقْبَلَ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُ ثُمَّ صَلَّى رَكْعَتَيْنِ قَالَ ابْنُ أَبِي ذِئْبٍ وَقَرَأَ فِيهِمَا زَادَ ابْنُ السَّرْحِ يُرِيدُ الْجَهْرَحَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ قَالَ قَرَأْتُ فِي كِتَابِ عَمْرِو بْنِ الْحَارِثِ يَعْنِي الْحِمْصِيَّ عَنْ عَبْدِ اللَّهِ بْنِ سَالِمٍ عَنْ الزُّبَيْدِيِّ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ لَمْ يَذْكُرْ الصَّلَاةَ قَالَ وَحَوَّلَ رِدَاءَهُ فَجَعَلَ عِطَافَهُ الْأَيْمَنَ عَلَى عَاتِقِهِ الْأَيْسَرِ وَجَعَلَ عِطَافَهُ الْأَيْسَرَ عَلَى عَاتِقِهِ الْأَيْمَنِ ثُمَّ دَعَا اللَّهَ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] dan [Sulaiman bin Daud] keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Ibnu Abu Dzi`b] dan [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Abbad bin Tamim Al Mazini] bahwa dia mendengar [pamannya] -dia termasuk dari salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam- dia berkata; \"Pada suatu hari, Rasulullah shallallahu 'alaihi wasallam keluar untuk memohon hujan, lalu beliau membalikkan punggungnya dari orang-orang, beliau berdo'a kepada Allah 'azza wajalla.\" Sulaiman bin Daud mengatakan; \"Dengan menghadap ke arah Kiblat, kemudian beliau merubah posisi selendangnya, lalu shalat dua raka'at.\" Ibnu Abu Dzi`b berkata; \"…… dalam dua raka'at tersebut, beliau membaca (surat Al Qur'an).\" Ibnu Sarh menambahkan; \"Maksudnya dengan jelas.\" Telah menceritakan kepada kami [Muhammad bin 'Auf] dia berkata; \"Aku membaca di kitabnya ['Amru bin Al Harits yaitu Al Himshi] dari [Abdullah bin Salim] dari [Az Zubaidi] dari [Muhammad bin Muslim] seperti hadits ini berserta sanadnya, namun dia tidak menyebutkan 'Shalat', katanya; \"Kemudian beliau merubah posisi selendangnya, hingga ujung selendang kanannya di sebelah pundak kiri, dan ujung selendang di sebelah kiri menjadi di sebelah kanan, kemudian beliau berdo'a kepada Allah 'azza wajalla.\""},"970":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ قَالَاسْتَسْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَمِيصَةٌ لَ��ُ سَوْدَاءُ فَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْخُذَ بِأَسْفَلِهَا فَيَجْعَلَهُ أَعْلَاهَا فَلَمَّا ثَقُلَتْ قَلَبَهَا عَلَى عَاتِقِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz] dari ['Umarah bin Ghaziyah] dari ['Abbad bin Tamim] bahwa [Abdullah bin Zaid] berkata; \"Rasulullah shallallahu 'alaihi wasallam memohon di turunkannya hujan, sedangkan waktu itu beliau memakai pakaian berwarna hitam, beliau keberatan ketika hendak meletakkan bagian kain yang ada di bawah ke atas, maka beliau membaliknya di atas pundak.\""},"971":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ نَحْوَهُ قَالَا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا هِشَامُ بْنُ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ كِنَانَةَ قَالَ أَخْبَرَنِي أَبِي قَالَأَرْسَلَنِي الْوَلِيدُ بْنُ عُتْبَةَ قَالَ عُثْمَانُ ابْنُ عُقْبَةَ وَكَانَ أَمِيرَ الْمَدِينَةِ إِلَى ابْنِ عَبَّاسٍ أَسْأَلُهُ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الِاسْتِسْقَاءِ فَقَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَبَذِّلًا مُتَوَاضِعًا مُتَضَرِّعًا حَتَّى أَتَى الْمُصَلَّى زَادَ عُثْمَانُ فَرَقَى عَلَى الْمِنْبَرِ ثُمَّ اتَّفَقَا وَلَمْ يَخْطُبْ خُطَبَكُمْ هَذِهِ وَلَكِنْ لَمْ يَزَلْ فِي الدُّعَاءِ وَالتَّضَرُّعِ وَالتَّكْبِيرِ ثُمَّ صَلَّى رَكْعَتَيْنِ كَمَا يُصَلِّي فِي الْعِيدِقَالَ أَبُو دَاوُد وَالْإِخْبَارُ لِلنُّفَيْلِيِّ وَالصَّوَابُ ابْنُ عُقْبَةَ","id":"Telah menceritakan kepada kami [An Nufaili] dan [Utsman bin Abu Syaibah] semisalnya, keduanya berkata; telah menceritakan kepada kami [Hatim bin Ismail] telah berkata kepada kami [Hisyam bin Ishak bin Abdullah bin Kinanah] dia berkata; telah mengabarkan kepadau [ayahku] dia berkata; bahwa AlWalid bin Utbah-atau Utsman bin Uqbah- gubernur Madinah mengutus aku untuk menemui Ibnu Abbas untuk menanyakan kepadanya tentang shalat istisqa yang dilakukan Rasulullah Shollallahu alaihi wasallam, maka [Ibnu Abbas] menjawab bahwa Rasulullah Shollallahu alaihi wasallam keluar untuk melaksanakan shalat istisqa dalam keadaan lusuh, tawadhu' dan khusyu' hingga beliau sampai di tempat shalat- Utsman menambahkan- kemudian beliau naik mimbar -dan keduanya sepakat bahwa- beliau tidak khutbah, akan tetapi beliau berdo'a dan betul-betul khusyu' dalam berdo'a dan beliau bertakbir kemudian beliau shalat dua rakaat sebagaimana shalat Ied. Abu Daud berkata ikhbar bagi Nufaili dan yang benar adalah Ibnu Uqbah. "},"972":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ يَحْيَى عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى يَسْتَسْقِي وَأَنَّهُ لَمَّا أَرَادَ أَنْ يَدْعُوَ اسْتَقْبَلَ الْقِبْلَةَ ثُمَّ حَوَّلَ رِدَاءَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Bilal] dari [Yahya] dari [Abu Bakr bin Muhammad] dari ['Abbad bin Tamim] bahwa [Abdullah bin Zaid] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam keluar menuju Mushalla (tempat shalat) memohon di turunkannya hujan, dan ketika beliau hendak berdo'a, beliau menghadap kiblat sambil merubah posisi selendangnya.\""},"973":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّهُ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْمَازِنِيَّ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى فَاسْتَسْقَى وَحَوَّلَ رِدَاءَهُ حِينَ اسْتَقْبَلَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abdullah bin Abu Bakr] bahwa dia mendengar ['Abbad bin Tamim] berkata; saya mendengar [Abdullah bin Zaid Al Mazini] berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menuju mushalla (tempat shalat), kemudian beliau (berdo'a) memohon di turunkannya hujan, beliau merubah posisi selendangnya sambil menghadap ke Kiblat.\""},"974":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ حَيْوَةَ وَعُمَرَ بْنِ مَالِكٍ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عُمَيْرٍ مَوْلَى بَنِي آبِي اللَّحْمِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي عِنْدَ أَحْجَارِ الزَّيْتِ قَرِيبًا مِنْ الزَّوْرَاءِ قَائِمًا يَدْعُو يَسْتَسْقِي رَافِعًا يَدَيْهِ قِبَلَ وَجْهِهِ لَا يُجَاوِزُ بِهِمَا رَأْسَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah mengabarkan kepada kami [Ibnu wahb] dari [Haiwah] dan [Umar bin Malik] dari [Ibnul Had] dari [Muhammad bin Ibrahim] dari ['Umair bekas budak Bani Abu Lahm] bahwa dia melihat Nabi shallallahu 'alaihi wasallam memohon supaya di turunkannya hujan di Ahjaruz Zait dekat Zaura` dengan berdiri sambil berdo'a memohon diturunkannya hujan seraya mengangkat kedua tangannya ke depan dan tidak melebihi kepalanya.\""},"975":{"ar":"حَدَّثَنَا ابْنُ أَبِي خَلَفٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مِسْعَرٌ عَنْ يَزِيدَ الْفَقِيرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَوَاكِي فَقَالَ اللَّهُمَّ اسْقِنَا غَيْثًا مُغِيثًا مَرِيئًا مَرِيعًا نَافِعًا غَيْرَ ضَارٍّ عَاجِلًا غَيْرَ آجِلٍ قَالَ فَأَطْبَقَتْ عَلَيْهِمْ السَّمَاءُ","id":"Telah menceritakan kepada kami [Ibnu Abu Khalaf] telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Mis'ar] dari [Yazid Al Faqir] dari [Jabir bin Abdillah] dia berkata; \"Beberapa wanita mendatangi Rasulullah shallallahu 'alaihi wasallam sambil menangis (karena kekeringan), kemudian beliau berdo'a: \"Allahummasqina ghaitsan mughitsan mari'an nafi'an ghair dharrin 'ajilan ghaira ajilin\" (ya Allah, turunkanlah kepada kami hujan yang dapat menolong kami, yang menyenangkan kami, menyuburkan lagi bermanfaat dan tidak membahayakan, segera jangan ditunda-tunda).\" Seketika itu juga, langit menurunkan hujannya atas mereka.\""},"976":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ الدُّعَاءِ إِلَّا فِي الِاسْتِسْقَاءِ فَإِنَّهُ كَانَ يَرْفَعُ يَدَيْهِ حَتَّى يُرَى بَيَاضُ إِبِطَيْهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam tidak pernah mengangkat kedua tangannya ketika berdo'a kecuali ketika meminta hujan, ketika itu beliau mengangkat kedua tangan beliau sehingga terlihat putih ketiaknya.\""},"977":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَسْقِي هَكَذَا يَعْنِي وَمَدَّ يَدَيْهِ وَجَعَلَ بُطُونَهُمَا مِمَّا يَلِي الْأَرْضَ حَتَّى رَأَيْتُ بَيَاضَ إِبِطَيْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam meminta hujan dengan begini maksudnya beliau memanjangkan kedua tangannya dengan menjadikan punggung telapak tangannya menghadap ke arah bumi, sehingga aku melihat putih ketiaknya.\""},"978":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَخْبَرَنِي مَنْرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عِنْدَ أَحْجَارِ الزَّيْتِ بَاسِطًا كَفَّيْهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari ['Abdi Rabbihi bin Sa'id] dari [Muhammad bin Ibrahim] telah mengabarkan kepadaku [seorang yang pernah melihat Nabi shallallahu 'alaihi wasallam] bahwa beliau pernah berdo'a dekat Ahjaariz Zait sambil membentangkan kedua telapak tangan beliau.\""},"979":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا خَالِدُ بْنُ نِزَارٍ حَدَّثَنِي الْقَاسِمُ بْنُ مَبْرُورٍ عَنْ يُونُسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْشَكَا النَّاسُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُحُوطَ الْمَطَرِ فَأَمَرَ بِمِنْبَرٍ فَوُضِعَ لَهُ فِي الْمُصَلَّى وَوَعَدَ النَّاسَ يَوْمًا يَخْرُجُونَ فِيهِ قَالَتْ عَائِشَةُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَدَا حَاجِبُ الشَّمْسِ فَقَعَدَ عَلَى الْمِنْبَرِ فَكَبَّرَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَمِدَ اللَّهَ عَزَّ وَجَلَّ ثُمَّ قَالَ إِنَّكُمْ شَكَوْتُمْ جَدْبَ دِيَارِكُمْ وَاسْتِئْخَارَ الْمَطَرِ عَنْ إِبَّانِ زَمَانِهِ عَنْكُمْ وَقَدْ أَمَرَكُمْ اللَّهُ عَزَّ وَجَلَّ أَنْ تَدْعُوهُ وَوَعَدَكُمْ أَنْ يَسْتَجِيبَ لَكُمْ ثُمَّ قَالَ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ الرَّحْمَنِ الرَّحِيمِ مَلِكِ يَوْمِ الدِّينِ }لَا إِلَهَ إِلَّا اللَّهُ يَفْعَلُ مَا يُرِيدُ اللَّهُمَّ أَنْتَ اللَّهُ لَا إِلَهَ إِلَّا أَنْتَ الْغَنِيُّ وَنَحْنُ الْفُقَرَاءُ أَنْزِلْ عَلَيْنَا الْغَيْثَ وَاجْعَلْ مَا أَنْزَلْتَ لَنَا قُوَّةً وَبَلَاغًا إِلَى حِينٍ ثُمَّ رَفَعَ يَدَيْهِ فَلَمْ يَزَلْ فِي الرَّفْعِ حَتَّى بَدَا بَيَاضُ إِبِطَيْهِ ثُمَّ حَوَّلَ إِلَى النَّاسِ ظَهْرَهُ وَقَلَبَ أَوْ حَوَّلَ رِدَاءَهُ وَهُوَ رَافِعٌ يَدَيْهِ ثُمَّ أَقْبَلَ عَلَى النَّاسِ وَنَزَلَ فَصَلَّى رَكْعَتَيْنِ فَأَنْشَأَ اللَّهُ سَحَابَةً فَرَعَدَتْ وَبَرَقَتْ ثُمَّ أَمْطَرَتْ بِإِذْنِ اللَّهِ فَلَمْ يَأْتِ مَسْجِدَهُ حَتَّى سَالَتْ السُّيُولُ فَلَمَّا رَأَى سُرْعَتَهُمْ إِلَى الْكِنِّ ضَحِكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ فَقَالَ أَشْهَدُ أَنَّ اللَّهَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ وَأَنِّي عَبْدُ اللَّهِ وَرَسُولُهُقَالَ أَبُو دَاوُد وَهَذَا حَدِيثٌ غَرِيبٌ إِسْنَادُهُ جَيِّدٌ أَهْلُ الْمَدِينَةِ يَقْرَءُونَ{ مَلِكِ يَوْمِ الدِّينِ }وَإِنَّ هَذَا الْحَدِيثَ حُجَّةٌ لَهُمْ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Khalid bin Nizar] telah menceritakan kepadaku [Al Qasim bin Mabrur] dari [Yunus] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] dia berkata; \"Orang-orang mengadu kepada Rasulullah shallallahu 'alaihi wasallam tentang musim kemarau yang panjang, maka beliau memerintahkan untuk meletakkan mimbar di tempat shalat (tanah lapang), lalu beliau berjanji kepada orang-orang untuk bertemu pada suatu hari yang telah di tentukan.\" Aisyah berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam keluar ketika matahari mulai terlihat, lalu beliau duduk di mimbar, beliau shallallahu 'alaihi wasallam bertakbir dan memuji Allah Azza Wa Jalla, lalu bersabda: \"Sesungguhnya kalian mengadu kepadaku tentang kegersangan negeri kalian dan keterlambatan turunnya hujan dari musimnya, padahal Allah Azza Wa Jalla telah memerintahkan kalian agar kalian memohon kepadanya, dan berjanji akan mengabulkan do'a kalian, kemudian beliau mengucapkan: \"Segala puji bagi Allah, Rabb semesta alam, Maha Pemurah lagi Maha Penyayang. Dzat yang menguasai hari Pembalasan. (AlFatihah: 2-4). Tidak ada ilah yang berhak disembah kecuali Dia, Dia melakukan apa saja yang dikehendaki. Ya Allah, Engkau adalah Allah, tidak ada tuhan ilah yang berhak disembah kecuali Engkau, Maha kaya sementara kami yang membutuhkan, maka turunkanlah hujan kepada kami dan jadikanlah apa yang telah Engkau turunkan kekuatan bagi kami dan sebagai bekal di hari yang di tetapkan.\" kemudian beliau mengangkat kedua tangannya, dan senantiasa mengangkat kedua tangannya hingga terlihat putih ketiak beliau, kemudian beliau membalikkan punggungnya membelakangi orang-orang dan merubah posisi selendangnya, sedangkan beliau masih mengangkat kedua tangannya. Kemudian beliau menghadap ke orang-orang, lalu beliau turun dari mimbar dan shalat dua raka'at. Seketika itu Allah mendatangkan awan yang di sertai dengan gemuruh dan kilat, Maka turunlah hujan dengan izin Allah, beliau tidak kembali menuju masjid sampai air bah mengalir (di sekitarnya), ketika beliau melihat orang-orang berdesak-desakan mencari tempat berteduh, beliau tersenyum hingga terlihat gigi gerahamnya, lalu bersabda: \"Aku bersaksi bahwa Allah adalah Maha kuasa atas segala sesuatu dan aku adalah hamba dan rasul-Nya.\" Abu Daud berkata; \"Ini adalah hadits gharib, tapi sanadnya bagus, penduduk Madinah mambaca \"Malikiyaumid-din\" dan hadits ini juga menjadi argumentasi mereka.\""},"980":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ وَيُونُسَ بْنِ عُبَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَأَصَابَ أَهْلَ الْمَدِينَةِ قَحْطٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَمَا هُوَ يَخْطُبُنَا يَوْمَ جُمُعَةٍ إِذْ قَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْكُرَاعُ هَلَكَ الشَّاءُ فَادْعُ اللَّهَ أَنْ يَسْقِيَنَا فَمَدَّ يَدَيْهِ وَدَعَا قَالَ أَنَسٌ وَإِنَّ السَّمَاءَ لَمِثْلُ الزُّجَاجَةِ فَهَاجَتْ رِيحٌ ثُمَّ أَنْشَأَتْ سَحَابَةً ثُمَّ اجْتَمَعَتْ ثُمَّ أَرْسَلَتْ السَّمَاءُ عَزَالِيَهَا فَخَرَجْنَا نَخُوضُ الْمَاءَ حَتَّى أَتَيْنَا مَنَازِلَنَا فَلَمْ يَزَلْ الْمَطَرُ إِلَى الْجُمُعَةِ الْأُخْرَى فَقَامَ إِلَيْهِ ذَلِكَ الرَّجُلُ أَوْ غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ فَادْعُ اللَّهَ أَنْ يَحْبِسَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ حَوَالَيْنَا وَلَا عَلَيْنَا فَنَظَرْتُ إِلَى السَّحَابِ يَتَصَدَّعُ حَوْلَ الْمَدِينَةِ كَأَنَّهُ إِكْلِيلٌحَدَّثَنَا عِيسَى بْنُ حَمَّادٍ أَخْبَرَنَا اللَّيْثُ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسٍ أَنَّهُ سَمِعَهُ يَقُولُ فَذَكَرَ نَحْوَ حَدِيثِ عَبْدِ الْعَزِيزِ قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ بِحِذَاءِ وَجْهِهِ فَقَالَ اللَّهُمَّ اسْقِنَا وَسَاقَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik], dan [Yunus bin 'Ubaid] dari [Tsabit] dari [Anas] dia berkata; \"Penduduk Madinah pernah di timpa bencana kekeringan pada masa Rasulullah shallallahu 'alaihi wasallam, ketika beliau tengah menyampaikan khutbah Jum'at, tiba-tiba seorang laki-laki berdiri seraya berkata; \"Wahai Rasulullah, telah binasa kuda dan kambing, oleh karena itu, berdo'alah kepada Allah agar menurunkan hujan kepada kami.\" Lalu beliau merenggangkan kedua tangannya dan berdo'a.\" Anas berkata; \"Saat itu, langit sangat cerah laksana kaca, lalu angin bertiaup yang membawa awan yang menggumpal, setelah itu langit menurunkan hujan, lalu kami keluar mencebur ke air hujan, sehingga kami tiba di rumah kami, dan hujan senantiasa turun hingga jum'at berikutnya, maka laki-laki itu atau laki-laki lain berdiri sambil berkata; \"Wahai Rasulullah, rumah-rumah kami (hampir) roboh (karena hujan kebat), oleh karena itu, berdo'alah kepada Allah agar hujan di hentikan!.\" Maka Rasulullah shallallahu 'alaihi wasallam tersenyum kemudian bersabda: \"Turunkanlah hujan ini di sekeliling kami, dan jangan sampai ia membawa petaka bagi kami.\" Lalu aku melihat awan tersebut terputus-putus di sekitar Madinah, seolah-olah bagaikan Mahkota (maksudnya hujan turun menyebar di seluruh Madinah).\" Telah menceritakan kepada kami [Isa bin Hammad] telah mengabarkan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [Syarik bin Abdullah bin Abu Namir] bahwa dia mendengar [Anas] berkata; …\" kemudian dia menyebutkan sebagaimana hadits Abdul Aziz katanya; \"Maka Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya sejajar dengan wajah beliau seraya mengucapkan: \"Ya Allah turunkanlah hujan kepada kami…\" kemudian dia melanjutkan hadits seperti di atas.\""},"981":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ ح و حَدَّثَنَا سَهْلُ بْنُ صَالِحٍ حَدَّثَنَا عَلِيُّ بْنُ قَادِمٍ أَخْبَرَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَسْقَى قَالَ اللَّهُمَّ اسْقِ عِبَادَكَ وَبَهَائِمَكَ وَانْشُرْ رَحْمَتَكَ وَأَحْيِ بَلَدَكَ الْمَيِّتَهَذَا لَفْظُ حَدِيثِ مَالِكٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Yahya bin Sa'id] dari ['Amru bin Syu'aib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: …\" dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Sahl bin Shalih] telah menceritakan kepada kami [Ali bin Qadim] telah mengabarkan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam memohon turunnya hujan, beliau mengucapkan: \"Ya Allah, hujanilah hamba-hamba-Mu, binatang-binatang ternak-Mu dan tebarkanlah rahmat-Mu serta hidupkanlah tanah-Mu yang tandus.\" Lafadz ini dari hadits Malik. "},"982":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ أَخْبَرَنِي مَنْ أُصَدِّقُ وَظَنَنْتُ أَنَّهُ يُرِيدُ عَائِشَةَ قَالَكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيَامًا شَدِيدًا يَقُومُ بِالنَّاسِ ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ فَرَكَعَ رَكْعَتَيْنِ فِي كُلِّ رَكْعَةٍ ثَلَاثُ رَكَعَاتٍ يَرْكَعُ الثَّالِثَةَ ثُمَّ يَسْجُدُ حَتَّى إِنَّ رِجَالًا يَوْمَئِذٍ لَيُغْشَى عَلَيْهِمْ مِمَّا قَامَ بِهِمْ حَتَّى إِنَّ سِجَالَ الْمَاءِ لَتُصَبُّ عَلَيْهِمْ يَقُولُ إِذَا رَكَعَ اللَّهُ أَكْبَرُ وَإِذَا رَفَعَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ حَتَّى تَجَلَّتْ الشَّمْسُ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ يُخَوِّفُ بِهِمَا عِبَادَهُ فَإِذَا كُسِفَا فَافْزَعُوا إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Ibnu Juraij] dari ['Atha`] dari ['Ubaid bin 'Umair] telah mengabarkan kepadaku [seseorang yang aku percaya] -aku kira yang di maksud oleh 'Ubaid adalah Aisyah- dia berkata; \"Telah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam berdiri lama sekali bersama orang-orang. Kemudian beliau ruku', lalu berdiri dan ruku' lagi kemudian berdiri lalu ruku' lagi. Beliau mengerjakan shalat dua raka'at, yang setiap raka'atnya tiga kali ruku'. Setelah ruku' yang ketiga baru beliau sujud. Beberapa orang ketika itu pingsan karena lamanya beliau berdiri bersama mereka, sehingga seember air di percikkan ke tubuh mereka. Apabila ruku' beliau mengucapkan: \"Allahu akbar.\" Dan apabila mengangkat kepala (I'tidal) beliau mengucapkan: \"Sami'allahu liman hamidah\" sehingga matahari kembali terang. Kemudian berliau bersabda: 'Sesungguhnya gerhana matahari dan bulan terjadi bukan karena matinya atau hidupnya seseorang, akan tetapi keduanya merupakan tanda-tanda kebesaran Allah Azza Wa Jalla untuk memberi peringatan kepada para hamba-Nya, apabila terjadi gerhana, maka bersegeralah kalian melaksanakan shalat. '"},"983":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عَبْدِ الْمَلِكِ حَدَّثَنِي عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ ذَلِكَ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ إِبْرَاهِيمُ بْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّاسُ إِنَّمَا كُسِفَتْ لِمَوْتِ إِبْرَاهِيمَ ابْنِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ سِتَّ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ كَبَّرَ ثُمَّ قَرَأَ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ فَقَرَأَ دُونَ الْقِرَاءَةِ الْأُولَى ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ فَقَرَأَ الْقِرَاءَةَ الثَّالِثَةَ دُونَ الْقِرَاءَةِ الثَّانِيَةِ ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ فَانْحَدَرَ لِلسُّجُودِ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَرَكَعَ ثَلَاثَ رَكَعَاتٍ قَبْلَ أَنْ يَسْجُدَ لَيْسَ فِيهَا رَكْعَةٌ إِلَّا الَّتِي قَبْلَهَا أَطْوَلُ مِنْ الَّتِي بَعْدَهَا إِلَّا أَنَّ رُكُوعَهُ نَحْوٌ مِنْ قِيَامِهِ قَالَ ثُمَّ تَأَخَّرَ فِي صَلَاتِهِ فَتَأَخَّرَتْ الصُّفُوفُ مَعَهُ ثُمَّ تَقَدَّمَ فَقَامَ فِي مَقَامِهِ وَتَقَدَّمَتْ الصُّفُوفُ فَقَضَى الصَّلَاةَ وَقَدْ طَلَعَتْ الشَّمْسُ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ لَا يَنْكَسِفَانِ لِمَوْتِ بَشَرٍ فَإِذَا رَأَيْتُمْ شَيْئًا مِنْ ذَلِكَ فَصَلُّوا حَتَّى تَنْجَلِيَ وَسَاقَ بَقِيَّةَ الْحَدِيثِحَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ هِشَامٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمٍ شَدِيدِ الْحَرِّ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصْحَابِهِ فَأَطَالَ الْقِيَامَ حَتَّى جَعَلُوا يَخِرُّونَ ثُمَّ رَكَعَ فَأَطَالَ ثُمَّ رَفَعَ فَأَطَالَ ثُمَّ رَكَعَ فَأَطَالَ ثُمَّ رَفَعَ فَأَطَالَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَصَنَعَ نَحْوًا مِنْ ذَلِكَ فَكَانَ أَرْبَعُ رَكَعَاتٍ وَأَرْبَعُ سَجَدَاتٍ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari [Abdul Malik] telah menceritakan kepadaku ['Atha`] dari [Jabir bin Abdullah] dia berkata; \"Pernah terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, waktu itu bertepatan dengan wafatnya Ibrahim putra Rasulullah shallallahu 'alaihi wasallam, maka orang-orang berkata; \"Gerhana terjadi karena wafatnya Ibrahim putra beliau shallallahu 'alaihi wasallam.\" Mendengar itu, Nabi shallallahu 'alaihi wasallam berdiri untuk mengerjakan shalat bersama orang-orang dengan enam kali ruku', dan empat kali sujud (dua raka'at). Beliau kemudian bertakbir, lalu membaca (surat al Qur'an) dengan memanjangkan bacaannya, lalu ruku' lama seperti lama beliau berdiri, kemudian beliau mengangkat kepalanya (i'tidal) tanpa membaca (surat Al Qur'an) sebagaimana yang pertama, setelah itu beliau ruku' lama seperti lamanya beliau berdiri, lalu mengangkat kepalanya dan membaca (surat al Qur'an) yang ketiga kali (beliau berdiri) tidak sebagaimana bacaan yang kedua, kemudian ruku' lama seperti lama berdiri, lalu i'tidal dengan mengangkat kepala, lalu turun sujud dua kali. Setelah itu beliau berdiri kembali, lalu ruku' tiga sebelum sujud. Dalam shalat ini, raka'at pertama lebih panjang daripada raka'at sesudahnya (kedua), akan tetapi beliau ruku' sama lamanya dengan berdiri.\" Jabir berkata; \"Setelah itu, beliau mundur dalam shaf shalatnya, maka shaf-shaf shalat yang berada di belakang beliau pun turut mundur, kemudian beliau maju di tempat semula, maka shaf-shaf yang ada di belakang beliau turut maju ke depan. Seusai beliau shalat, ternyata matahari muncul kembali, lalu beliau bersabda; \"wahai sekalian manusia, sesungguhnya matahari dan bulan adalah salah satu tanda dari beberapa tanda kekuasaan Allah Azza Wa Jalla, tidaklah keduanya mengalami gerhana karena kematian seseorang, oleh karena itu, apabila kalian melihat suatu kejadian padanya, hendaklah kalian melaksanakan shalat sampai (matahari dan bulan) terang kembali…\" kemudian Perawi melanjutkan sisa dari hadits ini. telah menceritakan kepada kami [Mu`ammal bin Hisyam] telah menceritakan kepada kami [Isma'il] dari [Hisyam] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] dia berkata; \"Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam yaitu ketika hari sangat terik, maka Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat bersama para sahabatnya, beliau berdiri sangat lama sehingga sebagian mereka tersungkur jatuh, kemudian beliau ruku' hingga lama, lalu berdiri lagi hingga lama, kemudian beliau ruku' lagi hingga lama, lalu beliau sujud dua kali, setelah itu beliau bangkit (berdiri). Lalu beliau mengerjakan yang demikian itu (pada raka'at kedua) sebagaimana raka'at pertama, yaitu dengan empat kali ruku' dan empat kali sujud.\""},"984":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخُسِفَتْ الشَّمْسُ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَامَ فَكَبَّرَ وَصَفَّ النَّاسُ وَرَاءَهُ فَاقْتَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ قَامَ فَاقْتَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ فَاسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ كَانَ كَثِيرُ بْنُ عَبَّاسٍ يُحَدِّثُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ كَانَ يُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي كُسُوفِ الشَّمْسِ مِثْلَ حَدِيثِ عُرْوَةَ عَنْ عَائِشَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى رَكْعَتَيْنِ فِي كُلِّ رَكْعَةٍ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah istri Nabi shallallahu 'alaihi wasallam] dia berkata; \"Pernah terjadi gerhana matahari ketika Rasulullah shallallahu 'alaihi wasallam masih hidup, maka Rasulullah shallallahu 'alaihi wasallam keluar menuju masjid, kemudian beliau berdiri dan bertakbir, dan orang-orang juga ikut berbaris di belakang beliau, kemudian Rasulullah shallallahu 'alaihi wasallam memanjangkan bacaannya, lalu beliau bertakbir, kemudian ruku' hingga lama, setelah itu beliau mengangkat kepala (i'tidal) sambil membaca; 'samiallahu liman hamidah, rabbanaa walakal hamdu. ' Kemudian beliau berdiri dan memanjangkan bacaannya (Al Fatihah dan surat Al Qur'an), namun agak pendek dari bacaan yang pertama. Kemudian beliau bertakbir dan ruku' hingga lama, namun ia lebih pendek daripada ruku' yang pertama, lalu beliau mengucapkan 'sami'allahu liman hamidah, rabbanaa walakal hamdu', kemudian ia mengerjakan seperti itu pada raka'at kedua, maka sempurnalah empat kali ruku' dan empat kali sujud. Dan ternyata matahari telah terang kembali sebelum beliau beranjak pergi.\" Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami ['Anbasah] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; [Katsir bin 'Abbas] pernah bercerita bahwa [Abdullah bin 'Abbas] pernah bercerita bahwa Rasulullah shallallahu 'alaihi wasallam shalat gerhana matahari…\" kemudian Perawi menyebutkan seperti hadits 'Urwah dari Aisyah dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau shalat dua raka'at, dan di setiap raka'at, beliau mengerjakan dua kali ruku'.\""},"985":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْفُرَاتِ بْنِ خَالِدٍ أَبُو مَسْعُودٍ الرَّازِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ الرَّازِيُّ عَنْ أَبِيهِ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ قَالَ أَبُو دَاوُد وَحُدِّثْتُ عَنْ عُمَرَ بْنِ شَقِيقٍ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ وَهَذَا لَفْظُهُ وَهُوَ أَتَمُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فَقَرَأَ بِسُورَةٍ مِنْ الطُّوَلِ وَرَكَعَ خَمْسَ رَكَعَاتٍ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ الثَّانِيَةَ فَقَرَأَ سُورَةً مِنْ الطُّوَلِ وَرَكَعَ خَمْسَ رَكَعَاتٍ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ جَلَسَ كَمَا هُوَ مُسْتَقْبِلَ الْقِبْلَةِ يَدْعُو حَتَّى انْجَلَى كُسُوفُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Furat bin Khalid Abu Mas'ud Ar Razi] telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abu Ja'far Ar Razi] dari [ayahnya] dari [Abu Ja'far Ar Razi] dia berkata; Abu Daud mengatakan; \"aku telah di beritahu dari [Umar bin Syaqiq] telah menceritakan kepada kami [Abu Ja'far Ar Razi] dan ini dari lafadznya yang lebih sempurna. Dari [Ar Rabi' bin Anas] dari [Abu 'Aliyah] dari [Ubay bin Ka'b] dia berkata; \"Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, lalu Nabi shallallahu 'alaihi wasallam mengerjakan shalat bersama mereka, beliau membaca surat-surat yang di baca panjang dengan lima kali ruku' dan dua kali sujud, setelah itu beliau berdiri di raka'at kedua, lalu membaca surat-surat yang di baca panjang, dengan lima kali ruku' dan dua kali sujud, kemudian beliau duduk menghadap Kiblat sambil berdo'a, sampai gerhana hilang.\""},"986":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى فِي كُسُوفِ الشَّمْسِ فَقَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ سَجَدَ وَالْأُخْرَى مِثْلُهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami [Habib bin Abu Tsabit] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bahwa beliau mengerjakan shalat gerhana, lalu beliau membaca (Al Fatihah dan surat Al Qur'an) lalu ruku', kemudian membaca, kemudian ruku', kemudian membaca, kemudian ruku', kemudian membaca, kemudian ruku', kemudian sujud. Beliau mengerjakan seperti itu di raka'at berikutnya (raka'at kedua).\""},"987":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ حَدَّثَنِي ثَعْلَبَةُ بْنُ عِبَادٍ الْعَبْدِيُّ مِنْ أَهْلِ الْبَصْرَةِأَنَّهُ شَهِدَ خُطْبَةً يَوْمًا لِسَمُرَةَ بْنِ جُنْدُبٍ قَالَ قَالَ سَمُرَةُ بَيْنَمَا أَنَا وَغُلَامٌ مِنْ الْأَنْصَارِ نَرْمِي غَرَضَيْنِ لَنَا حَتَّى إِذَا كَانَتْ الشَّمْسُ قِيدَ رُمْحَيْنِ أَوْ ثَلَاثَةٍ فِي عَيْنِ النَّاظِرِ مِنْ الْأُفُقِ اسْوَدَّتْ حَتَّى آضَتْ كَأَنَّهَا تَنُّومَةٌ فَقَالَ أَحَدُنَا لِصَاحِبِهِ انْطَلِقْ بِنَا إِلَى الْمَسْجِدِ فَوَاللَّهِ لَيُحْدِثَنَّ شَأْنُ هَذِهِ الشَّمْسِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُمَّتِهِ حَدَثًا قَالَ فَدَفَعْنَا فَإِذَا هُوَ بَارِزٌ فَاسْتَقْدَمَ فَصَلَّى فَقَامَ بِنَا كَأَطْوَلِ مَا قَامَ بِنَا فِي صَلَاةٍ قَطُّ لَا نَسْمَعُ لَهُ صَوْتًا قَالَ ثُمَّ رَكَعَ بِنَا كَأَطْوَلِ مَا رَكَعَ بِنَا فِي صَلَاةٍ قَطُّ لَا نَسْمَعُ لَهُ صَوْتًا ثُمَّ سَجَدَ بِنَا كَأَطْوَلِ مَا سَجَدَ بِنَا فِي صَلَاةٍ قَطُّ لَا نَسْمَعُ لَهُ صَوْتًا ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ قَالَ فَوَافَقَ تَجَلِّي الشَّمْسُ جُلُوسَهُ فِي الرَّكْعَةِ الثَّانِيَةِ قَالَ ثُمَّ سَلَّمَ ثُمَّ قَامَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَشَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَشَهِدَ أَنَّهُ عَبْدُهُ وَرَسُولُهُثُمَّ سَاقَ أَحْمَدُ بْنُ يُونُسَ خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al Aswad bin Qais] telah menceritakan kepadaku [Tsa'labah bin 'Ibad Al 'Abdi] -dari penduduk Bashrah- bahwa suatu hari, dia pernah mendengarkan khutbahnya [Samurah bin Jundub]. Kata Samurah; \"Ketika aku dan seorang pemuda dari Anshar sedang memanah pada dua target kami, tiba-tiba matahari -yang terlihat berada seukuran dua tombak atau tiga tombak- diatas kami, berubah menjadi hitam seperti pohon tanumah (pohon hitam dan buahnya juga hitam). Salah seorang dari kami berkata: mari kita pergi ke masjid! Demi Allah, Rasulullah shallallahu 'alaihi wasallam pasti akan memberitahukan peristiwa ini kepada umatnya!\" Maka kami pun berangkat, (sesampainya di masjid) ternyata beliau sudah bersiap-siap dan maju, lalu beliau shalat. Beliau berdiri tersebut lama sekali dalam shalat tersebut, sepertinya shalat ini yang paling panjang beliau lakukan bersama kami, hingga kami tidak mendengar suara dari beliau. kemudian beliau ruku' dengan ruku' yang panjang juga dan kami tidak mendengar suara dari beliau, kemudian beliau sujud dengan sujud yang panjang juga dan kami tidak mendengar suara dari beliau. Dan beliau melakukan hal yang sama pada raka'at kedua. Samurah berkata; 'Duduk beliau pada raka'at kedua bersamaan dengan terangnya matahari. ' Kemudian beliau mengucapkan salam dan memuji Allah, bersaksi bahwa tiada ilah yang berhak disembah selainNya dan bersaksi bahwa beliau adalah hamba dan utusan-Nya.\"kemudian Ahmad bin Yunus melanjutkan khutbah Nabi shallallahu 'alaihi wasallam.\""},"988":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ الْهِلَالِيِّ قَالَكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ فَزِعًا يَجُرُّ ثَوْبَهُ وَأَنَا مَعَهُ يَوْمَئِذٍ بِالْمَدِينَةِ فَصَلَّى رَكْعَتَيْنِ فَأَطَالَ فِيهِمَا الْقِيَامَ ثُمَّ انْصَرَفَ وَانْجَلَتْ فَقَالَ إِنَّمَا هَذِهِ الْآيَاتُ يُخَوِّفُ اللَّهُ بِهَا فَإِذَا رَأَيْتُمُوهَا فَصَلُّوا كَأَحْدَثِ صَلَاةٍ صَلَّيْتُمُوهَا مِنْ الْمَكْتُوبَةِحَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا رَيْحَانُ بْنُ سَعِيدٍ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ هِلَالِ بْنِ عَامِرٍ أَنَّ قَبِيصَةَ الْهِلَالِيَّ حَدَّثَهُ أَنَّ الشَّمْسَ كُسِفَتْ بِمَعْنَى حَدِيثِ مُوسَى قَالَ حَتَّى بَدَتْ النُّجُومُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Qabishah Al Hilali] dia berkata; \"Telah terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka beliau bergegas keluar sambil menyingsingkan lengan bajunya, ketika itu aku bersama beliau di Madinah. Lalu beliau shalat dua raka'at dengan memanjangkan berdiri, seusainya beliau melaksanakan shalat, matahari sudah cerah lagi, lalu beliau bersabda: \"Sesungguhnya ini merupakan tanda dari tanda-tanda kebesaran Allah, dan dengannya Allah membuat hamba-Nya takut, apabila kalian melihat peristiwa itu, hendaklah kalian shalat seperti kalian melaksanakan shalat wajib.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim], telah menceritakan kepada kami [Raihan bin Sa'id] telah menceritakan kepada kami ['Abbad bin Manshur] dari [Ayyub] dari [Abu Qilabah] dari [Hilal bin 'Amir] bahwa [Qabishah Al Hilali] bercerita kepadanya, bahwa telah terjadi gerhana matahari..,. seperti makna hadits Musa, katanya \"… hingga bintang terlihat.\""},"989":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ وَعَبْدُ اللَّهِ بْنُ أَبِي سَلَمَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ كُلُّهُمْ قَدْ حَدَّثَنِي عَنْ عُرْوَةَ عَنْ عَائِش��ةَ قَالَتْكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَقَامَ فَحَزَرْتُ قِرَاءَتَهُ فَرَأَيْتُ أَنَّهُ قَرَأَ بِسُورَةِ الْبَقَرَةِ وَسَاقَ الْحَدِيثَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَأَطَالَ الْقِرَاءَةَ فَحَزَرْتُ قِرَاءَتَهُ أَنَّهُ قَرَأَ بِسُورَةِ آلِ عِمْرَانَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Hisyam bin 'Urwah] dan [Abdullah bin Abu Salamah] dari [Sulaiman bin Yasar], semuanya telah menceritakan kepadaku, dari ['Urwah] dari [Aisyah] dia berkata; \"Terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam keluar untuk mengerjakan shalat bersama orang-orang, setelah itu beliau berdiri. Maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Al Baqarah …\" kemudian dia melanjutkan hadits tersebut -\"lalu beliau sujud dua kali, kemudian beliau berdiri dan memanjangkan bacaannya, maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Ali Imran.\""},"990":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ أَخْبَرَنِي أَبِي حَدَّثَنَا الْأَوْزَاعِيُّ أَخْبَرَنِي الزُّهْرِيُّ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ قِرَاءَةً طَوِيلَةً فَجَهَرَ بِهَا يَعْنِي فِي صَلَاةِ الْكُسُوفِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid bin Mazyad] telah mengabarkan kepadaku [ayahku] telah menceritakan kepadaku [Al Auza'i] telah mengabarkan kepadaku [Az Zuhri] telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam membaca dalam bacaan panjangnya sambil mengeraskan (bacaannya), yaitu dalam shalat gerhana.\""},"991":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَخُسِفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا بِنَحْوٍ مِنْ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] dia berkata; \"Telah terjadi gerhana Matahari, lalu Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat bersama orang-orang, beliau berdiri lama (dalam shalat) kira-kira membaca surat Al Baqarah, kemudian beliau ruku'…\" kemudian (perawi) melanjutkan hadits tersebut.\""},"992":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ أَنَّهُ سَأَلَ الزُّهْرِيَّ فَقَالَ الزُّهْرِيُّ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْكُسِفَتْ الشَّمْسُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَنَادَى أَنْ الصَّلَاةُ جَامِعَةٌ","id":"Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Abdurrahman bin Namir] bahwa dia bertanya kepada [Az Zuhri], maka [Az Zuhri] menjawab; telah mengabarkan kepadaku ['Urwah] dari ['Asiyah] dia berkata; \"Gerhana matahari telah terjadi, maka Rasulullah shallallahu 'alaihi wasallam memerintahkan seseorang untuk menyerukan shalat berjama'ah.\""},"993":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشَّمْسُ وَالْقَمَرُ لَا يُخْسَفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَادْعُوا اللَّهَ عَزَّ وَجَلَّ وَكَبِّرُوا وَتَصَدَّقُوا","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Hisyam bin 'Urwah] dari ['Urwah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Terjadinya gerhana Matahari dan bulan bukanlah karena mati atau hidupnya salah seorang, apabila kalian melihat hal itu, maka berdo'alah kepada Allah 'azza wajalla, bertakbirlah serta perbanyak sedekah.\""},"994":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالْعَتَاقَةِ فِي صَلَاةِ الْكُسُوفِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Za`idah] dari [Hisyam] dari [Fathimah] dari [Asma`] dia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk membebaskan budak pada waktu shalat (khutbah) gerhana.\""},"995":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنِي الْحَارِثُ بْنُ عُمَيْرٍ الْبَصْرِيُّ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ أَبِي قِلَابَةَ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُصَلِّي رَكْعَتَيْنِ رَكْعَتَيْنِ وَيَسْأَلُ عَنْهَا حَتَّى انْجَلَتْ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani] telah menceritakan kepadaku [Al Harits bin 'Umair Al Bahsri] dari [Ayyub As Sakhtiyani] dari [Abu Qilabah] dari [An Nu'man bin Basyir] dia berkata; \"Telah terjadi gerhana Matahari pada zaman Rasulullah shallallahu 'alaihi wasallam, beliau mengerjakan shalat dua raka'at, dua raka'at, dan beliau bertanya (tentang gerhana) hingga gerhana selesai.\" "},"996":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَكَدْ يَرْكَعُ ثُمَّ رَكَعَ فَلَمْ يَكَدْ يَرْفَعُ ثُمَّ رَفَعَ فَلَمْ يَكَدْ يَسْجُدُ ثُمَّ سَجَدَ فَلَمْ يَكَدْ يَرْفَعُ ثُمَّ رَفَعَ فَلَمْ يَكَدْ يَسْجُدُ ثُمَّ سَجَدَ فَلَمْ يَكَدْ يَرْفَعُ ثُمَّ رَفَعَ وَفَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ ثُمَّ نَفَخَ فِي آخِرِ سُجُودِهِ فَقَالَ أُفْ أُفْ ثُمَّ قَالَ رَبِّ أَلَمْ تَعِدْنِي أَنْ لَا تُعَذِّبَهُمْ وَأَنَا فِيهِمْ أَلَمْ تَعِدْنِي أَنْ لَا تُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ فَفَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَلَاتِهِ وَقَدْ أَمْحَصَتْ الشَّمْسُ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari ['Atha` bin As Sa`ib] dari [ayahnya] dari [Abdullah bin 'Amru] dia berkata; \"Pernah terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam berdiri (lama) seakan-akan tidak ruku', lalu ruku' (lama) seakan-akan tidak mengangkat kepala, kemudian mengangkat kepala, seakan-akan tidak sujud, kemudian sujud, seakan-akan tidak mengangkat kepala (duduk di antara dua sujud), kemudian mengangkat kepala (duduk di antara dua sujud) seakan-akan tidak sujud, kemudian sujud seakan-akan tidak bangkit, setelah itu beliau berdiri, beliau juga mengerjakan seperti itu di raka'at berikutnya, kemudian di akhir sujudnya beliau menghembuskan nafas sambil mengucapkan: \"Uf, uf.\" Lalu beliau berdo'a: \"Wahai Rabbku, bukankah Engkau telah berjanji kepadaku, bahwa Engkau tidak akan menyiksa mereka, sedangkan aku bersama mereka?, bukankah Engkau telah berjanji kepadaku, bahwa Engkau tidak akan menyiksa mereka, sedangkan mereka memohon ampunan?.\" Seusainya Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat, matahari menjadi cerah kembali.\" …kemudian perawi melanjutkan hadits tersebut.\""},"997":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَبَيْنَمَا أَتَرَمَّى بِأَسْهُمٍ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ كُسِفَتْ الشَّمْسُ فَنَبَذْتُهُنَّ وَقُلْتُ لَأَنْظُرَنَّ مَا أَحْدَثَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسُوفُ الشَّمْسِ الْيَوْمَ فَانْتَهَيْتُ إِلَيْهِ وَهُوَ رَافِعٌ يَدَيْهِ يُسَبِّحُ وَيُحَمِّدُ وَيُهَلِّلُ وَيَدْعُو حَتَّى حُسِرَ عَنْ الشَّمْسِ فَقَرَأَ بِسُورَتَيْنِ وَرَكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisr bin Al Mufadlal] telah menceritakan kepada kami [Al Jurairi] dari [Hayyan bin 'Umair] dari [Abdurrahman bin Samurah] dia berkata; \"Ketika kami melepaskan anak panah di masa hidupnya Rasulullah shallallahu 'alaihi wasallam, tiba-tiba terjadi gerhana Matahari, lalu aku segera meletakkan anak panah tersebut dan berkata; \"Sungguh aku akan melihat kejadian apa yang akan menimpa Rasulullah shallallahu 'alaihi wasallam pada hari terjadinya gerhana Matahari ini.\" lalu aku menemui beliau, ternyata beliau sedang mengangkat kedua tangannya sambil bertasbih, tahmid dan bertahlil serta berdo'a hingga gerhana hilang dari matahari. Beliau membaca dua surat dan shalat dua raka'at.\""},"998":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ جَبَلَةَ بْنِ أَبِي رَوَّادٍ حَدَّثَنِي حَرَمِيُّ بْنُ عُمَارَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ النَّضْرِ حَدَّثَنِي أَبِي قَالَكَانَتْ ظُلْمَةٌ عَلَى عَهْدِ أَنَسِ بْنِ مَالِكٍ قَالَ فَأَتَيْتُ أَنَسًا فَقُلْتُ يَا أَبَا حَمْزَةَ هَلْ كَانَ يُصِيبُكُمْ مِثْلُ هَذَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَعَاذَ اللَّهِ إِنْ كَانَتْ الرِّيحُ لَتَشْتَدُّ فَنُبَادِرُ الْمَسْجِدَ مَخَافَةَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amru bin Jabalah bin Abu Rawwad] telah menceritakan kepadaku [Harami bin 'umarah] dari ['Ubaidullah bin An Nadlr] telah menceritakan kepadaku [ayahku] dia berkata; \"Telah terjadi kegelapan yang sangat pada masa [Anas bin Malik], maka aku mendatangi Anas dan berkata kepadanya; \"Wahai Abu Hamzah, apakah kalian pernah mengalami kejadian seperti ini pada zaman Rasulullah shallallahu 'alaihi wasallam?\" Dia menjawab; \"Aku berlindung kepada Allah! Apabila angin berhembus dengan kencang, maka kami segera bergegas ke masjid, khawatir kalau terjadi kiamat.\""},"999":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ الثَّقَفِيُّ حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ حَدَّثَنَا سَلْمُ بْنُ جَعْفَرٍ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ قَالَقِيلَ لِابْنِ عَبَّاسٍ مَاتَتْ فُلَانَةُ بَعْضُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَّ سَاجِدًا فَقِيلَ لَهُ أَتَسْجُدُ هَذِهِ السَّاعَةَ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ آيَةً فَاسْجُدُوا وَأَيُّ آيَةٍ أَعْظَمُ مِنْ ذَهَابِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Utsman bin Abu Shafwan Ats Tsaqafi] telah menceritakan kepada kami [Yahya bin Katsir] telah menceritakan kepada kami [Salm bin Ja'far] dari [Al Hakam bin Aban] dari [Ikrimah] dia berkata; pernah di beritahukan kepada [Ibnu Abbas] bahwa fulanah -salah seorang dari istri Nabi shallallahu 'alaihi wasallam meninggal dunia-, lalu dia tersungkur sujud, dia ditanya; \"Apakah kamu sujud karena hal ini?\" Dia menjawab; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian melihat tanda-tanda kebesaran Allah, maka sujudlah!.\" Dan tanda kebesaran Allah yang manakah yang lebih besar dari pada wafatnya salah seorang dari istri Nabi shallallahu 'alaihi wasallam?\""},"1000":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفُرِضَتْ الصَّلَاةُ رَكْعَتَيْنِ رَكْعَتَيْنِ فِي الْحَضَرِ وَالسَّفَرِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَزِيدَ فِي صَلَاةِ الْحَضَرِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Shalih bin Kaisan] dari ['Urwah bin Zubair] dari [Aisyah radliallahu 'anha] dia berkata; \"Shalat di wajibkan dua raka'at-dua raka'at, baik ketika mukim atau dalam perjalanan, di tetapkan dua raka'at dalam perjalanan, dan di tambah (raka'atnya) ketika mukim.\""}};
